-- Poems batch 155
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ee8045c8-7c9c-4201-ba4a-5f058fe8e09f','挽黄承事三首  其三','廖行之','宋','宋诗','song-poetry','','[]','疇昔雲天一覩披，十年徒有夢追隨。',64,'全唐诗/poet.song.157000.json','["疇昔雲天一覩披，十年徒有夢追隨。", "擔簦已負異時志，仰斗今餘後學師。", "夜壑舟亡人孰秘，少微名在世空悲。", "嗟嗟莫致徐芻奠，掩袂傷心隕淚洟。"]'),
('54ce6682-9d9d-4742-af12-305f19850746','挽李主簿長民二首  其一','廖行之','宋','宋诗','song-poetry','','[]','蚤擅湘中二妙聲，一官政爾爲親榮。',64,'全唐诗/poet.song.157000.json','["蚤擅湘中二妙聲，一官政爾爲親榮。", "倦遊未試胸中藴，苦學徒遺身後名。", "踵武世科知有子，盡心色養足生平。", "可堪膝下稱觴處，不見伯仁賢弟兄。"]'),
('d8787c22-e7c5-43bc-a264-fda680df14de','挽李主簿長民二首  其二','廖行之','宋','宋诗','song-poetry','','[]','帝里從遊情最親，江頭一別幾經春。',64,'全唐诗/poet.song.157000.json','["帝里從遊情最親，江頭一別幾經春。", "追思語笑恍如昨，時枉音書寧厭頻。", "憂患自嗟非故我，昂藏不復見斯人。", "每哦風月無邊句，西望潸然淚滿巾。"]'),
('aab5b199-7771-483a-9995-2f8c26002521','挽劉主簿令二首  其一','廖行之','宋','宋诗','song-poetry','','[]','鴈行場屋久聯翩，賦客終爲桂籍僊。',64,'全唐诗/poet.song.157000.json','["鴈行場屋久聯翩，賦客終爲桂籍僊。", "鸞誥已封慈母貴，鯉庭仍見世科傳。", "轉頭生死歸何地，反掌榮枯欲問天。", "賤子門闌方有託，驚嗟梁木忽先顛。"]'),
('92f5fcbc-b9c3-4cc3-a4fb-26c63f6d1ec7','挽劉主簿令二首  其二','廖行之','宋','宋诗','song-poetry','','[]','投檄巴陵本爲親，遲留方擬問通津。',64,'全唐诗/poet.song.157000.json','["投檄巴陵本爲親，遲留方擬問通津。", "一官粗報平生志，萬里俄傾未老身。", "里棘豈堪棲鳳駐，冢花重歎卧麟新。", "我慙李漢無才望，敢效韓編作序人。"]'),
('041e2d2f-c687-44ff-a5ef-6c95354710b6','挽朱監廟明二首  其一','廖行之','宋','宋诗','song-poetry','','[]','人間世事最堪悲，有子騎鯨去不歸。',64,'全唐诗/poet.song.157000.json','["人間世事最堪悲，有子騎鯨去不歸。", "客廐謾遺陶母薦，萱堂空對老萊衣。", "黄金榜上嗟陳跡，白玉階前泣斷機。", "頼有青氈存眼底，滿庭蘭玉侍親闈。"]'),
('b2b7bff9-08bd-4b68-a74f-3839ff1cabe4','挽朱監廟明二首  其二','廖行之','宋','宋诗','song-poetry','','[]','平生知己幾何人，高誼如君最好親。',64,'全唐诗/poet.song.157000.json','["平生知己幾何人，高誼如君最好親。", "鶴蓋不隨青眼顧，鷄窗唯有白頭新。", "今誰肯借周瑜宅，待我深知管仲貧。", "腸斷眼穿明月嶺，九河傾淚一沾巾。"]'),
('61fe6aea-a789-4dc0-acd4-3fcc9953a5d3','玩易齋  其一','廖行之','宋','宋诗','song-poetry','','[]','三椽函宇宙，一卷肇乾坤。',24,'全唐诗/poet.song.157000.json','["三椽函宇宙，一卷肇乾坤。", "深味畫前意，寧於紙上論。"]'),
('ef2422d3-2c15-4732-bdcc-5f81a54c9e87','玩易齋  其二','廖行之','宋','宋诗','song-poetry','','[]','作者亦何患，思深義亦深。',24,'全唐诗/poet.song.157000.json','["作者亦何患，思深義亦深。", "忘言更忘象，默會古人心。"]'),
('942545ae-97dd-4104-a0bf-001f33875dfc','遣興四首  其一','廖行之','宋','宋诗','song-poetry','','[]','賤宜人弗齒，貧遣日勞心。',24,'全唐诗/poet.song.157000.json','["賤宜人弗齒，貧遣日勞心。", "不著新詩句，春愁那可禁。"]'),
('a3f2aaf0-4daa-4310-8cf3-ead23ccc6263','遣興四首  其二','廖行之','宋','宋诗','song-poetry','','[]','窮達渠非命，機關不到心。',24,'全唐诗/poet.song.157000.json','["窮達渠非命，機關不到心。", "新詩聊自遣，高興若爲禁。"]'),
('8ba1c1a1-a01b-4f7e-b0d2-850cdb79c828','遣興四首  其三','廖行之','宋','宋诗','song-poetry','','[]','無客共談道，有誰能賞心。',24,'全唐诗/poet.song.157000.json','["無客共談道，有誰能賞心。", "人生要自得，窮困吾能禁。"]'),
('619302fa-32c7-4e0a-8faa-bb3d48afa8c9','遣興四首  其四','廖行之','宋','宋诗','song-poetry','','[]','一生俱有分，萬事要無心。',24,'全唐诗/poet.song.157000.json','["一生俱有分，萬事要無心。", "强聒誠行險，危哉安可禁。"]'),
('30503741-cc6e-4be2-91cd-2ca0e9821a26','書詩隠何元仲詩卷','廖行之','宋','宋诗','song-poetry','','[]','歌舞純周雅，風流見夏時。',24,'全唐诗/poet.song.157000.json','["歌舞純周雅，風流見夏時。", "可能供痛飲，無畏誤雌霓。"]'),
('461cc0e5-fd66-4573-86bf-32ae4cc2e48c','方壺','廖行之','宋','宋诗','song-poetry','','[]','閲世觚稜如許，照人冰玉淵然。',28,'全唐诗/poet.song.157000.json','["閲世觚稜如許，照人冰玉淵然。", "箇裏可藏天地，塵中自有神仙。"]'),
('813d74da-3232-4756-9690-be0aef725c13','書陳頤剛墨梅扇','廖行之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','玉斧琢成明月，陳玄幻出橫枝。',28,'全唐诗/poet.song.157000.json','["玉斧琢成明月，陳玄幻出橫枝。", "依舊西湖風景，素衣聊受塵緇。"]'),
('23bd1581-82e9-44b5-8ba6-ea6a33a638d5','寄題李筠叟主簿所居竹齋','廖行之','宋','宋诗','song-poetry','','[]','寄傲寧須門柳，哦詩不必庭松。',28,'全唐诗/poet.song.157000.json','["寄傲寧須門柳，哦詩不必庭松。", "伴我虛心直節，領渠明月清風。"]'),
('6f94ee73-1532-4fa2-9aaa-c00c95474f18','書詩隠何元仲詩卷','廖行之','宋','宋诗','song-poetry','','[]','相馬玄黄牝牡，斲輪甘苦疾徐。',28,'全唐诗/poet.song.157000.json','["相馬玄黄牝牡，斲輪甘苦疾徐。", "元亮得琴中趣，彌明非世間書。"]'),
('f67aba35-c0f8-4f5c-8cc9-2731964284e2','半隠詩','廖行之','宋','宋诗','song-poetry','','[]','遠引未能忘世，端居且學灰心。',28,'全唐诗/poet.song.157000.json','["遠引未能忘世，端居且學灰心。", "定自隨時隠見，應非與俗浮湛。"]'),
('6526c751-f137-4314-a61a-b3c1e242074c','山居三首  其一','廖行之','宋','宋诗','song-poetry','','[]','鳥語喚回春夢，鷄聲叫出朝暾。',28,'全唐诗/poet.song.157000.json','["鳥語喚回春夢，鷄聲叫出朝暾。", "一段可人晴景，幾家深處田村。"]'),
('4ba9a5c9-9103-4e65-b444-bbe72f1fa2e0','山居三首  其二','廖行之','宋','宋诗','song-poetry','','[]','暖地池塘早綠，春和筍蕨先肥。',28,'全唐诗/poet.song.157000.json','["暖地池塘早綠，春和筍蕨先肥。", "慣作田家活計，懶隨廛市關機。"]'),
('4dba78c7-cf59-44be-aa94-ee65a1468968','山居三首  其三','廖行之','宋','宋诗','song-poetry','','[]','貴賤孰欣孰戚，窮通何損何加。',28,'全唐诗/poet.song.157000.json','["貴賤孰欣孰戚，窮通何損何加。", "成毀舉同墮甑，妍媸不屬鉛華。"]'),
('13bb5854-5b7a-492b-886f-a2137463142b','立春二首  其一','廖行之','宋','宋诗','song-poetry','','[]','曉雪纔過天氣清，喧闐鉦鼓喜迎春。',32,'全唐诗/poet.song.157000.json','["曉雪纔過天氣清，喧闐鉦鼓喜迎春。", "世間多少虛名事，綵仗驅牛又一新。"]'),
('9fd57842-2d40-4fc2-b829-b01927449fda','立春二首  其二','廖行之','宋','宋诗','song-poetry','','[]','隨意旛花剪綴新，盃盤草草簇芳辛。',32,'全唐诗/poet.song.157000.json','["隨意旛花剪綴新，盃盤草草簇芳辛。", "還欣好景平生事，贏得旬餘分外春。"]'),
('38272974-cded-4a72-86b8-5d0ffcebf321','和清明後即事','廖行之','宋','宋诗','song-poetry','','[]','柳陰嫩綠藏鶑語，花徑餘香著燕泥。',32,'全唐诗/poet.song.157000.json','["柳陰嫩綠藏鶑語，花徑餘香著燕泥。", "南畝十分農事好，平疇野水稱耕犂。"]'),
('2ed74871-4079-4140-ae62-05cf33ae37c0','和清明前即事三首  其一','廖行之','宋','宋诗','song-poetry','','[]','乍雨還晴近禁烟，踏青人憩楚江邊。',32,'全唐诗/poet.song.157000.json','["乍雨還晴近禁烟，踏青人憩楚江邊。", "花枝處處爭妍媚，粧點春光二月天。"]'),
('b6f8a1e2-bb3b-400d-833f-84660742c25c','和清明前即事三首  其二','廖行之','宋','宋诗','song-poetry','','[]','漫山百卉效奇珍，尤喜原頭雀舌新。',32,'全唐诗/poet.song.157000.json','["漫山百卉效奇珍，尤喜原頭雀舌新。", "不待清明改泉火，擷芳收取最先春。"]'),
('65af3979-3ea5-4527-b097-f806bc0a4065','和清明前即事三首  其三','廖行之','宋','宋诗','song-poetry','','[]','雨歇花畦徑未乾，春衣初試覺輕寒。',32,'全唐诗/poet.song.157000.json','["雨歇花畦徑未乾，春衣初試覺輕寒。", "所欣節物能多好，祓禊臨流江不瀾。"]'),
('5dbc18d5-7580-4b79-a357-8a5eccb4f4f3','春晚雨中','廖行之','宋','宋诗','song-poetry','','[]','綠楊庭院雨如絲，已是梅林欲熟時。',32,'全唐诗/poet.song.157000.json','["綠楊庭院雨如絲，已是梅林欲熟時。", "慚愧春工起歸興，向來節物彼何知。"]'),
('12a8b831-4423-44f0-a883-536f3b98765a','雨中惜海棠花四首  其一','廖行之','宋','宋诗','song-poetry','','[]','東君何事妬花妍，不遣春風一笑嫣。',32,'全唐诗/poet.song.157000.json','["東君何事妬花妍，不遣春風一笑嫣。", "邀動芳心愁萬縷，盈盈含恨雨中天。"]'),
('51f3f584-3a7f-46bc-8ed7-0bcc2f903e32','雨中惜海棠花四首  其二','廖行之','宋','宋诗','song-poetry','','[]','點綴春容特地妍，艷粧金縷臉霞嫣。',32,'全唐诗/poet.song.157000.json','["點綴春容特地妍，艷粧金縷臉霞嫣。", "無端風雨妬顔色，半吐芳心向晚天。"]'),
('46f25573-b314-48b9-bc0a-5867473ffa68','雨中惜海棠花四首  其三','廖行之','宋','宋诗','song-poetry','','[]','誰恨花枝苦未妍，故將雨熟醉顔嫣。',32,'全唐诗/poet.song.157000.json','["誰恨花枝苦未妍，故將雨熟醉顔嫣。", "禁寒來把芳絲吐，會向和風放暖天。"]'),
('b456b7c9-d732-41d1-b682-622be68e6e50','雨中惜海棠花四首  其四','廖行之','宋','宋诗','song-poetry','','[]','費盡胭脂畫不妍，春心一縷褪唇嫣。',32,'全唐诗/poet.song.157000.json','["費盡胭脂畫不妍，春心一縷褪唇嫣。", "雨中似是花神意，猶作西來舊蜀天。"]'),
('4f7b4b0b-7928-4223-95a9-ac9aeb7bf818','和送春四首  其一','廖行之','宋','宋诗','song-poetry','','[]','瀟湘江上送春歸，酒榼何人共我携。',32,'全唐诗/poet.song.157000.json','["瀟湘江上送春歸，酒榼何人共我携。", "不是吾儂怨春別，明朝車馬各東西。"]'),
('d8857120-7f34-4dcb-86d7-cbe0b63816b5','和送春四首  其二','廖行之','宋','宋诗','song-poetry','','[]','三月春工倦欲歸，花神應約手同携。',32,'全唐诗/poet.song.157000.json','["三月春工倦欲歸，花神應約手同携。", "明年早赴東郊迓，未論渠儂南北西。"]'),
('393d9be8-6f20-4628-8b20-5b5dff6135fd','和送春四首  其三','廖行之','宋','宋诗','song-poetry','','[]','晼晚春光作意歸，送春誰把酒樽携。',32,'全唐诗/poet.song.157000.json','["晼晚春光作意歸，送春誰把酒樽携。", "多情風雨留連處，幾看霖霪到日西。"]'),
('7bbe050c-5367-4532-b255-3cda823a2590','和送春四首  其四','廖行之','宋','宋诗','song-poetry','','[]','匆匆春馭去何忙，挽繫難憑柳線長。',32,'全唐诗/poet.song.157000.json','["匆匆春馭去何忙，挽繫難憑柳線長。", "好著新晴送行色，莫教風雨漫彷徨。"]'),
('af0a25a7-c71b-49c6-b2db-1dda682b0a90','和詠鶑','廖行之','宋','宋诗','song-poetry','','[]','雅正餘音隠小成，咿哇嘈囐彼何榮。',32,'全唐诗/poet.song.157000.json','["雅正餘音隠小成，咿哇嘈囐彼何榮。", "數聲睆彼遷喬語，一洗紛紛百口鳴。"]'),
('8c48be76-75de-413d-aebd-baad7071d438','豐城道中聞鶑書于故縣','廖行之','宋','宋诗','song-poetry','','[]','底事離羣今暮春，故人懷想渴生塵。',32,'全唐诗/poet.song.157000.json','["底事離羣今暮春，故人懷想渴生塵。", "陽關聲斷空回首，慚愧遷喬鳥語新。"]'),
('3d4f2845-012f-4ff4-b84d-f48b8def4b0e','午睡','廖行之','宋','宋诗','song-poetry','','[]','暑日薰蒸睡思濃，黑甜真處世情空。',32,'全唐诗/poet.song.157000.json','["暑日薰蒸睡思濃，黑甜真處世情空。", "那知一枕窗前夢，無限塵緣在眼中。"]'),
('29687a25-6e07-4a0d-a798-7159cfa01388','溽暑中一雨遂翛然枕上口占喜凉','廖行之','宋','宋诗','song-poetry','','[]','枕簟翛然夜氣舒，煩蒸無復到襟裾。',32,'全唐诗/poet.song.157000.json','["枕簟翛然夜氣舒，煩蒸無復到襟裾。", "慇懃多謝天公意，一雨生涼足有餘。"]'),
('ae4fcde8-e50a-4824-afc9-c37b81692cb5','月夜不寐  其一','廖行之','宋','宋诗','song-poetry','','[]','月薄西山夜氣清，就牀欹枕不勝情。',32,'全唐诗/poet.song.157000.json','["月薄西山夜氣清，就牀欹枕不勝情。", "姮娥似欲相鈎引，特地窺窗巧獻明。"]'),
('59d79be5-f935-4f9f-b678-f82d04dc216b','月夜不寐  其二','廖行之','宋','宋诗','song-poetry','','[]','寒著衾裯思不禁，月娥於我似鍾情。',32,'全唐诗/poet.song.157000.json','["寒著衾裯思不禁，月娥於我似鍾情。", "更添睠睠窺簷入，容與橫窗一带明。"]'),
('7243930b-c8c8-43bb-aae4-bad153b9f495','重九前二日夜雨','廖行之','宋','宋诗','song-poetry','','[]','去去重陽越夕間，瀟瀟風雨作輕寒。',32,'全唐诗/poet.song.157000.json','["去去重陽越夕間，瀟瀟風雨作輕寒。", "心知又負登高興，籬菊留來過後看。"]'),
('5f5cc858-af32-473f-b7e4-01458b5e57d1','和惜香紅二首  其一','廖行之','宋','宋诗','song-poetry','','[]','花神那作世間香，狂蝶遊蜂暗斷腸。',32,'全唐诗/poet.song.157000.json','["花神那作世間香，狂蝶遊蜂暗斷腸。", "不是朱顔向人吝，恥隨桃李倚門牆。"]'),
('dab7defd-9fb3-46cf-93c1-f4c180633d34','和惜香紅二首  其二','廖行之','宋','宋诗','song-poetry','','[]','韜藏馥郁保天真，珍重芳姿肯殢人。',32,'全唐诗/poet.song.157000.json','["韜藏馥郁保天真，珍重芳姿肯殢人。", "莫道清高便無韵，春來誰是解全身。"]'),
('3c8bfcac-5967-4294-be05-c9fa95dbf3d5','和武公望催梅三首  其一','廖行之','宋','宋诗','song-poetry','','[]','長羨南枝笑北枝，東風能早亦能遲。',32,'全唐诗/poet.song.157000.json','["長羨南枝笑北枝，東風能早亦能遲。", "而今滿樹渾無那，管領春光更有誰。"]'),
('73b5d828-572e-421f-af43-466e8c678248','和武公望催梅三首  其二','廖行之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','準擬花前玉斚飛，那知辜負隔年期。',32,'全唐诗/poet.song.157000.json','["準擬花前玉斚飛，那知辜負隔年期。", "枝頭未報春來信，閒却西湖處士詩。"]'),
('dc7ded3e-52f7-409b-8528-95ec0e1a8c97','和武公望催梅三首  其三','廖行之','宋','宋诗','song-poetry','','[]','絲絲弱柳猶迎歲，點點飛霙亦餞年。',32,'全唐诗/poet.song.157000.json','["絲絲弱柳猶迎歲，點點飛霙亦餞年。", "可是清高厭紛競，百花那許著鞭先。"]'),
('735bdf39-ce4d-4a15-9497-13b8337e9265','和武公望雪梅五首  其一','廖行之','宋','宋诗','song-poetry','','[]','雪裏最憐梅破萼，花時那負歲寒心。',32,'全唐诗/poet.song.157000.json','["雪裏最憐梅破萼，花時那負歲寒心。", "不因王子聊乘興，爭得林逋爲賞音。"]'),
('233e4850-ea95-4af6-b7c5-051ff3ead321','和武公望雪梅五首  其二','廖行之','宋','宋诗','song-poetry','','[]','自是陽和生處有，不同凡卉競時開。',32,'全唐诗/poet.song.157000.json','["自是陽和生處有，不同凡卉競時開。", "居然茹雪猶全節，底爲藏冰但却災。"]'),
('6711b0cd-36ab-4261-a331-b8ce0cffe0e5','和武公望雪梅五首  其三','廖行之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','刺火藝蘭能九畹，白衣訪菊亦東籬。',32,'全唐诗/poet.song.157000.json','["刺火藝蘭能九畹，白衣訪菊亦東籬。", "君詩喚起西湖老，好處何慙幼婦碑。"]'),
('0dfb21d0-8208-4035-8e23-20abc49f3f30','和武公望雪梅五首  其四','廖行之','宋','宋诗','song-poetry','','[]','臘殘春到無多日，留得清芬伴頌椒。',32,'全唐诗/poet.song.157000.json','["臘殘春到無多日，留得清芬伴頌椒。", "却放東風吹凍裂，遣渠堤柳又新條。"]'),
('8826e621-c50e-479f-befd-b29dcba5fb07','和武公望雪梅五首  其五','廖行之','宋','宋诗','song-poetry','','[]','水精宮闕偏宜汝，鐵石心腸肯受欺。',32,'全唐诗/poet.song.157000.json','["水精宮闕偏宜汝，鐵石心腸肯受欺。", "應笑蠟梅猶族姓，祇堪薪槱薦晨炊。"]'),
('1533c193-1ed6-4b83-850f-7faba69c53d2','再次武公望雪梅韵五首  其一','廖行之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','每憶西湖處士吟，暗香浮處最關心。',32,'全唐诗/poet.song.157000.json','["每憶西湖處士吟，暗香浮處最關心。", "而今也有冰霜操，祇要人知韶濩音。"]'),
('3340733d-034f-4589-bf09-558b1a05af59','再次武公望雪梅韵五首  其二','廖行之','宋','宋诗','song-poetry','','[]','從來陋巷祇顔回，子悅胡爲羨漆開。',32,'全唐诗/poet.song.157000.json','["從來陋巷祇顔回，子悅胡爲羨漆開。", "端向歲寒觀雅操，須知冰凌不爲災。"]'),
('bc79372a-d6a7-4d92-9651-58bffe6e834f','再次武公望雪梅韵五首  其三','廖行之','宋','宋诗','song-poetry','','[]','梅邊好與酒杯持，寂寂牙簷短短籬。',32,'全唐诗/poet.song.157000.json','["梅邊好與酒杯持，寂寂牙簷短短籬。", "但有詩人出佳句，絕勝謏墓得金碑。"]'),
('193a742e-1454-4efe-8d85-b330e781df94','再次武公望雪梅韵五首  其四','廖行之','宋','宋诗','song-poetry','','[]','自有天香軋魏姚，何須裂麝與塗椒。',32,'全唐诗/poet.song.157000.json','["自有天香軋魏姚，何須裂麝與塗椒。", "蠟梅卑俗紅梅媚，漫與增添本草條。"]'),
('4e3f148d-d0ca-4f83-837e-d7556e98328a','再次武公望雪梅韵五首  其五','廖行之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','休論青瑣與黄扉，祇有西湖不受欺。',32,'全唐诗/poet.song.157000.json','["休論青瑣與黄扉，祇有西湖不受欺。", "每向冰霜見全操，笑渠長夏受蒸炊。"]'),
('0f305b31-8080-4f25-b3b2-b34b56389744','梅','廖行之','宋','宋诗','song-poetry','','[]','江北江南入夏來，雲蒸日煦欲黄梅。',32,'全唐诗/poet.song.157000.json','["江北江南入夏來，雲蒸日煦欲黄梅。", "邸居兀坐關山隔，空想微酸到齒隈。"]'),
('2152f78b-9594-496e-aeec-fb77f83aeba6','和周少晳咏梅韵五首  其一','廖行之','宋','宋诗','song-poetry','','[]','孤根應得暖先回，天惜花房遣護開。',32,'全唐诗/poet.song.157000.json','["孤根應得暖先回，天惜花房遣護開。", "早是冰肌自清絕，却因冠玉更奇瑰。"]'),
('7d23aad4-bfb7-4419-959c-61ba19dc8b8c','和周少晳咏梅韵五首  其二','廖行之','宋','宋诗','song-poetry','','[]','太息凋年雨木冰，歲寒心事屬何人。',32,'全唐诗/poet.song.157000.json','["太息凋年雨木冰，歲寒心事屬何人。", "携筇試遶牆邊樹，喜見瓊林第一春。"]'),
('91d9e958-cb8c-419a-a19b-8e704142dfe6','和周少晳咏梅韵五首  其三','廖行之','宋','宋诗','song-poetry','','[]','銀色諸天渺不窮，森羅萬象匪磨鎔。',32,'全唐诗/poet.song.157000.json','["銀色諸天渺不窮，森羅萬象匪磨鎔。", "眼明的歷南枝好，絕勝瑶臺月下逢。"]'),
('530035a7-51ed-4859-8763-68d7d5f9b935','和周少晳咏梅韵五首  其四','廖行之','宋','宋诗','song-poetry','','[]','天姿不解入時粧，綴佩聯瓊特地芳。',32,'全唐诗/poet.song.157000.json','["天姿不解入時粧，綴佩聯瓊特地芳。", "幾日東風回隴首，却教羣卉羨天香。"]'),
('1103f92a-4a8a-426e-8984-0bfe6868aac2','和周少晳咏梅韵五首  其五','廖行之','宋','宋诗','song-poetry','','[]','弱植卑叢凍易摧，百花誰伴雪花開。',32,'全唐诗/poet.song.157000.json','["弱植卑叢凍易摧，百花誰伴雪花開。", "如今最識春先處，紅紫紛紛亦漫栽。"]'),
('4bbba421-21a1-4852-a723-426a30c988db','又和前韵十首  其一','廖行之','宋','宋诗','song-poetry','','[]','梅君消得爲高吟，素艷曾無媚世心。',32,'全唐诗/poet.song.157000.json','["梅君消得爲高吟，素艷曾無媚世心。", "粲粲牆隈自瀟灑，江南到處有知音。"]'),
('4b5aa8bc-1bdb-4aca-83c1-1ce06ce8e9a4','又和前韵十首  其二','廖行之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','貪看繁紅錦被堆，有人青眼爲君開。',32,'全唐诗/poet.song.157000.json','["貪看繁紅錦被堆，有人青眼爲君開。", "西湖千古林和靖，還悟犧尊木質災。"]'),
('a125bfa0-3ee6-4c56-9622-59fc41aa5c76','又和前韵十首  其三','廖行之','宋','宋诗','song-poetry','','[]','曲檻琱欄詫護持，寬閒何用著藩籬。',32,'全唐诗/poet.song.157000.json','["曲檻琱欄詫護持，寬閒何用著藩籬。", "林間立馬多真賞，須信行人口是碑。"]'),
('09abb857-a4c4-4d93-bf86-8980a4170680','又和前韵十首  其四','廖行之','宋','宋诗','song-poetry','','[]','結實收功鼎鼐調，不論江路與山椒。',32,'全唐诗/poet.song.157000.json','["結實收功鼎鼐調，不論江路與山椒。", "可憐楊柳空牽嫵，飛盡狂緜祇綠條。"]'),
('db5177aa-5b78-4faf-bdc0-a62a8235b6e4','又和前韵十首  其五','廖行之','宋','宋诗','song-poetry','','[]','客舍袁安雪壅扉，清標廩廩詎容欺。',32,'全唐诗/poet.song.157000.json','["客舍袁安雪壅扉，清標廩廩詎容欺。", "如今凍解梅無恙，還似高眠甑不炊。"]'),
('65ec1bf6-915d-44fa-89dd-e341d4ea02d1','又和前韵十首  其六','廖行之','宋','宋诗','song-poetry','','[]','新詩筆力可天回，萬里東風掃凍開。',32,'全唐诗/poet.song.157000.json','["新詩筆力可天回，萬里東風掃凍開。", "照眼玉英清徹骨，花神報子亦瓊瑰。"]'),
('2827580b-ec84-4f4a-b74c-ee76d29e5a40','又和前韵十首  其七','廖行之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','嫩蘂含芳恰褪冰，此時偏惱少陵人。',32,'全唐诗/poet.song.157000.json','["嫩蘂含芳恰褪冰，此時偏惱少陵人。", "顛狂覓酒尋詩去，賞遍西湖幾樹春。"]'),
('68a3076f-30fe-4078-8fee-4b715d81dc37','又和前韵十首  其八','廖行之','宋','宋诗','song-poetry','','[]','癡絕兒童不耐窮，搓酥綴蠟競銷鎔。',32,'全唐诗/poet.song.157000.json','["癡絕兒童不耐窮，搓酥綴蠟競銷鎔。", "如何見得真風度，須索天工歲一逢。"]'),
('ceff3bd3-75ec-42cf-8321-2c6c529f207a','又和前韵十首  其九','廖行之','宋','宋诗','song-poetry','','[]','如今總總鬭新粧，天與風姿壓衆芳。',32,'全唐诗/poet.song.157000.json','["如今總總鬭新粧，天與風姿壓衆芳。", "自是百年中第一，不因蘭菊返魂香。"]'),
('aaa4f19a-3415-4d83-914a-eae5d9e98a44','又和前韵十首  其一○','廖行之','宋','宋诗','song-poetry','','[]','勁氣由來不可摧，年年偏向臘前開。',32,'全唐诗/poet.song.157000.json','["勁氣由來不可摧，年年偏向臘前開。", "清芬肯爲冰霜減，好在含章簷下栽。"]'),
('26b4e217-8a0a-4741-a327-24b28f333c53','和真珠花二首  其一','廖行之','宋','宋诗','song-poetry','','[]','瓊林玉女職司花，裝綴珠璣泣露華。',32,'全唐诗/poet.song.157000.json','["瓊林玉女職司花，裝綴珠璣泣露華。", "妙手有神俄點化，靈根何日下天涯。"]'),
('9c8a48b1-bfe2-419e-9e73-0fa9d506d999','和真珠花二首  其二','廖行之','宋','宋诗','song-poetry','','[]','纍纍瓔珞作新裝，萬蘤勻開細細香。',32,'全唐诗/poet.song.157000.json','["纍纍瓔珞作新裝，萬蘤勻開細細香。", "好是花時最清絕，月明珠露夜初長。"]'),
('844ed1d6-d5f4-475b-8e3b-f12201f8cb68','和人乞朱櫻十首  其一','廖行之','宋','宋诗','song-poetry','','[]','見說朱櫻正及時，眼穿火齊曉雲披。',32,'全唐诗/poet.song.157000.json','["見說朱櫻正及時，眼穿火齊曉雲披。", "筠籠走送還能否，好带朝霜摘幾枝。"]'),
('fc73a585-8ad8-4b3d-8f94-51af4a0f5e40','和人乞朱櫻十首  其二','廖行之','宋','宋诗','song-poetry','','[]','桃李從渠著斗量，明珠顆顆更含香。',32,'全唐诗/poet.song.157000.json','["桃李從渠著斗量，明珠顆顆更含香。", "紅顔不老如丹渥，笑詫南翁見未嘗。"]'),
('b2a931f7-b6d8-483f-8a5a-8161eea6b361','和人乞朱櫻十首  其三','廖行之','宋','宋诗','song-poetry','','[]','當年上苑得殊觀，爾許勻圓訝走盤。',32,'全唐诗/poet.song.157000.json','["當年上苑得殊觀，爾許勻圓訝走盤。", "容易香山白居士，漫同樊素等閑看。"]'),
('bf9e15c2-0c07-4647-a0f5-04ffef8c183d','和人乞朱櫻十首  其四','廖行之','宋','宋诗','song-poetry','','[]','浮沉閑却紫玻璃，洗盞丁寧已戒兒。',32,'全唐诗/poet.song.157000.json','["浮沉閑却紫玻璃，洗盞丁寧已戒兒。", "會見金盤紅萬顆，爲君痛飲倒酴醾。"]'),
('a862a3ea-6749-4dee-8731-557e73537d98','和人乞朱櫻十首  其五','廖行之','宋','宋诗','song-poetry','','[]','侯門珍膳詫猩唇，肉食愚哉鄙若人。',32,'全唐诗/poet.song.157000.json','["侯門珍膳詫猩唇，肉食愚哉鄙若人。", "安得頳珠洗葷濁，驪龍方寐詎非真。"]'),
('90591f85-5aca-4a54-88f7-6842d615e2f8','和人乞朱櫻十首  其六','廖行之','宋','宋诗','song-poetry','','[]','那須得得列盃盤，不念貧兒逐彈丸。',32,'全唐诗/poet.song.157000.json','["那須得得列盃盤，不念貧兒逐彈丸。", "齒頰猶能識珍味，乞渠細咀辨甘酸。"]'),
('4b7e95fe-8e51-463f-a8a2-5e3f05aa5b09','和人乞朱櫻十首  其七','廖行之','宋','宋诗','song-poetry','','[]','舊聞雲夢澤邊城，飽飫林間主不嗔。',32,'全唐诗/poet.song.157000.json','["舊聞雲夢澤邊城，飽飫林間主不嗔。", "薄暮一鞭飛騎迅，歸來盈袖熟紅勻。"]'),
('558a6e91-a043-4366-8d37-830ade661741','和人乞朱櫻十首  其八','廖行之','宋','宋诗','song-poetry','','[]','族派蟠桃譜牒存，三千歷歲物難羣。',32,'全唐诗/poet.song.157000.json','["族派蟠桃譜牒存，三千歷歲物難羣。", "黠兒尚許三偷摘，可是年年不見分。"]'),
('8a7ba2f6-d206-4ed4-b720-74f49b2f9425','和人乞朱櫻十首  其九','廖行之','宋','宋诗','song-poetry','','[]','連朝急雨相狂風，愁絕枝頭入望中。',32,'全唐诗/poet.song.157000.json','["連朝急雨相狂風，愁絕枝頭入望中。", "不比來禽與青李，端能炯炯照顔紅。"]'),
('7394aa04-ec26-4dac-a1fc-c9ad756730ab','和人乞朱櫻十首  其一○','廖行之','宋','宋诗','song-poetry','','[]','惱亂詩情庾子山，饞涎渾似未朝餐。',32,'全唐诗/poet.song.157000.json','["惱亂詩情庾子山，饞涎渾似未朝餐。", "張頤一飽非難辦，爭得君家伏火丹。"]'),
('bc2d3d33-ba85-483d-a3bb-bad14ba2a9d4','和食蕨三首  其一','廖行之','宋','宋诗','song-poetry','','[]','放箸朝來頗不貧，野盤春蕨正宜人。',32,'全唐诗/poet.song.157000.json','["放箸朝來頗不貧，野盤春蕨正宜人。", "玉條縷縷東風軟，慚愧山家爲薦新。"]'),
('4d037a12-7fa3-47a3-bdf8-eac4f2016d8f','和食蕨三首  其二','廖行之','宋','宋诗','song-poetry','','[]','根荄蔓衍布山巔，一夕春雷引怒拳。',32,'全唐诗/poet.song.157000.json','["根荄蔓衍布山巔，一夕春雷引怒拳。", "足我窮中八珍味，竹萌木耳更求旃。"]'),
('d373f920-3ab4-4a0a-8838-dc6d5a913929','和食蕨三首  其三','廖行之','宋','宋诗','song-poetry','','[]','不須態掌夸珍膳，安用雞趺快嗜情。',32,'全唐诗/poet.song.157000.json','["不須態掌夸珍膳，安用雞趺快嗜情。", "富有漫山千臂指，何妨採擷日充盈。"]'),
