('1e825e93-7e8a-4105-873a-213b9551c504','壽五一弟四首  其三','廖行之','宋','宋诗','song-poetry','','[]','奉養烝嘗子職共，盍迎爾相重承宗。',32,'全唐诗/poet.song.157000.json','["奉養烝嘗子職共，盍迎爾相重承宗。", "人生正始嚴昏娶，嬖御雖賢禮不容。"]'),
('6c8a7a4b-0c03-4b7a-b146-77635bb23961','壽五一弟四首  其四','廖行之','宋','宋诗','song-poetry','','[]','哲命天年本自貽，若爲五福具期頤。',32,'全唐诗/poet.song.157000.json','["哲命天年本自貽，若爲五福具期頤。", "義方端是長生藥，安用金丹與玉芝。"]'),
('75b281c5-0f36-4ed4-b1fd-dda10d581d30','壽湖南汪倉十首  其一','廖行之','宋','宋诗','song-poetry','','[]','西府風流載世長，玉龍鱗甲更儲祥。',32,'全唐诗/poet.song.157000.json','["西府風流載世長，玉龍鱗甲更儲祥。", "慶源衮衮多英傑，可但韋平一再芳。"]'),
('4d882f32-0691-4f4e-8122-9f0f7e9685aa','壽湖南汪倉十首  其二','廖行之','宋','宋诗','song-poetry','','[]','見說奎文得歲時，杓携天北啟天機。',32,'全唐诗/poet.song.157000.json','["見說奎文得歲時，杓携天北啟天機。", "黄陂嗣有公侯氣，牛斗揚光曜紫微。"]'),
('48481829-7d78-4944-8145-9c5ca1e64d34','壽湖南汪倉十首  其三','廖行之','宋','宋诗','song-poetry','','[]','萬卷詩書即肯堂，儒宗氣習洗膏粱。',32,'全唐诗/poet.song.157000.json','["萬卷詩書即肯堂，儒宗氣習洗膏粱。", "天資問學俱前輩，須信源深流正長。"]'),
('112b7eff-10de-456f-9abd-b5c9953a9561','壽湖南汪倉十首  其四','廖行之','宋','宋诗','song-poetry','','[]','不用籝金累世資，名家人物照清時。',32,'全唐诗/poet.song.157000.json','["不用籝金累世資，名家人物照清時。", "碧梧翠竹今何羨，森立庭前丹桂枝。"]'),
('90ee377c-ac39-48da-9715-becda221633f','壽湖南汪倉十首  其五','廖行之','宋','宋诗','song-poetry','','[]','六月湖田槁欲𤓉，嶽雲俄起雨如川。',32,'全唐诗/poet.song.157000.json','["六月湖田槁欲𤓉，嶽雲俄起雨如川。", "不憑公意回天意，爭得饑年變有年。"]'),
('512dbb8a-4bc5-4a47-951a-87cf214e3e55','壽湖南汪倉十首  其六','廖行之','宋','宋诗','song-poetry','','[]','百萬喁喁日苦饑，左餐右粥轉歡嬉。',32,'全唐诗/poet.song.157000.json','["百萬喁喁日苦饑，左餐右粥轉歡嬉。", "也知振廩非私惠，端爲皇家愛本基。"]'),
('449dd836-e2cb-4667-8c18-bdac57925839','壽湖南汪倉十首  其七','廖行之','宋','宋诗','song-poetry','','[]','饑腹那堪癘鬼欺，萬金良藥起沈羸。',32,'全唐诗/poet.song.157000.json','["饑腹那堪癘鬼欺，萬金良藥起沈羸。", "致和自可消羣沴，小試猶煩活國醫。"]'),
('2e2286a6-022d-4653-802a-81aea1282695','壽湖南汪倉十首  其八','廖行之','宋','宋诗','song-poetry','','[]','賦政頻年合簡求，民情滋欲得公留。',32,'全唐诗/poet.song.157000.json','["賦政頻年合簡求，民情滋欲得公留。", "雖然湖外私膏澤，須索樊侯入佐周。"]'),
('07fa88b7-f94b-42bb-bd59-ff37be4dfe23','壽湖南汪倉十首  其九','廖行之','宋','宋诗','song-poetry','','[]','紫樞勳業舊青氈，更上中台秉化權。',32,'全唐诗/poet.song.157000.json','["紫樞勳業舊青氈，更上中台秉化權。", "它日鴻鈞陶壽域，赤松相與不論年。"]'),
('93dd5e09-51eb-4f38-9101-27702b8bcaf0','壽湖南汪倉十首  其一○','廖行之','宋','宋诗','song-poetry','','[]','三年弱羽自清陰，行借高風入上林。',32,'全唐诗/poet.song.157000.json','["三年弱羽自清陰，行借高風入上林。", "猶向齊庭一伸喙，此鳴端亦爲知音。"]'),
('bd1dbe98-3d58-4c9e-9401-e312562ba8d5','田縣尉悲風詞','廖行之','宋','宋诗','song-poetry','','[]','風蕭蕭兮吹我衣，念故人兮我心孔悲。',196,'全唐诗/poet.song.157000.json','["風蕭蕭兮吹我衣，念故人兮我心孔悲。", "飛霞爲襜兮彩雲爲旂，胡徘徊兮耒江之湄。", "風蕭蕭兮吹我裳，念故人兮我心孔傷。", "星辰爲珮兮明月爲璫，胡襄羊兮耒山之陽。", "耒山高高兮耒水清清，高者君之氣兮清爲君之神。", "君挾此以生兮不隘以大，胡皎以明兮忽湮以曖。", "堂有老兮室有稚，能不抱孫兮樂親以戲。", "子如不暇恤兮親寧忍忘，孰奪之去兮不少翺翔。", "大江之南兮淛江之東，昔與君兮笑言相從。", "想丹旐兮埋圭玉於土中，千里泫然兮余獨感此悲風。"]'),
('5a52c97c-88ba-4e84-be50-d3b3d5b08375','野花','廖行之','宋','宋诗','song-poetry','','[]','草木送春歸去後，山花種種自然開。',64,'全唐诗/poet.song.157000.json','["草木送春歸去後，山花種種自然開。", "略無醉倒遊人至，自有交情戲蝶來。", "日暖欲令紛錦繡，風和未遣委莓苔。", "清幽渾絕囂塵態，應遣青陽恨莫陪。"]'),
('5de709a1-c48a-46fe-8c69-17630b1a9c49','落花  其一','廖行之','宋','宋诗','song-poetry','','[]','春深處處有花妍，已覺春工興浩然。',32,'全唐诗/poet.song.157000.json','["春深處處有花妍，已覺春工興浩然。", "投曉憑欄枝上看，飄零贏得舞容翩。"]'),
('f84c44ad-f4a4-4693-b11f-2f3853138c55','落花  其二','廖行之','宋','宋诗','song-poetry','','[]','花枝春老不禁寒，一夕狂風到畫欄。',32,'全唐诗/poet.song.157000.json','["花枝春老不禁寒，一夕狂風到畫欄。", "飛盡繁紅委苔徑，明朝猶作錦茵看。"]'),
('ba838695-b0e1-41bf-84c9-d10926adab10','落花  其三','廖行之','宋','宋诗','song-poetry','','[]','芳心都付蜜紛披，薄恨狂蜂有底知。',32,'全唐诗/poet.song.157000.json','["芳心都付蜜紛披，薄恨狂蜂有底知。", "紅雨一番春事罷，綠陰誰把酒杯持。"]'),
('165bec95-fffd-4f98-be24-9130bfcdd532','句','羅舜舉','宋','宋诗','song-poetry','','[]','臘酒催詩處，春幡剪綵時。',12,'全唐诗/poet.song.157000.json','["臘酒催詩處，春幡剪綵時。"]'),
('710f5747-5bbf-47f5-be50-ce4f6fa34d1b','暮之春六章章五句  其一','陳傅良','宋','宋诗','song-poetry','','[]','暮之春兮物維其嘉，乾際兮坤涯。',43,'全唐诗/poet.song.157000.json','["暮之春兮物維其嘉，乾際兮坤涯。", "母將雛兮彼實者華，魚在藻兮燕子還于故家，今者不樂兮云何。"]'),
('e45f1c91-2983-4978-941f-f539ec2264a4','暮之春六章章五句  其二','陳傅良','宋','宋诗','song-poetry','','[]','暮之春兮風日與柔，桑女兮南疇。',39,'全唐诗/poet.song.157000.json','["暮之春兮風日與柔，桑女兮南疇。", "相爾夏畦兮悲秋，斲冰兮長夜無裘，今者不樂兮何求。"]'),
('d78f8ac5-c022-4aef-ae23-623559e18e92','暮之春六章章五句  其三','陳傅良','宋','宋诗','song-poetry','','[]','暮之春兮雍雍熙熙，堯裳兮舜衣。',46,'全唐诗/poet.song.157000.json','["暮之春兮雍雍熙熙，堯裳兮舜衣。", "五絃之琴兮一夔，曾不知結繩與秉鉞兮何時，瞻言千載兮忽焉其遠而。"]'),
('20274c86-9d8e-4bb7-b1d6-f69e2614e38b','暮之春六章章五句  其四','陳傅良','宋','宋诗','song-poetry','','[]','山有龜蒙兮水有沂，天未喪斯文兮在茲。',42,'全唐诗/poet.song.157000.json','["山有龜蒙兮水有沂，天未喪斯文兮在茲。", "二三子兮皇皇欲何之，鼓瑟兮爲誰，捨此兮吾將安歸。"]'),
('7a61e11e-12d3-434e-b51b-b3c8790732a1','暮之春六章章五句  其五','陳傅良','宋','宋诗','song-poetry','','[]','止齋兮年年，室環堵兮兩山有川。',44,'全唐诗/poet.song.157000.json','["止齋兮年年，室環堵兮兩山有川。", "鷗鷺巢簷兮圓荷田田，豈無芳草兮杜鵑，世微孔子兮獨抱乎韋編。"]'),
('6d1f4b95-0bd9-4f22-be9a-ac90022264e4','暮之春六章章五句  其六','陳傅良','宋','宋诗','song-poetry','','[]','雲漢之章兮光燭天，朝宗兮列仙。',46,'全唐诗/poet.song.157000.json','["雲漢之章兮光燭天，朝宗兮列仙。", "胡歸晚兮病骨拳然，與客歌商兮忘食與眠，點爾何如兮吾未知其孰賢。"]'),
('1942da8a-af53-4610-a039-33328a7cd676','西廟招辭','陳傅良','宋','宋诗','song-poetry','','[]','君昔兮胡不去斯，君今兮胡不來斯。',191,'全唐诗/poet.song.157000.json','["君昔兮胡不去斯，君今兮胡不來斯。", "文棟兮琱楣，峴山之麓兮江圻。", "旨酒牲兮潔肥，皓遺老兮鬚眉。", "坎擊鼓兮吹箎，君勿來兮遲遲。", "山蜿蜿兮榕陰萎蕤，江水清夷兮無蛟與螭。", "君之來兮可以娛嬉，君不共安兮誰與共危。", "鳴玉兮衮衣，彼亦君兮一時。", "莽中州兮爲夷，匪冢則廟兮牛羊纍纍。", "尚我民兮有知，子子孫孫兮永依。", "揆之兮以是非，君舍此兮安之。", "田有畔兮澤有陂，桑稻兮誕彌，懷不報兮忸怩。", "日早暮兮夜何其，猶容與兮誰須。"]'),
('e1fb11ba-cb1e-4678-a7a9-51f48423ab37','落葉一首別諸友客新昌','陳傅良','宋','宋诗','song-poetry','','[]','落葉一二數，遥夜忽已午。',84,'全唐诗/poet.song.157000.json','["落葉一二數，遥夜忽已午。", "百年能幾何，望道猶未睹。", "清揚得邂逅，簡易從險阻。", "明朝買扁舟，萬議付風雨。", "新詩話別恨，爲我謝酸楚。", "蒼蒼歲後竹，白首見肺腑。", "要有不別時，尸居一環堵。"]'),
('edc47029-7acc-41ed-baab-0badbe458513','讀范文正公神道碑有感佚事','陳傅良','宋','宋诗','song-poetry','','[]','武侯不可致，玄德造其廬。',132,'全唐诗/poet.song.157000.json','["武侯不可致，玄德造其廬。", "公在衰絰中，乃上時政書。", "維時君臣定，事與草昧殊。", "出處千載同，豈必名迹如。", "行伍拔大將，寒饑得名儒。", "推轂天下士，百年用其餘。", "生平慕河汾，未許王魏俱。", "慇懃八司馬，意獨何區區。", "自古朋黨論，消復莽無期。", "誰令羣疑亡，韓富及有爲。", "惜哉公不見，功名止西陲。"]'),
('57351738-d78b-4b2c-ba36-50b5997f98f6','送國子監丞顔幾聖提舉江東分韵得動字','陳傅良','宋','宋诗','song-poetry','','[]','長安夜未艾，客枕厭羣動。',96,'全唐诗/poet.song.157000.json','["長安夜未艾，客枕厭羣動。", "平明視天闕，劍珮鳴珌琫。", "學省雖冷官，上意嚮周孔。", "六飛自天下，多士溘雲滃。", "饔餐燕苹鹿，道義發醯蠓。", "方將屬耆英，高舉出埃塕。", "離觴春駘蕩，歸路月朣朧。", "勳業當及時，千年付南董。"]'),
('b6afdba9-24ee-4f79-8baf-65c1e9132007','懷寧國守鄭少卿景望','陳傅良','宋','宋诗','song-poetry','','[]','一日一度過短牆，三日風雨撓我觴。',64,'全唐诗/poet.song.157000.json','["一日一度過短牆，三日風雨撓我觴。", "天球河圖在東序，保障繭絲分晉陽。", "我欲從之苕水遠，搔首不見月滿廊。", "笑看兒女羅列拜，老人星下燒夜香。"]'),
('a9236001-ec42-43ef-b90c-61c7e1ef066b','送宋國博參議江東分韵得夜字前年上幸學一時同舍今去略盡爲之悵然','陳傅良','宋','宋诗','song-poetry','','[]','南門供帳江上亭，北門觴酒湖邊榭。',208,'全唐诗/poet.song.157000.json','["南門供帳江上亭，北門觴酒湖邊榭。", "兩年出餞略可數，往往行人半同舍。", "憶昔翠華臨璧海，儒先一日爭聲價。", "蘇君舌掉巫峽水，楊君氣奪幽并夜。", "黄君石矻不可轉，夫子居然古彜斚。", "艾軒風流天下少，獨奏咸韶無濩夏。", "黄粱未熟事如許，白髮不生心亦怕。", "古來賢俊多坎軻，道與世違胡足詫。", "武皇好少臣已老，孟子尊王君尚霸。", "嗟乎夫子幸遭時，諸公衮衮皆流亞。", "德尊不過五品薄，歲晚曾無一飯暇。", "君恩豈必間湖海，家事姑惟問桑稼。", "此行端可振頹俗，令我短轅今欲駕。"]'),
('b811a045-8991-4528-8639-56644d80a4fd','遊鼓山','陳傅良','宋','宋诗','song-poetry','','[]','鼓山聞天下，一見名不空。',168,'全唐诗/poet.song.157000.json','["鼓山聞天下，一見名不空。", "自從周職方，閩在王會中。", "登山亦幾人，興寄隨所逢。", "騎君常愒日，遷客多悲風。", "劍川發甌西，萬阻與海通。", "忽焉得平壤，北山矗其東。", "我行未及巔，已見國勢雄。", "三韓到吳會，不可道里窮。", "俯瞰南來帆，沄沄自朝宗。", "曩時諸降王，各撫千里封。", "相招神銜圖，旅獻東都宮。", "東都今何如，胡馬鳴蒿蓬。", "一春長雨霧，明日歸樊籠。", "恣探泉石幽，篝燈道歸筇。"]'),
('8daa292a-d1dc-4f12-9c2b-b445bedb48e0','和孫偉卿雜言十章  其一','陳傅良','宋','宋诗','song-poetry','','[]','萬事如浮雲，可翫不可有。',24,'全唐诗/poet.song.157000.json','["萬事如浮雲，可翫不可有。", "三年刻一葉，未就骨已朽。"]'),
('6a0256c6-790e-4b27-9bb8-d19707208b9e','和孫偉卿雜言十章  其二','陳傅良','宋','宋诗','song-poetry','','[]','可憐負薪子，誤有廊廟志。',24,'全唐诗/poet.song.157000.json','["可憐負薪子，誤有廊廟志。", "出門欲何之，馬拙車未試。"]'),
('d8bb5087-2b4d-4f44-b213-f263062f58e7','和孫偉卿雜言十章  其三','陳傅良','宋','宋诗','song-poetry','','[]','一飯腹果然，身外百不須。',24,'全唐诗/poet.song.157000.json','["一飯腹果然，身外百不須。", "深知饑方朔，不似飽侏儒。"]'),
('0e8984d6-3990-43ce-b7d6-bfdbd0667c1d','和孫偉卿雜言十章  其四','陳傅良','宋','宋诗','song-poetry','','[]','墮落生死間，大患爲有身。',24,'全唐诗/poet.song.157000.json','["墮落生死間，大患爲有身。", "老子識未破，天地豈不仁。"]'),
('8f78603a-b4fb-4f73-8dce-4ebe44ad89dc','和孫偉卿雜言十章  其五','陳傅良','宋','宋诗','song-poetry','','[]','幽居悟前疲，寡欲得身健。',24,'全唐诗/poet.song.157000.json','["幽居悟前疲，寡欲得身健。", "筮之此何祥，厥繇無水困。"]'),
('23834ad1-5f1a-451d-afac-e6b7ab363905','和孫偉卿雜言十章  其六','陳傅良','宋','宋诗','song-poetry','','[]','有書但插架，有門亦常關。',24,'全唐诗/poet.song.157000.json','["有書但插架，有門亦常關。", "是非天下爭，而我土石頑。"]'),
('0a742215-23dc-4cdc-9e71-c646d913ef71','和孫偉卿雜言十章  其七','陳傅良','宋','宋诗','song-poetry','','[]','好酒來誰家，明月得我心。',24,'全唐诗/poet.song.157000.json','["好酒來誰家，明月得我心。", "把酒弄明月，醉卧盜不侵。"]'),
('208b5e0b-db37-4fb4-b574-5c2e58d15dee','和孫偉卿雜言十章  其八','陳傅良','宋','宋诗','song-poetry','','[]','阨窮果何尤，利達竟誰在。',24,'全唐诗/poet.song.157000.json','["阨窮果何尤，利達竟誰在。", "眷言荷鉏人，妻子敬相待。"]'),
('fc372948-ea45-46d7-9b05-ade402bfa83d','和孫偉卿雜言十章  其九','陳傅良','宋','宋诗','song-poetry','','[]','或勸著子書，我恐落人世。',24,'全唐诗/poet.song.157000.json','["或勸著子書，我恐落人世。", "呼兒具紙筆，一歲復一歲。"]'),
('76bdec98-436c-4018-8c25-1126e864fe5a','和孫偉卿雜言十章  其一○','陳傅良','宋','宋诗','song-poetry','','[]','人事盡鄉曲，田租了王官。',24,'全唐诗/poet.song.157000.json','["人事盡鄉曲，田租了王官。", "獨於大海枯，不改古井寒。"]'),
('48eb4e6d-3153-452e-a4b8-483f845f14e4','送林正仲丞王山','陳傅良','宋','宋诗','song-poetry','','[]','去年我爲客，持酒送君歸。',108,'全唐诗/poet.song.157000.json','["去年我爲客，持酒送君歸。", "君今理征驂，我適卧舊廬。", "人生足離合，仕宦相乘除。", "科名餘十年，丞縣亦既遲。", "顔色日愈好，絕口無歔欷。", "自言有時命，歲宴知何如。", "深藏濟人具，不作借勢書。", "虛名多自誤，徐步乃疾驅。", "從茲拭老眼，看君上亨衢。"]'),
('35fff1f8-f649-44fa-8e99-8818a4df7e62','和林懿仲喜雪韵','陳傅良','宋','宋诗','song-poetry','','[]','常晹厥咎何，君相疚朝夕。',168,'全唐诗/poet.song.157000.json','["常晹厥咎何，君相疚朝夕。", "愧莫慰羣黎，凄其望三白。", "是心與天通，昨夜平地尺。", "簑笠在東阡，耰耡在西陌。", "忍待明年飽，欣及吾事隙。", "海宇正無塵，草木亦煥赫。", "遥知紫宸朝，千官手加額。", "溫綸粲龍光，賀牘交馬跡。", "銜枚懸瓠城，仗節居延澤。", "獨擁藍關馬，共飯滹沱麥。", "更願吾君相，對此念忠赤。", "當今挾纊溫，恩意到疆埸。", "有士如有年，要豈旦日積。", "袁安自甘寢，掃軌無過客。"]'),
('b736b5e7-61cf-4c61-ae82-cf2cdb5e0eac','再和前韵','陳傅良','宋','宋诗','song-poetry','','[]','冬夜苦難曉，短景復易夕。',168,'全唐诗/poet.song.157000.json','["冬夜苦難曉，短景復易夕。", "安得戶牖光，不待東方白。", "恍如游化城，瓊臺若千尺。", "英華發林藪，餘彩散阡陌。", "平鋪浩無垠，巽入微有隙。", "忍寒貪縱觀，未願朝曦赫。", "柳綿著歌茵，梅片墮粧額。", "皭然羣汙中，有意欲比迹。", "自識玉皇家，癯仙陋山澤。", "新來學爲農，遭歲屢無麥。", "穉子色恒饑，老婢脚盡赤。", "一飯今有待，喜更問瓜埸。", "歸來看牀頭，瓶粟幸餘積。", "且以炊春醪，號召已散客。"]'),
('53ce2288-fe0f-4a7d-a03b-4331d375abdd','除夜用前韵','陳傅良','宋','宋诗','song-poetry','','[]','又添犬馬齒，常恐牛羊夕。',168,'全唐诗/poet.song.157000.json','["又添犬馬齒，常恐牛羊夕。", "牙無數株牢，鬢已太半白。", "六朝貴人家，珊瑚高數尺。", "復有陵邑豪，沃壤動連陌。", "居然燕巢幙，忽矣駒過隙。", "伊傅亦中壽，至今名赫赫。", "蒼苔卧風雨，曾乏斷碑額。", "中原五十載，胡騎亂禹跡。", "誰當懶折腰，去學陶彭澤。", "憂端壓不下，中夜歌秀麥。", "昭代豈無人，腰黄眼前赤。", "鴻儒籌禁蒼，壯士守邊埸。", "罷歌且盃酒，澆此懷抱積。", "柴門剝剝響，已有賀年客。"]'),
('0425a3ae-c8ea-4295-b476-0c4c0fda9550','和林宗簡除夜韵余與宗簡皆病餘而除夜皆賦詩因反前意','陳傅良','宋','宋诗','song-poetry','','[]','窮懷卿相憂，老作兒女悲。',72,'全唐诗/poet.song.157000.json','["窮懷卿相憂，老作兒女悲。", "百爾皆妄想，一粲看新詩。", "短長總歸盡，君閲古盛衰。", "煌煌五侯家，寬作數世期。", "經史或不讀，名字亦奚爲。", "茂對乾三陽，靜養月一規。"]'),
('ce49996c-fc4f-4a59-8c75-c4e814c6554b','再用喜雪除夕二韵寄宗簡  其一','陳傅良','宋','宋诗','song-poetry','','[]','百年彈指頃，羣動不遑夕。',168,'全唐诗/poet.song.157000.json','["百年彈指頃，羣動不遑夕。", "孌彼惰游者，長夜浮太白。", "豪俠旁無人，卧我樓百尺。", "衲子縛禪靜，不敢踐桑陌。", "武夫髀肉滿，睥睨候邊隙。", "道家求不死，真火養陰赫。", "躁人干速化，自點雷門額。", "書生苦穿鑿，奇字窮鳥迹。", "何如吾老農，一雨犂春澤。", "相忘與雞豚，所辨纔菽麥。", "不聞有孔子，安識由與赤。", "紛紛舉世士，肝膽自疆埸。", "老翁捧腹笑，空洞無一積。", "有來問時事，請以臆對客。"]'),
('90422fb6-ae76-43f6-917e-df1f09d8cae7','再用喜雪除夕二韵寄宗簡  其二','陳傅良','宋','宋诗','song-poetry','','[]','子歌我有感，我和子益悲。',72,'全唐诗/poet.song.157000.json','["子歌我有感，我和子益悲。", "文武有天下，二南無變詩。", "陵夷及其季，小雅亦既衰。", "殷人早墜命，秦氏不及期。", "治身如治國，夭壽人所爲。", "舊恙何時已，與子看前規。"]'),
('dcad0d85-c5d6-421e-9b33-3b7a2d18825a','賦芙蕖簡諸友','陳傅良','宋','宋诗','song-poetry','','[]','我欲待明月，相從弄芙蕖。',120,'全唐诗/poet.song.157000.json','["我欲待明月，相從弄芙蕖。", "月郭一再滿，我行竟徐徐。", "誅茅困黄埃，開卷疲蠹魚。", "纏縛二事間，紅披綠蕭疎。", "秋風白髮生，撫事增欷歔。", "美人隔雲山，芙蓉並吾廬。", "近者不得見，逾遠還何如。", "花無三月長，人壽千歲餘。", "相期不朽事，勿與草木俱。", "君上鍾鼎銘，我作山澤癯。"]'),
('a2c3c2fa-e47b-480c-8c7e-3eb24a174e90','送楊似之提舉湖南','陳傅良','宋','宋诗','song-poetry','','[]','昨日有客去分符，今朝有客來攬轡。',192,'全唐诗/poet.song.157000.json','["昨日有客去分符，今朝有客來攬轡。", "蕨芽掇盡筍可𠜾，送客焉知老將至。", "儒雅風流能有幾，南宮先生無乃是。", "十年不復夢蓬山，萬里何爲隔湘水。", "葉公巋然地官貳，顔公領袖天下士。", "星聯郎署尤與何，次第諸公亦連茹。", "一時臺省舊名德，十見班行已三四。", "可令僕馬病崔嵬，獨抱蘭蓀吊憔悴。", "漁樵混迹山窮處，故故肯臨人不記。", "酒半停盃問鬚髮，夜闌秉燭徵文字。", "多時渴見痛折節，萬事要看方得意。", "先生行矣扈甘泉，請自此心扶大議。"]'),
('1ef8a48e-2556-404a-9a8f-b0f9afe586c9','哭呂伯恭郎中舟行寄諸友','陳傅良','宋','宋诗','song-poetry','','[]','去年上溪船，落日建安旐。',192,'全唐诗/poet.song.157000.json','["去年上溪船，落日建安旐。", "今年上溪船，濡露金華草。", "當代能幾人，胡不白髮早。", "念昔會合時，心事得傾倒。", "倚廬魚鼓夜，聯轡鷄人曉。", "遐搜接混茫，細剖入幽眇。", "挹注隘溟渤，扶携薄穹昊。", "斯文何契闊，之子復凋槁。", "百年在無窮，寥廓一過鳥。", "家人徵舊聞，學者拾餘稿。", "區區存萬一，散逸誰可保。", "君看魯論上，彭壽顔回夭。", "于今懸日月，豈必言語好。", "儻無後來者，泯沒秋毫小。", "南浮吳蜀會，北顧關河杳。", "懷哉各努力，人物古來少。"]'),
('7e20c15c-cef4-4e3f-ab6d-aa271f26e98d','張冠卿以前詩懷哉各努力人物古來少之句爲十詩見寄次韵奉酬  其一','陳傅良','宋','宋诗','song-poetry','','[]','明月不可涴，有時障氛霾。',48,'全唐诗/poet.song.157000.json','["明月不可涴，有時障氛霾。", "芙蕖生淤泥，豈必所處佳。", "老子苦鍊藏，釋氏多遣排。", "如欲盡物累，自古誰好懷。"]'),
('47e2bcde-29b1-4ccf-b058-b96178518001','張冠卿以前詩懷哉各努力人物古來少之句爲十詩見寄次韵奉酬  其二','陳傅良','宋','宋诗','song-poetry','','[]','連楹著胡椒，環堵誅蒿萊。',48,'全唐诗/poet.song.157000.json','["連楹著胡椒，環堵誅蒿萊。", "節士亦良苦，乃築懷清臺。", "世故何浩蕩，人心亦崔嵬。", "之子訪田舍，厥繇安在哉。"]'),
('a1adce29-bd66-473f-9f03-40563d741fbf','張冠卿以前詩懷哉各努力人物古來少之句爲十詩見寄次韵奉酬  其三','陳傅良','宋','宋诗','song-poetry','','[]','冥心觀宇宙，孰是同與各。',48,'全唐诗/poet.song.157000.json','["冥心觀宇宙，孰是同與各。", "夜旦無反惡，日出星河落。", "此有齊人瑟，彼有荆人璞。", "嗟余耳目短，豈故重然諾。"]'),
('f356df08-4c7b-46a9-831d-0f8472aef477','張冠卿以前詩懷哉各努力人物古來少之句爲十詩見寄次韵奉酬  其四','陳傅良','宋','宋诗','song-poetry','','[]','朝雞警冠劍，巷犬吠村塢。',48,'全唐诗/poet.song.157000.json','["朝雞警冠劍，巷犬吠村塢。", "胡然子列子，越在鄭東甫。", "永懷王黍離，莫與戍申許。", "雞犬各有役，人亦宜自努。"]'),
('aacfc121-155e-480b-9a15-9977c225bf86','張冠卿以前詩懷哉各努力人物古來少之句爲十詩見寄次韵奉酬  其五','陳傅良','宋','宋诗','song-poetry','','[]','說合何必然，金化黄河塞。',48,'全唐诗/poet.song.157000.json','["說合何必然，金化黄河塞。", "真然說不合，千鈞等蟬翼。", "纍纍近丘墓，浩浩古載籍。", "崎嶇蓋天意，解后匪人力。"]'),
('3a496eff-4891-4d1c-b3d9-49231e2cb6d7','張冠卿以前詩懷哉各努力人物古來少之句爲十詩見寄次韵奉酬  其六','陳傅良','宋','宋诗','song-poetry','','[]','我友天下士，逝者八九人。',48,'全唐诗/poet.song.157000.json','["我友天下士，逝者八九人。", "非無新造交，亦有久故親。", "可與共安利，未可同隠淪。", "欣然得一箇，迴首終酸辛。"]'),
('079149e0-f9d4-47d9-9804-6b393f421d85','張冠卿以前詩懷哉各努力人物古來少之句爲十詩見寄次韵奉酬  其七','陳傅良','宋','宋诗','song-poetry','','[]','秦人弊申韓，亡梁以崇佛。',48,'全唐诗/poet.song.157000.json','["秦人弊申韓，亡梁以崇佛。", "六經獨何罪，莽亦竊大物。", "堪嗟二百年，吾道功第一。", "熙豐餘論在，河洛諸賢沒。"]'),
('fa229671-851e-4615-8868-e2da361211f9','張冠卿以前詩懷哉各努力人物古來少之句爲十詩見寄次韵奉酬  其八','陳傅良','宋','宋诗','song-poetry','','[]','澶淵竟要盟，老萊氣安吐。',48,'全唐诗/poet.song.157000.json','["澶淵竟要盟，老萊氣安吐。", "韓范猶自憐，不遂臣西虜。", "人材繫其逢，事業隨所附。", "千載有南董，何啻今視古。"]'),
('8637bf5c-2024-4108-801c-ad9f289a37e6','張冠卿以前詩懷哉各努力人物古來少之句爲十詩見寄次韵奉酬  其九','陳傅良','宋','宋诗','song-poetry','','[]','江梅歲已過，燕子春又來。',48,'全唐诗/poet.song.157000.json','["江梅歲已過，燕子春又來。", "不愁吾鬢霜，所恨此志灰。", "扶桑焞焞明，閶闔蕩蕩開。", "欲往豈不可，致遠非駑駘。"]'),
('aec6003f-d2a6-4e8e-8482-7161e120c8e2','張冠卿以前詩懷哉各努力人物古來少之句爲十詩見寄次韵奉酬  其一○','陳傅良','宋','宋诗','song-poetry','','[]','子歌我三嘆，我和子一笑。',48,'全唐诗/poet.song.157000.json','["子歌我三嘆，我和子一笑。", "方期俗耳合，勿與知音道。", "頗聞古韶卷，不落人間調。", "悲歌泣鬼神，妙語無餘少。"]'),
('ed63d451-694f-4ba8-84f5-411332294681','黄巖張之望之立來訪與遊梅潭詩以送之','陳傅良','宋','宋诗','song-poetry','','[]','張子好兄弟，別我今九年。',180,'全唐诗/poet.song.157000.json','["張子好兄弟，別我今九年。", "東風刮瞇眼，雙鵠忽墮前。", "坐定看兩鬢，喜極意慘然。", "來日豈不多，此意合少延。", "念子伏巖穴，有作皆巨編。", "稻粱未暇謀，從我志獨堅。", "虛名適相累，浩嘆當誰憐。", "積雨得新霽，綠漲彌百川。", "載酒問何有，漾舟隨所便。", "與子梅潭游，以茲寓惓惓。", "傾崖俯仰立，中有飛瀑懸。", "平地儼閶闔，晴空自雲烟。", "既見各有得，欲語不可傳。", "衆妙在領會，天成謝琱鎸。", "子歸有新詩，時寄三兩篇。"]'),
('12c2c091-fb95-4fcd-826a-0a40d8bcc26c','和張孟阜尋梅韵','陳傅良','宋','宋诗','song-poetry','','[]','平生拙狀物，出語輒自咍。',208,'全唐诗/poet.song.157000.json','["平生拙狀物，出語輒自咍。", "久欲頌梅花，恒恐累紙寫不該。", "羨子年少氣豪敏，詩筒往往歲一來。", "語不驚人意不止，筆力待盡千松煤。", "我以病驥追霜隼，著鞭不上嗔人催。", "置詩太息梅困我，恨不縱斧尋條枚。", "嗟乎孤山無人老坡死，水邊竹外誰低徊。", "我嘗欲擬禁字體，不道雪月冰瓊瑰。", "退藏物後獨笑傲，奄有歲晚多驚猜。", "紛紛自謂好顔色，萬彙禿立皆堪哀。", "模將此意入詩句，十年未就梅空開。", "君詩却怪梅不早，令我內熱紅生腮。", "强隨嶮韵終不滿，今年又恐坐看落片飛莓苔。"]'),
('a5e50878-cc6c-4f51-8df7-bff1f6743dd9','送劉茂實宰奉新','陳傅良','宋','宋诗','song-poetry','','[]','遠別欲無寐，細論誰有酒。',120,'全唐诗/poet.song.157000.json','["遠別欲無寐，細論誰有酒。", "今當作劇縣，君意亦樂不。", "江湖吏道僻，歲月民勞久。", "救之敝精神，自愛終袖手。", "要中名甚美，用意物所咎。", "君觀蘭桂林，餘茂及樵槱。", "移根託客土，顔色非故有。", "贈言幾滿車，一字堪皓首。", "於焉但裁擇，對越二三友。", "諸賢在當路，公論在衆口。"]'),
('4fc4caa5-de13-4a32-ba86-fa1945e25595','送趙叔靜教授閩中四首  其一','陳傅良','宋','宋诗','song-poetry','','[]','家無宿舂糧，適意恣所向。',48,'全唐诗/poet.song.157000.json','["家無宿舂糧，適意恣所向。", "征鞍催上官，帆海看疊嶂。", "有言及當代，浩飲益悲壯。", "以茲寘周行，盍在幾人上。"]'),
('73c8a5cd-bdf2-47a8-874c-0f27b0d9f9df','送趙叔靜教授閩中四首  其二','陳傅良','宋','宋诗','song-poetry','','[]','讀書須讀經，學文須學古。',48,'全唐诗/poet.song.157000.json','["讀書須讀經，學文須學古。", "青松故不換，白髮早可數。", "我亦窶人子，風雨蔽蓬戶。", "胡爲數相過，夜話恒過午。"]'),
('e6b7514c-aece-4929-ac86-cd4344bed92a','送趙叔靜教授閩中四首  其三','陳傅良','宋','宋诗','song-poetry','','[]','烱烱出萬壑，冰壺縣清秋。',48,'全唐诗/poet.song.157000.json','["烱烱出萬壑，冰壺縣清秋。", "孰與玉瓚中，穆然養黄流。", "孤松高半天，蘭芷復過幽。", "看君最雍容，柰何短自謀。"]'),
('f9efdbc4-efcb-478d-b857-432cb1751573','送趙叔靜教授閩中四首  其四','陳傅良','宋','宋诗','song-poetry','','[]','百吏不可試，卷懷州校官。',48,'全唐诗/poet.song.157000.json','["百吏不可試，卷懷州校官。", "翩然落南閩，不爲荔子丹。", "彫蟲妙經術，倚市多儒冠。", "吾道未必貴，政此良已難。"]'),
('db8f8ad9-d955-4400-a4f0-7b1ef30bd604','遊白石巖','陳傅良','宋','宋诗','song-poetry','','[]','地向東南傾，石際滄海立。',108,'全唐诗/poet.song.157000.json','["地向東南傾，石際滄海立。", "蛟鼉限波濤，鷄犬得城邑。", "居然通國望，跋莫他山及。", "道人獨有之，置屋三四級。", "幾看星月爛，却聽風雨急。", "于今二百年，我共冥鴻集。", "晤語夕陽低，對酒秋旻濕。", "明朝江上舟，避雨漁翁笠。", "邂逅一俛仰，此道可於邑。"]'),
('3fbf1882-14bd-42e6-8aad-9260f4355c8a','和孟阜老梅韵  其一','陳傅良','宋','宋诗','song-poetry','','[]','朝遊山南莫北隅，脩竹之下手所披。',160,'全唐诗/poet.song.157000.json','["朝遊山南莫北隅，脩竹之下手所披。", "五步一顧立不趨，柔枝弱榦千萬餘。", "粲然笑倩多新奇，歲寒安用衆穉爲。", "驚嗟怪怪丈人行，縞衣藍縷冰斲肌。", "莓苔雪片凍不飛，玉飾其末璣衡欹。", "藐姑之仙下縹緲，蒼虬爲駕羽葆希。", "三閭大夫從女須，枯槁嬋娟却並馳。", "張子愛之亦既癡，人不得覷以我歸。", "我生自視梅孰如，滄江獨立兒女嗤。", "年來稍稍學折枝，柰何復與此老期。"]'),
('07408e52-d6cc-41d7-a552-79a68e2ea789','和孟阜老梅韵  其二','陳傅良','宋','宋诗','song-poetry','','[]','望美人兮天一隅，薜蘿爲衣顛倒披。',163,'全唐诗/poet.song.157000.json','["望美人兮天一隅，薜蘿爲衣顛倒披。", "水竹隔我不可趨，今我搔首三歲餘。", "漢庭年少六七奇，鬚眉皓白來何爲。", "我欲避寢問之道，安得玉貌生枯肌。", "長翁傲睨欲奮飛，滄江釣雪蓑笠欹。", "少翁頓挫枿牙角，笑齒一粲知音希。", "樵家斧斤磨以須，過者萬人人背馳。", "梅乎梅乎我非癡，持汝二老將安歸。", "古來弱植剛不如，孰有嫵媚爲人嗤。", "君不見孤竹之管求孫枝，汝盍早定歸山期。"]'),
('1cf1edfc-1b5d-4001-b126-6c847394fb89','送同年林多益丞寧海','陳傅良','宋','宋诗','song-poetry','','[]','同里衣冠近闊疎，同年齒髮多衰變。',112,'全唐诗/poet.song.157000.json','["同里衣冠近闊疎，同年齒髮多衰變。", "美人宜在玉筍班，隠吏亦隨花雨縣。", "有杭一葦逢迎可，每食雙魚甘旨便。", "顧瞻周道竟何如，善爲身謀吾豈願。", "清廟笙鏞濟濟陳，碧梧鸞鵠深深見。", "由來盛事歲月晚，誰到脩途肝膽健。", "楊花吹水酒摇波，一請加餐再無倦。"]'),
('7f9f34d9-1c34-4045-8258-2f3209839eed','送謝希孟歸黄巖四首  其一','陳傅良','宋','宋诗','song-poetry','','[]','紛紛竹帛傳，浩浩金石刻。',48,'全唐诗/poet.song.157000.json','["紛紛竹帛傳，浩浩金石刻。", "淪亡已無限，存亦誰愛惜。", "如何伏羲氏，文字二三畫。", "姬孔豈不聖，用以演周易。"]'),
('bf781fb2-6d77-4bf6-b96f-4fde57e8bd06','送謝希孟歸黄巖四首  其二','陳傅良','宋','宋诗','song-poetry','','[]','法令如牛毛，斯鞅信手成。',48,'全唐诗/poet.song.157000.json','["法令如牛毛，斯鞅信手成。", "簿書積丘山，趙張眼愈明。", "萬人立下風，國勢尊且榮。", "未省三代前，誰獨有此名。"]'),
('b13dbc20-b967-425d-9c4f-e676e3b30298','送謝希孟歸黄巖四首  其三','陳傅良','宋','宋诗','song-poetry','','[]','圭璧襲繅藉，山龍飾衣裳。',48,'全唐诗/poet.song.157000.json','["圭璧襲繅藉，山龍飾衣裳。", "不聞燧古初，而興自虞唐。", "毀車崇騎射，隸作篆籀藏。", "至今人便之，秦亦忽以亡。"]'),
('3dd76c24-1391-4e01-b556-1e955bfb2c9f','送謝希孟歸黄巖四首  其四','陳傅良','宋','宋诗','song-poetry','','[]','累觴以爲歡，班荆以爲儀。',48,'全唐诗/poet.song.157000.json','["累觴以爲歡，班荆以爲儀。", "交際貴如此，勿使至意虧。", "頗常怪小雅，鹿鳴至魚麗。", "賓主禮百拜，六經似支離。"]'),
('5f11d255-345c-4db8-8a40-59b6038df8b9','看筍和潘養大韵','陳傅良','宋','宋诗','song-poetry','','[]','兒童纔丱角，兵衛忽森戟。',48,'全唐诗/poet.song.157000.json','["兒童纔丱角，兵衛忽森戟。", "十日不汝見，尋丈出咫尺。", "隠几觀物化，軒奮恣所極。", "褰裳欲從之，世事有繩墨。"]'),
('c9dba7e3-e9ab-4821-8bce-b3fa43f5e2c3','贈尹紹伊','陳傅良','宋','宋诗','song-poetry','','[]','吾友尹紹伊，十年抱心疾。',84,'全唐诗/poet.song.157000.json','["吾友尹紹伊，十年抱心疾。", "休然萬事廢，豆子黑如漆。", "從之問舊學，歷歷不遺一。", "佳篇間哇鄭，法語雜方術。", "豈其遇人耶，託此訪遺逸。", "張皇鬼物怪，漏泄宮禁密。", "君看服烏喙，孰與近參朮。"]'),
('ee53af58-256d-4360-8c65-5708fb49aa26','送郡守汪充之移治嚴陵','陳傅良','宋','宋诗','song-poetry','','[]','挂梁龍骨經時蟄，井井黄雲秋已及。',202,'全唐诗/poet.song.157000.json','["挂梁龍骨經時蟄，井井黄雲秋已及。", "十日不雨民未急，使君日膳長蔬湆。", "澄空颯颯雲霧入，饁婦休眠兒覓笠。", "村舂化出雲子粒，市上明朝升二十。", "農家語圃商語賈，恒願使君無疾苦。", "自今一飯吾腹果，健看將母從簫鼓。", "馮翊扶風天尺五，見說嚴陵在何所。", "詔書奪去萬舌吐，九重欲扣君門阻。", "棲鳥護巢駒戀皂，東人自視西人好。", "那知湛露漙秋草，春意平鋪無剩少。", "有客解事翻然笑，元祐治平諸故老，身要人扶功未了。", "誰知青絲絡馬橫門道，應笑江湖華髮早。"]'),
('8c4fdc8f-1ea3-4ac2-905d-94d7dd313218','寄題陳同甫抱膝亭','陳傅良','宋','宋诗','song-poetry','','[]','稻粱不難謀，軒冕亦易得。',144,'全唐诗/poet.song.157000.json','["稻粱不難謀，軒冕亦易得。", "胡爲抱膝翁，惻惻復惻惻。", "秋風墮碧梧，鳳鳥去無迹。", "愁吟草際蛩，兒女淚盈臆。", "忽然一長嘯，孤響起空寂。", "令人識雅頌，一唱三嘆息。", "室廬在路傍，耕鑿在民籍。", "行人聽笑語，稚子共眠食。", "讀書果何罪，鬚髮又半白。", "此意太勞勞，此身長抑抑。", "抱膝且不可，出門更何適。", "但勿問門外，蓬蒿若干尺。"]'),
('1d4e4f04-dbff-411f-ba98-5c18b2331a49','送葉正則赴浙西憲幕','陳傅良','宋','宋诗','song-poetry','','[]','頻年送行客，酒罄詩不工。',168,'全唐诗/poet.song.157000.json','["頻年送行客，酒罄詩不工。", "最晚與君別，柰此百感叢。", "岐山有鳴鳳，雅頌移豳風。", "于時二老生，出處海上同。", "曹劉對匕箸，失色一語中。", "明朝蜀江水，不與灞滻通。", "人心起毫末，世故關鴻蒙。", "乃知貧賤交，不下王覇功。", "霜根宿病驥，雲帆背蜚鴻。", "秋水能隔人，白蘋况連空。", "相從自束髮，各去隨轉蓬。", "今懷欣有合，後會苦未重。", "鱸魚直萬錢，羊酪醅一鍾。", "願君養盛年，我友半已翁。"]'),
('4d4db601-e59e-4417-9f5b-91e9991c7fc6','送陳益之架閣','陳傅良','宋','宋诗','song-poetry','','[]','論事不欲如戎兵，欲如衣冠佩玉嚴重而寬平。',192,'全唐诗/poet.song.157000.json','["論事不欲如戎兵，欲如衣冠佩玉嚴重而寬平。", "作文不欲如組繡，欲如疎林茂麓窈窕而敷榮。", "楨榦盍亦煩繩墨，滋味何如餘典則。", "吾宗受才萬人敵，排空所向無遺力。", "親喪三年面漆黑，交情一語千金璧。", "明朝不爨鼾撼壁，裘馬借人無德色。", "作掾閩山可蹤跡，擬將秉稈空螟𧎬。", "相君有令民未得，勿問堂高若干尺。", "春江瀰渺風張席，欲言江水何終極。", "貧賤相依鬢毛白，吾可雷同名送客，浩歌未放情彌激。", "君看風雅詩三百，亦有初章三嘆息。"]'),
('701f193b-d6b5-4311-b9bc-3bc573057d53','翁誠之尉慈溪再擬祖送不及','陳傅良','宋','宋诗','song-poetry','','[]','昨來久佇驪駒集，今來悵望檣烏急。',96,'全唐诗/poet.song.157000.json','["昨來久佇驪駒集，今來悵望檣烏急。", "中年送客亦多違，先事徒勞後無及。", "江頭祖帳幾百人，落紙珠璣詩什什。", "自哦短韵意甚得，亟欲陳之復羞澀。", "君方筮仕從茲始，驊騮開路日千里。", "若逢人話子陳子，侏儒一節今如此。"]'),
('8450f724-d5f0-480c-b4e1-f4a0304025b8','送鮑清卿教授莆中','陳傅良','宋','宋诗','song-poetry','','[]','閩中豈不好，莆中况多儒。',192,'全唐诗/poet.song.157000.json','["閩中豈不好，莆中况多儒。", "其山有丹荔，其水有子魚。", "艾軒諸老生，典則故所餘。", "堂堂退傅門，海內欲曳裾。", "宦遊得此樂，餞者酒滿車。", "我亦勸君酒，我意獨未舒。", "嘗聞入林獵，不可背水漁。", "背水漁尚可，背時更崎嶇。", "方今朝廷尊，紳笏日走趨。", "官多豈勝記，勢遠復易疎。", "媒身衆所同，藉口誰不如。", "柰何但溫飽，去向天一隅。", "平生拙自謀，蓬巷歲月除。", "更事亦既熟，畫此未必愚。", "豈有服茝蘭，佩之以瓊琚。", "令人愛不見，搔首空踟躕。"]'),
('069d5f19-6781-434f-a156-95a579b55cc6','作南塘記郡守沈持要以詩來謝次韵奉酬','陳傅良','宋','宋诗','song-poetry','','[]','周公作雅頌，退然在豳風。',192,'全唐诗/poet.song.157000.json','["周公作雅頌，退然在豳風。", "功成貴無迹，名大謗亦叢。", "彼人自標置，刻畫豈不工。", "君看榛莽間，斷碑卧頹墉。", "想當在世時，拳拳效深衷。", "胡然今弗省，身後議論公。", "達人悟物情，玄覽昭有融。", "區區强名我，咨爾來何從。", "沈公天下士，於今萬夫雄。", "邦入見未嘗，譽之口不容。", "請將氏南樓，語盡意未窮。", "公詩陳誼高，耻與好事同。", "年登百廢興，解后吾何功。", "勇去學休影，倦游謝遺蹤。", "吾方笑征南，雙雙勒堅玒。", "一以棲山顛，一以沒水中。"]'),
('5590cb80-23da-427e-81cf-c1e4a974b7cc','送謝倅景英赴闕','陳傅良','宋','宋诗','song-poetry','','[]','言詩必南雅，自鄶吾無譏。',168,'全唐诗/poet.song.157000.json','["言詩必南雅，自鄶吾無譏。", "嗟余生已晚，觀人以觀詩。", "人情日變化，往事十九非。", "相從飾邊幅，欲語懷銜羈。", "久不見官寺，下與家人夷。", "渡江六十年，得此心目疑。", "早從諸公游，晚佐一郡治。", "居嘗陳誼高，動與作吏違。", "大白浮朋簪，單車款民扉。", "多文雖素履，用拙真良規。", "二年意綢繆，一別事渺瀰。", "有酒公不飲，贈言我何裨。", "穆穆清朝班，僉曰尚德宜。", "何妨著此翁，衣冠皓鬚眉。"]'),
('277f3839-d934-4f8e-ac17-93d38a772a57','懷同舍石天民編脩','陳傅良','宋','宋诗','song-poetry','','[]','山陰不得見，見期在東陽。',276,'全唐诗/poet.song.157000.json','["山陰不得見，見期在東陽。", "東陽忽歲華，欲往又阻長。", "貽書輒無報，有便復寄將。", "以君懶於書，我豈望得當。", "永懷十年別，動止曾莫詳。", "君貌今何如，孰與我老蒼。", "就使白髮同，脚力誰弱强。", "日飯米多少，飲酒可幾觴。", "尚能甘寢耶，比之昔對床。", "嫂氏亦晚景，吾婦伯姊行。", "爲君過客頻，膏沐當不常。", "有兒若干人，已未勝冠裳。", "但要能譍門，勿問鄙與臧。", "一紙細說似，慰此遥相望。", "末乃及田舍，何有還何亡。", "丞郡祿已厚，豈不可小康。", "憶昔夜夢君，託交少年場。", "竦身而掀髯，眸子烱烱光。", "依然論時事，悲壯淚以滂。", "我方閉門嬉，謁至即暫忙。", "婆娑松竹下，細數秋葉黄。", "舊志益凋落，羣書半遺忘。", "請君勿他及，却使我意傷。"]'),
('ab49633a-097e-4a2a-afd3-30555e7dd3c0','次韵蕃叟弟月下有感','陳傅良','宋','宋诗','song-poetry','','[]','平原接翠微，脩竹圍綠浄。',48,'全唐诗/poet.song.157000.json','["平原接翠微，脩竹圍綠浄。", "乃於此中間，更以皓月映。", "佳人笑隠几，萬物獨我正。", "幸哉吾有母，侍飲得缾罄。"]'),
('12d10c07-c2c4-4889-b8d3-1ea2761668a1','夢人誦詩覺省數句足成一首','陳傅良','宋','宋诗','song-poetry','','[]','三人共一被，寒夜爭抽牽。',48,'全唐诗/poet.song.157000.json','["三人共一被，寒夜爭抽牽。", "一人耻不讓，起坐遲朝暄。", "明朝復雨雪，忍豈無春妍。", "四時各天運，二人正鼾眠。"]'),
('32109d4b-e257-4455-9f84-c29a3ac9df08','送曹器遠試臨安二首  其一','陳傅良','宋','宋诗','song-poetry','','[]','青衫豈必貴，未得不可已。',60,'全唐诗/poet.song.157000.json','["青衫豈必貴，未得不可已。", "皇皇海內人，趨走共一軌。", "生前極浮榮，沒後抱深耻。", "他山有隠淪，一笑粲冰齒。", "豈知天地間，樹立在人紀。"]'),
('53322146-e20a-4e8d-9924-072eb24cf364','送曹器遠試臨安二首  其二','陳傅良','宋','宋诗','song-poetry','','[]','大有扛鼎力，小有挈瓶智。',60,'全唐诗/poet.song.157000.json','["大有扛鼎力，小有挈瓶智。", "誰當頓八紘，舉以掩衆器。", "煌煌一百年，此道最宏被。", "雖躋三事尊，亦起一藝試。", "或云科目弊，此語復有味。"]'),
('7cba985f-3a69-4ca7-9401-fb266fb49a59','約同舍蜀人王德修三首  其一','陳傅良','宋','宋诗','song-poetry','','[]','遠莫遠關塞，鴻鴈來年年。',60,'全唐诗/poet.song.157000.json','["遠莫遠關塞，鴻鴈來年年。", "我嘗按輿圖，嶓漢在眼前。", "胡爲與君別，壯齒今華顛。", "下峽君有期，會吳我何緣。", "令人媿不如，鴻鴈得自便。"]'),
('4621c824-aa5b-42e7-8e63-6a11e0151a05','約同舍蜀人王德修三首  其二','陳傅良','宋','宋诗','song-poetry','','[]','疇昔夢遡江，巴陵至瞿唐。',60,'全唐诗/poet.song.157000.json','["疇昔夢遡江，巴陵至瞿唐。", "兩崖束秋旻，中有一带蒼。", "安流進分寸，怒去千丈强。", "求君竟不得，望之涕淋浪。", "往日事已然，來日理未詳。"]'),
('a1647c0e-8ef0-41cd-9a1f-65d1283f790f','約同舍蜀人王德修三首  其三','陳傅良','宋','宋诗','song-poetry','','[]','橙橘方粲粲，魚蝦亦多多。',60,'全唐诗/poet.song.157000.json','["橙橘方粲粲，魚蝦亦多多。", "能舂半年糧，豈惜一見過。", "良夜月如霜，聽我苦別歌。", "翳翳葭蘆鄉，風定水自波。", "或者阻君舟，柰此佇立何。"]'),
('667d0824-7bb7-40f1-81a1-4393d61117d1','次德脩仙巖韵','陳傅良','宋','宋诗','song-poetry','','[]','我家仙巖人跡稀，客從何來此何時。',128,'全唐诗/poet.song.157000.json','["我家仙巖人跡稀，客從何來此何時。", "岷山之陽適海嶠，萬里欲寫心精微。", "瀑泉自雨一丘壑，有龍蟄不隨羣飛。", "病樵弛檐渴猿喜，雖未作霖良已奇。", "吾聞岷山天與齊，仰止不見如調饑。", "君登絕頂小天下，此縱有山安足嬉。", "翩然肯過非所期，此道遼闊車誰脂。", "願言稅駕毋遄歸，爲我更賦崧高詩。"]'),
('87f8281a-23a9-4285-af96-3804790621c5','再用韵呈德脩','陳傅良','宋','宋诗','song-poetry','','[]','一日一見猶爲稀，如何十年見無期。',128,'全唐诗/poet.song.157000.json','["一日一見猶爲稀，如何十年見無期。", "昔方壯歲意輕別，一笑聽君歌式微。", "江流永矣劍閣阻，恨不羽翰能奮飛。", "不圖今日已華髮，話此怪怪還奇奇。", "桑麻不競蒿壓屋，厚祿書斷兒恒饑。", "誰當附熱斲冰雪，歲晏獨可相從嬉。", "功名富貴各有時，人亦空自爲韋脂。", "與君持此將安歸，滄海雪山無盡詩。"]'),
('4bc7d51e-84fb-4969-9ca5-c8e92c53a9e5','夷門歌送德脩還闕','陳傅良','宋','宋诗','song-poetry','','[]','萬古江入海，吳蜀有不通。',228,'全唐诗/poet.song.157000.json','["萬古江入海，吳蜀有不通。", "不通誰使然，人自爲異同。", "昔在李孟錢，士各懷土封。", "靜言彼何尤，亦各徇所忠。", "恭惟宋受命，三姓皆朝宗。", "斯文已百年，名世纔數公。", "眉山與金陵，柰何不相容。", "大雅如關洛，亦復互詆攻。", "朋分文字間，禍起師友中。", "四郊忽戎馬，塵滿夷門宮。", "往事已覆轍，後事如飄蓬。", "一飯忘苦饑，一褐忘苦冬。", "身謀每不長，王事靡有終。", "有客獨惻惻，萬里興深衷。", "相過話離合，歷歷繇熙豐。", "我久世慮薄，念之涕無從。", "貧賤將安歸，功名在其逢。", "有能用斯人，可使百阻空。", "西人不爲西，東人不爲東。"]'),
('1ec69d95-0ede-4ee1-b507-3ff98182325c','借書一首別薛子長','陳傅良','宋','宋诗','song-poetry','','[]','山阿著柴扉，陋甚誰盤桓。',180,'全唐诗/poet.song.157000.json','["山阿著柴扉，陋甚誰盤桓。", "美人此何求，鉅竹數十竿。", "日閲書百篇，尚覺日力寬。", "欲從我借書，我書何足觀。", "辛勤抱遺經，及此鬢髮班。", "一語未領會，累日不自安。", "雖更聖人手，亦恐衆說謾。", "况復秦漢下，曾莫脩與刪。", "致之獲麟前，存者今若干。", "我無以裁之，望洋久空嘆。", "羨君方盛年，恣意涉浩漫。", "又聞書少多，不繫學缺完。", "讀書固匪易，用書良獨難。", "昨來荷堤上，嘗試及孟韓。", "此話如涓埃，此道如丘山。"]'),
('9769668d-0b74-4d57-bc59-b2da4bc52068','寄陳同甫生日','陳傅良','宋','宋诗','song-poetry','','[]','南國雨初潤，西風水微波。',144,'全唐诗/poet.song.157000.json','["南國雨初潤，西風水微波。", "持酒欲勸君，奈此道阻何。", "天地自久長，日月良蹉跎。", "志士惜少年，用意矢靡他。", "豈無文字功，百代名不磨。", "胡然朝攬鏡，夜起瞻星河。", "思婦視貞操，驕人視勞歌。", "曾微强飯書，覆出爲詆訶。", "永懷姑射神，尸居養天和。", "下視塵冥冥，鴻鵠謝網羅。", "身將世誰親，得孰與喪多。", "請君以尊生，我亦以養痾。"]'),
('4cfbdcc7-ed40-481e-b576-ce15fc11617c','述懷','陳傅良','宋','宋诗','song-poetry','','[]','有客盈門飯不足，有書千卷兒懶讀。',64,'全唐诗/poet.song.157000.json','["有客盈門飯不足，有書千卷兒懶讀。", "王公勞問煬爭竈，樵牧相忘盜騎屋。", "古來堪笑如我少，生無一事能恰好。", "獨有居閑可引年，我又不然華髮蚤。"]'),
('8cab5f02-379d-4ebc-93e1-e75d5d568c00','簡鄭景元','陳傅良','宋','宋诗','song-poetry','','[]','西風肅萬物，於卦曷爲兌。',60,'全唐诗/poet.song.157000.json','["西風肅萬物，於卦曷爲兌。", "說言就凋蟄，之死矢靡悔。", "方當春和時，動植出草昧。", "喧號聒穹蒼，怒長彌大塊。", "紛紛誰則敢，所恃蓋有在。"]'),
('44287f42-4147-493c-a84a-b7e0659cf465','簡王道父','陳傅良','宋','宋诗','song-poetry','','[]','瞻彼萬仞巖，亭亭上烟霞。',72,'全唐诗/poet.song.157000.json','["瞻彼萬仞巖，亭亭上烟霞。", "其下寒淵水，清不容魚蝦。", "閔予生好修，而居東海涯。", "顧見泥中藏，日食百萬家。", "浮名太累人，未語衆已譁。", "爲海不爲淵，何道以自瑕。"]'),
('69b68931-b2ff-4073-b07f-bdb0cd48882f','贈東陽呂望孫周登二武士','陳傅良','宋','宋诗','song-poetry','','[]','鴻門無人易水寒，安得壯士久所患。',218,'全唐诗/poet.song.157000.json','["鴻門無人易水寒，安得壯士久所患。", "求之市隠戎行間，紛不當意鬢已班。", "逆胡未討憂萬端，此得兩君聊自寬。", "有石堂坳立礸𪿑，百夫睨之欲舉難。", "兩君挾起如弄丸，舞空一葉風團團。", "呂君忽作胡衣冠，瀝酒於地盟血殷。", "長劍久倚燕然山，義欲爲漢誅樓蘭。", "九重深窈虎守關，竟以劍器博一餐。", "語未良已聲珊珊，兩蛟出沒萬馬攢。", "夜闌月暗天汗漫，滿堂悲憤淚欲潸。", "嗟爾兩君誠義肝，我方乘障荆之蠻。", "五營諸將皆豢安，髀肉久不堪征鞍。", "誰能喚與百辟看，但得汝等一解吾君顔，書生老死不足歎。"]'),
('48441e51-e818-45a9-9e2c-11d43a05680c','書黄巖丁明仲墓誌碑陰','陳傅良','宋','宋诗','song-poetry','','[]','葉君隻字雙南金，予子拳石藏幽深。',224,'全唐诗/poet.song.157000.json','["葉君隻字雙南金，予子拳石藏幽深。", "百名以上辭不淫，我豈識子猶漸襟。", "黄山之阿墓林林，斷碑日爍秋雨霖。", "彼豈孫子力不任，人莫過問嘷孤禽。", "子以窮餓死苦吟，束棺逆旅無衣衾。", "末乃得此世所欽，子視昔者孰與今。", "區間壽短升與沉，長留天地誰無心。", "於中詩人最嶇嶔，竟亦朽腐如書蟫。", "何獨遺子天球琳，上與郊島名相尋。", "雖無薦藉鬼已歆，况立之後主釜鬵。", "期以數歲頭勝簪，有田可稼桑可紝。", "收拾舊稿編朱鋟，未必千載無知音。", "請我書此碑之陰，大亮一語不肯侵。", "嗚呼讀者悲不禁，牛羊勿踐木森森。"]'),
('af913471-c72c-4d03-ab18-491b2f7d0881','赴桂陽道中喜晴書事','陳傅良','宋','宋诗','song-poetry','','[]','十日九雨垂垂雪，馬僵僕病泥乘橇。',114,'全唐诗/poet.song.157000.json','["十日九雨垂垂雪，馬僵僕病泥乘橇。", "披衣闖戶得星月，喜有耻向妻兒說。", "耳根久與朝鷄別，熟睡八年謀未拙。", "乞米作糜蒙被啜，客來午漏家僮出。", "如今兒噭妻愁絕，我縱喜晴心已折。", "可以藝麻多筍蕨，苟有一丘吾計决。", "奈何諸公廝役皆豪傑，尚愛舂陵老元結。"]'),
('3cd5e601-c5d9-4d26-9902-dafb742b06c9','簡友人二首  其一','陳傅良','宋','宋诗','song-poetry','','[]','南去有五嶺，北來有重湖。',48,'全唐诗/poet.song.157000.json','["南去有五嶺，北來有重湖。", "水清石益奇，往往中州無。", "在昔宦游者，越若韓張徒。", "胡然自衡陽，隻鴈亦不徂。"]'),
('f5830f00-e149-4a29-989c-6222a24f9094','簡友人二首  其二','陳傅良','宋','宋诗','song-poetry','','[]','安眠夜至卯，休吏日加申。',48,'全唐诗/poet.song.157000.json','["安眠夜至卯，休吏日加申。", "廩稍亦已厚，養痾非隠淪。", "恨無封君法，老矣藏其身。", "遄歸豈不欲，更有宜歸人。"]'),
('b28dd83c-74ba-4195-b895-ad4a397a8229','和王教授謙叔述郡圃韵','陳傅良','宋','宋诗','song-poetry','','[]','守邊豈無事，治圃亦有說。',144,'全唐诗/poet.song.157000.json','["守邊豈無事，治圃亦有說。", "朝看士飲羽，暮與客投轄。", "且以示多暇，且以勞同列。", "我生腸九回，世故肱三折。", "環堵僅尋丈，短亭聊歲月。", "忽蒙當宁記，濫補專城缺。", "區區自米鹽，在在欲黼黻。", "矧惟有茲山，未省從何月。", "張羅上空庭，尋斧及勁節。", "舊觀誰緝熙，新思蓋綿蕝。", "幸方一小治，尚可六太息。", "胡然召南人，而驟歌所茇。"]'),
('a8083483-f809-4880-88ff-09f59401f309','臨桂尉楊渭夫以詩來因次其韵兼簡同僚','陳傅良','宋','宋诗','song-poetry','','[]','萬物各美惡，一室有面背。',144,'全唐诗/poet.song.157000.json','["萬物各美惡，一室有面背。", "去來故無恒，欣厭惟所會。", "有能悟茲理，何必著幽邃。", "後圃並山麓，脩竹積空翠。", "斧尋自何年，樊養特過計。", "陳根獨遭時，沃壤亦借勢。", "居然成獨清，可以掩衆媚。", "亭院起中𠘶，湖潦粲前際。", "於時吾豈敢，謂此天作對。", "新詩忽盛談，俗狀良內媿。", "子方及歸期，客復攪離思。", "尚當封殖之，去日如始至。"]'),
('40110342-c703-4e43-a6b0-3fc730a6e8f9','送宋伯潛宰高安','陳傅良','宋','宋诗','song-poetry','','[]','秋風日來諗，役車何時休。',96,'全唐诗/poet.song.157000.json','["秋風日來諗，役車何時休。", "有鳴丘中琴，玉瓚懷黄流。", "此腰不可折，此笏未忍抽。", "亦入鴈鶩行，而爲稻粱謀。", "四海楊誠齋，吾道得自由。", "悠哉思萬端，哿矣試一籌。", "風詩訖於豳，易象重以周。", "當知橫空翮，不若逆水舟。"]'),
('b8d58885-bd51-46c4-8a5a-1034c02ec14a','送楊渭夫歸省','陳傅良','宋','宋诗','song-poetry','','[]','應侯氣蓋百粵小，朱侯誼與灕江長。',88,'全唐诗/poet.song.157000.json','["應侯氣蓋百粵小，朱侯誼與灕江長。", "兩侯愛士早成癖，怪甚渭夫懷故鄉。", "士窮萬事一不就，就得一事窮何傷。", "渭夫壯者忍窮久，老驥欲秣胡沙霜。", "吾家何在雲橫嶺，趙媼不冤劉兒瞑，孰與親旁煮湯餠。"]'),
('2254e73e-2679-426c-8c56-f30c1abdde0e','南嶽聖業寺禹柏','陳傅良','宋','宋诗','song-poetry','','["\u8861\u5c71"]','久與林壑居，所見皆衆穉。',240,'全唐诗/poet.song.157000.json','["久與林壑居，所見皆衆穉。", "豈無壽千年，未有此柏異。", "壯而嘗參天，晚乃但仆地。", "定非風雨摧，殆是斤斧棄。", "其本則離披，其末則倒植。", "其枯如殘枿，而蔚有新意。", "其靡如弱植，而凜有高致。", "將前復却行，宜右忽左次。", "驤龍或俯顧，遁虎或回眙。", "隕石或猛起，飛翬或顛墜。", "山立或磬折，尸寢或拳跽。", "斷支或强附，橫陳或巽避。", "綢繆情不狎，頹墮力未瘁。", "朴畧自光怪，挺持匪標置。", "終焉人僞盡，獨以天巧遂。", "吾聞古有道，純朴去故智。", "與世每如此，全身亦幾是。", "疑將問歲月，缺弗見載記。", "誰言導江時，手植特嬉戲。", "世人那得識，會有神禹至。"]'),
('fa5e6255-90b0-450f-98cd-0bcb5e9b2b49','牡丹和潘養大韵','陳傅良','宋','宋诗','song-poetry','','[]','看花喜極翻愁人，京洛久矣爲胡塵。',64,'全唐诗/poet.song.157000.json','["看花喜極翻愁人，京洛久矣爲胡塵。", "還知姚魏輩何在，但有歐蔡名不泯。", "夕陽爲我作初霽，佳節過此無多春。", "更燒銀燭飲花下，五陵佳氣今方新。"]'),
('43df78de-b592-4904-840d-524de6284dd6','張漕行部過湘岸有作因次其韵','陳傅良','宋','宋诗','song-poetry','','[]','春晚得新霽，草木日夜綠。',144,'全唐诗/poet.song.157000.json','["春晚得新霽，草木日夜綠。", "陽光初蔽虧，野暝或單復。", "美人浮湘波，領此入蓬屋。", "故放歸帆遲，更呼漁火續。", "窮探物精華，盡付詩凡目。", "憶昨欣晤對，令我忘休沐。", "劇談酒行希，危坐兵衛肅。", "相思正倚樓，所寄忽累幅。", "瑰辭堪買貧，軼韵和難屬。", "自從楚騷興，悲些逮差玉。", "後來數唐人，欵乃巖隈宿。", "世無梁昭明，斯文又誰錄。"]'),
('5667e5e2-764f-4785-b040-0195369a136a','送王南强赴紹興簽幕四首  其一','陳傅良','宋','宋诗','song-poetry','','[]','詞章行天下，嘉頼二百年。',60,'全唐诗/poet.song.157000.json','["詞章行天下，嘉頼二百年。", "甲科至公卿，誰敢謂不然。", "有人妄媒孽，一世所棄捐。", "我亦欲護短，諱不言幽燕。", "汗簡在吾後，覆車在吾前。"]'),
('c0f2dfa7-ab01-4a71-b0b9-383744503909','送王南强赴紹興簽幕四首  其二','陳傅良','宋','宋诗','song-poetry','','[]','人人尊孔孟，家家誦詩書。',60,'全唐诗/poet.song.157000.json','["人人尊孔孟，家家誦詩書。", "未省有宇宙，孰與今多儒。", "儒者道如砥，豈其自崎嶇。", "申以黄老廢，賈以絳灌疎。", "漢家嘗紛紛，政爾門戶殊。"]'),
('fdb23b26-a753-4444-ab90-86e242cd267c','送王南强赴紹興簽幕四首  其三','陳傅良','宋','宋诗','song-poetry','','[]','歷官如歷階，越等多所傷。',60,'全唐诗/poet.song.157000.json','["歷官如歷階，越等多所傷。", "柰何坳堂水，持綆萬丈長。", "誰無斯世方，乃此抽手旁。", "永夜淚不禁，仲尼故皇皇。", "又聞雖小魯，乘田問牛羊。"]'),
('8a13fb00-74dc-4629-ad0f-8a30039c909c','送王南强赴紹興簽幕四首  其四','陳傅良','宋','宋诗','song-poetry','','[]','聞之浙河東，見之湘水南。',60,'全唐诗/poet.song.157000.json','["聞之浙河東，見之湘水南。", "未歸却相送，既喜復不堪。", "行矣乞自便，帥幕或可參。", "君方乘日長，勉爲停朝驂。", "我池有螃蟹，我園有黄柑。"]'),
('cbbc6c28-737b-4352-9112-55787f8763c4','題明皇醉歸圖','陳傅良','宋','宋诗','song-poetry','','[]','騎者兩人扶不正，夾道誰知爲萬乘。',97,'全唐诗/poet.song.157000.json','["騎者兩人扶不正，夾道誰知爲萬乘。", "一人前馳一顧後，懷欲並驅無號令。", "狩人亦忘記鷹犬，仰視只愁天欲暝。", "有司刺候上起居，杳莫得詳宮鑰靜。", "嗚呼開元自英主，前鑒竟遺盈幅紙。", "君不見漢宮圖妲己，未必當年甚如是。"]'),
('70602c1d-2d1d-485f-b59b-8afaf51f67e9','送范憲東叔帥潼川四首  其一','陳傅良','宋','宋诗','song-poetry','','[]','離逾十年合，合復十月離。',60,'全唐诗/poet.song.157000.json','["離逾十年合，合復十月離。", "往日苦無及，來日忽未知。", "江源與海通，吳會與蜀違。", "通固天道常，違亦物理宜。", "勿作兒女感，是中有精微。"]'),
('8b327b40-7407-4c00-bd1f-c751c5125aa6','送范憲東叔帥潼川四首  其二','陳傅良','宋','宋诗','song-poetry','','[]','相從意氣豪，相知鬢毛斑。',60,'全唐诗/poet.song.157000.json','["相從意氣豪，相知鬢毛斑。", "細說竟昨非，淺斟始今歡。", "每懷吾黨多，未捄此世難。", "一則琢冰雪，再則紉芝蘭。", "騷人絕芳潔，孰與風人寬。"]'),
('90eb8995-2321-431d-80d9-e3472d543b56','送范憲東叔帥潼川四首  其三','陳傅良','宋','宋诗','song-poetry','','[]','有書但遮眼，有位亦養痾。',60,'全唐诗/poet.song.157000.json','["有書但遮眼，有位亦養痾。", "養痾猶近名，遮眼已患多。", "聊復歲晏爾，柰此人遠何。", "聲光正橫空，議論如懸河。", "宜君見別輕，款曲理則那。"]'),
('2b100f6e-f255-4a06-acbf-c8d0008c0683','送范憲東叔帥潼川四首  其四','陳傅良','宋','宋诗','song-poetry','','[]','逢人九頓首，遇事三折肱。',60,'全唐诗/poet.song.157000.json','["逢人九頓首，遇事三折肱。", "雖知少爲狂，正復老可憎。", "吾今有儲粟，吾昔有短檠。", "魯論訓何如，周易讀未曾。", "言歸又言歸，兒女喚不譍。"]'),
('1bc68b85-e1e6-4f29-81d7-5e8119ee5f8b','行湘喜雨簡劉公度周明叔','陳傅良','宋','宋诗','song-poetry','','[]','將行客有戒，正熱人不禁。',192,'全唐诗/poet.song.157000.json','["將行客有戒，正熱人不禁。", "出門一昔雨，解纜十日陰。", "湘山益以碧，湘水益以深。", "天光接雲夢，野暝蒙衡郴。", "蠅無盤中蹟，蟬有木末音。", "顧乃廢枕簟，爰方索衣衾。", "我起問夾岸，往歲孰與今。", "衡茅或數間，叢竹皆十尋。", "蒲蓮間華實，鷗鷺時浮沉。", "老穉各有得，漁樵不相侵。", "早插禾欲孕，新炊粟如金。", "爲之失倦游，於以成孤斟。", "永懷泛湘人，屈賈多愁吟。", "往者亦此境，今者亦此心。", "空名但千載，佳思誰一襟。", "時哉不可失，浯溪更駸駸。"]'),
('e55a330c-4d57-48f5-ad32-b65b30256041','劉連州和前韵因道湘中之樂以謝','陳傅良','宋','宋诗','song-poetry','','[]','湘中足可樂，誰苦愁不禁。',192,'全唐诗/poet.song.157000.json','["湘中足可樂，誰苦愁不禁。", "孌彼蘭蕙姿，固怯霰雪陰。", "賈子天下士，子何念慮深。", "貞元兩御史，南還會於郴。", "亦復相唱酬，間有亡國音。", "愚溪更憔悴，中夜起擁衾。", "而得欵乃句，膾炙循至今。", "我後五百年，公來適相尋。", "田疇歲膴膴，獄市春沉沉。", "寬書日夕下，民蠹袪牟侵。", "况也省賦甚，小郡至萬金。", "交歡有陸賈，私恨無羊斟。", "我飽竟甘寢，公暇多長吟。", "乃知湘中樂，關時匪關心。", "湘民忘勞力，樂極翻沾襟。", "却愁吾二人，四牡歌駸駸。"]'),
('95e17774-0575-41c1-98d8-4e2daf8f35ba','聞葉正則閲藏經次其送客韵以問之','陳傅良','宋','宋诗','song-poetry','','[]','順水去吳會，逆水來夔門。',240,'全唐诗/poet.song.157000.json','["順水去吳會，逆水來夔門。", "萬古逆順舟，以斗占旦昏。", "曩余好百家，信不及魯論。", "初亦半喜愕，久之乍亡存。", "白髮一無成，頗識委與源。", "風停波自平，却視消長痕。", "六經夫如何，夫子手所翻。", "恒言但桑稼，怪志無鵬鵾。", "規圓而矩方，往往萬巧攢。", "諸儒各有得，長短賢若干。", "玉帛相會盟，兵車相并吞。", "一語苟暗合，羣生皆晏溫。", "經成今幾年，嘗試以是觀。", "此道未軻死，此書未秦燔。", "猶之斗經天，於以生蓋渾。", "西方亦人豪，國自爲乾坤。", "書來入中州，坐使學者奔。", "君豈捨從之，或但遊其藩。", "吾聞欲乘槎，鑿空訪河根。", "孰與瞻斗車，把柁行江湍。"]'),
('80458138-ed26-4f01-83c1-4ba4adb023d3','和張倅唐英詠梅十四首  其一','陳傅良','宋','宋诗','song-poetry','','[]','種梅欲百畝，誰老意未渝。',48,'全唐诗/poet.song.157000.json','["種梅欲百畝，誰老意未渝。", "有山在堂背，有溪在庭除。", "我危坐中央，花以寘坐隅。", "人固不可親，花亦不可疎。"]'),
('be116a31-e55c-4029-bb05-7d4753543dd2','和張倅唐英詠梅十四首  其二','陳傅良','宋','宋诗','song-poetry','','[]','花芳以養性，花陰以休影。',48,'全唐诗/poet.song.157000.json','["花芳以養性，花陰以休影。", "更欲從旁謀，種秫可半頃。", "衝寒時一觴，我醉花獨醒。", "醉醒兩相忘，久矣繫歸艇。"]'),
('a2f48b90-9fa5-4ca1-9666-77c307fc9955','和張倅唐英詠梅十四首  其三','陳傅良','宋','宋诗','song-poetry','','[]','因山爲高下，因水爲縱橫。',48,'全唐诗/poet.song.157000.json','["因山爲高下，因水爲縱橫。", "恣花欲何之，勿撓所性清。", "却愁雪太深，瞻言不勝情。", "有時亦肯來，當我戶牖明。"]'),
('adb62130-8fa2-4a47-8f93-82155d740cf8','和張倅唐英詠梅十四首  其四','陳傅良','宋','宋诗','song-poetry','','[]','我豈愛花者，而獨愛此花。',48,'全唐诗/poet.song.157000.json','["我豈愛花者，而獨愛此花。", "愛之匪無人，詩且數百家。", "前有水邊橫，後有竹外斜。", "但作如是觀，桃李亦可誇。"]'),
('d8ff0f60-382b-4d01-b5b9-cb1af470feb0','和張倅唐英詠梅十四首  其五','陳傅良','宋','宋诗','song-poetry','','[]','人言物不齊，相較三十里。',48,'全唐诗/poet.song.157000.json','["人言物不齊，相較三十里。", "以梅等羣芳，何啻隔弱水。", "杜陵狀百物，無語可著此。", "巡簷索之笑，但不禁冷蕊。"]'),
('399e97f6-fb9d-438a-a193-4d4b2afbabf7','和張倅唐英詠梅十四首  其六','陳傅良','宋','宋诗','song-poetry','','[]','駸駸入衰暮，故作不潔清。',48,'全唐诗/poet.song.157000.json','["駸駸入衰暮，故作不潔清。", "美人美無度，可使一國傾。", "胡然立林林，夾此東西榮。", "對之意自消，令我欲近名。"]'),
('7720f5ae-5a36-411e-a2c3-d16317b0ab76','和張倅唐英詠梅十四首  其七','陳傅良','宋','宋诗','song-poetry','','[]','以之爲雪耶，雪或墮汙淺。',48,'全唐诗/poet.song.157000.json','["以之爲雪耶，雪或墮汙淺。", "以之爲玉耶，玉或附旒冕。", "春前每嘗試，歲晏不退轉。", "悠哉似有道，可與共舒卷。"]'),
('72e40343-3baf-40de-88b7-8727d55977a6','和張倅唐英詠梅十四首  其八','陳傅良','宋','宋诗','song-poetry','','[]','政應違衆好，可忍負幽探。',48,'全唐诗/poet.song.157000.json','["政應違衆好，可忍負幽探。", "以茲落南雅，蜂蝶獨遺憾。", "豈無好顔色，一雨竟陳暗。", "誰知歲寒姿，可久非可暫。"]'),
('93d9e9e6-e0ef-4137-8b17-803a554142f0','和張倅唐英詠梅十四首  其九','陳傅良','宋','宋诗','song-poetry','','[]','若以色見我，色衰令人忘。',48,'全唐诗/poet.song.157000.json','["若以色見我，色衰令人忘。", "香爲衆妙宗，妙亦不在香。", "鄉來芸芸者，自意傲雪霜。", "當斯玉立時，曾莫一在旁。"]'),
('93ed8cdb-d18e-4bd3-8eaf-c8de5b6c50b2','和張倅唐英詠梅十四首  其一○','陳傅良','宋','宋诗','song-poetry','','[]','遲遲可殿後，寂寂可鎮浮。',48,'全唐诗/poet.song.157000.json','["遲遲可殿後，寂寂可鎮浮。", "風人第一章，窈窕河之洲。", "穆如三代英，惟此宜與儔。", "不然則臞仙，玉簫下秦樓。"]'),
('636bf337-3f02-4fa8-9ec7-a44bcbf0f560','和張倅唐英詠梅十四首  其一一','陳傅良','宋','宋诗','song-poetry','','[]','紛華有心說，艷美得目送。',48,'全唐诗/poet.song.157000.json','["紛華有心說，艷美得目送。", "越在篁葦間，顧使詩興動。", "詩人被花惱，盡日手自弄。", "愁吟日不足，又作栩栩夢。"]'),
('edad81ec-221d-42d3-b72a-c234b7ff06a0','和張倅唐英詠梅十四首  其一二','陳傅良','宋','宋诗','song-poetry','','[]','亭亭湘岸竹，炯炯湘波月。',48,'全唐诗/poet.song.157000.json','["亭亭湘岸竹，炯炯湘波月。", "其中雪垂垂，一樹爲誰設。", "不應皂蓋人，於此能忘折。", "折之寄相思，可以慰分裂。"]'),
('a066706f-f3fd-4570-8476-46ecc72693e2','和張倅唐英詠梅十四首  其一三','陳傅良','宋','宋诗','song-poetry','','[]','商山皓鬚眉，久不見綺黄。',48,'全唐诗/poet.song.157000.json','["商山皓鬚眉，久不見綺黄。", "邂逅一笑粲，可與斯人當。", "如何爲林逋，托根向錢塘。", "居遺蘭與芷，牢愁楚沅湘。"]'),
('02aba7bb-3905-4841-9c74-4968a66803c6','和張倅唐英詠梅十四首  其一四','陳傅良','宋','宋诗','song-poetry','','[]','先人手所種，家在何處村。',48,'全唐诗/poet.song.157000.json','["先人手所種，家在何處村。", "自別此堂堂，不知幾寒溫。", "盍歸封植之，歲歲爲此言。", "老如霧中看，正恐目力昏。"]'),
('7201fa8e-4494-4d11-beca-974be0f3c895','招隠二首  其一','陳傅良','宋','宋诗','song-poetry','','[]','將子無登山，山上岡復岡。',120,'全唐诗/poet.song.157000.json','["將子無登山，山上岡復岡。", "朝爲朱陽煒，暮作陰飈凉。", "磴滑幽鳥啼，林深山鬼翔。", "子兮何所求，樂此魑魅鄉。", "國人佇齊軾，吾黨多魯狂。", "望子子不來，翠袖天風揚。", "緇塵擺落盡，幽願次第償。", "焦䳟入冥雲，蟣虱寬貝陽。", "子兮竟誰從，獨樂無已康。", "豈其羊之饑，而可穀與臧。"]'),
('916edae1-6195-4bc2-a3b1-7b2941ee36be','招隠二首  其二','陳傅良','宋','宋诗','song-poetry','','[]','將子無涉水，水深下無極。',120,'全唐诗/poet.song.157000.json','["將子無涉水，水深下無極。", "鯈魚舞浮陽，螭首闖陰碧。", "弱去一羽沉，惡來萬波激。", "子兮何所求，快此蛟涎滴。", "議諫起陽城，拾遺招李渤。", "望子子不來，羊裘號逋客。", "踞坐山石麤，晞髮朔風疾。", "亂流兩白足，何日踔疎逸。", "子兮寧不悲，饑氓俟唐稷。", "豈其洛之涯，而可溫與石。"]'),
('e1629c51-f119-4147-a2f3-7de68818102b','記夢','陳傅良','宋','宋诗','song-poetry','','[]','漥然石壁罅，涓涓如絲繩。',84,'全唐诗/poet.song.157000.json','["漥然石壁罅，涓涓如絲繩。", "其人指此泉，下去爲滄溟。", "旁有玉蟾蜍，空中底方平。", "視之鼻通尻，徹竅刻畫精。", "泉從鼻聰入，可止不可盈。", "欲問已無人，我亦悟我生。", "惜哉烟火食，滓我朝清明。"]'),
('6235f57e-4a51-4ead-a533-6a8a84a60c03','始生七章章八句上皇子嘉王生辰  其一','陳傅良','宋','宋诗','song-poetry','','[]','生爲帝子貴，本自歷數歸。',48,'全唐诗/poet.song.157000.json','["生爲帝子貴，本自歷數歸。", "歷數萬億年，帝子壽無期。", "今夕果何夕，欲頌皆贅辭。", "但願王此心，無忘始生時。"]'),
('74c21789-08e3-4b61-b3db-2f2176878ceb','始生七章章八句上皇子嘉王生辰  其二','陳傅良','宋','宋诗','song-poetry','','[]','王看松柏萌，未具葉與枝。',48,'全唐诗/poet.song.157000.json','["王看松柏萌，未具葉與枝。", "沖然一點春，其大可十圍。", "云胡間不茂，爲失雨露滋。", "乃知生意同，其異各所罹。"]'),
('fab7f3a0-8540-440e-9209-23641935b258','始生七章章八句上皇子嘉王生辰  其三','陳傅良','宋','宋诗','song-poetry','','[]','入均此生爾，王生樂無涯。',48,'全唐诗/poet.song.157000.json','["入均此生爾，王生樂無涯。", "如將與人同，請自今夕推。", "奉觴一何多，于以介壽祺。", "王其敬舉觴，一念周八維。"]'),
('ef1b5a68-0d05-4286-8d5b-e8166d573d71','始生七章章八句上皇子嘉王生辰  其四','陳傅良','宋','宋诗','song-poetry','','[]','百鼎羅珍羞，世豈無調饑。',48,'全唐诗/poet.song.157000.json','["百鼎羅珍羞，世豈無調饑。", "錦綺爛盈門，藍縷還誰衣。", "龍樓近日月，茅舍或不支。", "三宮子孫孫，亦有孤與嫠。"]'),
('49f2498e-09d3-4072-9207-13e12d6cdbe2','始生七章章八句上皇子嘉王生辰  其五','陳傅良','宋','宋诗','song-poetry','','[]','吾方貴吾生，相彼多阽危。',48,'全唐诗/poet.song.157000.json','["吾方貴吾生，相彼多阽危。", "豈伊天地公，而獨及我私。", "於焉識仁端，一物豈忍遺。", "當思宇宙間，壽域咸熙熙。"]'),
('5e1ebe40-7efe-4060-89e8-ecdbbf6e7e68','始生七章章八句上皇子嘉王生辰  其六','陳傅良','宋','宋诗','song-poetry','','[]','獵人愛麛麌，漁人愛鯤鮞。',48,'全唐诗/poet.song.157000.json','["獵人愛麛麌，漁人愛鯤鮞。", "萬物欣自遂，况也民秉彜。", "家有舉桉婦，人有譍門兒。", "王心至於此，壽不數耆頤。"]'),
('8f4eb124-896d-481a-82ca-8512f1498d11','始生七章章八句上皇子嘉王生辰  其七','陳傅良','宋','宋诗','song-poetry','','[]','詩人誦稷功，造周本岐嶷。',48,'全唐诗/poet.song.157000.json','["詩人誦稷功，造周本岐嶷。", "首言民初生，次及稷誕彌。", "民命繫於稷，此語非夸毗。", "末僚甚拳拳，所愧無周詩。"]'),
('0afbd9b5-1b1d-42a1-86d2-0492daa2ab71','送丘宗卿帥蜀  其一','陳傅良','宋','宋诗','song-poetry','','[]','嘗陪諸老後，亦與晚進游。',60,'全唐诗/poet.song.157000.json','["嘗陪諸老後，亦與晚進游。", "有能一夕話，可洗萬古愁。", "昔君尚青衫，今我已白頭。", "闕下何匆匆，蜀江正悠悠。", "一請工治庖，再請拙操舟。"]'),
('a1329baf-8514-40a4-85f9-cfc962794903','送丘宗卿帥蜀  其二','陳傅良','宋','宋诗','song-poetry','','[]','好靜從古始，尚恩極今時。',60,'全唐诗/poet.song.157000.json','["好靜從古始，尚恩極今時。", "寧使舉國貧，勿與一士遺。", "熙寧固前轍，元祐誠良醫。", "我亦欲宴興，人方乏朝炊。", "持之訊人傑，人傑良自疑。"]'),
('151d0b57-3355-45f6-a49b-69f272cf42ea','送丘宗卿帥蜀  其三','陳傅良','宋','宋诗','song-poetry','','[]','前瞻及河隴，內顧連江沱。',60,'全唐诗/poet.song.157000.json','["前瞻及河隴，內顧連江沱。", "邊籌尚彈壓，民瘴須挼挱。", "方當上懷遠，况復歲薦瘥。", "宜公去帆輕，歲月亦易多。", "西人豈不好，奈此東人何。"]'),
('d924af4a-a203-470f-a976-331628fa6fed','短歌送呂子約丞郡天台','陳傅良','宋','宋诗','song-poetry','','[]','露荷不肯附綠漲，石榴自欲當朱明。',96,'全唐诗/poet.song.157000.json','["露荷不肯附綠漲，石榴自欲當朱明。", "我無一物與君別，持此薦以雙玉瓶。", "榴花結子荷成的，定亦扁舟去爲客。", "良集偏於吾輩慳，新功或向他山得。", "我歌雖短聲苦長，君不能飲酒滿觴。", "申公何在麗澤死，又送冥鴻謀稻粱。"]'),
('6ede7bd7-de7d-4ac6-b6a3-9f8c56026143','送黄子聞得縣瑞安','陳傅良','宋','宋诗','song-poetry','','[]','西都循吏無墨綬，密令忽用爲三公。',128,'全唐诗/poet.song.157000.json','["西都循吏無墨綬，密令忽用爲三公。", "仁人遭時乃自見，不係官爵汙與隆。", "黄君崎嶇髮半白，得縣吾州滄海東。", "平生經術久未試，今幸小試難爲功。", "休聲出自士論衆，遺愛見於民力窮。", "如君作吏豈擇便，第勿謂難斯令終。", "嗟余欲歸歸未得，觀政不在漁樵中。", "逢人每似卓傅傳，此道萬古君王同。"]'),
('1bb09385-4406-42f7-a758-2a9276ed63da','送陳仲孚還里','陳傅良','宋','宋诗','song-poetry','','[]','意勝不受暑，交深欲忘言。',48,'全唐诗/poet.song.157000.json','["意勝不受暑，交深欲忘言。", "子車今日脂，我經何時箋。", "卜稼豈無疇，頌橘亦有園。", "掛冠特易耳，奈何子盛年。"]'),
('3134bc26-d4c5-40c8-8c7d-f7675d96980f','教授李夢符惠宣聖畫像用韵奉酬','陳傅良','宋','宋诗','song-poetry','','[]','一藝必有師，尚論襄與夔。',264,'全唐诗/poet.song.157000.json','["一藝必有師，尚論襄與夔。", "一國必有師，尚論管與伊。", "信知師道尊，分與君父夷。", "吁嗟文王沒，斯文屬之誰。", "微言二十篇，論次自學而。", "傳之者顔曾，其後則子思。", "方當周之衰，諸子出怪奇。", "王公各師承，一語可觧頤。", "見之擁篲迎，不見嚬其眉。", "孟子獨推尊，是惟聖之時。", "苟不本孔氏，皆放其淫詞。", "於是尊孔孟，誕作百世師。", "自非戎翟秦，孰背此道馳。", "本朝郡爲學，薄海尸祝之。", "往往屈萬乘，降升廟庭垂。", "我作暮春堂，魯論以自隨。", "扁題落天上，鬼遁蛟龍移。", "江山護昭回，誰敢或訕嗤。", "中有夫子像，來從魯家兒。", "廣文以遺我，溫厲尚可追。", "吾今得吾師，下視衆說卑。", "世世萬子孫，永此巢一枝。"]'),
('431f7466-aec0-406d-91cc-6ec7573ccf22','還徐叔子犀带','陳傅良','宋','宋诗','song-poetry','','[]','徐子贈我舊寶犀，宣和國工所事治。',309,'全唐诗/poet.song.157000.json','["徐子贈我舊寶犀，宣和國工所事治。", "玄玉十截黄四垂，厚且半寸徑尺圍。", "方廉整不刻毫釐，金飾諸末柔丹韋。", "寘之止齋光陸離，天吳海若不敢窺。", "奈何骨相堪蓑衣，自得此带逢百罹。", "我服黑角二紀餘，歲月幾半蒙蛛絲。", "識與不識皆歔欷，恨不披拂來隆墀。", "湖湘老把乘邊麾，次第三節登王畿。", "脩門再入留郎闈，上皇一見玉色怡。", "闊步蓬山上坳螭，向者所恨今交譏。", "懼瀝肝膽得請歸，自意永與漁樵嬉。", "急詔適際潛龍飛，誤恩狎至湛露斯。", "古來逾分天不宜，百炊未滿萬事非。", "還觀櫝中一解頤，吾腰安用爾带爲。", "徐子盛年脩幹支，才華不數紛紛兒。", "請以带去藏待時，拖金縣玉未可知。", "招招車騎來何遲，苦勿留此令我悲。", "君不見在昔十圍終失之，終朝三褫事尤危。", "况我昏睡誰護持，亦恐夜半神運蛟龍移。"]'),
('f9618460-e383-44e0-aaea-6d8d6b5fa6a5','憶筇杖','陳傅良','宋','宋诗','song-poetry','','[]','岷峨山下筇竹杖，危者使安衰可壯。',203,'全唐诗/poet.song.157000.json','["岷峨山下筇竹杖，危者使安衰可壯。", "秦皇漢武窮兵不可得，我獨得之今丞相。", "前年有旨還故園，其冬急召朝日邊。", "半歲驅馳數千里，頼有此杖常扶顛。", "倉黄又別脩門去，私室無人謹呵護。", "夜半雷霆下取將，兒叫妻啼留不住。", "我聞丞相下峽時，一物無有杖自隨。", "屬當晏朝立仗久，憐我弱脛疲坳螭。", "如今步屧隨衰草，十步趑趄九步倒。", "假如杖在欲用之，山精海怪震怒亦不保。", "君不見杜陵桃竹欹，常恐失之君山湖上之風波。", "梓潼使君之贈尚爾耳，况自丞相還如何。"]'),
('fab7ef84-18d2-44fd-833a-024a559ca029','蘭花供壽國舉兄','陳傅良','宋','宋诗','song-poetry','','[]','山丹吹出青藜火，金蝶窺叢何妸娜。',196,'全唐诗/poet.song.157000.json','["山丹吹出青藜火，金蝶窺叢何妸娜。", "朱槿更作猩袍紅，夸道風人嘗印可。", "沒利從旁粲然笑，奄有諸香誰似我。", "素馨蕭然山澤臞，至香不數脂粉腴。", "衆芳固自有醖藉，要是傍人之庭除。", "何如琉璃千頃水，涵碧淤泥不解汙。", "芙蕖幽蘭獨自倚脩竹，生來未始受諸觸。", "深知抱此竟安用，用多亦豈芙蕖福。", "若以滋味屬厭人，虀粉此身人不足。", "今夕何夕新風露，入秋一雨天西顧。", "止齋有兄永難老，止齋之弟愛莫助。", "但以清白傳之萬子孫，歲供蘭花美無度。"]'),
('dad85cf0-b2af-482e-802b-66ffaa8308b7','東陽郭希呂山園十詠 清曠亭','陳傅良','宋','宋诗','song-poetry','','[]','幽人有遐心，蔀屋涵澄空。',24,'全唐诗/poet.song.157000.json','["幽人有遐心，蔀屋涵澄空。", "况復得此山，心事與境同。"]'),
('aa7db9fc-581d-402d-9016-8620e8eb1441','東陽郭希呂山園十詠 桂壑','陳傅良','宋','宋诗','song-poetry','','[]','一壑亦易得，安得桂林林。',24,'全唐诗/poet.song.157000.json','["一壑亦易得，安得桂林林。", "道人偶見之，不是歲月深。"]'),
('6dd33622-f9e6-4835-bf11-06ae3eb1f212','東陽郭希呂山園十詠 月峽','陳傅良','宋','宋诗','song-poetry','','[]','兩崖束青天，中有月皎皎。',24,'全唐诗/poet.song.157000.json','["兩崖束青天，中有月皎皎。", "乍可謂月低，不可謂天小。"]'),
('2c9135a6-ec7c-4165-ad75-6c905770bcea','東陽郭希呂山園十詠 小爛柯','陳傅良','宋','宋诗','song-poetry','','[]','促膝有仙凡，爛柯無小大。',24,'全唐诗/poet.song.157000.json','["促膝有仙凡，爛柯無小大。", "誰知桃源人，不在秦晉外。"]'),
('743260e9-3f91-4f0c-8407-fbcaea0dcd3f','東陽郭希呂山園十詠 傾月','陳傅良','宋','宋诗','song-poetry','','[]','嘗聞鳳棲梧，梧老鳳未棲。',24,'全唐诗/poet.song.157000.json','["嘗聞鳳棲梧，梧老鳳未棲。", "令我日佇立，不知月東西。"]'),
('1820a84b-b371-4880-8446-81b3e5cc734d','東陽郭希呂山園十詠 閟雲關','陳傅良','宋','宋诗','song-poetry','','[]','雲以無心出，雲歸亦何心。',24,'全唐诗/poet.song.157000.json','["雲以無心出，雲歸亦何心。", "樵牧窺其藏，妄意此阻深。"]'),
('7442f868-71d4-4c3a-9e90-d2e5cb04fad0','東陽郭希呂山園十詠 玉泉','陳傅良','宋','宋诗','song-poetry','','[]','清曉閲草木，各具天一水。',24,'全唐诗/poet.song.157000.json','["清曉閲草木，各具天一水。", "安用學餐玉，將以蘄不死。"]'),
('4f45e9e7-40d8-4137-a082-86ecde16bcd2','東陽郭希呂山園十詠 飛雪','陳傅良','宋','宋诗','song-poetry','','[]','涓涓自空來，霏霏復不見。',24,'全唐诗/poet.song.157000.json','["涓涓自空來，霏霏復不見。", "安得自尤物，使我耳目亂。"]'),
('4858abdf-bac0-4731-b4ae-352cc0f22dc7','東陽郭希呂山園十詠 壺天閣','陳傅良','宋','宋诗','song-poetry','','[]','凭欄時獨立，萬象皆見前。',24,'全唐诗/poet.song.157000.json','["凭欄時獨立，萬象皆見前。", "若非著眼高，亦是天一偏。"]'),
('ad86be00-1258-4e23-92ca-ca30017f3f34','東陽郭希呂山園十詠 石井','陳傅良','宋','宋诗','song-poetry','','[]','鬵釜吾已溉，吾纓亦無塵。',24,'全唐诗/poet.song.157000.json','["鬵釜吾已溉，吾纓亦無塵。", "漥石以潴之，恐有抱甕人。"]'),
('f8b2a20f-75e5-4ef5-a790-513809ac3a87','送郭希呂','陳傅良','宋','宋诗','song-poetry','','[]','我門閉重重，我徑阻且深。',96,'全唐诗/poet.song.157000.json','["我門閉重重，我徑阻且深。", "梅花獨相依，聊以慰我心。", "美人從何來，崎嶇自幽尋。", "亦於琢冰中，而和南風琴。", "萊甲尚可羹，新蒭足同斟。", "不知歲已華，歸興生霜砧。", "欲別復少住，棲烏歸月林。", "客去鳥翾飛，落花滿牆陰。"]'),
('cf6799b8-7bca-4dd9-a0b1-b381ac74fe81','水仙花','陳傅良','宋','宋诗','song-poetry','','[]','江梅丈人行，歲寒固天姿。',144,'全唐诗/poet.song.157000.json','["江梅丈人行，歲寒固天姿。", "蠟梅微著色，標致亦背時。", "胡然此柔嘉，支本僅自持。", "乃以平地尺，氣與松篁夷。", "粹然金玉相，承以翠羽儀。", "獨立萬槁中，冰膠雪垂垂。", "水仙誰强名，相宜未相知。", "刻畫近脂粉，而况山谷詩。", "吾聞抱太和，未易形似窺。", "當其自英華，造物且霽威。", "平生恨剛褊，未老齒髮衰。", "掇花置膽瓶，吾今得吾師。"]'),
('762cd21e-c375-4a07-820b-b57ae7c97f12','止齋曲廊初成','陳傅良','宋','宋诗','song-poetry','','[]','但酒勝如水，但花勝如草。',168,'全唐诗/poet.song.157000.json','["但酒勝如水，但花勝如草。", "小廊曲通幽，竹椽亦良好。", "止齋十數間，足以便衰老。", "簷低遠風露，地窄易汛掃。", "淺溪浮薄觴，短屏糊舊稿。", "著書僅玄易，過客多韋縞。", "於中榜退思，誰其諒深抱。", "吾思亦已晚，吾退盍更早。", "懷哉彭澤令，仰止商山皓。", "維淵有潛龍，維岳有藏寶。", "煌煌暮春堂，三字落穹昊。", "昭回際南極，鎮撫及東島。", "胡然乃在斯，夙夜懼不保。", "鬼神無世情，呵護必有道。"]'),
('56e7b74b-aab1-49fc-950e-97f7156c74ae','次沈儉夫求花木韵','陳傅良','宋','宋诗','song-poetry','','[]','我意何不樂，我顔復何㥏。',288,'全唐诗/poet.song.157000.json','["我意何不樂，我顔復何㥏。", "止齋有新畬，耕犢角已繭。", "止齋有溪水，釣席隨所展。", "兩山夾精舍，佳處迫廬峴。", "朋來盡名流，燕坐皆勝踐。", "頹然止齋翁，心故不可轉。", "厭書或窺園，乘興時陟巘。", "日月之蔽虧，木陰自幽顯。", "雨露之密疎，草色自深淺。", "翁子一觴詠，初不著姝孌。", "易老探醇駁，風騷較寬褊。", "眠食雖甚佳，病患盍加勉。", "謗篋况所招，訟缿那能辨。", "於焉更悟入，豈但苟排遣。", "寄言子沈子，所欲果何件。", "葭豕來春田，冥鴻脫秋獮。", "谷蘭猶見紉，月桂不可搴。", "慕遠失之近，求多得常鮮。", "請以壯縣才，從茲益懷卷。", "深居勿近市，隘巷莫容輦。", "有花門擁篲，無花地生蘚。", "嘗試玩喧寂，何者是真舛。", "舊學枉初心，新功費重研。", "何如過止齋，我亦精文選。"]'),
('e23e1585-9ac9-443d-a924-292f44aa9fba','春晚書懷二首奉簡陳益之  其一','陳傅良','宋','宋诗','song-poetry','','[]','百舌喜太甚，杜鵑恨何深。',48,'全唐诗/poet.song.157000.json','["百舌喜太甚，杜鵑恨何深。", "睍睆斯黄鸝，律中宮之音。", "物情自不齊，天運初無心。", "道人獨領會，杖藜立芳陰。"]'),
('ee209f3f-d080-4cae-b5a6-aca44f9cbb23','春晚書懷二首奉簡陳益之  其二','陳傅良','宋','宋诗','song-poetry','','[]','百卉得雨露，華滋巧相娛。',48,'全唐诗/poet.song.157000.json','["百卉得雨露，華滋巧相娛。", "但知說姚魏，河洛竟何如。", "我方悟吾生，箋經未成書。", "安得小學師，從之注蟲魚。"]'),
('ca65340c-bec8-4370-82ed-081e02571a67','題沈仲一所藏周氏羣公書帖','陳傅良','宋','宋诗','song-poetry','','[]','紛紛世上如落花，東風即入西鄰家，要亦餘事吾何嗟。',93,'全唐诗/poet.song.157000.json','["紛紛世上如落花，東風即入西鄰家，要亦餘事吾何嗟。", "斯人故國之喬木，枝葉胡然亦流落。", "吾生已晚講聞熟，見欲墮淚那忍讀。", "古來道德功名上，傳世不曾緣物重。", "君不見人間秦漢鼎彜銘與頌，子子孫孫永寶用。"]'),
('56385980-75ea-41f0-b4b7-95054b7931ca','贈章虞卿','陳傅良','宋','宋诗','song-poetry','','[]','章子一別二十年，此來銜袖書一編。',64,'全唐诗/poet.song.157000.json','["章子一別二十年，此來銜袖書一編。", "自出己意說百篇，至說五誥尤愕然。", "我今萬事付幽屏，是書插架漫不省。", "子之書意吾已領，且探梅花試湯餠。"]'),
('6f5fdc4e-3799-4173-adfc-18cfc86ddd13','題僧法傳爲沈仲一畫聽松圖','陳傅良','宋','宋诗','song-poetry','','[]','古松不知幾千年，直幹欲上干青天。',198,'全唐诗/poet.song.157000.json','["古松不知幾千年，直幹欲上干青天。", "樛枝下與人世接，冷風過之萬壑喧。", "猿驚鶴怪樵牧遁，百鬼愁絕誰傍邊。", "紛紛海內絲竹耳，何處縹緲來臞仙。", "整襟拱聽移永日，置琴弗顧僮欹眠。", "松風有際意無盡，莊騷不數惟易玄。", "嗟乎深山大澤松不乏，斯人往往千載之陳編。", "筆端若有夜半力，一日忽在軒楹前。", "止齋虛靜對立久，晴昊亦爲生蒼烟。", "畢宏韋偃骨已朽，畫工一世脂粉便。", "北湖居士安得此，奄有二子雲山傳。", "北湖居士雲山傳，吾詩孰與杜老起九原。"]'),
('c9b640c1-d0dc-45ac-8c19-660660bd22b8','送畫僧法傳','陳傅良','宋','宋诗','song-poetry','','[]','問訊雪庵今何如，子來搔首更踟躕。',64,'全唐诗/poet.song.157000.json','["問訊雪庵今何如，子來搔首更踟躕。", "時於戲墨窺禪悅，尚想家傳及緒餘。", "曾點爾各言爾志，陶潛吾亦愛吾廬。", "誰人解寫二歸意，欲放風帆還摻祛。"]'),
('1249349e-8311-4f16-bcec-0f57f38f74a2','題瑞安宰朱元成乃祖雲壑莊圖','陳傅良','宋','宋诗','song-poetry','','[]','功成不受富貴汙，輕舟翩然下五湖。',96,'全唐诗/poet.song.157000.json','["功成不受富貴汙，輕舟翩然下五湖。", "至今風流在姑蘇，我復見此雲壑圖。", "兩坡喬木樛相扶，殘山剩水千里餘。", "天際未知何有無，一葦橫絕雙風蒲。", "楊花春岸秋蓴鱸，在在著此儒仙臞。", "世無宗師貌不如，誰其嗣之吾大夫。"]'),
('b23d0843-1e9c-4ea1-a537-543c427ed7a1','詠梅分韵得蕊字','陳傅良','宋','宋诗','song-poetry','','[]','惜樹須惜枝，看花須看蕊。',48,'全唐诗/poet.song.157000.json','["惜樹須惜枝，看花須看蕊。", "枯瘦發纖穠，况此具衆美。", "千林墮黄埃，數點昭青泚。", "誰知霜雪深，天意欲玉女。"]'),
('a6cf819b-ad6f-4a80-a463-d8494015c7ce','送蕃叟弟赴江西帥幕分韵得獨字','陳傅良','宋','宋诗','song-poetry','','[]','生平未省友松竹，愛言從宦輸幽獨。',64,'全唐诗/poet.song.157000.json','["生平未省友松竹，愛言從宦輸幽獨。", "子也諸侯老賓客，襆被僅緣升斗祿。", "爲問江神何世情，霽月光風送帆幅。", "天意元來向事功，謹毋遐心自金玉。"]'),
('063e4f29-0ff8-41d8-a5ff-f870142b5e96','鼓琴行送許深父同知被詔赴闕','陳傅良','宋','宋诗','song-poetry','','[]','伯牙非不善鼓琴，指下能寫山高而水深。',252,'全唐诗/poet.song.157000.json','["伯牙非不善鼓琴，指下能寫山高而水深。", "亦有師曠號精絕，蜚雪白晝爲重陰。", "吾琴不以與二子，二子不過衰季愁嘆而悲吟。", "后夔安在九嶷遠，南風不競鳳鳥瘖。", "恭惟高宗復古殿得此，凈洗禁昧朱離任。", "一鼓朝綱日井井，再鼓邊柝秋沉沉。", "桑麻萬里皆按堵，笙歌三紀無沾襟。", "橋山遺此歲月侵，何時雅頌得所籥不僣。", "寶藏豈愛五重玉，市價敢論雙南金。", "公歸舊隠三霜砧，天子恭默思商霖。", "君臣祥琴適相際，使者十輩來駸駸。", "白麻已草弄印久，端揆虛左誰當今。", "我抱此琴病山林，不如送公西歸調釜鬵。", "但願爲作南風音，上以對揚高宗中興之大業，下以追還虞舜萬國之歡心。"]'),
('3afac8d5-1c82-479b-bf20-e6744f147cab','送徐一之客贛上兼簡贛守薛象先','陳傅良','宋','宋诗','song-poetry','','[]','清水一段出萬壑，越玉五重陳兩廂。',96,'全唐诗/poet.song.157000.json','["清水一段出萬壑，越玉五重陳兩廂。", "美人去作諸侯客，幾年薖澗籌行藏。", "繫舟夷猶暮春堂，細雨冥冥烟樹蒼。", "竹萌梅實盡此觴，別恨豈但山川長。", "章貢分流合江水，西風爲我送雙鯉。", "休言相憶强加餐，報道吳帆何日起。"]'),
('a2ef2453-b552-4874-b9d4-4469f4b9d1b7','新昌詠歸','陳傅良','宋','宋诗','song-poetry','','[]','回頭三十二年非，木落霜空水見涯。',64,'全唐诗/poet.song.157000.json','["回頭三十二年非，木落霜空水見涯。", "萬事自憐多譽早，半生猶幸一官遲。", "好將翰墨付儕輩，去與漁樵相爾誰。", "還有故人招隠否，寄聲橘柚欲黄時。"]'),
('06fcd44b-cdf7-40ec-8880-9aefbc5ca6c3','贈石時亨','陳傅良','宋','宋诗','song-poetry','','[]','要是同根本，應須識等差。',48,'全唐诗/poet.song.157000.json','["要是同根本，應須識等差。", "六經無剩語，百氏自名家。", "日落山含斗，潮回浦見沙。", "了知來往意，萬古一生涯。"]'),
('a1b7f9d0-593d-4e59-aec4-23abaf786969','題觀潮閣','陳傅良','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','俯拾滄溟大，衡陳蒼莽多。',48,'全唐诗/poet.song.157000.json','["俯拾滄溟大，衡陳蒼莽多。", "閩山飛鳥沒，吳會一帆過。", "消長看沙尾，行藏問釣蓑。", "登臨有如此，人物付誰何。"]'),
('63f52928-2727-42f6-9346-55b25267d388','上閩帥梁丞相生日二十二韵','陳傅良','宋','宋诗','song-poetry','','[]','炎正維中葉，皇圖再造年。',264,'全唐诗/poet.song.157000.json','["炎正維中葉，皇圖再造年。", "天潢流少海，星緯粲台躔。", "臣主嘗難並，乾坤豈偶然。", "千齡開歷數，一氣付陶甄。", "黄屋傳神器，彤庭領衆仙。", "風雲從此會，日月更誰先。", "昔者求侵地，何人賦甫田。", "吳兒咸抵掌，噲等欲差肩。", "廟論惟多士，戎功不在邊。", "一麾分赤社，萬事屬青編。", "吾道誠難用，諸儒亦自偏。", "才名多濩落，經行失枸攣。", "洛蜀何嗟及，熙豐竟禍延。", "帝羅兼鴈木，平步忽貂蟬。", "甚矣知當宁，凄其望濟川。", "年來羣老行，公在萬民懸。", "定作鹽梅夢，行歌杕杜還。", "滄溟宗衆濫，衡嶽倚蒼玄。", "要使垂身後，無爲慰眼前。", "管絃無算爵，桃李未央天。", "魯燕雖堪頌，閩山不足鎸。", "中原康濟事，彜鼎願聯翩。"]'),
('db479c4a-9a82-466a-b127-e6940dbe52c2','送鄭少卿景望知建寧  其一','陳傅良','宋','宋诗','song-poetry','','[]','過家鄉里敬，將母士夫榮。',48,'全唐诗/poet.song.157000.json','["過家鄉里敬，將母士夫榮。", "得失從人論，行藏獨自明。", "百年中古少，一笑萬金輕。", "廉讓吾何敢，新茶可擷英。"]'),
('e329f017-fee7-4d1b-bed4-5f812df99764','送鄭少卿景望知建寧  其二','陳傅良','宋','宋诗','song-poetry','','[]','有志須身健，關心在歲寒。',48,'全唐诗/poet.song.157000.json','["有志須身健，關心在歲寒。", "一時諸老盡，多見大名難。", "湖海方連旱，甌閩適少寬。", "爲州人不乏，千萬强加餐。"]'),
('494896bb-ba3f-49ca-b7d1-14067384d418','送鄭少卿景望知建寧  其三','陳傅良','宋','宋诗','song-poetry','','[]','清廟圖書寶，熙朝雅頌音。',48,'全唐诗/poet.song.157000.json','["清廟圖書寶，熙朝雅頌音。", "頻繁三節召，荏苒二毛侵。", "衣飯家纔足，丘園意亦深。", "卧聽床下士，時作武侯吟。"]'),
('3cfda97a-8d8e-4986-be5a-eb22200d60f8','送鄭少卿景望知建寧  其四','陳傅良','宋','宋诗','song-poetry','','[]','海內言華萼，誰名動搢紳。',48,'全唐诗/poet.song.157000.json','["海內言華萼，誰名動搢紳。", "豈無當世志，能忍十年貧。", "酒興新來減，交情老更親。", "公餘如促膝，剩把古書陳。"]'),
('fe044a85-c5a4-43a0-a9ac-835c5dff31d8','送鄭少卿景望知建寧  其五','陳傅良','宋','宋诗','song-poetry','','[]','屏廢誠愚分，牢愁更索居。',48,'全唐诗/poet.song.157000.json','["屏廢誠愚分，牢愁更索居。", "若逢知己問，猶解課兒書。", "地僻門長閉，年饑菜自鋤。", "相望無一字，不是故情疎。"]'),
('ed47644e-0d4e-413e-8155-48f9b75acf26','庚子除夜有懷','陳傅良','宋','宋诗','song-poetry','','[]','老盆自酌共誰歌，嘆息其如此夜何。',64,'全唐诗/poet.song.157000.json','["老盆自酌共誰歌，嘆息其如此夜何。", "已覺二毛嗔婦問，可堪一飯患兒多。", "關河滿眼風塵在，天地藏身歲月過。", "事業文章吾所畏，東陽人亦卧巖阿。"]'),
('b4b5d6f9-b0bb-4c06-85e5-748f8fad3d0c','送沈元誠赴臨漳主簿  其一','陳傅良','宋','宋诗','song-poetry','','[]','誰說鄉先進，能無沈隠侯。',48,'全唐诗/poet.song.157000.json','["誰說鄉先進，能無沈隠侯。", "青衫今適越，白髮竟依劉。", "道固爲名累，人當與命謀。", "三台行漸近，且勿問歸舟。"]'),
('97e301fe-7dc1-474d-b40c-d98ca7f6415d','送沈元誠赴臨漳主簿  其二','陳傅良','宋','宋诗','song-poetry','','[]','終藏懷未已，欲去事多違。',48,'全唐诗/poet.song.157000.json','["終藏懷未已，欲去事多違。", "士友方推轂，鄉鄰但挽衣。", "冥鴻寒汲汲，霜菊晚暉暉。", "何限春蜚動，君看果是非。"]'),
('2862465f-afb8-4b37-a303-a13261655214','送德遠弟赴省','陳傅良','宋','宋诗','song-poetry','','[]','科名雖細事，文字要新功。',48,'全唐诗/poet.song.157000.json','["科名雖細事，文字要新功。", "方拙存家學，豐腴與衆同。", "江湖多我友，臺省半諸公。", "爲道貧非病，連簷有芥菘。"]'),
('d1467331-806f-4ec4-b01d-b89bc811e7ef','和張孟阜歲旦韵','陳傅良','宋','宋诗','song-poetry','','[]','白髮朝看鏡，青燈夜數更。',48,'全唐诗/poet.song.157000.json','["白髮朝看鏡，青燈夜數更。", "文章輸善宦，名字誤浮生。", "廢學兒鼾睡，安貧婦饁耕。", "從今定逢吉，吾已卜先庚。"]'),
('ca9dbc20-9adf-4f5c-8e26-b1c6165649cf','聞沈元誠歸自臨漳喜而奉寄','陳傅良','宋','宋诗','song-poetry','','[]','荔圃班班熟，蠔房箇箇肥。',48,'全唐诗/poet.song.157000.json','["荔圃班班熟，蠔房箇箇肥。", "我雖緣此誤，公亦爲何歸。", "吏事生衣垢，家山減带圍。", "不無華衮字，卿月更光輝。"]'),
('29f922e1-9691-4806-8c8a-44d09ce77b28','晚春二首  其一','陳傅良','宋','宋诗','song-poetry','','[]','萬枝寂寞待春風，風雨過多春已空。',32,'全唐诗/poet.song.157000.json','["萬枝寂寞待春風，風雨過多春已空。", "未曉啼鶑相喚語，海棠飛盡一庭紅。"]'),
('ba10d3d4-aace-40df-9d7a-982117bb201f','晚春二首  其二','陳傅良','宋','宋诗','song-poetry','','[]','莫道春歸事已非，水邊天際綠成圍。',32,'全唐诗/poet.song.157000.json','["莫道春歸事已非，水邊天際綠成圍。", "隔籬聽得農家語，雨過田田麥含肥。"]'),
('86a280aa-9e15-410d-8910-feb5fae192ba','送孫謇卿赴壽昌主簿','陳傅良','宋','宋诗','song-poetry','','[]','烏鵲填門雪滿除，倩誰騎馬謝雙魚。',64,'全唐诗/poet.song.157000.json','["烏鵲填門雪滿除，倩誰騎馬謝雙魚。", "苦吟孫楚三年別，饑卧袁安一病餘。", "仕宦吾人聊復爾，夢魂今夜定何如。", "釣臺多是西征客，莫道渠能賦子虛。"]'),
('e679ec1a-f2c7-45b7-a1cc-c797298d169a','哭呂大著至明招寺簡潘叔度','陳傅良','宋','宋诗','song-poetry','','[]','小雨崇朝過，深秋薄海清。',48,'全唐诗/poet.song.157000.json','["小雨崇朝過，深秋薄海清。", "故人期不至，喬木眼偏明。", "欲往還何日，堪論久此情。", "侯芭幸無恙，應就太玄名。"]'),
('bdd13dca-4351-426b-854b-ec6564f62d3f','招徐居厚','陳傅良','宋','宋诗','song-poetry','','[]','老來却憶少相過，別自何年白髮多。',32,'全唐诗/poet.song.157000.json','["老來却憶少相過，別自何年白髮多。", "山葉抱蟬蟲吊夜，去看滄海壯秋波。"]'),
('70a8c50f-784f-4ad5-af53-e6012d0cd53e','天台王子木解官長樂見訪','陳傅良','宋','宋诗','song-poetry','','[]','夜深擘荔真愁絕，春淺傳柑更惘然。',64,'全唐诗/poet.song.157000.json','["夜深擘荔真愁絕，春淺傳柑更惘然。", "世事愛來欺兩鬢，人生堪得別多年。", "琢冰積雪江湖阻，樹羽崇牙日月懸。", "此理倉茫君勿問，明朝且莫刺歸船。"]'),
('f1696681-d369-497a-9db2-92742796da80','月夜書懷二首  其一','陳傅良','宋','宋诗','song-poetry','','[]','送客門初掩，收書室更虛。',48,'全唐诗/poet.song.157000.json','["送客門初掩，收書室更虛。", "新篁高過瓦，凉月下臨除。", "婦病纔扶杖，兒饞或饋魚。", "今朝吾已過，莫問夜何如。"]'),
('15f4e47b-a6cf-4345-8a36-e7846dcdd8e4','月夜書懷二首  其二','陳傅良','宋','宋诗','song-poetry','','[]','道德吾何敢，功名代有人。',48,'全唐诗/poet.song.157000.json','["道德吾何敢，功名代有人。", "倉黄恒畏咎，班白總憂貧。", "細字書全廢，深杯酒勿親。", "靜言空自愛，萬古亦泯泯。"]'),
('9e3d245a-aa15-4567-b541-50cf1b53ce26','送周魯山辰州法曹','陳傅良','宋','宋诗','song-poetry','','[]','團欒妻子是誰家，獨被饑驅天一涯。',64,'全唐诗/poet.song.157000.json','["團欒妻子是誰家，獨被饑驅天一涯。", "遠地豈無人晤語，長才能免世驚嗟。", "好於書作千年計，勿爲官驅兩鬢華。", "爲問湖南似湖北，逾年吾亦訪丹砂。"]'),
('89440f53-e803-40c2-a9a2-8a23b70b45f8','游丁次翁篔簹園期次翁不至','陳傅良','宋','宋诗','song-poetry','','[]','徑蹊曲折屋參差，半是天成半自治。',32,'全唐诗/poet.song.157000.json','["徑蹊曲折屋參差，半是天成半自治。", "修竹萬竿人獨立，我來搔首菊花期。"]'),
('fe0e931d-f010-4927-a0a0-7e04c50c4e4a','送朱同之福州戶掾','陳傅良','宋','宋诗','song-poetry','','[]','我自三山失馬餘，君方千里問津初。',64,'全唐诗/poet.song.157000.json','["我自三山失馬餘，君方千里問津初。", "衣冠萬室催科易，禮樂元戎節目疎。", "謹勿向人徵外事，只須著意訪奇書。", "一年正好榕陰密，丹荔黄蕉奉版輿。"]'),
('b053f3c0-38ed-45b0-9c8a-c594f4c3671d','覓樹栽','陳傅良','宋','宋诗','song-poetry','','[]','覓得循除數畝園，衰遲無力正乾坤。',64,'全唐诗/poet.song.157000.json','["覓得循除數畝園，衰遲無力正乾坤。", "學爲老圃徒幽意，富比封君亦浪言。", "計日若將栽樹木，成陰當待長兒孫。", "出門悵望春連塢，爲向雲屯斸一根。"]'),
('fd6508c6-c13a-429d-b5ff-930a88c310fe','題仙巖梅雨潭','陳傅良','宋','宋诗','song-poetry','','[]','衮衮羣山俱入海，堂堂背水若重闉。',64,'全唐诗/poet.song.157000.json','["衮衮羣山俱入海，堂堂背水若重闉。", "怒號懸瀑從天下，傑立蒼崖夾道陳。", "晉宋至今堪屈指，東南如此豈無人。", "結廬作對吾何敢，聊向樵漁寄此身。"]'),
('75555d33-df2f-4055-9f83-90f1dac4b9a0','次陳益之韵戲呈汪守充之','陳傅良','宋','宋诗','song-poetry','','[]','雨過山新沐，風平水漫流。',48,'全唐诗/poet.song.157000.json','["雨過山新沐，風平水漫流。", "移尊來選勝，立馬步通幽。", "春在桑麻塢，香團橘柚州。", "從君詩有律，還我酒無籌。"]'),
('caa9a988-0934-44d1-af84-8a76119099a2','汪守三以詩來次韵酬之  其一','陳傅良','宋','宋诗','song-poetry','','[]','一年春事墮槐宮，却愛清和與政通。',64,'全唐诗/poet.song.157000.json','["一年春事墮槐宮，却愛清和與政通。", "乳燕黄鸝相倡和，落花脩竹亂青紅。", "羨君有賦非占服，愧我無才可送窮。", "細與論文一樽酒，它時還憶暮江東。"]'),
('b909f2ae-a391-4ba4-83a7-84b357a1032b','汪守三以詩來次韵酬之  其二','陳傅良','宋','宋诗','song-poetry','','[]','江城如在水晶宮，百粵三吳一葦通。',64,'全唐诗/poet.song.157000.json','["江城如在水晶宮，百粵三吳一葦通。", "桑女不論裘粹白，橘奴堪當粟陳紅。", "絃歌滿市衣冠盛，缿訟無人刀筆窮。", "多荷弱翁今少霽，更能携客謝巖東。"]'),
('e4ee4ec6-7937-4ae5-bdad-97057b9be7cd','汪守三以詩來次韵酬之  其三','陳傅良','宋','宋诗','song-poetry','','[]','音合桑林律中宮，試聽布鼓亦三通。',64,'全唐诗/poet.song.157000.json','["音合桑林律中宮，試聽布鼓亦三通。", "相從璧水浮葱白，一別閩山擘荔紅。", "把釣扁舟將老去，款門多竹未全窮。", "若爲皂蓋能忘我，立盡斜陽車不東。"]'),
('ac4786f8-b2a0-4f43-8c51-52e35380f2d9','酬謝倅景英用前韵見寄','陳傅良','宋','宋诗','song-poetry','','[]','窮巷蕭然一畝宮，勞勞漫刺倩誰通。',64,'全唐诗/poet.song.157000.json','["窮巷蕭然一畝宮，勞勞漫刺倩誰通。", "空翻故紙頭垂白，晚對清標面發紅。", "諸老飄零亡幾在，百年放佚不勝窮。", "擬將舊學相從問，何獨詩壇欲讓東。"]'),
('caa9c9bf-5c4f-4ffa-a7b6-b58d12253d83','用幽字韵戲簡謝倅','陳傅良','宋','宋诗','song-poetry','','[]','當戶排危翠，循除漾淺流。',48,'全唐诗/poet.song.157000.json','["當戶排危翠，循除漾淺流。", "此生從稼圃，誰與伴深幽。", "韓子癡凭桉，龐公倦入州。", "青篘與白飯，却待爲君籌。"]'),
('405b47ab-3136-4df9-b02c-dce1b92b520b','用幽字韵呈汪守謝倅','陳傅良','宋','宋诗','song-poetry','','[]','旌騎收人迹，簪紳雜道流。',48,'全唐诗/poet.song.157000.json','["旌騎收人迹，簪紳雜道流。", "引盃忘日永，得句與山幽。", "行在今當路，中興此望州。", "爲將登覽目，著處訪邊籌。"]'),
('c7ff3398-8def-467d-9c08-a1baacd7591d','用幽字韵答賈端老','陳傅良','宋','宋诗','song-poetry','','[]','人皆忘姓字，誰獨訪源流。',48,'全唐诗/poet.song.157000.json','["人皆忘姓字，誰獨訪源流。", "病驥宜懷櫪，遷鶑故入幽。", "十年慚主簿，萬戶薄荆州。", "此事吾何敢，相將負一籌。"]'),
('a2a3722f-8992-4f8f-a33d-17bd28757e40','自仙巖還舍留別諸友','陳傅良','宋','宋诗','song-poetry','','[]','瀑布衡從雲一塢，浮圖明滅木千章。',32,'全唐诗/poet.song.157000.json','["瀑布衡從雲一塢，浮圖明滅木千章。", "在山終愛離山去，遮莫黄塵涴我裳。"]'),
('d1c4809f-ea44-40c4-bfcf-5b780ec46654','送任虞卿教授江陰','陳傅良','宋','宋诗','song-poetry','','[]','學省穿楊末，江城振羽端。',48,'全唐诗/poet.song.157000.json','["學省穿楊末，江城振羽端。", "聲名人不忌，仕宦意常寬。", "缺月天將曙，孤村歲已寒。", "小舟來話別，此道少人敦。"]'),
('c04bc5b1-a0bb-464e-8284-250c456fc205','和謝倅見贈生日二首  其一','陳傅良','宋','宋诗','song-poetry','','[]','朝天冠佩幾千員，熟數東州未乏賢。',32,'全唐诗/poet.song.157000.json','["朝天冠佩幾千員，熟數東州未乏賢。", "若論中原舊文物，蒲輪應合聘高年。"]'),
('b748f16e-444b-4a2a-9d48-19efe5ac8f0a','和謝倅見贈生日二首  其二','陳傅良','宋','宋诗','song-poetry','','[]','獨醒長愛衆歡酣，酸苦隨人却嗜甘。',32,'全唐诗/poet.song.157000.json','["獨醒長愛衆歡酣，酸苦隨人却嗜甘。", "好客不知彈劍鋏，聞公風味可無慚。"]'),
('f4d36e9c-dea9-44a9-901b-c8dce1016eb0','再和  其一','陳傅良','宋','宋诗','song-poetry','','[]','休將枘鑿問方員，且引壺觴對聖賢。',32,'全唐诗/poet.song.157000.json','["休將枘鑿問方員，且引壺觴對聖賢。", "鴻雁不賓滄海凍，梅花相伴笑年年。"]'),
('b37c12ae-8730-4ccd-b1ee-67da96273645','再和  其二','陳傅良','宋','宋诗','song-poetry','','[]','淺杯莫到十分酣，但愛齁齁夜夢甘。',32,'全唐诗/poet.song.157000.json','["淺杯莫到十分酣，但愛齁齁夜夢甘。", "萬里桑麻風雨好，一夫尸祿我何慚。"]'),
('e1f37931-727c-4b55-a4fe-3f653ddccd9b','謝倅生日','陳傅良','宋','宋诗','song-poetry','','[]','此夕其如好客何，秋風嫋嫋水微波。',64,'全唐诗/poet.song.157000.json','["此夕其如好客何，秋風嫋嫋水微波。", "渡江公子今無恙，上蔡家聲世不多。", "未放清朝空老去，欲談前事竟誰過。", "阻陪觴豆彷徨久，坐想風流爲一歌。"]'),
('a4e6e56f-02b6-4c8d-be7f-351bed122455','景元益之諸友考試旁郡余夢與步月聯詩得水花初浄月如銀之句追成一絕','陳傅良','宋','宋诗','song-poetry','','[]','連年波浪與埃塵，誰可論心五六人。',32,'全唐诗/poet.song.157000.json','["連年波浪與埃塵，誰可論心五六人。", "昨夜夢同天地闊，水花初浄月如銀。"]'),
('401a50eb-c0c5-480b-95fb-8b300ad63f8a','謝倅監試未畢事而出以詩三章來用韵奉酬  其一','陳傅良','宋','宋诗','song-poetry','','[]','殷勤送客蹇誰留，久待江城未解舟。',32,'全唐诗/poet.song.157000.json','["殷勤送客蹇誰留，久待江城未解舟。", "我醉欲眠君且去，不妨懶瓚繼前猷。"]'),
('ae2eb4b0-3663-4bf6-9671-6de9eb64d650','謝倅監試未畢事而出以詩三章來用韵奉酬  其二','陳傅良','宋','宋诗','song-poetry','','[]','歸舟莫訝太匆忙，會面何曾累十觴。',32,'全唐诗/poet.song.157000.json','["歸舟莫訝太匆忙，會面何曾累十觴。", "孰與持螯霜月下，拍浮酒浪舊陂塘。"]'),
('c5244944-0f2c-4849-8d75-022da9d3761c','謝倅監試未畢事而出以詩三章來用韵奉酬  其三','陳傅良','宋','宋诗','song-poetry','','[]','極欲從君十日歡，倦飛終羨鳥知還。',32,'全唐诗/poet.song.157000.json','["極欲從君十日歡，倦飛終羨鳥知還。", "棘圍觀戰緣何事，亦縱驊騮自出關。"]'),
('a4f13094-f3fd-4191-828e-a2719119a04c','沈仲一三益堂','陳傅良','宋','宋诗','song-poetry','','[]','有此名三益，之人可晤言。',48,'全唐诗/poet.song.157000.json','["有此名三益，之人可晤言。", "游藏無俗物，典則似諸昆。", "剩著書充棟，仍添竹過垣。", "翻愁長者轍，稀得到柴門。"]'),
('b1069c5c-d995-4d33-ab20-63bb93c2c93c','遊金嶴趙園','陳傅良','宋','宋诗','song-poetry','','[]','脈脈循簷水，林林夾岸山。',48,'全唐诗/poet.song.157000.json','["脈脈循簷水，林林夾岸山。", "令兒從竹下，領客入雲間。", "稠木容人過，懸崖著手攀。", "從今名字出，不到徑苔班。"]'),
('ce78f1ea-0a8a-46ff-96f8-855276bc1354','海棠絕句','陳傅良','宋','宋诗','song-poetry','','[]','淡月看花似霧中，遽呼燈燭倚花叢。',32,'全唐诗/poet.song.157000.json','["淡月看花似霧中，遽呼燈燭倚花叢。", "夜來月色明如晝，却向庭蕪數落紅。"]'),
('8308392d-dcdb-435b-96b2-50ce787400e2','湖樓送客即事一首奉懷益之兼簡同餞諸友','陳傅良','宋','宋诗','song-poetry','','[]','誰家喧馬盍朋簪，屋壓城頭水照簷。',64,'全唐诗/poet.song.157000.json','["誰家喧馬盍朋簪，屋壓城頭水照簷。", "橘柚兩山香盡在，蒲荷十里浄相兼。", "愁將久雨春無頼，別在明朝酒未厭。", "甚欲去同三四友，鱸風更捲一江簾。"]'),
('1d2ee0a6-fb2e-428b-a35a-ab42bda30309','春晚一首約同志泛舟','陳傅良','宋','宋诗','song-poetry','','[]','匆匆春事竟如何，問訊庭前手種花。',64,'全唐诗/poet.song.157000.json','["匆匆春事竟如何，問訊庭前手種花。", "又送行人又風雨，半爲芳草半泥沙。", "橘香通國今無恙，梅實於人晚更佳。", "莫放此春齊去蓋，夜深愁聽一池蛙。"]'),
('88d4a39c-1fe8-41be-8fa0-6dd755d07c44','用前韵招蕃叟弟仍和蕃叟癸卯二絕  其一','陳傅良','宋','宋诗','song-poetry','','[]','細看物理愁如海，遥想朋從眼欲花。',64,'全唐诗/poet.song.157000.json','["細看物理愁如海，遥想朋從眼欲花。", "逆水魚兒衝斷岸，貪泥燕子墮危沙。", "百年喬木參天上，一昔平蕪著處佳。", "行樂不妨隨邂逅，我無官守似蚔蛙。"]'),
('93080503-1edb-4f12-ac24-c48062b76529','用前韵招蕃叟弟仍和蕃叟癸卯二絕  其二','陳傅良','宋','宋诗','song-poetry','','[]','落花風雨奈愁何，愁亦不應緣落花。',64,'全唐诗/poet.song.157000.json','["落花風雨奈愁何，愁亦不應緣落花。", "尚可流觴追曲水，底須占鵩似長沙。", "無人晤語鳥烏落，爲我食貧樓筍佳。", "休說關河無限恨，腹非空怒道旁蛙。"]'),
('838092ff-3d3d-4c48-bd50-fd132569cf65','用前韵招蕃叟弟仍和蕃叟癸卯二絕  其三','陳傅良','宋','宋诗','song-poetry','','[]','大饗須三飯，中黄起四維。',24,'全唐诗/poet.song.157000.json','["大饗須三飯，中黄起四維。", "欲追千古意，眼底合深思。"]'),
('bf8d1e84-59d6-4fbc-ad46-178a4e874985','用前韵招蕃叟弟仍和蕃叟癸卯二絕  其四','陳傅良','宋','宋诗','song-poetry','','[]','功名還壯士，道術付諸儒。',24,'全唐诗/poet.song.157000.json','["功名還壯士，道術付諸儒。", "但欲謀田□，扁舟下五湖。"]'),
('5c2046e5-432f-45c9-b870-078bf9065bcb','送翁誠之尉慈溪  其一','陳傅良','宋','宋诗','song-poetry','','[]','徐劉文采後，鄒魯典刑間。',48,'全唐诗/poet.song.157000.json','["徐劉文采後，鄒魯典刑間。", "爲母求三釜，令人見一班。", "時平無事立，地僻得官閑。", "好索梅花笑，題詩海上山。"]'),
('7b203cf9-f0cf-4690-8637-7fd2c6b73cef','送翁誠之尉慈溪  其二','陳傅良','宋','宋诗','song-poetry','','[]','詩律吾將問，心期孰與親。',48,'全唐诗/poet.song.157000.json','["詩律吾將問，心期孰與親。", "明朝當異縣，永夜更懷人。", "尚友逢三益，明農識大臣。", "可無相問訊，勿道鬢毛新。"]'),
('d810097d-73a3-4d8e-801c-077bc357c637','和陳仲石韵','陳傅良','宋','宋诗','song-poetry','','[]','久矣懷相與，翩然喜見臨。',48,'全唐诗/poet.song.157000.json','["久矣懷相與，翩然喜見臨。", "清風生案□，短日過牆陰。", "王事何時暇，神州半陸沉。", "諸公宣力去，伴我水雲深。"]'),
('18bf2060-1987-4220-b88d-3e9a452303ea','送謝懷英道士歸廬山  其一','陳傅良','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','場屋收餘策，匡廬寄一瓢。',48,'全唐诗/poet.song.157000.json','["場屋收餘策，匡廬寄一瓢。", "款門如有欲，委幣輒難招。", "菜甲留終夕，蒲團共小橋。", "崆峒他日問，應記說神霄。"]'),
('ccbfd322-affa-4948-942a-ddbd71d9e2db','送謝懷英道士歸廬山  其二','陳傅良','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','一別忘年月，重來失故初。',48,'全唐诗/poet.song.157000.json','["一別忘年月，重來失故初。", "美髯今幾尺，銜袖竟何書。", "勛業諸公在，衰遲半世餘。", "許身無補報，吾亦欲樵漁。"]'),
('a9130dde-ba5a-40a6-945d-ff4c030b7479','送陳持中赴四明節推二首  其一','陳傅良','宋','宋诗','song-poetry','','[]','更無人未識東州，晚得吾宗第一流。',64,'全唐诗/poet.song.157000.json','["更無人未識東州，晚得吾宗第一流。", "編磬在縣金奏合，清冰出壑玉壺秋。", "喜纔一見還分袂，懷欲多言但倚樓。", "亦有鄮山三四友，可令觀政話然不。"]'),
('4ff16ad6-0998-4ccf-bc98-e5ff819fb8e5','送陳持中赴四明節推二首  其二','陳傅良','宋','宋诗','song-poetry','','[]','前修恨不爲同姓，更有跫然喜似人。',64,'全唐诗/poet.song.157000.json','["前修恨不爲同姓，更有跫然喜似人。", "歲晏得君顔面好，天涯從此尺書頻。", "政須有力同扶世，業已將名自絆身。", "它日雲臺勛績上，南陽應記舊比鄰。"]'),
('6bbac08d-0cb4-4eb3-b2e9-b89a1d1b83b3','乙巳歲首寄彭子復徐子直','陳傅良','宋','宋诗','song-poetry','','[]','又過一年空草草，尋思萬事太勞勞。',64,'全唐诗/poet.song.157000.json','["又過一年空草草，尋思萬事太勞勞。", "歲煩士友愁薪米，日見兒童嘆鬢毛。", "亂卉各隨分寸長，新禽已變兩三號。", "及時君亦圖良集，莫待春深水一篙。"]'),
('6f1ab07d-4572-4083-bb70-1b8693c90f1e','次韵奉酬丁少詹見過同遊仙巖遇雨而別','陳傅良','宋','宋诗','song-poetry','','[]','佳人何似似江梅，邂逅梅陰共舉盃。',64,'全唐诗/poet.song.157000.json','["佳人何似似江梅，邂逅梅陰共舉盃。", "欲與溪山成勝話，却因風雨得空回。", "新詩報我春乘興，小徑從今日掃埃。", "自是衰遲愁獨立，敢論名字望朋來。"]'),
('ff45124c-19fb-4b2c-862c-b12984b8bb05','瑞安宰劉伯協載酒遊趙園叔靜道甫子宜行之同集小雨喜霽','陳傅良','宋','宋诗','song-poetry','','[]','上巳所餘春有幾，不堪風雨付春愁。',64,'全唐诗/poet.song.157000.json','["上巳所餘春有幾，不堪風雨付春愁。", "君能載酒知誰侶，我欲看花不自由。", "倚岸小舟謀未定，隔林斜日故相投。", "莓苔踏遍篝燈去，收拾殘紅插滿頭。"]'),
('648432d9-ee7f-47f0-8109-9dd41dba429c','和丁少詹韵  其一','陳傅良','宋','宋诗','song-poetry','','[]','盡日支頤聽雨聲，閑中惟得自知明。',64,'全唐诗/poet.song.157000.json','["盡日支頤聽雨聲，閑中惟得自知明。", "朋來何敢煩公等，老去方慚負此名。", "待欲短檠看少作，敢將尺牘論交情。", "區區却望從容意，要莫令人一座傾。"]'),
('b96403a6-ceb0-4164-a48c-a1b9d3a24629','和丁少詹韵  其二','陳傅良','宋','宋诗','song-poetry','','[]','明月隋珠忽墮前，坐令衰颯意飄然。',64,'全唐诗/poet.song.157000.json','["明月隋珠忽墮前，坐令衰颯意飄然。", "無端太史頭搶地，安得揚雄賦上天。", "前輩門牆餘幾在，他時竹帛竟誰傳。", "落花流水君愁不，南渡于今六十年。"]'),
('df4be3c4-6464-424d-b3a5-e7b7f37ce6e3','病餘久不趨郡且遷仙巖書院於屋西有懷同志','陳傅良','宋','宋诗','song-poetry','','[]','欲往如天際，相期忽歲華。',48,'全唐诗/poet.song.157000.json','["欲往如天際，相期忽歲華。", "山空明獨樹，江晚暗連葭。", "作屋皆三益，藏書可萬家。", "豈無人裹飯，躬自灌園芽。"]'),
('de0c2d41-49b8-4eb7-a56b-b7c6ad57256c','酬陳頤剛見和前韵','陳傅良','宋','宋诗','song-poetry','','[]','離合皆天意，盈虛幾月華。',48,'全唐诗/poet.song.157000.json','["離合皆天意，盈虛幾月華。", "家纔辦藜莧，吾亦逐蘆葭。", "憂世還當路，論兵有故家。", "深深看踵息，陰火養黄芽。"]'),
('fc055319-9298-42f0-b164-70db49a83d9b','寄謝景英參議','陳傅良','宋','宋诗','song-poetry','','[]','故人不見吾何適，欲見其人已異鄉。',64,'全唐诗/poet.song.157000.json','["故人不見吾何適，欲見其人已異鄉。", "魂夢半年皆草草，鬢毛一別益蒼蒼。", "籌邊淮海何遲暮，乘障湖湘亦阻長。", "及此居閑宜問訊，題書須待滿林霜。"]'),
('5056b3ee-1bcb-4f85-9165-f58492f49c2c','寄題翁誠之慈溪縣尉廳無我亭','陳傅良','宋','宋诗','song-poetry','','[]','星月明當戶，烏鳶下傍人。',48,'全唐诗/poet.song.157000.json','["星月明當戶，烏鳶下傍人。", "小亭長獨立，通國自相親。", "置尉緣求盜，居官已喪真。", "須知三尺外，敲榜亦深仁。"]'),
('c6cec6f9-45d5-45c2-abe8-56e593cddf8d','和郡守沈持要賞柑之什三首  其一','陳傅良','宋','宋诗','song-poetry','','[]','滄海無波日萬艘，山農囷廩自相豪。',64,'全唐诗/poet.song.157000.json','["滄海無波日萬艘，山農囷廩自相豪。", "爭看紫橐行阡陌，可對黄甘負酒醪。", "曲水一觴隨意集，成都千騎最頭遨。", "風流儒雅誰公似，增得東嘉地望高。"]'),
('8e1d45df-51c2-411d-8e50-416fe4907a0c','和郡守沈持要賞柑之什三首  其二','陳傅良','宋','宋诗','song-poetry','','[]','東都門外問征艘，去國身輕亦太豪。',64,'全唐诗/poet.song.157000.json','["東都門外問征艘，去國身輕亦太豪。", "誰可對床聽夜雨，自於同社燕春醪。", "不知溫詔從天下，又罷幽尋與世遨。", "從此宜休堂下夢，顧瞻松柏爲誰高。"]'),
('0d7ebbc2-84cc-4b84-b23c-fac8f3f87390','和郡守沈持要賞柑之什三首  其三','陳傅良','宋','宋诗','song-poetry','','[]','仰止苕溪近一艘，幾年猶未識人豪。',64,'全唐诗/poet.song.157000.json','["仰止苕溪近一艘，幾年猶未識人豪。", "黄堂爲客知何夕，白髮從公飲此醪。", "四海衣冠多後進，兩朝几杖舊同遨。", "令人仰視冥冥翮，不道微風燕雀高。"]'),
('54b332bd-80f6-4a93-9986-08025795c2ae','和沈守持要觀潮閣留題','陳傅良','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','畢生欲賦觀潮閣，立盡斜陽倦復還。',64,'全唐诗/poet.song.157000.json','["畢生欲賦觀潮閣，立盡斜陽倦復還。", "一日江山蒙筆力，百年名字滿人寰。", "郡從晉宋風流後，詩到蘇黄伯仲間。", "向去摩挲看石刻，誰知功在十年閑。"]'),
('3b626918-a8f8-4139-a055-3ed1349ce656','奉陪王德脩登觀海閣兼呈邑宰劉伯協','陳傅良','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','觀潮閣在東溟上，有客來登自華陽。',64,'全唐诗/poet.song.157000.json','["觀潮閣在東溟上，有客來登自華陽。", "不道雪山通老柏，却看朝日上扶桑。", "勝游氣合南三郡，妙畫家傳晉二王。", "後會不知誰與繼，爾江吾海永相望。"]'),
('9a557cc0-99ba-4b78-a3b3-d5ad990c3b03','落成王朝奉廟以薄恙不獲預謝劉宰并諸鄉丈五首  其一','陳傅良','宋','宋诗','song-poetry','','[]','盜起清溪兩淛空，童王親自帥元戎。',32,'全唐诗/poet.song.157000.json','["盜起清溪兩淛空，童王親自帥元戎。", "誰知小邑無亭障，但握空弮有隠功。"]'),
('74f6293f-28d5-4fa3-b444-66a658f3a4fd','落成王朝奉廟以薄恙不獲預謝劉宰并諸鄉丈五首  其二','陳傅良','宋','宋诗','song-poetry','','[]','橫塘一字比南金，滿紙書勞屬意深。',32,'全唐诗/poet.song.157000.json','["橫塘一字比南金，滿紙書勞屬意深。", "太史不知收拾未，邦人父老淚漸襟。"]'),
('d4fdd228-93d3-4f62-ac60-e67ae8611e57','落成王朝奉廟以薄恙不獲預謝劉宰并諸鄉丈五首  其三','陳傅良','宋','宋诗','song-poetry','','[]','操一豚蹄亦可憐，欲將廟食自旌賢。',32,'全唐诗/poet.song.157000.json','["操一豚蹄亦可憐，欲將廟食自旌賢。", "壞牆頹壁神臺笠，不見干戈六十年。"]'),
('4cca4c44-b3bb-48fe-915b-f905de462160','落成王朝奉廟以薄恙不獲預謝劉宰并諸鄉丈五首  其四','陳傅良','宋','宋诗','song-poetry','','[]','却向平時念後艱，榱題百尺忽如山。',32,'全唐诗/poet.song.157000.json','["却向平時念後艱，榱題百尺忽如山。", "誰將西上逢人問，令尹何如此一班。"]'),
('7abb10cb-0859-4da1-8e84-92ef68fa763a','落成王朝奉廟以薄恙不獲預謝劉宰并諸鄉丈五首  其五','陳傅良','宋','宋诗','song-poetry','','[]','抱病荒村望欲迷，駿奔無數獨鷄棲。',32,'全唐诗/poet.song.157000.json','["抱病荒村望欲迷，駿奔無數獨鷄棲。", "瞻言鼕鼓何時歇，好聽農郊雨一犂。"]'),
('9ccaaf5e-8757-47ab-aec5-0ded6d758bd6','和沈守持要題謝公樓額','陳傅良','宋','宋诗','song-poetry','','[]','危樓何在水雲中，穿市牙旗退自公。',64,'全唐诗/poet.song.157000.json','["危樓何在水雲中，穿市牙旗退自公。", "閑作此來橫笛夜，愛看人醉落帆風。", "歡呼夾道江聲合，硬語蟠空客技窮。", "姓字從今聯沈謝，不知千古更誰同。"]'),
('5e3fee94-88d3-4b07-a173-fad3a0e46f33','沈守生日','陳傅良','宋','宋诗','song-poetry','','[]','燕寢凝香不記春，宜休堂下柏輪囷。',64,'全唐诗/poet.song.157000.json','["燕寢凝香不記春，宜休堂下柏輪囷。", "三吳南渡今多士，四皓東宮此一人。", "雅不欲書名上上，謾令在處歲陳陳。", "玉巵宴罷思黄髮，應合從頭第從臣。"]'),
('86b6d85f-8455-4b5f-baa8-7e2c4740c9a8','觀南塘四首呈沈守  其一','陳傅良','宋','宋诗','song-poetry','','[]','曾不容舠咫尺間，誰知救溺合纓冠。',32,'全唐诗/poet.song.157000.json','["曾不容舠咫尺間，誰知救溺合纓冠。", "今從枕席人行過，最好翻盆雨後看。"]'),
('544f1cbe-08b4-48c7-be4d-417ba46c96e0','觀南塘四首呈沈守  其二','陳傅良','宋','宋诗','song-poetry','','[]','夾道歡呼百里間，不論扶杖與勝冠。',32,'全唐诗/poet.song.157000.json','["夾道歡呼百里間，不論扶杖與勝冠。", "公年幾許顔何似，遲放牙檣待我看。"]'),
('7c0d5cbb-1b5b-4172-a995-1c7e4d62571b','觀南塘四首呈沈守  其三','陳傅良','宋','宋诗','song-poetry','','[]','樂在宜休水竹間，十年黄帕裹朝冠。',32,'全唐诗/poet.song.158000.json','["樂在宜休水竹間，十年黄帕裹朝冠。", "却乘五箇花文馬，來與江村婦子看。"]'),
('ecfe9b85-61cd-4e48-919e-bae50f28b231','觀南塘四首呈沈守  其四','陳傅良','宋','宋诗','song-poetry','','[]','別乘潘郎伯仲間，朅來公適去彈冠。',32,'全唐诗/poet.song.158000.json','["別乘潘郎伯仲間，朅來公適去彈冠。", "更將未盡公碑意，收入新詩爲並看。"]'),
('e44f1382-3cfe-4579-b11c-185e81687e42','桂陽勸農','陳傅良','宋','宋诗','song-poetry','','[]','雨耨風耕病汝多，誰將一一手摩挲。',64,'全唐诗/poet.song.158000.json','["雨耨風耕病汝多，誰將一一手摩挲。", "幸因奉令來循壟，恨不分勞去荷蓑。", "凉德未知年熟不，微官其奈月樁何。", "殷勤父老曾無補，待放腰鎌與醉歌。"]'),
('de56a7cf-bf43-4477-af26-ea3513525f09','九日奉呈同僚四絕句  其一','陳傅良','宋','宋诗','song-poetry','','[]','澤國重陽花較遲，得花雖□□愁余。',32,'全唐诗/poet.song.158000.json','["澤國重陽花較遲，得花雖□□愁余。", "家家人醉鷄豚社，獨對西風憶鱠魚。"]'),
('7f7c365e-0ab5-4ec7-b0a9-e091bd1ee581','九日奉呈同僚四絕句  其二','陳傅良','宋','宋诗','song-poetry','','[]','小雨廉纖僅滑泥，强隨年少更攀躋。',32,'全唐诗/poet.song.158000.json','["小雨廉纖僅滑泥，强隨年少更攀躋。", "欲憑最上浮圖望，晚稻如今齊未齊。"]'),
('4ce0aeca-e189-49e0-95b8-99efc069ae9f','九日奉呈同僚四絕句  其三','陳傅良','宋','宋诗','song-poetry','','[]','臨風遮莫晚山佳，自古功名看鬢華。',32,'全唐诗/poet.song.158000.json','["臨風遮莫晚山佳，自古功名看鬢華。", "幸自不知余種種，可教容易落烏紗。"]'),
('fb509e54-f141-4394-9888-af90d9ce5888','九日奉呈同僚四絕句  其四','陳傅良','宋','宋诗','song-poetry','','[]','領客山危亦既懽，故人往往去歸班。',32,'全唐诗/poet.song.158000.json','["領客山危亦既懽，故人往往去歸班。", "明年此會知誰肯，爲上吳山望楚山。"]'),
('2a8577d6-1bda-4d27-be85-a77b8b1c7f96','郴守丁端叔以九日詩至次韵奉酬','陳傅良','宋','宋诗','song-poetry','','[]','十年不見尋常事，九日相違咫尺間。',64,'全唐诗/poet.song.158000.json','["十年不見尋常事，九日相違咫尺間。", "橙蟹渠能追勝賞，藙牲孰與奉慈顔。", "逝將酒坫更酬酢，乍可詩筒略往還。", "新將適聞臨遣罷，鹿頭吾待望吳山。"]'),
('0b31619b-6ebb-44f0-bde6-02ff42d38f69','丁端叔和九日詩至用韵奉謝恤鄰之義且申前請  其一','陳傅良','宋','宋诗','song-poetry','','[]','壯不如人老更遲，可憐赤□□宗余。',32,'全唐诗/poet.song.158000.json','["壯不如人老更遲，可憐赤□□宗余。", "鄉微膚使賢方伯，誰激西江活鮒魚。"]'),
('6c677723-bac4-41c2-9f6e-351ba3d61efb','丁端叔和九日詩至用韵奉謝恤鄰之義且申前請  其二','陳傅良','宋','宋诗','song-poetry','','[]','生怕遄歸趁紫泥，緣危方藉得同躋。',32,'全唐诗/poet.song.158000.json','["生怕遄歸趁紫泥，緣危方藉得同躋。", "交鄰誼與春秋並，應許臧孫數告齊。"]'),
('84a3d14c-f74f-4b00-a948-daae00ad3169','丁端叔和九日詩至用韵奉謝恤鄰之義且申前請  其三','陳傅良','宋','宋诗','song-poetry','','[]','夏畦不病晚穜佳，哿矣將詩補黍華。',32,'全唐诗/poet.song.158000.json','["夏畦不病晚穜佳，哿矣將詩補黍華。", "散百爲千吾寫似，深山窮谷徧籠紗。"]'),
('c32d5cb6-08fc-4ee6-bd0e-0a77df72e041','丁端叔和九日詩至用韵奉謝恤鄰之義且申前請  其四','陳傅良','宋','宋诗','song-poetry','','[]','不因與國近交歡，冰齒相從髮已班。',32,'全唐诗/poet.song.158000.json','["不因與國近交歡，冰齒相從髮已班。", "多見長才無肯綮，豈辭一簣竟爲山。"]'),
('93b44fbe-4c2a-4241-acda-2065a6c280d0','再用前韵簡丁端叔  其一','陳傅良','宋','宋诗','song-poetry','','[]','乞鄰亟只報何遲，愁絕饑甿一勝余。',32,'全唐诗/poet.song.158000.json','["乞鄰亟只報何遲，愁絕饑甿一勝余。", "上有加餐下相憶，莫同泛泛寄雙魚。"]'),
('7f47c503-7585-46cc-a889-4cb04212f84d','再用前韵簡丁端叔  其二','陳傅良','宋','宋诗','song-poetry','','[]','閉關饒著一丸泥，我亦前扳更後躋。',32,'全唐诗/poet.song.158000.json','["閉關饒著一丸泥，我亦前扳更後躋。", "四海弟兄君看取，苛風不斷鴈行齊。"]'),
('2394b9fe-08de-49ab-b653-1a99004e97fb','再用前韵簡丁端叔  其三','陳傅良','宋','宋诗','song-poetry','','[]','事到難時意轉佳，聲名早已動皇華。',32,'全唐诗/poet.song.158000.json','["事到難時意轉佳，聲名早已動皇華。", "撥煩自古書生短，只合橫經住絳紗。"]'),
('131acac3-f057-4cc8-bf54-ebb97c26c6cc','再用前韵簡丁端叔  其四','陳傅良','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','繇吳入楚共悲歡，懷欲班荆竟未班。',32,'全唐诗/poet.song.158000.json','["繇吳入楚共悲歡，懷欲班荆竟未班。", "直待還艫願銜尾，洞庭彭蠡浪如山。"]'),
('aa01e993-6370-4a69-a9fa-9a1cb4f7b2eb','和丁端叔竹梅二詩韵  其一','陳傅良','宋','宋诗','song-poetry','','[]','空階琤若下琅玕，全楚何人巧耐寒。',32,'全唐诗/poet.song.158000.json','["空階琤若下琅玕，全楚何人巧耐寒。", "誰伴八龍長傲雪，蕭然一榻卧袁安。"]'),
('010399d2-3b4d-4197-a1ae-b9104e529415','和丁端叔竹梅二詩韵  其二','陳傅良','宋','宋诗','song-poetry','','[]','管領春風別有天，不論水際與山巔。',32,'全唐诗/poet.song.158000.json','["管領春風別有天，不論水際與山巔。", "祝融玉立湖湘凍，獨付寒梢笑粲然。"]'),
('335cedd8-ecfb-4b4c-ad3b-6828f57e6e6f','丁端叔送牡丹以詩來用韵酬之  其一','陳傅良','宋','宋诗','song-poetry','','[]','覺省他年見一班，老從湖海看春頒。',64,'全唐诗/poet.song.158000.json','["覺省他年見一班，老從湖海看春頒。", "瞻言百里幾相及，仰止高山竟莫攀。", "每事乞公留上策，不才容我著中間。", "一時公論方當路，愁爲絲麻棄蒯菅。"]'),
('9eceba38-4fab-4435-8e87-26f801a6c766','丁端叔送牡丹以詩來用韵酬之  其二','陳傅良','宋','宋诗','song-poetry','','[]','客來談政已班班，况復書縢一再頒。',64,'全唐诗/poet.song.158000.json','["客來談政已班班，况復書縢一再頒。", "亦欲頡頏相上下，不容分寸得躋攀。", "花猶河洛承平□，詩在黄陳輩行間。", "簿領役人塵撲面，沃如雲霧下茅菅。"]'),
('d4ad1192-30f3-4e2b-9128-a01837b24abe','和丁端叔歲晚書懷韵','陳傅良','宋','宋诗','song-poetry','','[]','來涂藍縷雪埋人，三百於今又六旬。',64,'全唐诗/poet.song.158000.json','["來涂藍縷雪埋人，三百於今又六旬。", "奏課定應書下下，班春聊復喜津津。", "餘蔬被壤農亡恙，茂草連扉盜自新。", "曳杖鹿頭時極目，炊烟齊起兩州民。"]'),
('40083ad9-b865-4321-a17e-6e9a67dd29b6','丁端叔送海錯以詩來用韵酬之','陳傅良','宋','宋诗','song-poetry','','[]','澤魚山豕各忘年，味可勝窮總所便。',64,'全唐诗/poet.song.158000.json','["澤魚山豕各忘年，味可勝窮總所便。", "堪笑荆吳相俎豆，遂令蠻觸自矛鋋。", "食無誤蟹車同軌，貢不徵蚶澤漏泉。", "我在窮山人迹罕，亦蒙惟錯饋甘鮮。"]'),
('105fd574-8f2d-449f-aa7a-ace63cca7ad3','酬王判官和九日韵  其一','陳傅良','宋','宋诗','song-poetry','','[]','皇華六轡按倭遲，博採參差到接余。',32,'全唐诗/poet.song.158000.json','["皇華六轡按倭遲，博採參差到接余。", "我獨內慚無具甚，萬家亦免釜生魚。"]'),
('2ffe08d7-820e-48d4-a038-ca0691dcec0b','酬王判官和九日韵  其二','陳傅良','宋','宋诗','song-poetry','','[]','想懸郴桂一雲泥，夫子聲名正日躋。',32,'全唐诗/poet.song.158000.json','["想懸郴桂一雲泥，夫子聲名正日躋。", "乞與早移河內粟，牙牌歸聽報班齊。"]'),
('556894c9-35b9-4c51-a813-17892a4494a9','酬王判官和九日韵  其三','陳傅良','宋','宋诗','song-poetry','','[]','翩翩公子一何佳，銜命窮山薄歲華。',32,'全唐诗/poet.song.158000.json','["翩翩公子一何佳，銜命窮山薄歲華。", "獨自把將詩過日，不知梅影下窗紗。"]'),
('398e9cab-fc2b-4123-bb5f-5027d7c270f7','酬王判官和九日韵  其四','陳傅良','宋','宋诗','song-poetry','','[]','懷自何年晚見懽，匆匆惜已□聲班。',32,'全唐诗/poet.song.158000.json','["懷自何年晚見懽，匆匆惜已□聲班。", "青芻白飯吾何有，風月猶堪倒玉山。"]'),
('54198842-19fd-46d0-94db-188ab88ed82f','戊申臘桂陽喜雪','陳傅良','宋','宋诗','song-poetry','','[]','月不能明雨却稀，山容野色夜輝輝。',64,'全唐诗/poet.song.158000.json','["月不能明雨却稀，山容野色夜輝輝。", "清霄下際雙瓊闕，仙仗前驅萬玉妃。", "亙古嶺旁冬不到，從今湖外歲無饑。", "來年此日吾何適，蓑笠寒江一釣磯。"]'),
('8acc2800-07fd-49e9-8b2e-630ac1fc8837','再用喜雪韵  其一','陳傅良','宋','宋诗','song-poetry','','[]','南人見雪古來稀，見只愁吟草木輝。',64,'全唐诗/poet.song.158000.json','["南人見雪古來稀，見只愁吟草木輝。", "留囓氈毛窮漢使，說開圍角老胡妃。", "我嘗豪健能無褐，今已衰遲要不饑。", "北望鴈門腸欲斷，春蒲空老舊漁磯。"]'),
('9161501c-7d3a-4492-92ce-acd225b8df3a','再用喜雪韵  其二','陳傅良','宋','宋诗','song-poetry','','[]','瘴雨蠻烟此後稀，山童亦與借餘輝。',64,'全唐诗/poet.song.158000.json','["瘴雨蠻烟此後稀，山童亦與借餘輝。", "爭看狂穉相呼喚，下啄饑烏自匹妃。", "苦乏貂裘堪夜永，喜無蝝子著冬饑。", "興來那况山陰客，爲我扁舟倚石磯。"]'),
('1a4e917d-782d-4eed-a7f5-79f2cc7d0bdd','題范秀才萬卷堂','陳傅良','宋','宋诗','song-poetry','','[]','雅尚時相背，幽棲我數過。',48,'全唐诗/poet.song.158000.json','["雅尚時相背，幽棲我數過。", "兒應看客慣，田孰與書多。", "自析唐郴縣，誰聯漢甲科。", "儒門今有此，天意定如何。"]'),
('f1ed19c7-4004-416e-b2fc-65a0a5b0beb4','和段君仲衡同令嗣天晴少出之作','陳傅良','宋','宋诗','song-poetry','','[]','文字時高下，功名勢去來。',48,'全唐诗/poet.song.158000.json','["文字時高下，功名勢去來。", "誰人堪語此，吾道竟懷哉。", "携幼安容膝，巡簷笑索梅。", "巷門通後圃，今數爲君開。"]'),
('cf4a2c16-48ff-4af9-bc4b-aeb0e122b0dd','陳頤剛注孫子許拾遺贈詩用韵寄之','陳傅良','宋','宋诗','song-poetry','','[]','千帆過盡獨舟沈，玩世齁齁踵息深。',64,'全唐诗/poet.song.158000.json','["千帆過盡獨舟沈，玩世齁齁踵息深。", "何自著書今白髮，不禁戀闕此丹心。", "詩來滄海珠盈把，人在掖垣梧十尋。", "應爲一編三致意，細論小雅到交侵。"]'),
('77dc7979-13e6-490a-8efd-0658dcbca011','和段仲衡譙樓新軍額二首  其一','陳傅良','宋','宋诗','song-poetry','','[]','筆落元戎重，詩成坐客新。',48,'全唐诗/poet.song.158000.json','["筆落元戎重，詩成坐客新。", "譙門雙壯觀，邊將一團春。", "夢破盤行玉，名存甕得銀。", "衰遲亡補報，著意與民親。"]'),
('de751ca6-47a3-4566-8125-595b9fc7db87','和段仲衡譙樓新軍額二首  其二','陳傅良','宋','宋诗','song-poetry','','[]','寒消晴後雪，光轉凍前風。',48,'全唐诗/poet.song.158000.json','["寒消晴後雪，光轉凍前風。", "歲已宜麻麥，人猶厭芥菘。", "樓頭千里望，筆勢萬夫雄。", "及此吾何力，天低露草豐。"]'),
('0a7d5791-98ae-4e45-b560-f8caeda53dfe','和蕭俊仲司法詠譙樓新軍額韵','陳傅良','宋','宋诗','song-poetry','','[]','海濱驅馬過湘濱，喜及今春憶舊春。',64,'全唐诗/poet.song.158000.json','["海濱驅馬過湘濱，喜及今春憶舊春。", "公燕有時令市酤，村舂不繼待炊新。", "嚴城鼓角留三字，當代衣冠第一人。", "看取吾民繇此去，萬家雞犬永無塵。"]'),
('07d17ce5-a826-4e19-8bb0-9bf8cf4a9edd','送洪子端還鄉','陳傅良','宋','宋诗','song-poetry','','[]','將相三陳後，文章兩漢餘。',48,'全唐诗/poet.song.158000.json','["將相三陳後，文章兩漢餘。", "英標還有此，天意定何如。", "海內相離合，年來半毀譽。", "未知貪尚友，孰與鄴侯書。"]'),
('f42046e8-0936-43b1-ab84-1b598ff303e0','送吳德夫','陳傅良','宋','宋诗','song-poetry','','[]','嶽麓樓頭卧，湖湘眼底空。',48,'全唐诗/poet.song.158000.json','["嶽麓樓頭卧，湖湘眼底空。", "聲名無處著，容止與人同。", "白髮何多日，輕帆不待風。", "修門春漏淺，封事倩誰通。"]'),
('f995b83c-6a37-4004-9d64-d0dafb79d50f','楊伯子以其尊人誠齋南海集爲贈以詩奉酬','陳傅良','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','辱與門牆最不遲，白頭方誦嶺南詩。',64,'全唐诗/poet.song.158000.json','["辱與門牆最不遲，白頭方誦嶺南詩。", "文從嘉祐今三變，人在廬陵此一時。", "細數儒先能幾見，獨憐歲晚欲何之。", "瀟湘直下長江去，得望蓬萊却更疑。"]'),
('b7d31ce8-8987-4089-8a2c-61690b6f0a68','潭帥潘德鄜生辰','陳傅良','宋','宋诗','song-poetry','','[]','落南添得黑髭歸，歸與相忘草木知。',64,'全唐诗/poet.song.158000.json','["落南添得黑髭歸，歸與相忘草木知。", "嶽麓沈沈秋柝靜，湘波穆穆夜帆遲。", "人間公論今何在，柱下家聲此不疑。", "但欲公年如衛武，爲留淇澳變風詩。"]'),
('a67259c9-7cea-4f32-98b3-2f08ba31abcc','衡守劉子澄以詩來和韵奉酬','陳傅良','宋','宋诗','song-poetry','','[]','曳裾朝路不同時，謀食衡湘亦把麾。',64,'全唐诗/poet.song.158000.json','["曳裾朝路不同時，謀食衡湘亦把麾。", "一見相忘光可鑑，十年何在惄如饑。", "力堪扶世將誰可，語不驚人或自危。", "夜雪埋山江欲凍，依然春信在南枝。"]'),
('b633d1e8-6fef-4611-9231-1e99c1d4f49a','遊南嶽','陳傅良','宋','宋诗','song-poetry','','["\u8861\u5c71", "\u957f\u6c5f"]','天作之山曷爲哉，遥知閶闔正南開。',64,'全唐诗/poet.song.158000.json','["天作之山曷爲哉，遥知閶闔正南開。", "兩川文武長江下，百粵車書五嶺來。", "柴望久爲周墜典，牢愁多見楚遺才。", "不知崧岱還何似，我欲將書寄鴈回。"]'),
('064b8e21-a6a3-4e20-9e19-5cb623b1b798','登祝融峰喜霽','陳傅良','宋','宋诗','song-poetry','','[]','仰止扶藜鬢髮蒼，恰當風雨暗三湘。',64,'全唐诗/poet.song.158000.json','["仰止扶藜鬢髮蒼，恰當風雨暗三湘。", "爲誰一闢天無際，及我重來日未央。", "江過數州多曲折，山緣長畝半青黄。", "老僧耐得從頭問，問到吳門竟渺茫。"]'),
('5c3e97e8-68b8-4cbf-a918-af0a07a7cfed','和沈帥持要張漕季長韵二首  其一','陳傅良','宋','宋诗','song-poetry','','[]','欲杭一葦近聲光，恨不先期燕子凉。',64,'全唐诗/poet.song.158000.json','["欲杭一葦近聲光，恨不先期燕子凉。", "舊學甘盤聊此日，倦游司馬尚他鄉。", "別從滄海山橫斗，來自岷峨水濫觴。", "不謂偶成三楚客，得爲蘭杜附諸香。"]'),
('7a8db2fb-2b87-4e5a-9dd1-ddd059088d76','和沈帥持要張漕季長韵二首  其二','陳傅良','宋','宋诗','song-poetry','','[]','麾節元戎祖席光，晚風吹雨借初凉。',64,'全唐诗/poet.song.158000.json','["麾節元戎祖席光，晚風吹雨借初凉。", "師傳問訊誰書院，石刻摩挲是道鄉。", "聞有先聲來召馹，想無後會到流觴。", "路朝正設橫經席，冊府重紬辟蠹香。"]'),
('fb941d33-6119-47e8-abb6-bb16889515f3','送沈帥','陳傅良','宋','宋诗','song-poetry','','[]','甘盤夢不入高宗，四皓莫知其所終。',64,'全唐诗/poet.song.158000.json','["甘盤夢不入高宗，四皓莫知其所終。", "傅野有人能論學，漢庭無事可言功。", "行藏於此嘗成趣，談笑從今得退公。", "分付諸兒理民社，宜休堂上聽松風。"]'),
('7e48f0c7-d54c-42d1-a2d4-c01095256480','携客過王提舉園訪梅劉連州以詩來因用其韵','陳傅良','宋','宋诗','song-poetry','','[]','屋後雲梢萬箇長，屋前風蔓一川芳。',64,'全唐诗/poet.song.158000.json','["屋後雲梢萬箇長，屋前風蔓一川芳。", "有梅自索巡簷笑，無酒還酤踏雪香。", "偶與三劉同下榻，却懷二宋對持觴。", "寫將詩句吾何敢，欵乃聽人汲曉湘。"]'),
('a88e6bed-130c-4ae1-82df-34baaec7ec1e','再用前韵簡劉連州','陳傅良','宋','宋诗','song-poetry','','[]','吳楚相望道阻長，我來邂逅挹羣芳。',64,'全唐诗/poet.song.158000.json','["吳楚相望道阻長，我來邂逅挹羣芳。", "人如盤谷元非隠，詩到孤山不道香。", "每與盍簪移永日，更須篝火及餘觴。", "何須誇去東州說，不學藍關獨吊湘。"]'),
('d13203e7-2f0c-41b8-ae2f-080cebefa020','小詩爲張漕壽','陳傅良','宋','宋诗','song-poetry','','[]','皇華散作九州春，老穉□□夾道陳。',64,'全唐诗/poet.song.158000.json','["皇華散作九州春，老穉□□夾道陳。", "韓子莫愁今夕雨，甫侯元是此山神。", "我雖載酒□□算，孰與將詩附不泯。", "他日中興編小雅，若論孝友更誰人。"]'),
('8611de15-03b1-4041-9c4f-0d4181bcdd10','謝司馬倅惠東坡竹石','陳傅良','宋','宋诗','song-poetry','','[]','出自坡翁餘百年，傳之溫國子孫孫。',32,'全唐诗/poet.song.158000.json','["出自坡翁餘百年，傳之溫國子孫孫。", "兩家文物來歸我，便盍投簪去杜門。"]'),
('797eb3b2-dce3-4e96-9486-f0937f03d45b','和趙帥壽張漕韵二首  其一','陳傅良','宋','宋诗','song-poetry','','[]','但得桑麻徧楚間，此心不在大夫環。',64,'全唐诗/poet.song.158000.json','["但得桑麻徧楚間，此心不在大夫環。", "落花流水深春好，畫戟清香永日閒。", "英簜偶來成勝賞，萱庭孰與奉慈顔。", "正應得句尤奇傑，可繼淮南大小山。"]'),
('f04154f6-141a-4558-b581-cfb978962975','和趙帥壽張漕韵二首  其二','陳傅良','宋','宋诗','song-poetry','','[]','使者耕時出省春，聯翩珠玉又前陳。',64,'全唐诗/poet.song.158000.json','["使者耕時出省春，聯翩珠玉又前陳。", "先聲所暨摇山嶽，落筆相豪泣鬼神。", "嘉與九城俱晏粲，訖無一事尚棼泯。", "獨慚衰惰歸何晚，亦著中間作廩人。"]'),
('c1f8cac1-8e1d-4aec-a81d-f5b0aeaf27b6','題耒陽黄宰詩卷','陳傅良','宋','宋诗','song-poetry','','[]','詩卷來何處，棠陰日夕佳。',48,'全唐诗/poet.song.158000.json','["詩卷來何處，棠陰日夕佳。", "令人添白髮，及此有黄花。", "事業誰千載，文章各一家。", "何時定還闕，解柂向長沙。"]'),
('4610deb8-7e34-4806-b182-75ff28937114','送黄元吉','陳傅良','宋','宋诗','song-poetry','','[]','荷君來意固非輕，曾未深交意便傾。',64,'全唐诗/poet.song.158000.json','["荷君來意固非輕，曾未深交意便傾。", "語到七篇無欠少，學從三畫已分明。", "每懷前此傷標置，頗欲從今近老成。", "爲謝荆門三益友，何時尊酒話生平。"]'),
('fea65ff7-7142-467f-a741-c7c442bb90fa','懷歸丐祠','陳傅良','宋','宋诗','song-poetry','','[]','久矣懷歸曷月哉，冠纓吾欲濯吾埃。',64,'全唐诗/poet.song.158000.json','["久矣懷歸曷月哉，冠纓吾欲濯吾埃。", "天寒病馬尚遠放，日夕罷牛宜下來。", "名家翰墨書還蠹，蓋世功名骨已苔。", "孰與東籬訪黄菊，柴門終不爲人開。"]'),
('682a3038-f3e8-49ea-9a2f-8deeb3d7c62a','送范東叔歸帥潼川','陳傅良','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','楚山黄落洞庭波，背却鷄人問釣蓑。',64,'全唐诗/poet.song.158000.json','["楚山黄落洞庭波，背却鷄人問釣蓑。", "歸思甚於三峽壯，才名空自十年多。", "曩游記得青燈在，後會愁如白髮何。", "我更有懷言不盡，故將短韵代長歌。"]'),
('bcdf0249-784c-41cf-aee8-6320693ff08c','送丁懷忠教授象州','陳傅良','宋','宋诗','song-poetry','','[]','二毛覊旅久，一飯瘴鄉輕。',48,'全唐诗/poet.song.158000.json','["二毛覊旅久，一飯瘴鄉輕。", "把酒時相屬，令人意自平。", "校官無簿領，帥閫甚聲名。", "所恨冥冥雨，梅天不肯明。"]'),
('901b52ca-ea8d-4449-b987-7724af05ae47','長沙臘月雷是日約宴趙帥俊臣聞雷乃罷越三日雨雪帥喜以詩相賀用韵酬之','陳傅良','宋','宋诗','song-poetry','','[]','民欲遮留上欲來，政聲無間到輿臺。',64,'全唐诗/poet.song.158000.json','["民欲遮留上欲來，政聲無間到輿臺。", "道迎和氣收蠻瘴，彈壓餘陰蟄楚雷。", "已是因風成柳絮，會須逐馬見銀盃。", "一觴好上公堂壽，不爲梅花昨夜開。"]'),
('0879f27f-e42f-4aff-9979-33484118f56e','又和','陳傅良','宋','宋诗','song-poetry','','["\u8861\u5c71"]','沴氣反爲和氣來，長沙千里一瑶臺。',64,'全唐诗/poet.song.158000.json','["沴氣反爲和氣來，長沙千里一瑶臺。", "新炊頓頓匙抄玉，熟睡家家壁撼雷。", "天直於人如合券，公應憐我欲停盃。", "向來韓子誇精禱，雲合衡山特易開。"]'),
('b4b31f74-b295-4ae9-b345-2023cefbe456','趙帥復賦詩來用韵酬之','陳傅良','宋','宋诗','song-poetry','','[]','天水交光地欲無，中間老子獨軒渠。',64,'全唐诗/poet.song.158000.json','["天水交光地欲無，中間老子獨軒渠。", "一蓑漁隠真堪畫，萬玉龍驤不可屠。", "已卜菑畬何幸甚，却憐藍縷更愁如。", "莫將此惠長私楚，好上甘泉扈屬車。"]'),
('595e8ade-5444-42b4-8e67-429bc5acc08f','用韵詠雪簡湘中諸友','陳傅良','宋','宋诗','song-poetry','','[]','夾湘而住一塵無，不在瑶池在石渠。',64,'全唐诗/poet.song.158000.json','["夾湘而住一塵無，不在瑶池在石渠。", "氣蓋松篁誰與競，令行螟𧎬自相屠。", "山光際水天無間，夜色通朝月不如。", "中有一翁鬚皓白，蕭然野鶴亦乘車。"]'),
('5ef83886-fb01-4dd6-b713-9f04a8fea436','贈張孟阜絕句','陳傅良','宋','宋诗','song-poetry','','[]','燕坐何曾論古今，束書高閣反求心。',32,'全唐诗/poet.song.158000.json','["燕坐何曾論古今，束書高閣反求心。", "若能領會無多子，絕勝相從歲月深。"]'),
('40876ab1-57a0-4fdb-be64-a17d88894391','用趙帥韵爲孟阜解嘲','陳傅良','宋','宋诗','song-poetry','','[]','恨無毫髮老波瀾，世有曹劉亦後班。',32,'全唐诗/poet.song.158000.json','["恨無毫髮老波瀾，世有曹劉亦後班。", "堪笑燕人夸璞腊，欲隨圭璧上三壇。"]'),
('e9375086-8447-45a1-a9e7-1480d4d94fa3','登祝融峰觀日出','陳傅良','宋','宋诗','song-poetry','','[]','星月凋零萬象昏，誰能先我見朝暾。',64,'全唐诗/poet.song.158000.json','["星月凋零萬象昏，誰能先我見朝暾。", "東南已得乾坤正，蠻貊方知夜旦分。", "但覺滄溟浮佛屋，却忘衡嶽近天閽。", "迢迢下憇山腰寺，人世烟雲尚吐吞。"]'),
('317dcef8-7e7b-4efc-9a00-4376ce246938','舟中奉呈趙帥一首且速迎侍相與滿歲','陳傅良','宋','宋诗','song-poetry','','[]','曷不放言追鵩賦，豈無幽思續離騷。',64,'全唐诗/poet.song.158000.json','["曷不放言追鵩賦，豈無幽思續離騷。", "去年比屋餘三釜，昨夜沿江長一篙。", "白髮豈曾緣吏役，青衫那更有兒曹。", "魚軒肯爲公來否，相約春光訪蟹螯。"]'),
('2b7ace63-69c3-4613-b61e-e1ff14aae54c','除浙西憲舟過釣臺有感','陳傅良','宋','宋诗','song-poetry','','[]','一再登臨萬事非，裹頭還已雪垂垂。',64,'全唐诗/poet.song.158000.json','["一再登臨萬事非，裹頭還已雪垂垂。", "敢論筆力今無恨，欲附碑陰始不疑。", "臺閣有人堪共政，江山如此且隨宜。", "論功漢鼎吾何有，自是風流百代師。"]'),
('4229c12a-4606-4207-9d0d-4b27a89ca95c','上皇子嘉王生辰詩三章  其一','陳傅良','宋','宋诗','song-poetry','','[]','兩官頻燕喜，交舉萬年觴。',48,'全唐诗/poet.song.158000.json','["兩官頻燕喜，交舉萬年觴。", "會慶川方至，重明日未央。", "聖賢何繼世，孫子更宜王。", "聞說斯干夢，祥占近一陽。"]'),
('7126612d-24e9-458c-92ca-83854b8c3280','上皇子嘉王生辰詩三章  其二','陳傅良','宋','宋诗','song-poetry','','[]','造次依儒術，朝迴只一經。',48,'全唐诗/poet.song.158000.json','["造次依儒術，朝迴只一經。", "更無他嗜好，端是衆儀刑。", "符應當良月，聲華自妙齡。", "帝垣從此日，光焰粲前星。"]'),
('1c1fd302-00bf-4ac7-a6a2-2f43378bb4e2','上皇子嘉王生辰詩三章  其三','陳傅良','宋','宋诗','song-poetry','','[]','要識皇圖永，當觀藝祖初。',48,'全唐诗/poet.song.158000.json','["要識皇圖永，當觀藝祖初。", "維持今盡是，回復更何如。", "庸陋誰推轂，衰遲此曳裾。", "慙無爲壽具，獨袖一編書。"]'),
('e40c12ad-62fb-472c-8cdf-c89e1c1cb0da','袁起巖會飲湖上出示古刻酒罷各携桂花以歸因成一絕','陳傅良','宋','宋诗','song-poetry','','[]','湖光不動見魚蝦，敗紙殘編數十家。',32,'全唐诗/poet.song.158000.json','["湖光不動見魚蝦，敗紙殘編數十家。", "巖桂叢中三四客，醉歸人得一瓶花。"]'),
('1411f5d3-8758-46a6-a459-c80e91303ba4','又和','陳傅良','宋','宋诗','song-poetry','','[]','湖上簾須半捲蝦，調冰雪藕各名家。',32,'全唐诗/poet.song.158000.json','["湖上簾須半捲蝦，調冰雪藕各名家。", "有人不觧長安飲，話極茶鐺吸井花。"]'),
('d15f1c38-68d7-484c-9980-810b0c080414','寄陳同甫','陳傅良','宋','宋诗','song-poetry','','[]','古來材大難爲用，納納乾坤著幾人。',64,'全唐诗/poet.song.158000.json','["古來材大難爲用，納納乾坤著幾人。", "但把雞豚燕同社，莫將鵝鴨惱比隣。", "世非文字將安托，身與兒孫竟孰親。", "一語觧紛吾豈敢，祇應行道亦酸辛。"]'),
('d3a1c012-b219-4a41-a624-71bb59966d29','送辛卿幼安帥閩','陳傅良','宋','宋诗','song-poetry','','[]','長才自昔恨平時，三入修門兩鬢絲。',64,'全唐诗/poet.song.158000.json','["長才自昔恨平時，三入修門兩鬢絲。", "甕下可能長夜飲，花間却學晚唐詞。", "潸然北顧關河水，簡在西清日月遲。", "乘鴈雙鳬滄海上，與君從此恐差池。"]'),
('a847bd9b-0d30-41a3-8e2c-a71fc6bea2d5','送盧郎中國華赴閩憲','陳傅良','宋','宋诗','song-poetry','','[]','相望千里馬牛風，聯事湖湘各已翁。',64,'全唐诗/poet.song.158000.json','["相望千里馬牛風，聯事湖湘各已翁。", "造次便呼兒女見，綢繆略與弟兄同。", "百年又是梅花發，萬事何如荔子紅。", "欲附使軺嗟不及，却憐身在俊躔中。"]'),
('ac8fe422-e79d-47bb-9e07-c68c4f2c49b6','送范大著文叔知彭州','陳傅良','宋','宋诗','song-poetry','','[]','中書世祿今無幾，唐鑑家聲世不多。',64,'全唐诗/poet.song.158000.json','["中書世祿今無幾，唐鑑家聲世不多。", "安得有人賢若此，忽聞去國意如何。", "同朝最是頭先白，知己還愁語太苛。", "盡欲讀書三萬卷，蓬萊未必似岷峨。"]'),
('cb433df2-5e75-4d28-8dd5-1e95cbfa5aa9','和劉進之韵兼簡吳阜之','陳傅良','宋','宋诗','song-poetry','','[]','憧憧滿眼事何稠，落落論心思獨幽。',64,'全唐诗/poet.song.158000.json','["憧憧滿眼事何稠，落落論心思獨幽。", "去國未能身一葉，懷人但覺日三秋。", "池塘春草方同夢，江漢歸舟更別愁。", "安得簫韶儀兩鳳，不妨燕雀自嘲啁。"]'),
('d48dda64-bcf3-4847-809e-8b4c684cf02f','初夏有感因用前韵久旱適得雨欣然卒章','陳傅良','宋','宋诗','song-poetry','','[]','湖山嫵媚綠陰稠，誰向芸芸得趣幽。',64,'全唐诗/poet.song.158000.json','["湖山嫵媚綠陰稠，誰向芸芸得趣幽。", "半破榴花方恨晚，新來燕子未知秋。", "去爲吏隠雖吾願，歸得家山政自愁。", "頼有雨聲寬百感，忽如孤鳳見羣啁。"]'),
('73190c02-c310-43ea-8452-25edcf9e305c','送潘德久之官建康','陳傅良','宋','宋诗','song-poetry','','[]','平生不解通毛刺，萬事無能改鬢華。',64,'全唐诗/poet.song.158000.json','["平生不解通毛刺，萬事無能改鬢華。", "豈是襟懷堪逆旅，直須詩句可名家。", "老爲賓客從戎幙，强使妻孥理帽紗。", "不有將軍寬禮數，新愁却恐墮江花。"]'),
('e495104b-11db-49dc-bce5-89fad6fe60c1','同游張園酒中各嘆明年未知誰與此會余最衰病宜去因作詩識之','陳傅良','宋','宋诗','song-poetry','','[]','春過新烟能有幾，愁生飛絮轉難禁。',64,'全唐诗/poet.song.158000.json','["春過新烟能有幾，愁生飛絮轉難禁。", "可憐衰白隨年少，愛看殘紅到夜深。", "一輩衣冠方事事，故園松竹已陰陰。", "明年此會知誰共，鴈蕩山前寄好音。"]'),
('bb51be8b-4a62-40c5-98cf-d77278955bcf','次韵奉酬方輝先','陳傅良','宋','宋诗','song-poetry','','[]','也知朝士愧山林，猿鶴相懷怨亦深。',64,'全唐诗/poet.song.158000.json','["也知朝士愧山林，猿鶴相懷怨亦深。", "屈指落花年荏苒，斷魂凋鬢日侵尋。", "向來相與期何事，老去誰能會此心。", "多謝故人重話舊，獨憐志古定遺今。"]'),
('2bba6561-06e8-4845-85ea-0e08e3c7a472','送倪正甫侍郎賀正','陳傅良','宋','宋诗','song-poetry','','[]','雪枿冰芽又復春，中原□覩屬車塵。',64,'全唐诗/poet.song.158000.json','["雪枿冰芽又復春，中原□覩屬車塵。", "懽呼漢節從天下，愕立胡兒夾道陳。", "老去獨慚□偃蹇，君行决意問經綸。", "顧瞻河洛關心處，應記幽燕用事人。"]'),
('52e22b22-75e7-40d7-b875-825602f42545','喜雨','陳傅良','宋','宋诗','song-poetry','','[]','天顧於人略有情，片時收盡越山青。',64,'全唐诗/poet.song.158000.json','["天顧於人略有情，片時收盡越山青。", "老農望外扶犂立，倦客愁邊擁被聽。", "塵翳欲清閶闔道，井花已上轆轤亭。", "冥冥直待黄梅熟，未要風池看約萍。"]'),
('144d1f1c-6a03-492d-9573-c1317a8a2b93','送曾繼先赴山陰路鈐','陳傅良','宋','宋诗','song-poetry','','[]','鬍髯白盡猶强飯，髀肉添多未跨鞍。',64,'全唐诗/poet.song.158000.json','["鬍髯白盡猶强飯，髀肉添多未跨鞍。", "不向胡沙親矢石，却來橋塚護衣冠。", "歸舟自此長相背，薦墨于今尚未乾。", "只恐燕然他日事，獨無名字可同刊。"]'),
('3fddfed7-70bb-4d47-b640-492123153e71','送何起巖之江東','陳傅良','宋','宋诗','song-poetry','','[]','苦吟海內知音少，獨往江東問政頻。',64,'全唐诗/poet.song.158000.json','["苦吟海內知音少，獨往江東問政頻。", "我亦他山於此別，世無吾黨更誰親。", "六朝故實皆新句，一代風流尚幾人。", "話次儻懷無恙否，爲將衰惰再三陳。"]'),
('f8f879f5-02f8-4773-8ccb-9cc6e65107b5','上元日同京仲遠趙德老羅春伯謝子肅訪郭殿帥游鳳凰山次韵','陳傅良','宋','宋诗','song-poetry','','[]','層雲飛鳥共危欄，江漢朝宗萬折盤。',64,'全唐诗/poet.song.158000.json','["層雲飛鳥共危欄，江漢朝宗萬折盤。", "王氣信知千古盛，聖圖元自九朝寬。", "公餘曳履探殊勝，酒罷磨崖記衆懽。", "衰惰不知能健否，相從河岱弄柔翰。"]'),
('a36ec373-c4c7-4d31-a43e-444af49b1af0','癸丑冬車駕過宮留相還朝','陳傅良','宋','宋诗','song-poetry','','[]','一聲警蹕接天齊，馳道無塵馬不嘶。',64,'全唐诗/poet.song.158000.json','["一聲警蹕接天齊，馳道無塵馬不嘶。", "月御順行隨日轂，乾端和氣匝坤倪。", "三槐相繼歸公衮，細柳還須聽將鼙。", "老矣尚能歌二聖，不應專美在浯溪。"]'),
('5a280d62-9a08-4262-978a-4778b6b32a46','和樓大防尚書送行韵','陳傅良','宋','宋诗','song-poetry','','[]','齊年兄弟又齊名，商略行藏共此生。',64,'全唐诗/poet.song.158000.json','["齊年兄弟又齊名，商略行藏共此生。", "自昔從君瞻馬首，如今輸我與鷗盟。", "讀書松竹交千載，曳履星辰聽五更。", "借問塞翁誰得失，諸無一語到留行。"]'),
('e3b0e9e2-65b5-4303-adc2-d4e4c730dc92','折子明提刑自湘中以詩問訊用韵酬之','陳傅良','宋','宋诗','song-poetry','','[]','久立天涯詠式微，胡然華髮尚□□。',64,'全唐诗/poet.song.158000.json','["久立天涯詠式微，胡然華髮尚□□。", "□□□望歸簪履，便冀君恩到蓋帷。", "當世豈無君子論，□□□□□人詩。", "湘中一似桐鄉好，安得扁舟著釣絲。"]'),
('894b8eb2-4f36-4772-8d19-e8b256d3ccf0','泊釣臺灘下','陳傅良','宋','宋诗','song-poetry','','[]','今歲僅餘今夜月，此舟三泊此江沂。',64,'全唐诗/poet.song.158000.json','["今歲僅餘今夜月，此舟三泊此江沂。", "遭逢明主還遺恨，慚愧先生獨見幾。", "泗水列侯多不免，湘山四皓竟安歸。", "漢家故舊嘗枚數，孰與東南一釣磯。"]'),
('4727f9d2-5f78-40ed-919d-be65511996fa','臘月望泊舟釣臺灘下賦詩既而登婺女明遠樓誦之鄉丈陳德承同集黄奇卿張伯廣因書以遺德承之子性甫直甫後春六日奉和德承韵兼簡奇卿伯廣爲別','陳傅良','宋','宋诗','song-poetry','','[]','行藏獨倚少陵樓，怨鶴愁猿孰與儔。',64,'全唐诗/poet.song.158000.json','["行藏獨倚少陵樓，怨鶴愁猿孰與儔。", "嘗與萬人爭魏闕，何如一壑老菟裘。", "追隨士友從吾好，領略江山自此遊。", "急趁梅花理歸棹，雙溪爲我亦西流。"]'),
('84684c6f-0249-4234-b81e-afcfb1253aed','贈杜伯高','陳傅良','宋','宋诗','song-poetry','','[]','臘後玄冥意氣驕，餘寒造物亦亡聊。',64,'全唐诗/poet.song.158000.json','["臘後玄冥意氣驕，餘寒造物亦亡聊。", "風收夜雨春何淺，雲障朝暾雪不消。", "真悟此生纔半歲，恣聽何處是三朝。", "粲然一笑將迎我，頼有江梅慰寂寥。"]'),
('292ab228-f604-4df5-87b6-81c8396eae6a','除夜宿處州天寧寺','陳傅良','宋','宋诗','song-poetry','','[]','人言老去不如初，我愛初心老轉無。',63,'全唐诗/poet.song.158000.json','["人言老去不如初，我愛初心老轉無。", "懶向門前題鬰壘，喜從人後飲屠蘇。", "杯盤甚簡眠須早，禮數多寬拜要扶。", "况復齁齁紙帳，雞人不聽禁庭呼。"]'),
('29019a36-5118-4f5d-8b94-545538189489','寄僧嗣清','陳傅良','宋','宋诗','song-poetry','','[]','衡陽傑閣宵人記，淮右豐碑刺史書。',64,'全唐诗/poet.song.158000.json','["衡陽傑閣宵人記，淮右豐碑刺史書。", "永已橋山藏劍佩，空餘雲漢照林廬。", "河圖萬古陳東序，汗簡諸儒校石渠。", "誰道幽深窮衲子，乞錢買石更崎嶇。"]'),
('47f5f442-982a-47cd-af37-9de5a9980e11','蔣處州仲可惠酒','陳傅良','宋','宋诗','song-poetry','','[]','括州太守□亭侯，及與前時一輩游。',64,'全唐诗/poet.song.158000.json','["括州太守□亭侯，及與前時一輩游。", "剩欲池塘看芳草，謾隨烟雨上危樓。", "無錢可解催科拙，有酒能寬放逐愁。", "可笑杜陵嚴武客，時時傍舍過牆頭。"]'),
('a51f8daa-b529-481d-a43d-ebd6ef07b4a5','再寄用前韻','陳傅良','宋','宋诗','song-poetry','','[]','幸無骨相可封侯，歸理先人舊釣游。',64,'全唐诗/poet.song.158000.json','["幸無骨相可封侯，歸理先人舊釣游。", "山下剩栽諸本竹，水邊須著數間樓。", "羣書可讀自隨喜，一客不來誰與愁。", "時把釣絲銷永日，魚兒亦得兩三頭。"]'),
('8ec41bc6-7f17-458d-ab2e-e2a2cb43b5d8','丙辰寄國舉兄','陳傅良','宋','宋诗','song-poetry','','[]','是間南極老人星，喬木脩篁亦有情。',64,'全唐诗/poet.song.158000.json','["是間南極老人星，喬木脩篁亦有情。", "直向朱明爲後殿，不隨黄落入秋聲。", "兒孫衮衮看新出，兄弟團團得晚成。", "笑閲世人心事短，却從黄老問長生。"]'),
('1ce6fc83-4d7e-42dc-b441-408c7f0badae','送長溪高國楹從學朱元晦','陳傅良','宋','宋诗','song-poetry','','[]','洛學今無恙，東南屬此翁。',48,'全唐诗/poet.song.158000.json','["洛學今無恙，東南屬此翁。", "從游雖已晚，趣向竟誰同。", "一第收良易，遺經語未終。", "歸期定何日，我欲叩新功。"]'),
('5ce5ea06-77d2-47cc-8b6b-bb0a1e976c7a','以兩鶴壽薛象先','陳傅良','宋','宋诗','song-poetry','','[]','日與山農共一廛，不應家有四乘軒。',32,'全唐诗/poet.song.158000.json','["日與山農共一廛，不應家有四乘軒。", "殷勤分送平齋下，爲看蟠桃熟幾年。"]'),
('eee23e5c-ddaf-441d-ab4e-d02599bb5a4c','重陽日寄瑞安留宰留宰以是日宴新第人併見招不及赴','陳傅良','宋','宋诗','song-poetry','','[]','落帽沾衣總失真，追隨萸菊亦勞神。',64,'全唐诗/poet.song.158000.json','["落帽沾衣總失真，追隨萸菊亦勞神。", "酒無肴核依然好，家有溪山豈是貧。", "沆瀣從空來夜氣，青冥隨處際秋旻。", "不知此是登高否，爲問慈恩塔上人。"]'),
('a3855100-62b5-4d7a-accc-9874247f53e7','和林宗易菊花韻','陳傅良','宋','宋诗','song-poetry','','[]','一歲所餘秋有幾，重陽偏與老相催。',64,'全唐诗/poet.song.158000.json','["一歲所餘秋有幾，重陽偏與老相催。", "每憐白髮能長健，雖愛黄花亦懶栽。", "好景游從須好友，新詩風味似新醅。", "人生適意無過此，恣聽東籬早晏開。"]'),
('2c5521b8-c8db-4d23-abba-68ffbc505139','和沈仲一北湖十詠 北湖','陳傅良','宋','宋诗','song-poetry','','[]','北湖只隔嶺頭雲，誰在湖邊問訊人。',32,'全唐诗/poet.song.158000.json','["北湖只隔嶺頭雲，誰在湖邊問訊人。", "若得小舟通我過，雨晴須破半時辰。"]'),
('fd3caa15-7595-4d8b-9cb7-54093a4959dc','和沈仲一北湖十詠 豫章閣','陳傅良','宋','宋诗','song-poetry','','[]','人去岷峨水自流，豫章三字竟沈浮。',32,'全唐诗/poet.song.158000.json','["人去岷峨水自流，豫章三字竟沈浮。", "懷人好上層樓看，木落山寒不肯秋。"]'),
('a02faaad-4c70-4fd0-b48b-89e5157e004b','和沈仲一北湖十詠 仰止亭','陳傅良','宋','宋诗','song-poetry','','[]','可愛南山與北山，北山上有斗芒寒。',32,'全唐诗/poet.song.158000.json','["可愛南山與北山，北山上有斗芒寒。", "碧雲歸盡人何在，更捲珠簾到夜闌。"]'),
('ac41e448-c513-4284-bc01-93de9f2b859b','和沈仲一北湖十詠 葯房','陳傅良','宋','宋诗','song-poetry','','[]','平平下語及雲管，學到詩人豈不難。',32,'全唐诗/poet.song.158000.json','["平平下語及雲管，學到詩人豈不難。", "莫似□人大芳潔，湘波千古訴椒蘭。"]'),
('0c618bb9-e3df-421c-b50d-178bebde893e','和沈仲一北湖十詠 穆波亭','陳傅良','宋','宋诗','song-poetry','','[]','一年曾得幾番圓，恨不驂鸞上廣寒。',32,'全唐诗/poet.song.158000.json','["一年曾得幾番圓，恨不驂鸞上廣寒。", "占得波光須細翫，恰聞滄海已狂瀾。"]'),
('2bba0834-a59d-467a-9939-92d6f35657d6','和沈仲一北湖十詠 粹白堂','陳傅良','宋','宋诗','song-poetry','','[]','欲來花底竟差池，我有佳名誰與歸。',32,'全唐诗/poet.song.158000.json','["欲來花底竟差池，我有佳名誰與歸。", "翌日看花天一色，狐裘猶自織寒機。"]'),
('79d4f774-9cda-471a-8881-9089bf8e1faf','和沈仲一北湖十詠 遲客臺','陳傅良','宋','宋诗','song-poetry','','[]','借無舟楫亦褰裳，目斷蒹葭水一方。',32,'全唐诗/poet.song.158000.json','["借無舟楫亦褰裳，目斷蒹葭水一方。", "今夜不來同剪韭，隔山明日事茫茫。"]'),
('0e561895-6de9-4e26-b63c-7df204551447','和沈仲一北湖十詠 萱竹堂','陳傅良','宋','宋诗','song-poetry','','[]','萱草須鋤莫放深，竹須剪伐待成林。',32,'全唐诗/poet.song.158000.json','["萱草須鋤莫放深，竹須剪伐待成林。", "一花一葉皆相附，要使兒孫識此心。"]'),
('20b1f844-c905-40bb-8770-cb55df20fbef','和沈仲一北湖十詠 楚頌亭','陳傅良','宋','宋诗','song-poetry','','[]','紛紛萬木盡西風，獨立霜林我御冬。',32,'全唐诗/poet.song.158000.json','["紛紛萬木盡西風，獨立霜林我御冬。", "滓畔無人誰著語，止齋但護紫泥封。"]'),
('123537db-1193-49c1-9180-c67d4fd3f86d','和沈仲一北湖十詠 宜雨亭','陳傅良','宋','宋诗','song-poetry','','[]','看花只爲雨愁人，一片纔飛減却春。',32,'全唐诗/poet.song.158000.json','["看花只爲雨愁人，一片纔飛減却春。", "獨此得春無盡藏，每於愁外見精神。"]'),
('61ab4b94-1188-4d74-8622-a13bfb9b0e1b','周宣義三子仲敏明□幼謹同年登第因以前韻奉寄','陳傅良','宋','宋诗','song-poetry','','[]','營營浮俗贋還真，孰與傳經妙入神。',64,'全唐诗/poet.song.158000.json','["營營浮俗贋還真，孰與傳經妙入神。", "一榜及看三子貴，數椽能忍十年貧。", "自將弧矢書閭史，便使冰淵誦小旻。", "家學如君今有幾，殷勤羅拜我何人。"]'),
('d2031f70-958a-4ab5-94cd-ca38a4a38eb9','再次韻簡新第諸人','陳傅良','宋','宋诗','song-poetry','','[]','行酒何如溫太真，風流元不鄙錢神。',64,'全唐诗/poet.song.158000.json','["行酒何如溫太真，風流元不鄙錢神。", "扁舟容我歸來老，一子令人買得貧。", "雖有羣仙來月窟，欲扶衰力上霜旻。", "吾今已定漁樵約，勛業煩公一輩人。"]'),
('aad6d8b2-242f-4289-be0c-ee040cc79f2a','送瑞安尉林叔全尊人還鄉','陳傅良','宋','宋诗','song-poetry','','[]','論交海內略飄零，最晚相看却有情。',64,'全唐诗/poet.song.158000.json','["論交海內略飄零，最晚相看却有情。", "不以一經誇魯諺，自於二子識徐卿。", "橘香賸與蜂衙晚，麥信急催鳩喚晴。", "天氣正佳歸恰好，莫將愁思爲空名。"]'),
('c73051d1-7b22-42d3-b786-910ac04b6dc2','送林叔全秩滿歸四明','陳傅良','宋','宋诗','song-poetry','','[]','三年絕境興誰同，雞叫桑巔犬巷中。',64,'全唐诗/poet.song.158000.json','["三年絕境興誰同，雞叫桑巔犬巷中。", "但欲戶庭多暇日，不將鞭朴奏膚公。", "相期霄漢摶風翮，每見燈花綴玉蟲。", "此去逢人臺閣上，丁寧莫道止齋翁。"]'),
('66f7ca03-bbd4-40c8-a807-b1757d15c4e5','送雪庵瑾禪師還山','陳傅良','宋','宋诗','song-poetry','','[]','五馬逢迎甚闊疎，滿朝問訊近何如。',64,'全唐诗/poet.song.158000.json','["五馬逢迎甚闊疎，滿朝問訊近何如。", "諸公極有遲留意，一日連收竟別書。", "佛法盛衰千劫後，人生老壯百年餘。", "向來游舊今亡恙，願得斯人尚起予。"]'),
('43813cf7-2250-4336-ba2d-c70c7ad6341a','周和叔通判雪寒索酒戲用來韻以將朋尊','陳傅良','宋','宋诗','song-poetry','','[]','持盃雖念故人寒，欲予還不似印刓。',32,'全唐诗/poet.song.158000.json','["持盃雖念故人寒，欲予還不似印刓。", "此債豈應行處有，麯春何日寄雲安。"]'),
('1063f852-ed7f-4547-84fb-2bf4b26045d2','奉和周蕃伯用王道夫韻二章見寄  其一','陳傅良','宋','宋诗','song-poetry','','[]','森森萬木一精廬，黄卷青燈自卷舒。',64,'全唐诗/poet.song.158000.json','["森森萬木一精廬，黄卷青燈自卷舒。", "却肯追隨三舍遠，不論聞問十年疎。", "遺賢公已長懷玉，老圃吾方欲荷鋤。", "安得謝巖題壁處，一尊相伴看芙蕖。"]'),
('fa36f8a9-473a-410c-8994-69470bb5ccab','奉和周蕃伯用王道夫韻二章見寄  其二','陳傅良','宋','宋诗','song-poetry','','[]','論定千年後，心寬萬事平。',48,'全唐诗/poet.song.158000.json','["論定千年後，心寬萬事平。", "吾方慚鼠伎，安敢道鴻冥。", "門戶雖入境，溪山亦世情。", "半天喬木立，盡日好禽鳴。"]'),
('38b487bd-eed4-4c98-9f06-ec7962a665be','壽叔祖母','陳傅良','宋','宋诗','song-poetry','','[]','三陽昨夜轉洪鈞，鳳曆今年又紀寅。',64,'全唐诗/poet.song.158000.json','["三陽昨夜轉洪鈞，鳳曆今年又紀寅。", "再拜與君觴壽母，更生猶我面先人。", "兒孫夾侍渾忘數，梅柳前陳不記春。", "從此常爲湯餠主，賸看諸婦抱麒麟。"]'),
('3e1734f4-587d-46ab-b600-bccde235c2c1','東陽杜季高遠訪詩以送之','陳傅良','宋','宋诗','song-poetry','','[]','當世關衰壯，斯文看合離。',48,'全唐诗/poet.song.158000.json','["當世關衰壯，斯文看合離。", "强餐吾豈敢，後會子何期。", "村落秋彌好，溪山晚最宜。", "逢人相問訊，所欠更能詩。"]'),
('02b4cbff-355f-4ed0-8182-9a3fe64da843','春日和林宗易韻','陳傅良','宋','宋诗','song-poetry','','[]','白與紅兼盡落梅，小園獨步日千迴。',64,'全唐诗/poet.song.158000.json','["白與紅兼盡落梅，小園獨步日千迴。", "浮空曉色臨無際，排闥春光撥不開。", "學語新禽更後囀，鋪茸細草雨邊來。", "却憐追逐今無力，放下簾鈎就麝煤。"]'),
('04b5659a-cde9-467b-a249-446bcc1738db','移花','陳傅良','宋','宋诗','song-poetry','','[]','櫻柳初無素與蠻，可將何物伴身閒。',32,'全唐诗/poet.song.158000.json','["櫻柳初無素與蠻，可將何物伴身閒。", "欲栽花木千餘本，但候春風還未還。"]'),
('2b2d2d1b-b857-42e6-87ca-7bf36326ae6e','送花還宗易','陳傅良','宋','宋诗','song-poetry','','[]','酷愛看花懶種花，知心惟有故人家。',32,'全唐诗/poet.song.158000.json','["酷愛看花懶種花，知心惟有故人家。", "花開兮送花殘取，娛老扶衰度歲華。"]'),
('09ea1a99-abab-497c-97c5-d824ac6b9a72','遊鳴山寺徐一之兄弟載酒即席和其韻','陳傅良','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','惰歸春力不勝驅，風雨尚愁人摻裾。',64,'全唐诗/poet.song.158000.json','["惰歸春力不勝驅，風雨尚愁人摻裾。", "掠盡殘紅前日樹，催還新綠去年畬。", "相將興盡隨花屧，頼有朋來載酒車。", "但得從今身尚健，吾鄉風物勝匡廬。"]'),
('2552da62-7e7a-4374-bb0d-b82194d8bbc8','和徐叔子用林宗易韻見示','陳傅良','宋','宋诗','song-poetry','','[]','相過風雨獨何歟，校酒論文已不如。',64,'全唐诗/poet.song.158000.json','["相過風雨獨何歟，校酒論文已不如。", "方信深交相戀繆，却因衰退更躊躇。", "吟生池草書成束，飲落簷花醉墮車。", "明日待隨公等去，我頭應始自今梳。"]'),
('38b62706-8da3-49f2-bd13-736329df96d0','和徐叔子勸農韻呈留宰','陳傅良','宋','宋诗','song-poetry','','[]','親從蓑笠問饑寒，赴愬人人得犯顔。',64,'全唐诗/poet.song.158000.json','["親從蓑笠問饑寒，赴愬人人得犯顔。", "更向棠陰聊憇茇，要令粒食共鮮艱。", "身歸雨露司存後，詩在山川刻畫間。", "飽飯之餘能細和，止齋應有幾年閑。"]'),
('784352ec-3a31-464b-81b8-61b168c04117','遊金嶴趙園賦海棠梨花呈留宰','陳傅良','宋','宋诗','song-poetry','','[]','海棠故作十分紅，梨更超然與雪同。',32,'全唐诗/poet.song.158000.json','["海棠故作十分紅，梨更超然與雪同。", "文物英華周盛事，風流玄遠晉餘風。"]'),
('9e82965d-8529-4ee1-a951-a07ea1757497','赴留宰寶壇之集因和蕃叟弟趙園韻','陳傅良','宋','宋诗','song-poetry','','[]','一枝纔放前村雪，一線初開愛日天。',64,'全唐诗/poet.song.158000.json','["一枝纔放前村雪，一線初開愛日天。", "潘縣風流凡五客，趙園名字亦千年。", "可無能賦如難弟，恨不曾來有尉仙。", "待得中興用循吏，更於此地設離筵。"]'),
('bf572f63-56c5-4c00-be8e-7abc25a726c8','示留宰','陳傅良','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','縣樓即日氣橫空，施及觀潮亦奏功。',32,'全唐诗/poet.song.158000.json','["縣樓即日氣橫空，施及觀潮亦奏功。", "曾上石崗看蟻穴，當圖一飽到三農。"]'),
('ec7ba71a-676a-4ebb-b542-351862df09e2','或以詩送來禽次韻奉酬  其一','陳傅良','宋','宋诗','song-poetry','','[]','連年栽樹未成陰，赬實堆盤慰我心。',32,'全唐诗/poet.song.158000.json','["連年栽樹未成陰，赬實堆盤慰我心。", "手把新詩堪永日，休誇法帖送來禽。"]'),
('4edfa3cf-8d31-460c-a1e0-201768be6747','或以詩送來禽次韻奉酬  其二','陳傅良','宋','宋诗','song-poetry','','[]','隔水佳人久不逢，祇應我懶或君慵。',32,'全唐诗/poet.song.158000.json','["隔水佳人久不逢，祇應我懶或君慵。", "感時相饋情何厚，却說雲泥笑殺儂。"]'),
('33b9d5a5-11ef-4c05-a2b0-945984dc54fc','遊雲頂院和徐叔子韻','陳傅良','宋','宋诗','song-poetry','','[]','老大生憎兒女態，更無春怨與秋悲。',64,'全唐诗/poet.song.158000.json','["老大生憎兒女態，更無春怨與秋悲。", "略將盃酌隨宜具，剩有溪山取次嬉。", "愛客不妨兼泛泛，論文何苦太奇奇。", "况曾窺得尊生術，通昔蒲團日一炊。"]'),
('0706d61d-d15a-481f-bb6a-8e39dcceabea','壽薛象先','陳傅良','宋','宋诗','song-poetry','','[]','蕭然山澤一臞仙，故被聲名絆俊躔。',64,'全唐诗/poet.song.158000.json','["蕭然山澤一臞仙，故被聲名絆俊躔。", "祇爲春秋同社燕，遂歸風雨對牀眠。", "中年曾未鬚眉白，盡日全無車馬喧。", "我有壽觴誰與共，會昌湖上釣魚船。"]'),
('2c3978b9-95a2-4368-b2e2-004a635e5020','酬蕃叟弟韻','陳傅良','宋','宋诗','song-poetry','','[]','朋游同一輩，伯季自相師。',48,'全唐诗/poet.song.158000.json','["朋游同一輩，伯季自相師。", "薄宦俄衰暮，清懽僅暇時。", "我懷青冢曲，子念紫荆詩。", "但得無憂患，幽棲豈不宜。"]'),
('f67fb41f-b535-4dbf-b87e-3d042adb9efa','壽潘省之','陳傅良','宋','宋诗','song-poetry','','[]','泛水淺紅荷十里，蔽雲濃綠木千章。',64,'全唐诗/poet.song.158000.json','["泛水淺紅荷十里，蔽雲濃綠木千章。", "旁無俗子山居巷，中有臞仙一瓣香。", "今夕還知是何夕，吾鄉終勝似他鄉。", "雙鳬便合青冥上，笑看兒孫樂未央。"]'),
('81ad3367-6777-4d70-b42f-91bfc981d920','丁巳壽國舉兄','陳傅良','宋','宋诗','song-poetry','','[]','歲自爲詩歲自賡，愁無新思思還生。',64,'全唐诗/poet.song.158000.json','["歲自爲詩歲自賡，愁無新思思還生。", "更從今閏書初伏，待看何年值後庚。", "漢網疏如天地闊，奎文下與水雲平。", "弟兄長健貧何病，判解金龜當一酲。"]'),
('765332c6-852f-4013-8a47-ec99d6ca0a9c','村居二首  其一','陳傅良','宋','宋诗','song-poetry','','[]','業已將身落耦耕，時於觀物悟浮生。',64,'全唐诗/poet.song.158000.json','["業已將身落耦耕，時於觀物悟浮生。", "擇栖未定鳥離立，避礙已通魚並行。", "野老窺巢占太歲，牧兒敲角報殘更。", "絕勝倚市看郵置，客至還無菜甲羹。"]'),
('690ad9ee-b6db-4d82-af31-6c170df0a25f','村居二首  其二','陳傅良','宋','宋诗','song-poetry','','[]','野衣農圃雜，華髮弟兄同。',48,'全唐诗/poet.song.158000.json','["野衣農圃雜，華髮弟兄同。", "佚老便居僻，貪閑喜命窮。", "習成杯酌少，脫落語言工。", "危坐看流景，新萌又落紅。"]'),
('24353119-c1cc-4024-8011-26c7daccad08','和宗易作屋之什','陳傅良','宋','宋诗','song-poetry','','[]','欲因舊築倍勞形，昔在先生配二程。',64,'全唐诗/poet.song.158000.json','["欲因舊築倍勞形，昔在先生配二程。", "梅樹護持供北顧，萱堂潤色作東榮。", "但堪樽俎來三益，何必籓牆屏五兵。", "若徙荼𧃲分乞我，亦令兒輩記家聲。"]'),
('abc49982-7523-45ed-9cc4-13bc8537eb06','送縉雲葉正初兼簡杜伯高','陳傅良','宋','宋诗','song-poetry','','[]','我固閲人非草草，君於前輩亦拳拳。',64,'全唐诗/poet.song.158000.json','["我固閲人非草草，君於前輩亦拳拳。", "經師未數郯夫子，筆力方窺李謫仙。", "所恨尚於收第晚，將詩空與背時傳。", "頻年不信燈花報，報得人來亦可憐。"]'),
('fa2e4aaf-9a6b-4fe3-914c-75e5aa049fb4','和宗易賦素馨茉莉白蓮韻','陳傅良','宋','宋诗','song-poetry','','[]','軒窗一日粲三英，盡室無塵眼倍明。',64,'全唐诗/poet.song.158000.json','["軒窗一日粲三英，盡室無塵眼倍明。", "閩粵固嘗矜絕美，風騷猶未及知名。", "羞將姿媚隨花譜，愛伴孤高上月評。", "獨恨遇寒成弱植，色香殊不讓梅兄。"]'),
('f3931ea4-5180-4b00-b93a-ed9f7e05493d','沈仲一送菊自言封殖之勞欲得詩爲報爲賦三絕  其一','陳傅良','宋','宋诗','song-poetry','','[]','東籬何在菊年年，菊視陶詩竟孰賢。',32,'全唐诗/poet.song.158000.json','["東籬何在菊年年，菊視陶詩竟孰賢。", "未必緣詩花更好，花將詩與萬人傳。"]'),
('866e4421-a2ee-4b46-bda9-d1dd1b2672eb','沈仲一送菊自言封殖之勞欲得詩爲報爲賦三絕  其二','陳傅良','宋','宋诗','song-poetry','','[]','霜螯風味小槽春，新樣宮衣試麯塵。',32,'全唐诗/poet.song.158000.json','["霜螯風味小槽春，新樣宮衣試麯塵。", "一段秋光誰領此，芙蓉凡子桂陳人。"]'),
('5adc8c4f-a18d-4d25-8d75-893965d0d998','沈仲一送菊自言封殖之勞欲得詩爲報爲賦三絕  其三','陳傅良','宋','宋诗','song-poetry','','[]','愁乾手自搭連筒，苦雨丁丁杙小篷。',32,'全唐诗/poet.song.158000.json','["愁乾手自搭連筒，苦雨丁丁杙小篷。", "乞得花開急催客，明朝恐已著霜紅。"]'),
('4ef17086-37ac-432a-aa6f-dc1def790183','仲一以詩來用韻奉答  其一','陳傅良','宋','宋诗','song-poetry','','[]','陪侍經幃涉歲年，亦嘗尚論鞠衣賢。',32,'全唐诗/poet.song.158000.json','["陪侍經幃涉歲年，亦嘗尚論鞠衣賢。", "如今三嗅馨香泣，惟恐將詩去浪傳。"]'),
('72c0a199-4ab7-4ecc-a3bd-7229176bbb6c','仲一以詩來用韻奉答  其二','陳傅良','宋','宋诗','song-poetry','','[]','嗚咽苔移玉座春，昔年曾扈屬車塵。',32,'全唐诗/poet.song.158000.json','["嗚咽苔移玉座春，昔年曾扈屬車塵。", "重陽不見黄封酒，只見餐英獨醒人。"]'),
('4eee87d5-aac9-4f95-ad3c-890bd98298c8','仲一以詩來用韻奉答  其三','陳傅良','宋','宋诗','song-poetry','','[]','剩有新詩入遞筒，豈無能畫作掀篷。',32,'全唐诗/poet.song.158000.json','["剩有新詩入遞筒，豈無能畫作掀篷。", "金錢翠蓋相輝映，著我皤然酒借紅。"]'),
('4834123d-9680-466d-8e37-aefb5e60405c','寄題薛象先新樓','陳傅良','宋','宋诗','song-poetry','','[]','矮簷風雨送蝸牛，有客來誇百尺樓。',64,'全唐诗/poet.song.158000.json','["矮簷風雨送蝸牛，有客來誇百尺樓。", "闔郡臺池皆下瞰，背城湖海亦全收。", "清時未放徒高卧，半世何爲故倦遊。", "解盡橐金君計决，月明長笛起漁舟。"]'),
('0d73d833-5a84-42df-86d7-b20791495281','立春','陳傅良','宋','宋诗','song-poetry','','[]','千官勒馬謝幡勝，萬國鞭牛占雨晴。',32,'全唐诗/poet.song.158000.json','["千官勒馬謝幡勝，萬國鞭牛占雨晴。", "誰據槁梧相近午，頰車徐轉鼻無聲。"]'),
('d9fd5f3a-b19e-4f9a-8377-334076bc7915','除夜用前韻','陳傅良','宋','宋诗','song-poetry','','[]','春來十日垂垂雨，歲盡今朝亦未晴。',32,'全唐诗/poet.song.158000.json','["春來十日垂垂雨，歲盡今朝亦未晴。", "衰老見年殊不覺，卧聽穿葉打窗聲。"]'),
('4596f8d5-735e-47f7-8cc6-32bd19ac9e64','送子婿林申甫還侍','陳傅良','宋','宋诗','song-poetry','','[]','鏘鏘笙磬阼階東，穆穆黄流玉瓚中。',64,'全唐诗/poet.song.158000.json','["鏘鏘笙磬阼階東，穆穆黄流玉瓚中。", "近在門闌無此稱，老來襟抱更誰同。", "幽燕遺恨須收第，孔孟微言要忍窮。", "精舍一區泉石好，何時相就看冥鴻。"]'),
('9a7c1403-3164-47e4-8124-e8c28aa98c2e','遊趙園','陳傅良','宋','宋诗','song-poetry','','[]','主人避客竟何之，雨過停橈落日遲。',32,'全唐诗/poet.song.158000.json','["主人避客竟何之，雨過停橈落日遲。", "頼有畦丁曾識客，來禽花送兩三枝。"]'),
('6ae8231b-bf22-481e-a9ce-32f217bbddff','赴林宗大招賞牡丹之集','陳傅良','宋','宋诗','song-poetry','','[]','剝啄要春酌，團欒得晚晴。',48,'全唐诗/poet.song.158000.json','["剝啄要春酌，團欒得晚晴。", "千花名品下，一葦病身輕。", "文會非投轄，清歡勝絕纓。", "倦遊吾獨愧，歸趁兩山明。"]'),
('2590f36d-ae20-49bd-95b7-b5600be2b399','寄謝懷英高士','陳傅良','宋','宋诗','song-poetry','','[]','聞君已得歸山請，顧我方當絕跡時。',32,'全唐诗/poet.song.158000.json','["聞君已得歸山請，顧我方當絕跡時。", "欲葺止齋猶未就，篋中應有草堂資。"]'),
('8767dedc-8268-4879-8bcf-fe3b18266a8c','和張端士初夏','陳傅良','宋','宋诗','song-poetry','','[]','綠陰四合水迷津，春去雖愁却可人。',64,'全唐诗/poet.song.158000.json','["綠陰四合水迷津，春去雖愁却可人。", "無數飛螢窺案帙，有時乳燕落梁塵。", "滿塘荷蔭將還舊，試火包香又斬新。", "短夜得眠常不足，僧鍾遮莫報昏晨。"]'),
('1aacde8e-4a84-4b5d-a2dc-4968d7b74d3f','送周介之同年赴德化宰','陳傅良','宋','宋诗','song-poetry','','[]','民社須吾黨，江湖足此情。',48,'全唐诗/poet.song.158000.json','["民社須吾黨，江湖足此情。", "不堪秋暑近，欲趁莫潮平。", "拙宦成華髮，憂時自短檠。", "君看廬阜石，千載尚垂名。"]'),
('de70e3a8-f46c-498e-9778-894b450edb49','謝林默之居士惠酒居士山居方與世絕尚欲友此廢人耶小詩舉發一笑','陳傅良','宋','宋诗','song-poetry','','[]','不將鵞鴨惱比隣，林下蕭然老幅巾。',32,'全唐诗/poet.song.158000.json','["不將鵞鴨惱比隣，林下蕭然老幅巾。", "乞與青州十從事，添成明月兩閒人。"]'),
('ffe5559b-19bd-4e62-bbdb-7c7f64292379','戊午壽國舉兄','陳傅良','宋','宋诗','song-poetry','','[]','一母分身四白頭，從今家事付兒流。',64,'全唐诗/poet.song.158000.json','["一母分身四白頭，從今家事付兒流。", "只須老草供觴味，乍可婆娑伴釣遊。", "勞世萬人輸暇日，好天一雨薦新秋。", "平章何物宜爲壽，三十餘年晏子裘。"]'),
('351d8496-59da-43d4-a287-00a05416a492','止齋即事二首  其一','陳傅良','宋','宋诗','song-poetry','','[]','性已耐岑寂，老應忘隠憂。',48,'全唐诗/poet.song.158000.json','["性已耐岑寂，老應忘隠憂。", "齊年雙白髮，盡日一蒼頭。", "竹閉緘門鑰，蒲團數漏籌。", "未知庭廡下，還有雀羅不。"]'),
('763b18ad-3678-4c5d-907f-cc3cd25bee73','止齋即事二首  其二','陳傅良','宋','宋诗','song-poetry','','[]','教子時開卷，逢人强整襟。',48,'全唐诗/poet.song.158000.json','["教子時開卷，逢人强整襟。", "再貧看晚節，多病得初心。", "地僻茭蓮好，山低竹樹深。", "寄聲同燕社，明月又秋砧。"]'),
('bfb73364-3cd3-4acc-a6f3-5c306179e6b1','戲題止齋叢石','陳傅良','宋','宋诗','song-poetry','','[]','雖無壁立翠琅玕，聊當庭前犢鼻裩。',32,'全唐诗/poet.song.158000.json','["雖無壁立翠琅玕，聊當庭前犢鼻裩。", "我亦聞之方伎者，衆山皆大小爲尊。"]'),
('8c7c4a47-938f-426d-b75c-efd29c81d87a','重陽和朱直方韻','陳傅良','宋','宋诗','song-poetry','','[]','衰老登臨得並家，絕勝十載向天涯。',64,'全唐诗/poet.song.158000.json','["衰老登臨得並家，絕勝十載向天涯。", "直須與世爲陶令，謹勿令人識孟嘉。", "藍水悲吟空雅健，牛山醉墨謾欹斜。", "誰知竹葉雖無分，一笑何妨菊自花。"]'),
('8f67dea4-20c4-40ea-a401-84d535f95011','用徐叔子韻送其過毗陵','陳傅良','宋','宋诗','song-poetry','','[]','家食年年未解忙，浮沉閭里但壺觴。',64,'全唐诗/poet.song.158000.json','["家食年年未解忙，浮沉閭里但壺觴。", "偶緣他故趨吳會，可使吾徒憶魯狂。", "曲水風流王逸少，鑑湖窮約賀知章。", "請於百尺樓頭上，下視人間有肺腸。"]'),
('7d8551b9-bf21-409f-942e-7d085a8f5c22','送四明汪文子','陳傅良','宋','宋诗','song-poetry','','[]','文盛經生少，官輕舉子繁。',48,'全唐诗/poet.song.158000.json','["文盛經生少，官輕舉子繁。", "誰能堪遠役，相與及微言。", "殘凍留春雨，新愁起夜樽。", "斯文吾不敢，短句送歸轅。"]'),
('1d8e30fe-808d-4ef6-af7b-382b34941cbb','寄九江宋居士','陳傅良','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','篋中每閲所藏書，長憶瀟湘九宛餘。',32,'全唐诗/poet.song.158000.json','["篋中每閲所藏書，長憶瀟湘九宛餘。", "一別十年身尚健，恨無飛羽過匡廬。"]'),
('c7a40f99-3ef2-405f-a8fd-472c4df8579f','酬劉進之','陳傅良','宋','宋诗','song-poetry','','[]','冰柱劉叉句，綈袍范叔寒。',48,'全唐诗/poet.song.158000.json','["冰柱劉叉句，綈袍范叔寒。", "所親多物望，相識半人寰。", "今老猶徒步，吾窮亦厚顔。", "幽懷真易足，萬卷屋三間。"]'),
('0ec6f409-198d-454f-a529-df25ccc3f69e','己未上巳清明','陳傅良','宋','宋诗','song-poetry','','[]','霖霪故作落花天，佳節重重倍悵然。',64,'全唐诗/poet.song.158000.json','["霖霪故作落花天，佳節重重倍悵然。", "雖有庭除臨曲水，更無尊俎試新烟。", "酴醾雅欲延春賞，杜宇還能破晝眠。", "頼得二昆同一客，蕨芽蒲笋短檠邊。"]'),
('59a05b7c-0452-4c15-ba44-3d1f5612f8c1','和林宗易上巳韻','陳傅良','宋','宋诗','song-poetry','','[]','㲇㲇曙鼓五更初，枚數何門可曳裾。',64,'全唐诗/poet.song.158000.json','["㲇㲇曙鼓五更初，枚數何門可曳裾。", "孰與課兒翻故紙，幾曾緣客掃精廬。", "常饑未免時中酒，多病安能强著書。", "自笑無才供視草，徒勞身後問相如。"]'),
('9cd928d3-a219-4546-9903-e3916be4a8bb','和林宗易雨後韻兼簡沈仲一','陳傅良','宋','宋诗','song-poetry','','[]','溪山秋色日侵尋，一水循除萬木陰。',64,'全唐诗/poet.song.158000.json','["溪山秋色日侵尋，一水循除萬木陰。", "幸有新炊送農扈，可無勝踐盍朋簪。", "蒲荷綿亙衡從畝，鷗鷺追隨下上音。", "寄語北湖休獨自，摩挲周鼎與商鬵。"]'),
('b34acff2-6cb7-41cf-8da3-a1c4f2f7d76a','張端士以詩送蘭蕙因和其韻','陳傅良','宋','宋诗','song-poetry','','[]','暮春堂上抱天和，時啟柴扉與客過。',32,'全唐诗/poet.song.158000.json','["暮春堂上抱天和，時啟柴扉與客過。", "客有可人須語似，新篁來看玉森羅。"]'),
('264267d8-fecb-4d6b-90d4-76d42832d31f','寶壇寺和林宗易韻','陳傅良','宋','宋诗','song-poetry','','[]','夢回齒頰自天香，何必招魂怨渡湘。',64,'全唐诗/poet.song.158000.json','["夢回齒頰自天香，何必招魂怨渡湘。", "少待精廬天向曉，有來嘉客歲爲常。", "雲山鎮壓魚蝦市，煙雨莊嚴橘柚鄉。", "最好題名雙石闕，可題周曆萬年長。"]'),
('ffe7ab56-96a3-402a-9f1c-87d1f0453c16','答朱翔遠見別之作','陳傅良','宋','宋诗','song-poetry','','[]','總角相看五十年，行藏殊轍各皤然。',64,'全唐诗/poet.song.158000.json','["總角相看五十年，行藏殊轍各皤然。", "豈無子美書成束，欲送相如賦上天。", "俗眼不寬多小謹，交情何限復長篇。", "乘壺偶自兵厨至，聊助征帆一醉眠。"]'),
('8abf87ea-28b7-4622-ac0f-c936929cc309','嘗語客蓴鱸橙蟹的對或言今年斗門堅寒故蟹不上又今秋風急鱸魚亦鮮余發一笑因成二十八字','陳傅良','宋','宋诗','song-poetry','','[]','蓴鱸有玉西風急，橙蟹無金東海深。',32,'全唐诗/poet.song.158000.json','["蓴鱸有玉西風急，橙蟹無金東海深。", "祇爲酒醒愁夜永，二蟲得失我何心。"]'),
('6b833ae2-be68-4006-8f83-5cdcc8609f1d','因客說秋秫水傷復用前韻','陳傅良','宋','宋诗','song-poetry','','[]','風鱠不須鹽豉好，霜螯須著酒船深。',32,'全唐诗/poet.song.158000.json','["風鱠不須鹽豉好，霜螯須著酒船深。", "無由種秫求旁舍，旁舍秋螟已蠹心。"]'),
('77a27177-e0cb-4b7d-b361-ed4d5395c672','己未生朝謝莘叟兄送梅  其一','陳傅良','宋','宋诗','song-poetry','','[]','無歲探梅不恨遲，緝齋今送兩三枝。',64,'全唐诗/poet.song.158000.json','["無歲探梅不恨遲，緝齋今送兩三枝。", "也知造物多生意，亦爲畸人解笑頤。", "壬子恰同身墮地，庚申還值國開基。", "數家誇道明年好，好在長貧誦繫辭。"]'),
('1f84e3f1-85a2-4081-98f3-b11dfeeeab53','己未生朝謝莘叟兄送梅  其二','陳傅良','宋','宋诗','song-poetry','','[]','莫笑栽培日月遲，待看老幹及孫枝。',64,'全唐诗/poet.song.158000.json','["莫笑栽培日月遲，待看老幹及孫枝。", "天將臈去春回首，人與花同雪滿頤。", "萬里隴頭空故蹟，孤山籬落但餘基。", "至今佳句無人繼，誰與招魂著楚辭。"]'),
('cb9bd6e1-e04d-4416-b07c-9f4a65789eca','覓花','陳傅良','宋','宋诗','song-poetry','','[]','背山面水竹週遭，雖乏樓臺氣已豪。',32,'全唐诗/poet.song.158000.json','["背山面水竹週遭，雖乏樓臺氣已豪。", "更得好花千百本，中間容我誦莊騷。"]'),
('14468db7-f3c5-44fa-b5ee-4fef4d1c1411','和徐魏叔見寄三絕  其一','陳傅良','宋','宋诗','song-poetry','','[]','蒲團坐閲歲如梭，不管門前雀可羅。',32,'全唐诗/poet.song.158000.json','["蒲團坐閲歲如梭，不管門前雀可羅。", "投贈紵衣纔薄物，道人微笑已嫌多。"]'),
('a6411d9b-96ff-4450-a120-2759df74b7cc','和徐魏叔見寄三絕  其二','陳傅良','宋','宋诗','song-poetry','','[]','紈袴何嘗不誤身，梁園金谷草長春。',32,'全唐诗/poet.song.158000.json','["紈袴何嘗不誤身，梁園金谷草長春。", "送將重錦齊三十，笑殺生芻一束人。"]'),
('3d87f184-514d-49ad-8d60-727c5ef53c19','和徐魏叔見寄三絕  其三','陳傅良','宋','宋诗','song-poetry','','[]','獨向心源識背趨，豈於身外較精粗。',32,'全唐诗/poet.song.158000.json','["獨向心源識背趨，豈於身外較精粗。", "凄其下視人間世，朝市區區地一夫。"]'),
('a525fe36-c3f6-4915-8816-b2de18a14488','和朱宰遊丁園韻','陳傅良','宋','宋诗','song-poetry','','[]','榆火逢佳節，棠陰接勝遊。',48,'全唐诗/poet.song.158000.json','["榆火逢佳節，棠陰接勝遊。", "移樽忻及暇，乘屐共尋幽。", "日靜竹光合，風喧花氣浮。", "主情殊未倦，衰暮爲遲留。"]'),
('b630e62f-9e51-44d3-adb2-7f144ab15004','庚申上巳','陳傅良','宋','宋诗','song-poetry','','[]','何事□□□，天低雨露慳。',48,'全唐诗/poet.song.158000.json','["何事□□□，天低雨露慳。", "一□遺晚□，百感又春關。", "墨客山陰竹，騷人洧外蘭。", "誰知千古意，不在□游間。"]'),
('ed910f5a-54fb-4bca-917c-b8bfd5ea859a','清明後一日宴客明日宗易送牡丹有詩次韻','陳傅良','宋','宋诗','song-poetry','','[]','客去朝酲惡，詩來晚思和。',48,'全唐诗/poet.song.158000.json','["客去朝酲惡，詩來晚思和。", "名花如洛上，佳句近陰何。", "雨故妨新火，春應墮夢柯。", "莫將行樂地，蝸角動干戈。"]'),
('fd7857d2-f231-4fb5-aa85-f0433231df28','和汪仲嘉樓大防二尚書賀鄭貴和華文休致韻  其一','陳傅良','宋','宋诗','song-poetry','','[]','簪笏相摩入殿廬，人皆自笑此區區。',64,'全唐诗/poet.song.158000.json','["簪笏相摩入殿廬，人皆自笑此區區。", "豈無隻字踰華衮，未必千鍾勝飯蔬。", "吾見北山多後倦，誰如東里竟先驅。", "追隨曳履枌榆社，猶及香山退傅無。"]'),
('9d561b05-a2cb-4071-a202-7ee47ab79b51','和汪仲嘉樓大防二尚書賀鄭貴和華文休致韻  其二','陳傅良','宋','宋诗','song-poetry','','[]','巋然名節萬人尊，詩落文昌帝九閽。',64,'全唐诗/poet.song.158000.json','["巋然名節萬人尊，詩落文昌帝九閽。", "耄及衛公還失策，早如疎傅亦傷恩。", "華文延閣如今少，神武脩門自古存。", "我與東樓最欣慕，掖垣燈火幾同論。"]'),
('a365ffa8-7215-43a4-bd65-5b9b5db955a0','寒食早起圍爐中戲和林宗易韻二首  其一','陳傅良','宋','宋诗','song-poetry','','[]','疊帳重裘更怯風，絕憐寒食到匆匆。',32,'全唐诗/poet.song.158000.json','["疊帳重裘更怯風，絕憐寒食到匆匆。", "一春不見花開落，但說栽花費幾工。"]'),
('39cf814a-308b-4194-b14b-003d1f358bb8','寒食早起圍爐中戲和林宗易韻二首  其二','陳傅良','宋','宋诗','song-poetry','','[]','春工偏以速爲神，誰管沉痾未覺春。',32,'全唐诗/poet.song.158000.json','["春工偏以速爲神，誰管沉痾未覺春。", "禁得春寒長恣賞，甘心輸與少年人。"]'),
('443d8837-1ff2-469e-b94c-fce3ec47e8a2','晚移舟塘次值風而回華叟兄有詩次韻','陳傅良','宋','宋诗','song-poetry','','[]','經春屏跡與誰同，苦雨衣篝亦自烘。',64,'全唐诗/poet.song.158000.json','["經春屏跡與誰同，苦雨衣篝亦自烘。", "方此欲爲官况事，依然不值世情風。", "蒙茸水國蒲荷蕩，馥郁田家橘柚叢。", "最是一年行樂處，翻成咄咄坐書空。"]'),
('a9809014-eda7-453b-95db-f1bed0270172','送四明方伯起','陳傅良','宋','宋诗','song-poetry','','[]','世事關分合，人情看短長。',48,'全唐诗/poet.song.158000.json','["世事關分合，人情看短長。", "君應愁富貴，人已畏文章。", "竚立親雙鬢，追隨客累觴。", "未知歸定否，吾亦愛吾鄉。"]'),
('39d00a10-f073-4d63-97d0-f433b2cc2f1a','送楊渭夫入淮','陳傅良','宋','宋诗','song-poetry','','[]','老去關心最語離，不堪離久會還希。',64,'全唐诗/poet.song.158000.json','["老去關心最語離，不堪離久會還希。", "君方慷慨思矜振，我已婆娑喜惰歸。", "萬事莫如身自愛，十詩亦與世多違。", "倘將書寄南來鴈，且問瓊花果是非。"]'),
('8e340123-08ba-4b10-b3e8-893900f607f2','從族叔覓老桂','陳傅良','宋','宋诗','song-poetry','','[]','他山有桂老鬅鬆，好植梅旁伴槁容。',64,'全唐诗/poet.song.158000.json','["他山有桂老鬅鬆，好植梅旁伴槁容。", "著我對吟前赤壁，乞君分與左青龍。", "踰牆之樹宜無取，益屋於東本不凶。", "恭想短章蒙一笑，便呼鉏钁破苔封。"]'),
('4b3b7ff4-8dc3-4ffb-b4c6-5820931b4dc1','蓮花','陳傅良','宋','宋诗','song-poetry','','[]','伯仲之間竹與梅，魏姚聲價浪崔嵬。',32,'全唐诗/poet.song.158000.json','["伯仲之間竹與梅，魏姚聲價浪崔嵬。", "雖然亦混魚蝦處，風度自從丘壑來。"]'),
('7ac4616d-390d-423b-8b67-4904e7903fbd','寄林宗大','陳傅良','宋','宋诗','song-poetry','','[]','春已無情雨妬花，病還妬客到花家。',32,'全唐诗/poet.song.158000.json','["春已無情雨妬花，病還妬客到花家。", "今當未雨纔身健，杖策來看半吐葩。"]'),
('e7353e6a-d97e-4303-bca5-5dedccb7b758','和莘叟兄詠張子房韻','陳傅良','宋','宋诗','song-poetry','','[]','不緣多病遽懷安，閲盡人間萬事難。',32,'全唐诗/poet.song.158000.json','["不緣多病遽懷安，閲盡人間萬事難。", "謾以笑談分楚漢，竟將功業付蕭韓。"]'),
('bd59788b-99be-408a-9eb4-f147d436a024','朱及之以所種荔枝結實招飲不及赴以詩謝之','陳傅良','宋','宋诗','song-poetry','','[]','閩譜余嘗第狀元，年來雖見僅名存。',64,'全唐诗/poet.song.158000.json','["閩譜余嘗第狀元，年來雖見僅名存。", "貢存天寶猶徒擾，賦似相如亦妄論。", "每羨朝陽私沃壤，正愁秋雨妬芳樽。", "絳衣玉質今何夕，照我西歸十二軒。"]'),
('ba379a00-82c3-4b43-9728-ded6e28e22fa','從徐一之覓菊  其一','陳傅良','宋','宋诗','song-poetry','','[]','我欲作亭題獨立，苦無翠蓋著金錢。',32,'全唐诗/poet.song.158000.json','["我欲作亭題獨立，苦無翠蓋著金錢。", "園林百輩皆名勝，爲趁西風乞冗員。"]'),
('923dc734-ba34-4f66-a7d9-de1d764f9d1e','從徐一之覓菊  其二','陳傅良','宋','宋诗','song-poetry','','[]','土盆瓦斛空中久，羞見重陽插滿頭。',32,'全唐诗/poet.song.158000.json','["土盆瓦斛空中久，羞見重陽插滿頭。", "寄向柁樓煩送似，芼鱸齏蟹待新篘。"]'),
('f00df5a4-3d6d-4f32-a7ef-439a620c3fef','次韻奉酬徐一之送菊','陳傅良','宋','宋诗','song-poetry','','[]','桂叢蘭畹悄無譁，但有哀鴻天一涯。',64,'全唐诗/poet.song.158000.json','["桂叢蘭畹悄無譁，但有哀鴻天一涯。", "節物更誰知白髮，交情於此見黄花。", "聲名獨立空秋際，香色平鋪與露華。", "南雅未收騷致意，騷人應欲補詩葩。"]'),
('d418148a-d19b-432b-8cae-235011310342','廷植姪得男朱文昭寄詩於湯餠集即席和韻','陳傅良','宋','宋诗','song-poetry','','[]','喜說徐卿得二雛，吾家波及亦君餘。',64,'全唐诗/poet.song.158000.json','["喜說徐卿得二雛，吾家波及亦君餘。", "青衫手板宜從此，斷簡家藏莫付渠。", "但欲健如黄犢走，不妨錯寫弄麞書。", "更看湯餠頻頻供，笑索梅花到歲除。"]'),
('acb64951-9de0-41e0-98d2-dcf146670ad3','送鄭主簿泰興解官歸四明','陳傅良','宋','宋诗','song-poetry','','[]','師友於今說鄭鄉，親庭分付舊行藏。',64,'全唐诗/poet.song.158000.json','["師友於今說鄭鄉，親庭分付舊行藏。", "但知職分宜棲棘，盡把聲名屬憇棠。", "一字未曾緣薦墨，扁舟纔可著詩囊。", "問津漁浦多西笑，獨爲萊衣味更長。"]'),
('2a6db566-4883-4741-b639-9a6fd4f8e257','送孟延昌歸蘭溪','陳傅良','宋','宋诗','song-poetry','','[]','典同周命士，律協漢諸郎。',48,'全唐诗/poet.song.158000.json','["典同周命士，律協漢諸郎。", "師友今千載，妻孥各一方。", "髮從何處白，菊有去年黄。", "惜別無多語，關雎三斷章。"]'),
('e66fa935-56a6-4251-a629-b7fa5f2040b2','劉進之飲蕃叟弟筠亭且賦詩余與蕃叟族居蓋屏迹不出各數年於是有感次其韵','陳傅良','宋','宋诗','song-poetry','','[]','判與漁樵日往還，鶴亡蜂遁徑苔班。',64,'全唐诗/poet.song.158000.json','["判與漁樵日往還，鶴亡蜂遁徑苔班。", "何人不棄尋常事，有弟相忘咫尺間。", "寬網及余端已老，祥琴相爾未應閒。", "但將丘壑全分付，可待移文始厚顔。"]'),
('fb101cb5-4362-4ee6-8d95-2303f3d67a64','林宗易劉進之見訪有詩再用前韻','陳傅良','宋','宋诗','song-poetry','','[]','牛羊日夕鳥知還，休說年時玉笋班。',64,'全唐诗/poet.song.158000.json','["牛羊日夕鳥知還，休說年時玉笋班。", "四皓亦嘗空老去，二疏不在共功間。", "脩書尚覺歸期晚，隠几兼忘永日閒。", "况有宸章長對越，昭回雲漢不違顔。"]'),
('3d3fefea-13c6-4eb5-a53b-5896217973b4','題錢宰吸光亭圖','陳傅良','宋','宋诗','song-poetry','','[]','棲身雲夢八九上，用意風雩五六間。',32,'全唐诗/poet.song.158000.json','["棲身雲夢八九上，用意風雩五六間。", "惟有澄波兼皓月，尚憐波月蔽虧山。"]'),
('89b8a83c-0afb-4a6a-8015-d34abcbc376c','孝宗皇帝挽詞五首  其一','陳傅良','宋','宋诗','song-poetry','','[]','九廟威靈遠，三宗德業尊。',48,'全唐诗/poet.song.158000.json','["九廟威靈遠，三宗德業尊。", "謳歌思藝祖，曆數在神孫。", "欲返皇圖正，先推帝繫恩。", "諸儒議東嚮，此意定初元。"]'),
('cfbb1f59-9c82-4698-bb61-cdfc9d91f6dc','孝宗皇帝挽詞五首  其二','陳傅良','宋','宋诗','song-poetry','','[]','但謹雞鳴問，何知鶴髮侵。',48,'全唐诗/poet.song.158000.json','["但謹雞鳴問，何知鶴髮侵。", "石經方典學，盟載更關心。", "四海堯喪畢，三年舜慕深。", "匆匆付神器，長樂尚沾襟。"]'),
('248ad62a-50e5-4112-ba84-1e262b13d316','孝宗皇帝挽詞五首  其三','陳傅良','宋','宋诗','song-poetry','','[]','神機規禹迹，鬼膽破胡兒。',48,'全唐诗/poet.song.158000.json','["神機規禹迹，鬼膽破胡兒。", "大號初歸我，成功少待時。", "鞬櫜懷不滿，簞食問何遲。", "河洛空遺恨，年年上玉巵。"]'),
('6eaf063b-b7bb-40d8-b166-dbd5da5425d2','孝宗皇帝挽詞五首  其四','陳傅良','宋','宋诗','song-poetry','','[]','好學元無斁，忘疲晚有加。',48,'全唐诗/poet.song.158000.json','["好學元無斁，忘疲晚有加。", "明謨宗六藝，妙用合三家。", "照映天經緯，流傳士齒牙。", "奎文尊閣處，更合榜重華。"]'),
('33b463bf-5fb0-4bf9-80fc-7f24984c7533','孝宗皇帝挽詞五首  其五','陳傅良','宋','宋诗','song-poetry','','[]','群才何輻輳，聖度似天寬。',48,'全唐诗/poet.song.158000.json','["群才何輻輳，聖度似天寬。", "清蹕留儒館，黄金散將壇。", "風雲一語合，日月萬人看。", "攀附今無路，哀摧壯士肝。"]'),
('201c9c20-1be0-416e-b3bc-2e92dc2c3409','孝宗皇帝挽詞五首  其一','陳傅良','宋','宋诗','song-poetry','','[]','藝祖開皇極，何心畀後昆。',48,'全唐诗/poet.song.158000.json','["藝祖開皇極，何心畀後昆。", "天將翊堯運，世復見湯孫。", "武接規模在，仁追典則存。", "煌煌宋宗社，永永配乾坤。"]'),
('624b497d-fb4b-42e8-9e93-e788370e7975','孝宗皇帝挽詞五首  其二','陳傅良','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','深衷何自見，寬詔不勝書。',48,'全唐诗/poet.song.158000.json','["深衷何自見，寬詔不勝書。", "當宁延方岳，逢人問里閭。", "歲爲周委積，家被漢蠲除。", "巷哭彌天遠，長江淚不如。"]'),
('d61f00c9-0a9e-400c-aec9-f4bc00f6c176','孝宗皇帝挽詞五首  其三','陳傅良','宋','宋诗','song-poetry','','[]','豈以崇高極，能忘凜凜憂。',48,'全唐诗/poet.song.158000.json','["豈以崇高極，能忘凜凜憂。", "衣更三澣舊，費爲十金休。", "熊館無秋獵，期門絕夜遊。", "恭惟懷顯德，真可締孫謀。"]'),
('056a8c95-4e67-4651-a842-5243ef02ad74','孝宗皇帝挽詞五首  其四','陳傅良','宋','宋诗','song-poetry','','[]','貞觀真英主，三王合庶幾。',48,'全唐诗/poet.song.158000.json','["貞觀真英主，三王合庶幾。", "此時生後聖，端欲踵前徽。", "濟世功何異，除凶志偶違。", "辛勤三十載，十漸更無譏。"]'),
('02bb0ad6-d33c-4fda-a520-7495e1ee90db','孝宗皇帝挽詞五首  其五','陳傅良','宋','宋诗','song-poetry','','[]','不作脩齡夢，天乎詎可諶。',48,'全唐诗/poet.song.158000.json','["不作脩齡夢，天乎詎可諶。", "白雲新厭世，黄屋舊非心。", "德業成千古，閭閻寢八音。", "烏號在何許，霜重越山岑。"]'),
('72994a92-72ce-4cd1-a66e-bfa647c1cff5','挽吳明可給事  其一','陳傅良','宋','宋诗','song-poetry','','[]','諸老俱淪落，流風日轉移。',48,'全唐诗/poet.song.158000.json','["諸老俱淪落，流風日轉移。", "獨懷憂國意，長說渡江時。", "姓字誰如此，功名早不疑。", "却收湖海氣，燕坐雪垂頤。"]'),
('3b479259-1e04-46f8-9e62-09563aff9ec6','挽吳明可給事  其二','陳傅良','宋','宋诗','song-poetry','','[]','憶上諸生謁，公方薄恙侵。',48,'全唐诗/poet.song.158000.json','["憶上諸生謁，公方薄恙侵。", "欣然蒙絮帽，恨不醉花陰。", "自說看人熟，相期晚歲深。", "半天蒼嶺雪，回首爲沾襟。"]'),
('7146cf6a-0933-4563-ae3f-502924b62f6f','挽木奉議  其一','陳傅良','宋','宋诗','song-poetry','','[]','寵數頻年及，俞音萬口傳。',48,'全唐诗/poet.song.158000.json','["寵數頻年及，俞音萬口傳。", "豐碑來少海，大軸落台躔。", "教子宜如此，聞風亦凜然。", "送車今塞道，拱木看參天。"]'),
('add9e8ab-fcea-4965-98b1-1d199b049c96','挽木奉議  其二','陳傅良','宋','宋诗','song-poetry','','[]','盛事無虛得，玄襟可自知。',48,'全唐诗/poet.song.158000.json','["盛事無虛得，玄襟可自知。", "徧觀同輩行，誰似暮年時。", "衮冕趨椒殿，簫韶送玉巵。", "又宜天一笑，獨此有遺悲。"]'),
('d43f9296-cc04-478a-8dda-31e30248cb8e','悼蔣昇仲承事','陳傅良','宋','宋诗','song-poetry','','[]','扁舟來徃適吾真，却笑旁觀道隠淪。',64,'全唐诗/poet.song.158000.json','["扁舟來徃適吾真，却笑旁觀道隠淪。", "三釜豈無兒可就，百年要與酒相親。", "賸栽梅竹皆緣客，晚得冠裳不語人。", "試向南塘問漁牧，定於此老亦沾巾。"]'),
('5abd020d-3f5c-42fd-9860-48ae37bc4746','挽族叔父  其一','陳傅良','宋','宋诗','song-poetry','','[]','松竹深圍屋，□蓮賸種魚。',48,'全唐诗/poet.song.158000.json','["松竹深圍屋，□蓮賸種魚。", "所愁賓客少，不問稻粱餘。", "盡日□相語，盈門手自書。", "吾兒有名字，萬事聽何如。"]'),
('b31fbf6c-9dc3-4c80-840d-fdf723db381e','挽族叔父  其二','陳傅良','宋','宋诗','song-poetry','','[]','我懷終古恨，不及奉觴時。',48,'全唐诗/poet.song.158000.json','["我懷終古恨，不及奉觴時。", "滿眼看諸弟，何心賦此詩。", "牛羊來蟄蟄，丘墓去纍纍。", "亦有千鍾養，曾無一字碑。"]'),
('724aedaf-80ce-442b-bb1e-7731a6fe8a15','題丁少詹姑墓誌後','陳傅良','宋','宋诗','song-poetry','','[]','白髮從夫志，青芻爲客謀。',48,'全唐诗/poet.song.158000.json','["白髮從夫志，青芻爲客謀。", "送車今幾兩，樂土有斯丘。", "猶子聲名甚，他時雨露秋。", "摩挲看石刻，嗟惜到松楸。"]'),
('7a1e1315-0652-4d7e-881f-d77f80d2647a','挽樓朝奉  其一','陳傅良','宋','宋诗','song-poetry','','[]','裘馬朋簪盛，緋魚筦庫卑。',48,'全唐诗/poet.song.158000.json','["裘馬朋簪盛，緋魚筦庫卑。", "行藏公論在，然否寸心知。", "歲晏曾三接，民功僅一麾。", "空餘華衮字，有恨蓋棺時。"]'),
('56fe77a9-1cd5-426a-9567-ec3352903d8b','挽樓朝奉  其二','陳傅良','宋','宋诗','song-poetry','','[]','九寺方連茹，專城又夾河。',48,'全唐诗/poet.song.158000.json','["九寺方連茹，專城又夾河。", "晚看諸子好，孰與一門多。", "薄海皆驚嘆，亨衢忽薦瘥。", "大連同厚夜，其柰少連何。"]'),
('3e89aa00-c9ee-4136-854b-73896f16492b','挽包顒叟  其一','陳傅良','宋','宋诗','song-poetry','','[]','樵牧常事席，篇觴早策功。',48,'全唐诗/poet.song.158000.json','["樵牧常事席，篇觴早策功。", "有懷隨事見，不耻與人同。", "我故奇諸子，年來識此翁。", "待看稽古力，喬木已悲風。"]'),
('d1edb4e7-9299-44a9-af83-92f6e1236ddf','挽包顒叟  其二','陳傅良','宋','宋诗','song-poetry','','[]','翁子看時輩，平生不妄賢。',48,'全唐诗/poet.song.158000.json','["翁子看時輩，平生不妄賢。", "獨於公有誄，惟恐世無傳。", "他日須深刻，吾詩可附聯。", "草黄松柏禿，名與石巋然。"]'),
('7e5eb777-c876-4a76-94ec-d0063a0f5881','挽張子由母','陳傅良','宋','宋诗','song-poetry','','[]','又是君王上玉巵，未央雨露湛垂垂。',64,'全唐诗/poet.song.158000.json','["又是君王上玉巵，未央雨露湛垂垂。", "版輿此去還無恙，芝檢重來更不疑。", "四世團欒能有幾，百年澌盡亦堪悲。", "里中諸母今誰在，聽說承平祐聖時。"]'),
('7b1ee84f-15a6-462a-9c50-1a41b9be37b3','挽潘才叔母','陳傅良','宋','宋诗','song-poetry','','[]','剝啄唯深夜，門前杙小船。',48,'全唐诗/poet.song.158000.json','["剝啄唯深夜，門前杙小船。", "有兒能自致，此母已堪傳。", "竹院前聞熟，桓楹大字懸。", "病懷嗟不及，健筆附諸賢。"]'),
('ba0effb2-5048-4531-b2fe-d7272136ff30','挽周宣義','陳傅良','宋','宋诗','song-poetry','','[]','無酒澆陳草，將詩刻隧碑。',48,'全唐诗/poet.song.158000.json','["無酒澆陳草，將詩刻隧碑。", "遺名從此在，真意竟誰知。", "教子還餘事，周人亦有時。", "憶嘗從夜話，欲去更遲遲。"]'),
('b2d3ab14-ce25-4986-a3f1-870626787b45','挽婺女何茂宏','陳傅良','宋','宋诗','song-poetry','','[]','勸駕嘗連萼，應門忽二毛。',48,'全唐诗/poet.song.158000.json','["勸駕嘗連萼，應門忽二毛。", "竟於時不偶，吾更晚相遭。", "宿草堪揮淚，豐碑忍泚毫。", "送車今幾兩，誰最戀綈袍。"]'),
('948782cb-66c8-4755-8a60-3a77ff83c0e3','挽薛季益尚書  其一','陳傅良','宋','宋诗','song-poetry','','[]','徧試江淮聲藉藉，久勞荆蜀鬢蒼蒼。',64,'全唐诗/poet.song.158000.json','["徧試江淮聲藉藉，久勞荆蜀鬢蒼蒼。", "同時半已登槐棘，卒歲纔能足稻粱。", "遺藁不爲他日計，佳城尚及此丘藏。", "豈無後作多文勝，今我懷人淚欲滂。"]'),
('fe0f5cb7-4fd5-4d60-878f-f1e44024cd30','挽薛季益尚書  其二','陳傅良','宋','宋诗','song-poetry','','[]','州里誰如此達尊，戶庭深靜最情敦。',64,'全唐诗/poet.song.158000.json','["州里誰如此達尊，戶庭深靜最情敦。", "不將尺牘通當路，却枉扁舟訪杜門。", "每見色溫如有屬，欲書心愧不能言。", "從今若祭枌榆社，好配橫塘兩獻樽。"]'),
('2a81c1d4-f2ca-4907-b6cf-74d25a3d058e','挽彭通直','陳傅良','宋','宋诗','song-poetry','','[]','前輩如同郡，流風僅幾人。',48,'全唐诗/poet.song.158000.json','["前輩如同郡，流風僅幾人。", "不令兒巧宦，所尚世清貧。", "及老猶書卷，通班但幅巾。", "吾銘雖未就，鄉譽勝堅眠。"]'),
('83b2b3d4-b580-43e3-b433-f85cc7fe6c5e','挽沈次卿學正','陳傅良','宋','宋诗','song-poetry','','[]','洛學傳當代，家聲屬此翁。',48,'全唐诗/poet.song.158000.json','["洛學傳當代，家聲屬此翁。", "一生無世味，萬事與人同。", "恨不師前鄭，欣嘗客阿戎。", "宜銘千古意，豈在語言工。"]'),
('b2ae4cbb-eb34-4d5e-9101-6ad6051d0429','挽林承信','陳傅良','宋','宋诗','song-poetry','','[]','重交寧問田安在，急義固於官不知。',64,'全唐诗/poet.song.158000.json','["重交寧問田安在，急義固於官不知。", "膴仕幸多花萼好，幽棲宜與竹林期。", "床頭周易吾將老，案上楞嚴晚得師。", "此意自應天予後，嶧陽未琢長孫枝。"]'),
('38f5ea31-181e-4d50-bfd1-81d82e508ff4','悼林仲逸縣尉','陳傅良','宋','宋诗','song-poetry','','[]','家故書千卷，生纔試一斑。',48,'全唐诗/poet.song.158000.json','["家故書千卷，生纔試一斑。", "賞音殊不少，筮仕獨何艱。", "松菊將身隠，蘋蘩忽涕潸。", "幸哉賢玉潤，有誄不容刪。"]'),
('66f741f0-48b3-4a28-bf52-0435c41f2905','挽張材卿知郡','陳傅良','宋','宋诗','song-poetry','','[]','貂蟬不逮老端明，世濟誰如好弟兄。',64,'全唐诗/poet.song.158000.json','["貂蟬不逮老端明，世濟誰如好弟兄。", "能著青衫偕計吏，却將白髮去邊城。", "夜魂俄斷凝香寢，秋淚仍兼曳履聲。", "萬石君家同一傳，嗣書應更有公卿。"]'),
('89a4382f-a311-4f8a-9b85-d6b52ed2a7b6','挽新昌呂脩職  其一','陳傅良','宋','宋诗','song-poetry','','[]','頃作庵廬客，看公手種蒔。',48,'全唐诗/poet.song.158000.json','["頃作庵廬客，看公手種蒔。", "溪毛無亂理，宰木有連枝。", "久欲鑱他石，今還賦此詩。", "黯然懷宿昔，絮酒定何時。"]'),
('4070a8a7-00eb-4d6d-9521-3b187108ea2d','挽新昌呂脩職  其二','陳傅良','宋','宋诗','song-poetry','','[]','不道千山阻，將遺百世名。',48,'全唐诗/poet.song.158000.json','["不道千山阻，將遺百世名。", "有兒能自致，此老已堪銘。", "祿豈無三釜，賢誰似一經。", "吾詞雖未就，應有護幽扃。"]'),
('264180d2-ba40-446c-89a3-ce6517b0e5e8','挽尤延之尚書  其一','陳傅良','宋','宋诗','song-poetry','','[]','自爲師說竟誰宗，每事持平屬此翁。',64,'全唐诗/poet.song.158000.json','["自爲師說竟誰宗，每事持平屬此翁。", "有志政須名節是，斯文非獨語言工。", "要令舉世人材出，合在前朝行輩中。", "安得長年留把柁，後來各與一帆風。"]'),
('4e6a7ba5-100d-4ca2-b7de-afcdb6c99340','挽尤延之尚書  其二','陳傅良','宋','宋诗','song-poetry','','[]','宿留江湖長子孫，行藏節節耐人看。',64,'全唐诗/poet.song.158000.json','["宿留江湖長子孫，行藏節節耐人看。", "及爲侍從身垂老，欲試平生事轉難。", "書就僅題前太史，功成方記舊甘盤。", "令人長恨經綸意，歷事三朝見一斑。"]'),
('8dd0d8ee-917a-46f8-a9cc-f23351f5e5cd','挽尤延之尚書  其三','陳傅良','宋','宋诗','song-poetry','','[]','向來諸老獨巋然，羸不勝衣萬事便。',64,'全唐诗/poet.song.158000.json','["向來諸老獨巋然，羸不勝衣萬事便。", "燈下細書批敕字，雪邊先著趁朝鞭。", "豈應無故令身健，却止功名與世傳。", "遺奏定留封禪藁，憑誰吹送九重天。"]'),
('3607bf09-1c56-4a0a-9d9c-251da710f6d4','挽尤延之尚書  其四','陳傅良','宋','宋诗','song-poetry','','[]','壯歲從游兩鬢霜，重來函丈各堪傷。',64,'全唐诗/poet.song.158000.json','["壯歲從游兩鬢霜，重來函丈各堪傷。", "那知卒業今無及，極悔論心昨未嘗。", "相約歸期須次第，獨存病骨更凄凉。", "他年頼有門生記，託在碑陰永不忘。"]'),
('57cd1a9a-9a11-40e8-92ab-3ccb2c37cf75','挽沈虞卿侍郎  其一','陳傅良','宋','宋诗','song-poetry','','[]','官重元非好，思閒樂有餘。',48,'全唐诗/poet.song.158000.json','["官重元非好，思閒樂有餘。", "生兒早傳業，課女夜抄書。", "時事方關念，歸懷不遂初。", "經綸緣未了，天意盍留渠。"]'),
('b8ab2c4f-4232-4571-bafa-09b11965eb48','挽沈虞卿侍郎  其二','陳傅良','宋','宋诗','song-poetry','','[]','嗜古真成癖，摩挲笑眼開。',48,'全唐诗/poet.song.158000.json','["嗜古真成癖，摩挲笑眼開。", "斷編遺汲冢，名篆出秦臺。", "□□緣應盡，雲山喚不回。", "凄凉子雲宅，問字有誰來。"]'),
('031e41e9-f7f3-4608-bfac-595f3d135b83','挽東陽郭德誼','陳傅良','宋','宋诗','song-poetry','','[]','簪紱何能貴，聲名幸自脩。',48,'全唐诗/poet.song.158000.json','["簪紱何能貴，聲名幸自脩。", "凡今爲我友，幾半與君遊。", "翰墨千年托，松梧一夜秋。", "令人懷昔日，烱烱夢丹丘。"]'),
('5af24261-ac16-4dca-9755-521b9bc10e79','悼楊休甫','陳傅良','宋','宋诗','song-poetry','','[]','袖手旁觀一世餘，元非親物亦非疎。',64,'全唐诗/poet.song.158000.json','["袖手旁觀一世餘，元非親物亦非疎。", "酒邊每事如人意，燈下通宵讀我書。", "學到莊騷纔止此，生逢周漢定何如。", "西州相識無遺恨，獨恨無從摻子祛。"]'),
('1c42c77c-558b-4677-a9ef-17afa5838d41','挽宋巖老參議  其一','陳傅良','宋','宋诗','song-poetry','','[]','居然是是亦非非，錯處稠中定不疑。',64,'全唐诗/poet.song.158000.json','["居然是是亦非非，錯處稠中定不疑。", "萬事過人旁袖手，一生從衆自觀頤。", "肯爲壯縣雖嘗試，略見周行已逆知。", "盡日杜門佳客至，小槽親校酒醇漓。"]'),
('40758d69-502c-46a6-9117-018fcc85b3a1','挽宋巖老參議  其二','陳傅良','宋','宋诗','song-poetry','','[]','少小修藏近市朝，亦非著意混漁樵。',64,'全唐诗/poet.song.158000.json','["少小修藏近市朝，亦非著意混漁樵。", "不爲禦寇猶爭席，好說淵明更折腰。", "一飯重違凡子約，千金終却故人招。", "送車幾兩交相唁，我獨難忘最久要。"]'),
('32c3dc34-2057-485d-9499-b3768fa16774','悼劉謙之知錄','陳傅良','宋','宋诗','song-poetry','','[]','海內多吾友，飄零今幾人。',48,'全唐诗/poet.song.158000.json','["海內多吾友，飄零今幾人。", "相忘尤墮淚，欲誄輒傷神。", "才力矜餘地，心期耻後塵。", "溘然無一語，愁殺白頭親。"]'),
('36b59538-2964-490f-b5cf-d9e3a02c5cff','挽王興之提刑','陳傅良','宋','宋诗','song-poetry','','[]','四海王詹事，傳家有象賢。',48,'全唐诗/poet.song.158000.json','["四海王詹事，傳家有象賢。", "宦情塵滓外，風誼典刑邊。", "遺愛依前鄭，群居得少連。", "生平纔樂此，一夢涕潸然。"]'),
('5744d96a-f298-418e-9fc5-383fb1758fc4','悼濟陽夫人','陳傅良','宋','宋诗','song-poetry','','[]','久接江山境，曾論子姓文。',48,'全唐诗/poet.song.158000.json','["久接江山境，曾論子姓文。", "於焉觀內則，可以繼前聞。", "榛栗嚴賓豆，蘋蘩潔祀芬。", "有人言不朽，片石合摩雲。"]'),
('793ef868-6d71-4147-ba7b-e19706b455b2','挽張春卿尚書  其一','陳傅良','宋','宋诗','song-poetry','','[]','懷抱今遺直，身名古象賢。',48,'全唐诗/poet.song.158000.json','["懷抱今遺直，身名古象賢。", "路車陳左塾，笙磬在東懸。", "再世星辰上，三年雨露邊。", "崎嶇空老去，有識共潸然。"]'),
('2c4c41bb-deb9-47fd-935b-0303cb777bc2','挽張春卿尚書  其二','陳傅良','宋','宋诗','song-poetry','','[]','論建回天力，生平與衆同。',48,'全唐诗/poet.song.158000.json','["論建回天力，生平與衆同。", "居常焚諫草，人自避乘驄。", "朝譽多張仲，家聲近魯公。", "挽辭吾不愧，收入汗青中。"]'),
('90f7538e-aedd-48b3-a53a-6b662099c549','悼翁仲立達州  其一','陳傅良','宋','宋诗','song-poetry','','[]','憶昔看封事，令人激懦衷。',48,'全唐诗/poet.song.158000.json','["憶昔看封事，令人激懦衷。", "邊籌皆破的，硬語更盤空。", "晚亦通家好，居然與衆同。", "行藏嘗論定，誰假一帆風。"]'),
('e8268c4d-062a-415d-b94d-4af8925fe7f4','悼翁仲立達州  其二','陳傅良','宋','宋诗','song-poetry','','[]','淮幙何多譽，巴城僅一麾。',48,'全唐诗/poet.song.158000.json','["淮幙何多譽，巴城僅一麾。", "最書膚使上，好語近臣知。", "篳路江山久，維舟日月遲。", "空懷歸報牘，不逮勞還時。"]'),
('85391c58-03da-449a-b96a-0ab7349d9ea1','挽劉端木司戶','陳傅良','宋','宋诗','song-poetry','','[]','十年共語昨來非，長憶初年握手時。',64,'全唐诗/poet.song.158000.json','["十年共語昨來非，長憶初年握手時。", "身世自憐心炯炯，功名猶恐論卑卑。", "民彝亙古非蕪沒，學者如公好器資。", "緩轡徐行逢九軌，可堪倏忽九原悲。"]'),
('7d046017-2dbf-47ed-9eb9-b18d8c1d548c','挽林致賢提舉','陳傅良','宋','宋诗','song-poetry','','[]','一經韋氏學，五桂竇儀家。',48,'全唐诗/poet.song.158000.json','["一經韋氏學，五桂竇儀家。", "每耻鄉評過，深懲履道華。", "人方貴全璧，事已墮空花。", "褒衮來黄閣，千年置齒牙。"]'),
('d155bb0d-070b-4ad5-b077-2d6a22cf7360','挽劉茂實和州','陳傅良','宋','宋诗','song-poetry','','[]','欲課民庸元道州，欲評人品馬少游。',64,'全唐诗/poet.song.158000.json','["欲課民庸元道州，欲評人品馬少游。", "居無一事可切齒，薦有三公方掉頭。", "送公歷陽令我愁，目斷賓鴈書沈浮。", "識與不識涕淚流，人世安用須封侯。"]'),
('ade3309d-82f2-4c51-b993-4bbb84e3e76a','鄭自明哀詞','陳傅良','宋','宋诗','song-poetry','','[]','母曰余兒兮，吾莫知其何尤。',163,'全唐诗/poet.song.158000.json','["母曰余兒兮，吾莫知其何尤。", "婦曰良人兮，吾曷爲罹此憂。", "兄弟不以是咎兮，朋友稱其好脩。", "恭不得其故兮，庸强名之曰命。", "相彼下堂而貽戚兮，或結纓以順聽。", "萬不同咸自取兮，曾二者孰失其正聲。", "鬼神之所仇兮，人直躬焉是病。", "胥屬鏤忽墮其前兮，屈魚腹以爲穽。", "奇禍作於牖下兮，顧奚悲而宜慶。", "嗟子何傷兮，獨余懷不能以自勝。", "尚或相爾藐孤兮，天終焉其有定。"]'),
('8f5d2d05-f702-449e-a621-0004286c188b','洛陽橋','陳傅良','宋','宋诗','song-poetry','','[]','跨海爲橋布石牢，那知直下壓靈鰲。',64,'全唐诗/poet.song.158000.json','["跨海爲橋布石牢，那知直下壓靈鰲。", "基連岳嶼規模壯，勢截淵潭氣象豪。", "鐵馬著行橫絕漠，玉鯨張鬣露寒濤。", "縑圖已幸天顔照，應得元豐史筆褒。"]'),
('2e427e68-d4f4-4074-b73e-7d259a1910bb','句  其一','陳傅良','宋','宋诗','song-poetry','','[]','夢由今日賚，事與古人求。',12,'全唐诗/poet.song.158000.json','["夢由今日賚，事與古人求。"]'),
('b4c9e96b-3fa8-4b6b-93c2-78bfe0c56f84','句  其二','陳傅良','宋','宋诗','song-poetry','','[]','玉龍十二蓬山頂，寶髻三千漢殿中。',16,'全唐诗/poet.song.158000.json','["玉龍十二蓬山頂，寶髻三千漢殿中。"]'),
('66ca7ee0-aa2e-4dc0-8c54-bdb763e2bcfd','句  其三','陳傅良','宋','宋诗','song-poetry','','[]','半粧宮面迎風笑，間色仙衣带露收。',16,'全唐诗/poet.song.158000.json','["半粧宮面迎風笑，間色仙衣带露收。"]'),
('b768265f-6bdb-45b1-930c-4ee48389e092','句  其四','陳傅良','宋','宋诗','song-poetry','','[]','密葉自成金罽飾，亂英誰輯紫茸香。',16,'全唐诗/poet.song.158000.json','["密葉自成金罽飾，亂英誰輯紫茸香。"]'),
('90086bd0-4375-4a47-a2c7-9fb08e1e58ec','句  其五','陳傅良','宋','宋诗','song-poetry','','[]','凝脂新賜浴，半面更啼紅。',12,'全唐诗/poet.song.158000.json','["凝脂新賜浴，半面更啼紅。"]'),
('ae67cfcf-8f15-4095-9a31-88fb94e6675b','句  其六','陳傅良','宋','宋诗','song-poetry','','[]','苗分鄭七穆，香發謝諸郎。',12,'全唐诗/poet.song.158000.json','["苗分鄭七穆，香發謝諸郎。"]'),
('6b7579de-1039-4785-bc41-001929bebf35','句  其七','陳傅良','宋','宋诗','song-poetry','','[]','羲皇向上人。',6,'全唐诗/poet.song.158000.json','["羲皇向上人。"]'),
('f90669cb-728f-4ab7-9c99-06a72f6bc30f','晁景迂大觀庚寅冬爲四明船場後七十有餘年某適以倉氏之職至此閒而王兄季和亦來作景迂官相與訪問舊迹故傳尚有可考偶成數語簡季和因呈叔晦','呂祖儉','宋','宋诗','song-poetry','','[]','鄞川舊有船司空，小亭晚望江之東。',336,'全唐诗/poet.song.158000.json','["鄞川舊有船司空，小亭晚望江之東。", "父老猶能理前話，無錢無木人無功。", "風流已往四十載，水仙木犀徒自紅。", "吾嘗夜看司空集，元符上書入邪中。", "歲月蹉跎今幾許，俯仰一身隨轉蓬。", "自爾怕道四明守，詎有律呂爲始終。", "易系後譜此時有，又得剛說來發蒙。", "魯人獵較亦獵較，復使妙句追飛鴻。", "朅來海頭四閲月，塵埃滿袖生𣰥氃。", "平生執鞭所欣慕，追尋故蹟得數弓。", "超然之名猶可想，海氣微茫日未曨。", "越中豈是不好事，別乘皆賢心已㤝。", "場官繾綣真我友，欲來卜築祠此翁。", "大書特書景迂號，庶幾遺躅常清通。", "簿書期會目前耳，此意當令齊洛嵩。", "豐公室外草芃芃，了齋却埽耳若聾。", "當時二士相游從，夜闌太息非爲躬。", "年運而往將溟濛，後輩風□□□□。", "薄材微宦猶未工，尸祝越俎自忡忡。", "誰圖遺像寘學宮，時與先儒相磨礲。", "却歸金華守吾宗，端坐不出固其窮。"]'),
('565bb12c-9322-4f2d-b606-52642bab26b4','慈溪龍虎軒偶成  其一','呂祖儉','宋','宋诗','song-poetry','','[]','龍蟠虎踞秣陵城，甬上蒼官亦强名。',32,'全唐诗/poet.song.158000.json','["龍蟠虎踞秣陵城，甬上蒼官亦强名。", "獨占高峰傲千古，夜深月照落潮聲。"]'),
('b5f9cb6e-59d7-4c7a-bcc1-b31c1cc1105e','慈溪龍虎軒偶成  其二','呂祖儉','宋','宋诗','song-poetry','','[]','老松偃蹇卧江濱，風月煙雲寄此身。',32,'全唐诗/poet.song.158000.json','["老松偃蹇卧江濱，風月煙雲寄此身。", "不羨參天二千尺，低徊欲對小峩岷。"]'),
('e3914bbc-74e9-4330-b8ca-7d3457da7c0f','慈溪龍虎軒偶成  其三','呂祖儉','宋','宋诗','song-poetry','','[]','仙都石筍似天成，鳬水松龍是弟兄。',32,'全唐诗/poet.song.158000.json','["仙都石筍似天成，鳬水松龍是弟兄。", "走徧游人與行客，未知誰可寄深情。"]'),
('f60b406a-53b9-4faf-8230-7de0ca9f8b75','慈溪龍虎軒偶成  其四','呂祖儉','宋','宋诗','song-poetry','','[]','蒼然暮色已崢嶸，姑射山頭卧玉鯨。',32,'全唐诗/poet.song.158000.json','["蒼然暮色已崢嶸，姑射山頭卧玉鯨。", "墨客强生龍虎想，我來猶自怯威名。"]'),
('c65a16e4-04b7-4fb7-aa0c-5ebc26a1ec78','慈溪龍虎軒偶成  其五','呂祖儉','宋','宋诗','song-poetry','','[]','尚書風節映鄞川，人物蕭然又幾年。',32,'全唐诗/poet.song.158000.json','["尚書風節映鄞川，人物蕭然又幾年。", "世路逶迤雖已極，軒前龍虎尚依然。"]'),
('aea40f6a-b7ba-49ab-b5fe-bffb5e7a581c','慈溪龍虎軒偶成  其六','呂祖儉','宋','宋诗','song-poetry','','[]','年來世路轉蹉跎，正大中庸論愈多。',32,'全唐诗/poet.song.158000.json','["年來世路轉蹉跎，正大中庸論愈多。", "出本無心歸亦好，何須胸次自干戈。"]'),
('066f6fbe-fd67-41f6-8af8-906f9118ad84','泛舟至竹洲','呂祖儉','宋','宋诗','song-poetry','','[]','湖光拍天浮竹洲，隠然一面城之幽。',160,'全唐诗/poet.song.158000.json','["湖光拍天浮竹洲，隠然一面城之幽。", "中有高士披素裘，我欲從之恐淹留。", "探囊百金辦扁舟，又煩我友著意修。", "微風一動生波頭，飛棹來往倦則休。", "兀兀坐曹如繫囚，吏餘只有萬斛愁。", "一生安坐無幾求，今日棲遲如置郵。", "脫帽露頂固狂流，俯首折腰亦可羞。", "誓將入海登之罘，棄置人閒繞指柔。", "蒼然暮色下羊牛，出處語默兩悠悠。", "九原可起柳柳州，燕坐相與未始遊。"]'),
('c0ca1a00-5cfa-489a-87fb-1b9721573c30','題史子仁碧沚  其一','呂祖儉','宋','宋诗','song-poetry','','[]','相家小有四明山，更葺桃源渺莽間。',32,'全唐诗/poet.song.158000.json','["相家小有四明山，更葺桃源渺莽間。", "四面樓臺相映發，一川烟水自彎環。"]'),
('8fc68407-05d4-4637-b9c0-ca773d1b3a01','題史子仁碧沚  其二','呂祖儉','宋','宋诗','song-poetry','','[]','中州纍石勢嵯峩，城外遥峰聳翠螺。',32,'全唐诗/poet.song.158000.json','["中州纍石勢嵯峩，城外遥峰聳翠螺。", "舊說夕陽無限好，此中更得夕陽多。"]'),
('9774e39a-d751-4b15-a5a1-0f03b9cc1841','金沙臺','呂祖儉','宋','宋诗','song-poetry','','[]','謫居無地寄幽懷，□有高臺自漢開。',64,'全唐诗/poet.song.158000.json','["謫居無地寄幽懷，□有高臺自漢開。", "紫極晨光招我望，錦江春色逐誰來。", "賡歌惟憶多炎裔，作賦應憐乏賈才。", "人物若增山水勝，詩仙龍種兩奇哉。"]'),
('66f8a889-312d-4b2d-94a2-a35b0ec8cce5','題聽雨堂','呂祖儉','宋','宋诗','song-poetry','','[]','王筍參參好弟兄，幽軒共對短燈檠。',64,'全唐诗/poet.song.158000.json','["王筍參參好弟兄，幽軒共對短燈檠。", "摶風萬里志將遂，聽雨幾年心獨清。", "戯綵奉觴歡正洽，對床欹枕夢初成。", "此時細細簷花落，別是一觥風雨報。"]'),
('f513c2d9-57a4-48f0-85f6-800c6e940ce3','和趙戶曹遊南湖之篇','呂祖儉','宋','宋诗','song-poetry','','[]','金華山下舊同遊，甬水相逢又半秋。',64,'全唐诗/poet.song.158000.json','["金華山下舊同遊，甬水相逢又半秋。", "明月初開青玉匣，徹雲吹破白雲頭。", "誰能共我同清賞，且得從君散客愁。", "深夜沉沉欲回棹，浩歌相送過青州。"]'),
('567f72fc-224f-4426-bc28-d361b5916774','詩一首','呂祖儉','宋','宋诗','song-poetry','','[]','小齋標新名，清風自成響。',24,'全唐诗/poet.song.158000.json','["小齋標新名，清風自成響。", "世累已破除，陽來道方長。"]'),
('61c5c0ab-a210-4e60-80b2-37119f1f80a5','韶陽之遷道中呈汪時法  其一','呂祖儉','宋','宋诗','song-poetry','','[]','南江一道水分明，寂寂扁舟不記程。',32,'全唐诗/poet.song.158000.json','["南江一道水分明，寂寂扁舟不記程。", "回望家山在雲際，夢魂猶對短書檠。"]'),
('c11b9145-7f4a-4218-810f-7da4e251e3ea','韶陽之遷道中呈汪時法  其二','呂祖儉','宋','宋诗','song-poetry','','[]','汪氏諸郎子獨賢，相從過嶺過韶川。',32,'全唐诗/poet.song.158000.json','["汪氏諸郎子獨賢，相從過嶺過韶川。", "九齡風味猶存否，莫向南華却問禪。"]'),
('ccad156d-52d3-4caf-9fa6-dc2911c5fdd9','韶陽之遷道中呈汪時法  其三','呂祖儉','宋','宋诗','song-poetry','','[]','一川風月下扁舟，蕩漾金波泛白鷗。',32,'全唐诗/poet.song.158000.json','["一川風月下扁舟，蕩漾金波泛白鷗。", "此去韶江知幾里，九成縹渺在雲頭。"]'),
('d82d67f6-397e-4222-b551-d48efe38540a','道上有感','呂祖儉','宋','宋诗','song-poetry','','[]','羣書亂插架，荏苒忽忘年。',132,'全唐诗/poet.song.158000.json','["羣書亂插架，荏苒忽忘年。", "歸來誰謂必，拂拭復茫然。", "聖遠道難繼，事變如山連。", "寒夜煨芋栗，炎天浮藕蓮。", "時與舊朋儔，曳杖訪林泉。", "忽來朝市中，歲月復推遷。", "一朝忽南去，道里有餘艱。", "韶陽號善地，九齡亦稱賢。", "杜門省愆咎，夙夜問周旋。", "異時歸故里，拜掃明招阡。", "目力儻未衰，庶幾守遺編。"]'),
('7533cecc-56d4-4344-b265-b0cd11f10c95','送汪時法歸金華  其一','呂祖儉','宋','宋诗','song-poetry','','[]','扁舟南去意茫然，襆被追隨便欲前。',32,'全唐诗/poet.song.158000.json','["扁舟南去意茫然，襆被追隨便欲前。", "親故道途相與語，但言高義薄雲天。"]'),
('eb4ec2c7-153d-45f4-af7c-23ddc476f97c','送汪時法歸金華  其二','呂祖儉','宋','宋诗','song-poetry','','[]','梅潦因仍不計旬，舟車屢易敢因循。',32,'全唐诗/poet.song.158000.json','["梅潦因仍不計旬，舟車屢易敢因循。", "昭真觀裏泠泠水，豈解遊人有怒瞋。"]'),
('80c7b24d-6798-4c12-9d42-5b7a1d3c7c83','送汪時法歸金華  其三','呂祖儉','宋','宋诗','song-poetry','','[]','霽虹解纜動江聲，風不隨人舟易橫。',32,'全唐诗/poet.song.158000.json','["霽虹解纜動江聲，風不隨人舟易橫。", "咫尺青泥含淡月，何時相對話平生。"]'),
('70daf1aa-a607-4d1b-80dc-eaf957a40ba3','送汪時法歸金華  其四','呂祖儉','宋','宋诗','song-poetry','','[]','問途快閣得寬恩，舟轉風移日未昏。',32,'全唐诗/poet.song.158000.json','["問途快閣得寬恩，舟轉風移日未昏。", "山月相忘期度歲，別懷祗覺暗銷魂。"]'),
('1f0e3ce1-f9e3-45f2-a0d1-4f4505954f06','送汪時法歸金華  其五','呂祖儉','宋','宋诗','song-poetry','','[]','人言追送不嫌遠，我獨衰殘懶出門。',32,'全唐诗/poet.song.158000.json','["人言追送不嫌遠，我獨衰殘懶出門。", "重教來時路旁候，猶留風月伴黄昏。"]'),
('9e7b8255-1004-4236-b2ee-bf9dbd980250','送汪時法歸金華  其六','呂祖儉','宋','宋诗','song-poetry','','[]','歸去兒曹欲與言，相思切處莫窺園。',32,'全唐诗/poet.song.158000.json','["歸去兒曹欲與言，相思切處莫窺園。", "吾宗事業無多子，守得簞瓢始見根。"]'),
('5b9dc5b6-5439-483b-9bdb-223d4af430fe','送汪時法歸金華  其七','呂祖儉','宋','宋诗','song-poetry','','[]','携手山橋第一軒，誰能結我夢中緣。',32,'全唐诗/poet.song.158000.json','["携手山橋第一軒，誰能結我夢中緣。", "他年有意重過我，細細爐熏理舊編。"]'),
('f8892e4a-58d8-4832-b0df-0e53c3eb1682','送時法登舟','呂祖儉','宋','宋诗','song-poetry','','[]','四山寒雨送行舟，獨掩柴扉淚未收。',32,'全唐诗/poet.song.158000.json','["四山寒雨送行舟，獨掩柴扉淚未收。", "歸見故人應問我，爲言卒歲敢優游。"]'),
('e0d4b949-d51c-4fc7-8597-06864c535357','白紵辭','李丙','宋','宋诗','song-poetry','','[]','嬌如花，美如玉，越溪女兒十五六。',64,'全唐诗/poet.song.158000.json','["嬌如花，美如玉，越溪女兒十五六。", "光風入簾睡初足，起畫修眉遠山綠。", "飛香走紅三月心，一聲白紵千黄金。", "高堂客散燈火深，醉鬢斜釵夜沈沈。"]'),
('03d7cb9f-18bf-4e87-ba46-529e7d8d64ca','夜夜曲','李丙','宋','宋诗','song-poetry','','[]','玉窗結怨歌幽獨，絃絕鸞膠幾時續。',64,'全唐诗/poet.song.158000.json','["玉窗結怨歌幽獨，絃絕鸞膠幾時續。", "銅龍漏促春夜長，冷雨酸風亂心曲。", "閒熏翠被鬰金香，拂拭繡枕屏山綠。", "飛飛乳燕歸不歸，寂寞流蘇帳前燭。"]'),
('2771269f-8465-4682-a10a-631f41aec00a','攻媿齋','樓鑰','宋','宋诗','song-poetry','','[]','聖賢不得見，道散固已久。',192,'全唐诗/poet.song.158000.json','["聖賢不得見，道散固已久。", "學者多自賢，鮮肯事師友。", "顛冥聲利中，悔吝皆自取。", "動言無媿怍，未知果然否。", "寡過云未能，先聖欣善誘。", "凜凜孟氏言，幾希異禽獸。", "參乎病知免，遂使啟足手。", "寧知起易簀，又在此段後。", "吾儕況小人，氣質素凡陋。", "以其所以養，孝道亦何有。", "勉前類水馬，立處祇如舊。", "儻復不自力，其末當愈謬。", "每思攻所媿，扁榜銘座右。", "三誦故人書，慙汗幾欲溜。", "夫豈爲戲言，知君於我厚。", "因之更加警，補過尚無咎。"]'),
('5e04db38-0bb5-4327-9360-6676c645b2dc','謝湖山居士示和陶詩','樓鑰','宋','宋诗','song-poetry','','[]','淵明千載人，風節仰孤峭。',288,'全唐诗/poet.song.158000.json','["淵明千載人，風節仰孤峭。", "豈惟辭督郵，蓮社不得召。", "書不求甚解，眼高得玄要。", "詩亦本無意，但寫胸中妙。", "齊梁紛衆作，嘈雜春禽叫。", "稚子候簷隙，文通劇搜紹。", "矯矯玉局翁，尚友謝浮漂。", "飽喫惠州飯，追和欲同調。", "湖山老居士，宏才盍廊廟。", "出入官五紀，懷歸自年少。", "屢賡歸來辭，吾行有先兆。", "老龍卧林壑，年高德彌邵。", "向來批敕手，甘心事耕釣。", "築室據仙居，泉石造深穾。", "亭榭望堂皇，蓬萊對圓嶠。", "涉園日成趣，遇客酒頻釂。", "巖巖鸞鶴姿，炯炯雙眸瞭。", "墮體黜聰明，坐忘樂遺照。", "西疇時告春，東臯快舒嘯。", "襟期古暗合，此事不容詔。", "盡和靖節詩，筆走追風驃。", "又如裴旻劍，騰空徑投鞘。", "人生嗜慾深，山林不供燒。", "何當從公游，翛然寧荷蓧。"]'),
('cfa856ba-9fb9-4fdb-a3e6-a13e7c7f2a36','送袁和叔尉江陰','樓鑰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','澄江少日曾經行，高城傍有長江橫。',384,'全唐诗/poet.song.158000.json','["澄江少日曾經行，高城傍有長江橫。", "君山特立江之汀，下瞰淮甸一掌平。", "申港引潮深無聲，萬頃灌注滋農耕。", "戰國今幾二千齡，黄歇此地猶垂名。", "舊以邑屬南蘭陵，疲於奔命吏失寧。", "今焉裂地爲專城，獨當一面行雙旌。", "井市雖小民厚生，四十萬緡輸賦征。", "舶商輻湊衆貨贏，牒訴簡省官曹清。", "一邑負郭相依憑，守宰同僚齊弟兄。", "脈絡貫通易盡情，尉職無卑近編氓。", "坐閲是否真權衡，傍郡孔道困將迎。", "我乃靜趣如郊坰，安輿並行人子榮。", "況有海錯供庖烹，河肫鰣鮆鮮不腥。", "車螯蛤蟹均藜羹，夫君傳家有典刑。", "父子知己人一經，詩書滿門不慙卿。", "豈羨漢士黄金籝，薦口久已徹帝京。", "九萬自此開鵬程，平生寒窗照短檠。", "興亡千古無遁形，妙年射策當彤庭。", "歸領後生爲主盟，友朋講習誠專精。", "世故多端須飽更，京口直下連滄溟。", "官府闊稀行旅驚，邊頭久無夕烽青。", "要在彈壓潢池兵，簿書期會勤經營。", "人物酬應審重輕，一言行之可終身。", "謹毋失己毋失人，贈人以言豈吾能。"]'),
('4f831ec4-150e-4197-858a-bc0a54f4a975','登育王望海亭','樓鑰','宋','宋诗','song-poetry','','[]','瘦藤拄破山頭雲，山蹊盡處開危亭。',144,'全唐诗/poet.song.158000.json','["瘦藤拄破山頭雲，山蹊盡處開危亭。", "平田萬頃際大海，海無所際空冥冥。", "乾端坤倪悉呈露，飛帆去鳥無遺形。", "蓬萊去人似不遠，指點水上三山青。", "褰裳濡足恐未免，儻有飈馭吾當乘。", "是中始覺宇宙大，眼力雖窮了無礙。", "雲夢八九不足吞，回視塵寰一何隘。", "曾聞芥子納須彌，漫說草庵含法界。", "看我振衣千仞岡，笑把豪端捲煙海。"]'),
('6e31771e-662b-4a37-98d4-34b352f1b72f','林景思雪巢','樓鑰','宋','宋诗','song-poetry','','[]','四時不皆雪，陸居本非巢。',192,'全唐诗/poet.song.158000.json','["四時不皆雪，陸居本非巢。", "高人興寄遠，表此一把茅。", "吾非二祖可，夜立寒齊腰。", "吾非鳥窠師，結廬真樹梢。", "白日照我心，不以見睍消。", "兩脚踏實地，風雨無漂摇。", "作詩窮益工，寒瘦逼島郊。", "落筆句驚人，不復尋推敲。", "客至不問誰，淡若君子交。", "直氣干霄上，下視鄙斗筲。", "富貴頃刻花，誰能等幻泡。", "附離如幕燕，自謂漆與膠。", "先生閲世熟，兀坐山城坳。", "春陽會有時，豈曰終繫匏。", "錫山寄雄文，凜然豎髮毛。", "我非敢言詩，爲君聊解嘲。"]'),
('ccf908fe-184a-469a-9ff6-d82090857618','題龍眠畫騎射拖毬戲','樓鑰','宋','宋诗','song-poetry','','[]','綠楊幾枝插平沙，柔梢裊裊隨風斜。',208,'全唐诗/poet.song.158000.json','["綠楊幾枝插平沙，柔梢裊裊隨風斜。", "紅綃去地不及尺，錦袍壯士斫鬃射。", "橫磨箭鋒滿分靶，一箭正截紅綃下。", "前騎長纓拖繡毬，後騎射中如星流。", "繡毬飛䃂最難射，十中三四稱爲優。", "元豐策士集英殿，金門應奉人方倦。", "日長因過衛士班，飛騎如雲人馬健。", "駕幸寶津知有日，窮景馳驅欣縱觀。", "龍眠胸中空萬馬，駭目洞心千萬變。", "追圖大槩寫當時，至今想象如親見。", "靜中似有叱咤聲，墨淡猶疑錦繡眩。", "閑窗撫卷三太息，五紀胡塵暗畿甸。", "安得士馬有如此，長驅爲决單于戰。"]'),
('37235b89-2da9-4331-b986-40ab8eeee556','題羅春伯所藏脩禊序','樓鑰','宋','宋诗','song-poetry','','[]','東游登會稽，祇見蘭亭不見碑。',126,'全唐诗/poet.song.158000.json','["東游登會稽，祇見蘭亭不見碑。", "北過中山府，欲訪此碑不知處。", "閒從故家看墨本，如此二者絕難遇。", "曾經耶律氈裹去，至今胡虜猶知慕。", "時將一二餽膚使，持歸往往快先覩。", "未知玉石真在否，要比江南終近古。", "他日縛取呼韓作編戶，勒銘歸來過定武。", "只問君王乞此碑，打向人間莫論數。"]'),
('ff4d820f-d85d-4a2f-91d3-95b8dde9de98','題孟東野聽琴圖因次其韻','樓鑰','宋','宋诗','song-poetry','','[]','誰歟住前谿，夜深以琴鳴。',108,'全唐诗/poet.song.158000.json','["誰歟住前谿，夜深以琴鳴。", "天高顥氣肅，月斜映疎星。", "橡林助蕭瑟，泉聲激琮琤。", "彈者人定佳，能使東野聽。", "束带不立朝，遥夜甘空庭。", "龍眠發妙思，神交窮杳冥。", "不見彈琴人，畫出琴外聲。", "郊寒凜如對，作詩太瘦生。", "恨不從之游，撫卷空含情。"]'),
('d4c7ac3d-a7db-4348-afe8-6b1355822a1e','壽安撫伯父','樓鑰','宋','宋诗','song-poetry','','["\u897f\u6e56", "\u6d1e\u5ead\u6e56"]','東樓德澤流無窮，我公挺生慶所鍾。',384,'全唐诗/poet.song.158000.json','["東樓德澤流無窮，我公挺生慶所鍾。", "瓊枝玉樹瑩精彩，迥然不墮風塵中。", "少年慷慨吐虹氣，文詞元不減儕輩。", "胸中妙藴經綸才，剸劇裁繁特餘事。", "曾從蓮幕試牛刀，舉城但識劉功曹。", "瀾翻薦口動天聽，一語便逾華衮褒。", "上方欲革嶺南弊，柬才果得吳刺史。", "不妨一勺飲貪泉，清德泠泠今可紀。", "憑軾雍容安七閩，列郡合詞稱得人。", "從茲十載秉麾節，坐令萬里回陽春。", "洞庭風月瀟湘雨，君王無復憂南顧。", "抗章乞得半生閑，遥指家山賦歸去。", "廟堂未肯閑宏材，大開東閤需公來。", "朝隨召節赴天闕，夜馳使馹歸長淮。", "廣陵卧治要汲直，金節熒煌照熊軾。", "底用腰纏十萬錢，且看身享二千石。", "忽思鱸膾寒菰羹，拂衣欲遂鄉關情。", "視去西陽如脫屣，意色蕭然同鬭生。", "畫船重泛西湖上，水光山色都無恙。", "主人管領東風回，故園桃李倍清爽。", "六鼇背負三山歸，輪囷老檜蒼龍姿。", "了無塵俗敗人意，棐几長物皆瑰奇。", "橫岸綸巾披鶴氅，神情直出羲皇上。", "塵事到頭曾不聞，卧聽歌臺傳煖響。"]'),
('25aca397-261d-4817-bc60-b617b24c0639','送伯舅汪運幹','樓鑰','宋','宋诗','song-poetry','','[]','人生自古悲別離，別離今日何足悲。',304,'全唐诗/poet.song.158000.json','["人生自古悲別離，別離今日何足悲。", "試問今日行者誰，鄞江名族真男兒。", "虬鬚燕頷軀十圍，凜凜端有熊豹姿。", "毅然剛立不怒威，笑視鼠輩何脂韋。", "州縣小試囊中錐，政績今在衆口碑。", "姓名通籍黄金閨，便汎王儉紅蓮池。", "平時幕府多素尸，坐縻公粟遨以嬉。", "只今方當多事時，正要名士同驅馳。", "森森百萬虎與貔，荷戈分駐淮東西。", "兩淮千里雙使麾，幕中僚吏皆擢犀。", "惟公婉畫明蓍龜，辯如懸河不可隄。", "胸中武庫深難窺，決策固有堂上奇。", "朔風吹空黄草齊，正恐秋高胡馬肥。", "萬人相顧目睽睽，見公此去多腹非。", "公獨襆被行不疑，單車西去征馬嘶。", "平生氣槩衝虹霓，恨無尺箠笞羌夷。", "方今天相中興期，黠虜戴頭來邊陲。", "願公速蹈功名機，匈奴不滅何家爲。", "出門千里何足辭，但願滿引金屈巵。"]'),
('c136e12c-f3dd-4e16-900d-95639c6207cc','月夜汎舟姚江','樓鑰','宋','宋诗','song-poetry','','[]','秋暑不可能，幾思泛中川。',132,'全唐诗/poet.song.158000.json','["秋暑不可能，幾思泛中川。", "晚來興有適，溪船偶及門。", "涼月纔上弦，平潮可黄昏。", "倚楫縱所如，卧看龍泉山。", "長虹跨空闊，過之凜生寒。", "坐穩興益佳，夜氣方漫漫。", "草蟲鳴東西，飛烏相與還。", "仰頭數明星，垂手摇碧瀾。", "坐客惜此景，不及携清樽。", "無酒要不惡，徜徉足幽歡。", "幽歡有何好，叩舷澹無言。"]'),
('2372c862-eebb-466e-8ad7-a99890dbfa74','送王正言守永嘉','樓鑰','宋','宋诗','song-poetry','','[]','江頭潮生江月小，暝煙綠暗垂楊道。',323,'全唐诗/poet.song.158000.json','["江頭潮生江月小，暝煙綠暗垂楊道。", "有客扁舟送史君，道傍不怕揶揄笑。", "向來一別三換歲，正喜情親得傾倒。", "吏民引頸望旌麾，空有離愁滿懷抱。", "史君讀殘萬卷書，古事今事俱了了。", "便應珥筆侍天陛，不然代言登鳳沼。", "瀛堧山水久寂寥，爲屈朱轓來坐嘯。", "帢幘峯高舊題詠，赤城所在經行飽。", "永嘉名郡太守尊，靈運後來詩絕少。", "天作鴈蕩地爲藏，蠟屐穿山未曾到。", "改轅却向箇中去，更得江山助詩好。", "齋鈴靜處定得句，不待池塘夢春草。", "去年海水上平地，大風駕浪從天杪。", "蒼生濈濈生魚頭，聚落隨波迹如掃。", "今年二麥連野秀，田家扶犁事秔稻。", "史君憂國眉不開，叱馭徑行仍及早。", "哀哉千里方更生，縣官租錢須戶曉。", "縱民自恐上不足，誅取仍憐下無告。", "邦儲邦本孰輕重，肯使疲民困征擾。", "君不見巖巖千古陽道州，政拙催科自書考。"]'),
('9b7e99c9-7432-4037-96fb-9011368a417e','遊龍瑞宮','樓鑰','宋','宋诗','song-poetry','','[]','隔山望危石，老面凜如鐵。',156,'全唐诗/poet.song.158000.json','["隔山望危石，老面凜如鐵。", "路回兩屏開，見此高嵽嵲。", "偉哉名公卿，峩冠會朝列。", "又如鼓迅霆，玄雲助擊烈。", "癡陰不作雨，空翠襲冰雪。", "野水不知源，遶徑幾萬折。", "子長真愛奇，萬里探禹穴。", "我家甬水東，扁舟輕入越。", "竊此半日閑，到處輒清絕。", "傳聞古洞天，瓊臺照金闕。", "神僊杳難問，一笑山石裂。", "相逢客路中，翻手數年別。", "勝地更躋攀，莫厭屐齒折。"]'),
('aa9a8714-ad51-425a-88dc-cd8d574271df','三日不得過都泗堰','樓鑰','宋','宋诗','song-poetry','','[]','南朝何公棲禹穴，嘉遁悠然志高潔。',64,'全唐诗/poet.song.158000.json','["南朝何公棲禹穴，嘉遁悠然志高潔。", "一朝送人都泗埭，歸嘆此途於此絕。", "我亦何爲走塵埃，數年不記幾往來。", "船橫三日不得度，愧想高風安在哉。"]'),
('88d0e983-01af-455c-b4af-9e232178b609','宿佛日山','樓鑰','宋','宋诗','song-poetry','','[]','平生臨平山，知誦藕花句。',168,'全唐诗/poet.song.158000.json','["平生臨平山，知誦藕花句。", "輕帆幾來往，山色澹如故。", "寧知千萬峯，中間著佳趣。", "蕭蕭蒼髯翁，爲指花城路。", "我來春正濃，天寒日將暮。", "雲深鍾唄鳴，自喜得勝具。", "緬懷玉局僊，老筆掃朝霧。", "玉槊儼相持，珠旒竟何所。", "惟餘渥洼水，蒼龍角牙露。", "人間翻覆手，烈日變煙雨。", "俗子眩炎涼，三四錯賦芋。", "道人笑視之，萬化隨所遇。", "深坐十笏地，一息了千慮。", "箇中誰得知，幽鳥背人去。"]'),
('5d0a4398-cf3b-4cbb-9995-da5a941d9c6c','求仲抑招遊山歸途遇雨','樓鑰','宋','宋诗','song-poetry','','[]','竹輿遶湖濱，宿露尚厭浥。',240,'全唐诗/poet.song.158000.json','["竹輿遶湖濱，宿露尚厭浥。", "徑到玉岑下，坐久客始集。", "起穿靈石山，萬松介而立。", "梅天氣清潤，空翠行可挹。", "古藤幾百年，枝蔓兩山及。", "見說春暮時，花紫光熠熠。", "直疑老潜虬，初起夜來蟄。", "俯翫歲寒泉，齒冷不敢吸。", "相將上龍泓，塵鞅謝羈馽。", "洞有靈獸居，臨深心岌岌。", "魚游明鏡中，巨浪無三級。", "寒苔載水去，萬頃潤原隰。", "濛濛山雨來，歸僕鳥飛急。", "野興殊未已，日昃不暇給。", "衝泥上湖船，雨陣遽奔襲。", "飄風將急點，回旋驚四入。", "中流益蕩兀，短蓬不當笠。", "停篙亦久之，怒勢不少戢。", "我徒方嘯歌，弗爲改豪習。", "但恥缾罍罄，莫問衣裳濕。"]'),
('810a8fe2-516d-434b-82c4-74ae6c359377','吳江舟中','樓鑰','宋','宋诗','song-poetry','','[]','阿連久矣共一被，小別愁生夜無寐。',64,'全唐诗/poet.song.158000.json','["阿連久矣共一被，小別愁生夜無寐。", "風帆將我上征途，回首江山忽千里。", "小舟橫卧吳江水，夢回依約蕭齋裏。", "五更漏急月黄昏，烏鵲一聲人未起。"]'),
('536e265b-0c9c-47be-a3fb-82b5c0b617ad','讀范吏部三高祠堂記','樓鑰','宋','宋诗','song-poetry','','[]','三高之風天與高，三高之靈或可招。',192,'全唐诗/poet.song.158000.json','["三高之風天與高，三高之靈或可招。", "小山以後無此作，具區笠澤空寥寥。", "幾從垂虹蕩雙槳，寓目滄浪獨怊悵。", "筆端不倒三峽流，欲遽招之恐長往。", "前身陶朱今董狐，襟抱磊落吞江湖。", "瑰詞三章妙天下，大書深刻江之隅。", "我來誦詩凜生氣，若有人兮在江水。", "扁舟獨釣膾鱸魚，茶竈筆床歸甫里。", "先生固是丘壑人，只今方迫功與名。", "謝公捉鼻恐未免，便看林藪生風雲。", "他年事業滿彜鼎，乞身歸來坐佳境。", "不嫌俗士三斗塵，容我漁蓑理煙艇。"]'),
('ac65d163-6ca3-4e8f-9e8e-ba27fc8f7399','僊都獨峰','樓鑰','宋','宋诗','song-poetry','','[]','漢家武徹求神僊，方士搤掔多夸言。',176,'全唐诗/poet.song.158000.json','["漢家武徹求神僊，方士搤掔多夸言。", "蓬萊隔海不可到，屬車方羊上橋山。", "傳聞黄帝久僊去，胡爲有石高巑岏。", "游談不經理欲屈，謾言此地藏衣冠。", "縉雲自是僊窟宅，萬壑千巖比如櫛。", "突然一石摩青雲，造化應勞巨靈擘。", "僊風吹墮碧蓮花，玉井半空人不識。", "望之不計幾千尺，八柱擎天此其一。", "伯夷制行高且孤，萬世猶能立懦夫。", "英魂凜凜今不死，化作此石山之隅。", "橫斜轍迹依然在，我亦何能窮古初。"]'),
('0280fc3e-8817-4ae8-8591-2cae48e0ec5c','靈壁道傍怪石','樓鑰','宋','宋诗','song-poetry','','[]','飽聞茲山産奇石，東南寶之如尺璧。',163,'全唐诗/poet.song.158000.json','["飽聞茲山産奇石，東南寶之如尺璧。", "誰知狼藉亂如麻，往往嵌空類鑱刻。", "長安東風萬歲山，搜抉珍怪窮人間。", "汴流一舸載數輩，徑上艮嶽增孱顔。", "當時巧匠斲山骨，寘之河干高突兀。", "干戈動地胡塵飛，坐使奇材成棄物。", "君不見黄金橫带號神運，不數臺城拜三品。", "只今零落荒草中，萬古淒涼有遺恨。", "木人漂漂不如土，坐閲興亡知幾許。", "行人沉嘆馬不前，石雖不言恐能語。"]'),
('e494d70b-11a0-4021-9cdb-c1611144a6f0','括蒼溪漲','樓鑰','宋','宋诗','song-poetry','','[]','雨餘大溪觸山流，氣勢直欲凌沙洲。',64,'全唐诗/poet.song.158000.json','["雨餘大溪觸山流，氣勢直欲凌沙洲。", "浮梁中分斷螮蝀，流沫東去行蛟虬。", "人家嘈嘈避新漲，雲稼苒苒添平疇。", "漁翁輕生有如此，小艇橫絕隨飛鷗。"]'),
('2bf780b0-f803-4096-9ad9-56f37ccf3540','石門洞','樓鑰','宋','宋诗','song-poetry','','[]','扁舟百里蓮城回，青山中斷立兩崖。',192,'全唐诗/poet.song.158000.json','["扁舟百里蓮城回，青山中斷立兩崖。", "清都虎豹隠不見，但見閶闔排雲開。", "峯回失喜大飛瀑，聲震萬壑驚春雷。", "掀髯目極九霄外，玉虹千丈飛空來。", "一冬青女靳天雪，不知聚此山之隈。", "傳聞神龍卧其上，寶藏擊碎真瓊瑰。", "胸中先自無塵埃，到此更覺心崔嵬。", "天風爲我噀空翠，春水瀉入騷人懷。", "謫僊曾來寫勝句，劉郎又爲開天台。", "我慚筆無挽牛力，醉墨滿壁誰爲裁。", "或言龍湫更奇絕，鴈山高處深雲埋。", "我方携筇往尋訪，未知比此何如哉。"]'),
('33c209ac-b7a4-4241-8057-6141b4367082','大龍湫','樓鑰','宋','宋诗','song-poetry','','[]','北上太行東禹穴，鴈蕩山中最奇絕。',240,'全唐诗/poet.song.158000.json','["北上太行東禹穴，鴈蕩山中最奇絕。", "龍湫一派天下無，萬口贊揚同一舌。", "行行路入兩山間，踏碎苔痕屐將折。", "山窮路斷脚力盡，始見銀河落雙闕。", "矩羅宴坐看不厭，騷人弄詞困搜抉。", "謝公千載有遺恨，李杜復生吟不徹。", "我遊石門稱勝地，未信此湫真卓越。", "一來氣象大不侔，石屏倚天驚鬼設。", "飛泉直自天際來，來處益高聲益烈。", "從他倒瀉三峽流，到此誰能定優劣。", "鴈山佳趣得要領，一日盡游神惡褻。", "驪龍高卧喚不應，自媿筆端無電掣。", "輪囷蕭索湍不怒，非霧非煙亦非雪。", "我聞涷雨初霽時，噴擊生風散空闊。", "更期雨後再來看，浄洗一生煩惱熱。"]'),
('aa28e87f-13af-47e9-ab92-fddd68e4558f','連雲亭望海中諸山','樓鑰','宋','宋诗','song-poetry','','[]','鴈山本在雲海中，波濤千古相撞舂。',160,'全唐诗/poet.song.158000.json','["鴈山本在雲海中，波濤千古相撞舂。", "泥沙洗盡見山骨，巖壑所在皆玲瓏。", "是誰一口吸水盡，平地卓立成奇峯。", "至今往往有遺迹，相傳渺漭何能窮。", "我乘單車來自東，佳處千數一覽空。", "晚登四十九盤頂，曠望巨海煙濛濛。", "羣山錯立不知幾，朝日照耀天霞紅。", "是閒瑰奇定多有，鯨波掩蔽深莫通。", "我無太真燬犀法，安得一闖馮夷宮。", "會聞滄海變成陸，却與鴈山爭長雄。"]'),
('aa6865e6-3fdf-40e0-8d02-249a6bd9e0ed','寄題張法曹瞻雲軒','樓鑰','宋','宋诗','song-poetry','','[]','張侯名軒意可知，如登太行看雲移。',208,'全唐诗/poet.song.158000.json','["張侯名軒意可知，如登太行看雲移。", "我雖未得登軒墀，不鄙要我巴人詞。", "爾時膝下遨以嬉，欲斵數語語不隨。", "娛侍東嘉樂無涯，官舍偪仄親不怡。", "安輿相將甬水湄，日日東望勞支頤。", "秋風得檄欣星馳，歸拜親下聊信眉。", "官事有程不得違，欲去故國行遲遲。", "重來橘柚黄金垂，霜著新蟹雙螯肥。", "海魚甘鮮一尺圍，欲奉色養春爲期。", "瞻雲之思今同之，慨然落筆成新詩。", "人閒至樂在庭闈，何用自縛微官爲。", "君方欲解左顧龜，我亦日思投檄歸。", "相望百里俱萊衣，從他天外閑雲飛。"]'),
('64f5f47b-50f8-4686-9dc9-fd3cdab88f14','次韻翁處度同遊北山','樓鑰','宋','宋诗','song-poetry','','[]','兩夫持鎌行我先，巧尋徑路其智專。',384,'全唐诗/poet.song.158000.json','["兩夫持鎌行我先，巧尋徑路其智專。", "我扶枯藤衣短後，意氣已出層峯巔。", "何郎鮑叔飽經歷，勝處一一手自編。", "我携舊記訪陳迹，正恐急景不得延。", "當年共登青雲梯，今日邀我爲擊鮮。", "始觀神龜闖清泚，上有石壁來飛泉。", "隠清遺基平可坐，下顧亂石如磨鋋。", "懸崖雙瀑灑空雪，來自一握孤雲天。", "却從下流泝深險，崎嶇直到清潭邊。", "朝陽射光破幽閟，斷虹上下遮潺湲。", "傳聞高山更高處，雅有行路從西偏。", "同行無乃深好事，盃酒自犒脚力全。", "誅鋤荆棘窮鳥道，欲進不得意愈堅。", "旋呼僮僕累危石，笑採野菊聊盤旋。", "捫蘿騰身上苔磴，往往歡呼爭著鞭。", "側行危步汗浹背，石角或使衣裳褰。", "少焉身在雙瀑上，又見高派衝泓淵。", "自笑泉石成膏肓，愛賞不減蟻慕羶。", "巉巖數峯巧遮護，妙處二老初無傳。", "脫迹塵埃到此地，便覺神思飄飄然。", "回首江南塵一聚，城郭歷歷眼俗穿。", "相期更看水流處，步履未倦夸輕翩。", "一上千尺窮山椒，碧澗靡迤流蒼煙。", "尋源不能且忘返，石猊巍踞驚神鑴。"]'),
('e671def1-bb29-45da-8d8d-ddf90f270232','遊白石巖','樓鑰','宋','宋诗','song-poetry','','[]','我遊僊都觀獨峯，轍迹雖在車不通。',336,'全唐诗/poet.song.158000.json','["我遊僊都觀獨峯，轍迹雖在車不通。", "鼎湖望極幾怊悵，悵無羽翮凌天風。", "茲來樂成望白石，玉甑突兀摩蒼穹。", "人言真人老聃裔，鑿開洞府遺僊蹤。", "無人共登青雲梯，躋攀伴我惟枯筇。", "縈回約略三十里，踏遍萬疊高巃嵸。", "斷崖泠泠落殘雨，雙石凜凜亭孤松。", "却從山椒下谷口，石欄屈曲遮碧椶。", "頗疑山高氣凝凜，古來積雪今未融。", "是誰玉斧妙鑴斲，僊洞雙闢驚神工。", "巖深白日尚幽閟，別有石竅開天聰。", "傳聞峯頭貯清泚，苔罅涓滴聲冬瓏。", "奮身更與上虛閣，海山錯立煙濛濛。", "脚底千山行伏龍，手揮五絃俯冥鴻。", "霜林摇落當玄冬，長嘯一覽萬象空。", "解衣寄宿旦過寮，魂夢亦墮冰壺中。", "曉看日出滄海東，蠟炬百萬燒天紅。", "眼高不數鴈蕩雄，行田下笑康樂公。", "未能辟穀追僊翁，頗亦有意棲琳宮。", "三山不覺去人遠，安期羨門宜相從。", "驂鸞駕鶴太多事，但欲御氣遊無窮。"]'),
('2c09bc7b-c92a-41cc-8dab-80b49ad4e405','約諸公再遊龍湫','樓鑰','宋','宋诗','song-poetry','','[]','昨暮與君上龍湫，天久不雨無湍流。',64,'全唐诗/poet.song.158000.json','["昨暮與君上龍湫，天久不雨無湍流。", "嘯呼拊掌喚不應，悵望頗亦令人愁。", "夜來雷鼓驚龍起，溪聲已覺亂人耳。", "莫辭重訪尊者居，坐看倒翻三峽水。"]'),
('4bde5058-0b19-4753-bbb4-e3497d3b8e58','送劉仲起主簿','樓鑰','宋','宋诗','song-poetry','','[]','劉郎鸞棲海瀕邑，不減向來人姓習。',128,'全唐诗/poet.song.158000.json','["劉郎鸞棲海瀕邑，不減向來人姓習。", "凜然軀幹即之溫，語恐傷人中有立。", "論交雖厚笑甘醴，御吏以嚴無束濕。", "公餘黄卷頻卷舒，藝圃工夫日加葺。", "永嘉素多君子僚，休沐新盟有清集。", "伯倫忽去誰鯨吸，欲挽不留情悒悒。", "君年方盛才有餘，逸驥寧容在羈馽。", "期君速蹈功名機，塞草連雲朔風急。"]'),
('c26d69bb-6ec6-4a17-824e-92662a83bdd3','王侍御壽詩','樓鑰','宋','宋诗','song-poetry','','[]','史君威名聞四方，南床凜凜凝秋霜。',384,'全唐诗/poet.song.158000.json','["史君威名聞四方，南床凜凜凝秋霜。", "史君和氣到甌越，幕府初開夜飛雪。", "頗聞此雪仍歲無，定知來隨御史車。", "黄堂洗印未多日，慶朝況此當懸弧。", "明年豐登日可數，父老兒童爭起舞。", "遲明賀版擁譙門，試拾歡謠作詩語。", "史君風度神僊人，相門出相寧非真。", "妙齡兩科談笑得，晚趨嚴召依風雲。", "臺端敢言姦聽聳，至今讜論時傳誦。", "踏遍巫山十二峯，却尋春草池塘夢。", "人傳史君威稜稜，我知威愛元兼行。", "蒼髯如戟面如鐵，惠養自有循良稱。", "高牙入境紛進謁，賓屬庭趨公磬折。", "民生共喜愛日溫，吏行獨畏春冰裂。", "向來夔州妙籌邊，夷蠻落膽皇靈宣。", "還朝奏課居第一，夜半帝席爲之前。", "東嘉今爲股肱郡，小試望之三輔近。", "會循故事入三公，致君要使登堯舜。", "東風未動春先回，梅花照眼歌筵開。", "吏民合詞頌難老，一笑千里傳銀盃。", "佳兒恂恂授衣鉢，玉樹芝蘭俱秀發。", "江南世胄比長淮，更看雲來萃簪笏。", "平生知己今上天，敢復坐嘆寒無氈。", "巴言未足贊公壽，載誦峻極崧高篇。"]'),
('b9d7dbfe-8db0-442e-9c50-0ebb0b16bb97','鮑清卿病目不赴竹院之集詩寄坐客次韻','樓鑰','宋','宋诗','song-poetry','','[]','鮑侯年少老文學，藝苑優游富耕穫。',352,'全唐诗/poet.song.158000.json','["鮑侯年少老文學，藝苑優游富耕穫。", "胸中涵養自成趣，妙處正恐兒輩覺。", "我慙門巷非尺五，字欲問奇誰與榷。", "開樽竹院望同醉，遮眼腦脂何太虐。", "團圞十客踏雨來，相從不負東風約。", "投壺雅歌了無恨，祇恨車公一前却。", "海棠春深照眼明，風物融融悟非昨。", "從教雨洗烟脂淡，小摘何妨供把握。", "夜闌燒燭照春睡，靚粧如在結綺閣。", "牆頭西望爛蜀錦，嫣然一笑無聲樂。", "飛紅點地綉作茵，正須席地天爲幕。", "要知富貴出天姿，艷杏夭桃何足錄。", "主人小築真好事，肯學區區專一壑。", "洞門不鎖要客來，笑君大似羊公鶴。", "雨餘珠淚色慘悽，一顧正嫌無伯樂。", "忽驚新詩來叩門，妙語天然不煩琢。", "坐中傳觀字欲漫，我豎降幡甘面縛。", "清明已過雨不休，雲霧猶屯四山脚。", "揩摩病目不應遲，及此紅英半零落。", "枝頭尚有未開花，縱已離披亦何惡。", "知君既負西岑游，可使一春終落寞。", "會須來此共賦之，正要重聞誦新作。"]'),
('6ca3d01d-86ec-412c-a0dd-7c128648bde5','贈光孝益老','樓鑰','宋','宋诗','song-poetry','','[]','鴒原鴻鴈行，此理懸諸天。',264,'全唐诗/poet.song.158000.json','["鴒原鴻鴈行，此理懸諸天。", "萬事可變滅，天性難推遷。", "顯菴幼出家，潔饑同玄蟬。", "一鉢寄西東，悠悠經幾年。", "外慕等浮雲，百念灰無煙。", "難兄忽相逢，觸動歡喜緣。", "光陰信可惜，征袂何翩翩。", "叱胥掩簿領，來同妙峯禪。", "剌剌道家世，客淚如迸泉。", "玉堂與黄閤，衣鉢親相傳。", "游宦非爲貧，不敢替所先。", "老師雖宴坐，至情豈唐捐。", "此會非偶爾，絕倒秋風前。", "手持詩卷來，謂予得無言。", "曉以天性語，人生要有原。", "嗟哉僞日薄，萁豆本同根。", "一旦成仇敵，釜中急相煎。", "寧知有佳人，芳草夢阿連。", "相見無幾時，瞥如魚躍淵。", "固知出世法，惜別詎不然。", "又當作大觀，勿爲愛網牽。", "千山元不隔，毋庸對床眠。"]'),
('59b03369-727f-46ae-af57-66abf83648b2','送王道州','樓鑰','宋','宋诗','song-poetry','','[]','九疑之南爲舂陵，瀟水清駃山爲城。',208,'全唐诗/poet.song.158000.json','["九疑之南爲舂陵，瀟水清駃山爲城。", "郡齋正據山直上，一覽萬家無遺形。", "家君頃年入蓮幕，我不得往空馳情。", "先生分符此中去，心旌摇颺隨雙旌。", "先生平生飽文學，身上著作承明庭。", "奧篇隠帙辨如響，一時自許文章鳴。", "高詞坐奪造化巧，凜凜韶濩聲鏘鏗。", "把麾江海非無意，親扶版輿賦南征。", "頗聞楚俗未蘇息，糟糠不厭嗟疲氓。", "正資儒術飾吏事，拔去强薤摩孩嬰。", "政成環召事未晚，天子日夜開延英。", "風流千古三刺史，往繼聱叟陽先生。", "毋庸自書追科考，但願寄我舂陵行。"]'),
('4e37bf34-342a-48f0-a690-0ca09aa97a2c','哭王知幾墓','樓鑰','宋','宋诗','song-poetry','','[]','知幾少也爽，萬事笑談了。',72,'全唐诗/poet.song.158000.json','["知幾少也爽，萬事笑談了。", "自謂頗寡合，見我輒傾倒。", "百年能幾見，一別迹如掃。", "父子俱埋璧，烏乎何其早。", "向來論文酒，和淚傾宿草。", "此意誰復知，寤歎令人老。"]'),
('affbd531-473f-41d0-889b-33eb0ce7e269','仲舅尚書生朝','樓鑰','宋','宋诗','song-poetry','','[]','去年生朝燕稽山，館舍朗朗屋百閒。',160,'全唐诗/poet.song.158000.json','["去年生朝燕稽山，館舍朗朗屋百閒。", "紅裙合樂飲徹旦，坐上衆客皆酡顔。", "今年生朝半歸路，竹輿蕭蕭曉衝雨。", "回頭風景非去年，當時賓客今何處。", "仕已喜慍曾何分，適齋未減楚子文。", "鼻閒栩栩固自若，世情物態徒紛紛。", "平生知足志閑退，歸老鄉關了無悔。", "但欲年年醉西風，坐閲人閒百千歲。", "人閒萬事日不同，尚書人望方顒顒。", "明年舉酒拜公壽，安知不在槐庭中。"]'),
('b6dbad2d-d521-492d-8b64-ecaf5ad26bda','送鄭惠叔司封江西提舉','樓鑰','宋','宋诗','song-poetry','','[]','君名切斗魁，步武上霄極。',144,'全唐诗/poet.song.158000.json','["君名切斗魁，步武上霄極。", "蓬萊群玉府，圖書照奎壁。", "郎官應列宿，寖覺象緯逼。", "胡爲作使星，炯炯向江國。", "仰奉鶴髮親，版輿映萊服。", "昔日紅蓮池，帥垣資婉畫。", "方將散餘潤，連城被膏澤。", "官搉與民繇，豐儉煩振糴。", "小試活國手，疲甿頼休息。", "便歸侍玉皇，拱立香案側。", "富貴殊未已，行行上鸞掖。", "君其妙演綸，三能看齊色。"]'),
('dc332463-5cc1-4da5-99d2-bc289154cc33','次韻胡元用末利花','樓鑰','宋','宋诗','song-poetry','','[]','殘暑未盡秋欲來，玉刻萬葉瓊英開。',192,'全唐诗/poet.song.158000.json','["殘暑未盡秋欲來，玉刻萬葉瓊英開。", "孤標雅韻一枝足，江上紫翠空成堆。", "素娥長與明月約，青女細把輕綃裁。", "主人好事趁時買，買置此地真宜哉。", "牆間閑地方丈所，幾年累甓裝層臺。", "春花秋卉紛互發，胡葵芍藥參徘徊。", "眼明忽見此奇絕，弟畜素馨兄事梅。", "夜深飛香性幽獨，未許蜂蝶來相陪。", "糖甖封餘有閩土，會須掃取添花栽。", "吾聞閩山千萬本，人或視此齊蒿萊。", "何如航海上天闕，玉色照映瑠璃杯。", "新涼徙倚看不足，坐見日影欹庭槐。"]'),
('fa10ffc4-a259-4c7d-aa85-40f4c44993fb','同官登敕局小樓觀雪','樓鑰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去年歲豐登，雨晹應時須。',240,'全唐诗/poet.song.158000.json','["去年歲豐登，雨晹應時須。", "所欠惟一雪，祈禳遍精廬。", "晚亦粗飄瞥，六花舞空虛。", "雲氣不待族，風伯隨驅除。", "淺春寒尚深，忽見雲糢糊。", "撒鹽壓衡茅，晨興粟生膚。", "隨班上原廟，恍若登蓬壺。", "岧嶤宮殿深，朱扉黄金鋪。", "百神衛靈居，半天散瓊琚。", "又疑守護嚴，寶網絡明珠。", "參差鵷鷺行，簪笏皆沾濡。", "退歸冷局中，窗間竹扶疎。", "爲思此絕景，往往終年無。", "不應憚凌寒，閉門守紅爐。", "爲君登危樓，深盃泛駝酥。", "崔嵬瞻吳山，莽蒼望西湖。", "瓊枝宿饑鷹，玉街走韓盧。", "酒興萬里遠，容我歌且呼。", "坐欲斲五言，所媿李與蘇。", "君與工屬聯，灞橋去騎馿。"]'),
('1d90b0f8-a2ef-4247-b62d-5f1e3a2faf08','久不作詩喜仲兄遷鄰居因成長句','樓鑰','宋','宋诗','song-poetry','','[]','宦游各天涯，皇州今鴈行。',120,'全唐诗/poet.song.158000.json','["宦游各天涯，皇州今鴈行。", "官居半里所，相過復相望。", "西鄰得老屋，往來連戶窗。", "水竹占幽勝，風雨對一床。", "十年短檠燈，今夜分餘光。", "兒曹亦可樂，洛誦聲洋洋。", "天邊有白雲，隨風正飛揚。", "相期奉旨甘，萊衣戲親傍。", "軒冕皆儻來，此意可暫忘。", "詩成喜可知，且復釂此觴。"]'),
('fba2a79c-302e-440b-8066-2fba798cca6f','送林宗丞浙東議幕','樓鑰','宋','宋诗','song-poetry','','[]','先生風骨天與清，孤松野鶴何瘦生。',208,'全唐诗/poet.song.158000.json','["先生風骨天與清，孤松野鶴何瘦生。", "胸中落落笥五經，大篇短章筆縱橫。", "壯年文場諸老驚，俯仰世故雙鬢星。", "萬事不理詩自鳴，笑視軒冕秋豪輕。", "市者爭利朝爭名，著脚往往遭譏評。", "先生四五官神京，又復歸去鴻冥冥。", "臺家急賢理不應，况復寮舊離觴傾。", "先生自喜得此行，祿粟可已啼號聲。", "秦望之山高且平，卧龍橫亙環州城。", "鏡湖千頃波不興，晉宋遺迹多豪英。", "議幕了無塵務縈，撫物吊古皆關情。", "我亦久矣懷滄溟，旦夕欲乘緹油屏。", "相望縱復三數程，詩筒尚得尋前盟。"]'),
('69976ff0-90a0-4f43-ac23-d04487e44995','臨海縣治琴堂','樓鑰','宋','宋诗','song-poetry','','[]','子賤彈琴真是琴，我今無弦知琴心。',64,'全唐诗/poet.song.158000.json','["子賤彈琴真是琴，我今無弦知琴心。", "使我不得琴中趣，弦以脩綆誰知音。", "才術高低不自由，單父二子心則侔。", "後人不得彈琴暇，勿以戴星爲可羞。"]'),
('39ec1e0e-087e-4f77-bef7-d29985d43064','送石應之司戶歸剡以室邇人遠爲韻  其一','樓鑰','宋','宋诗','song-poetry','','[]','捷徑指終南，索價譏少室。',48,'全唐诗/poet.song.158000.json','["捷徑指終南，索價譏少室。", "窮達豈無命，踏地胡不實。", "之人吏海隅，所吐百未一。", "夷塗澹無營，君其有終吉。"]'),
('3934f735-52b8-477d-8e05-0354f0179cbe','送石應之司戶歸剡以室邇人遠爲韻  其二','樓鑰','宋','宋诗','song-poetry','','[]','年來嘆離群，磨琢殆無幾。',48,'全唐诗/poet.song.158000.json','["年來嘆離群，磨琢殆無幾。", "資凡學益落，駑駘費尺箠。", "羨君富春秋，發軔方自邇。", "驊騮更著鞭，洗眼日千里。"]'),
('473770b5-e1fc-4e34-80d8-aa9d17735081','送石應之司戶歸剡以室邇人遠爲韻  其三','樓鑰','宋','宋诗','song-poetry','','[]','南明千古秀，慶源久益新。',48,'全唐诗/poet.song.158000.json','["南明千古秀，慶源久益新。", "剡溪照人清，況復屈斯人。", "摻袪不容留，椒觴思拜親。", "他年風雪中，扁舟儻知津。"]'),
('a568325a-965e-49ba-81c8-d77e9943b10f','送石應之司戶歸剡以室邇人遠爲韻  其四','樓鑰','宋','宋诗','song-poetry','','[]','平生貪賢心，山川恨悠緬。',48,'全唐诗/poet.song.158000.json','["平生貪賢心，山川恨悠緬。", "寧知日相見，懷抱竟不展。", "樽酒了無暇，離情果深淺。", "室邇猶許疎，況今乃真遠。"]'),
('183bd2e1-66ff-4bbf-82c8-2306627168dc','送王仲矜倅興元','樓鑰','宋','宋诗','song-poetry','','[]','蜀道難，難於上青天。',196,'全唐诗/poet.song.158000.json','["蜀道難，難於上青天。", "蜀道易，易於履平地。", "蜀山天險固自若，視難爲易在人爾。", "王尊真有四方志，叱馭徑行了無累。", "早登岷峨仕陰城，談笑動行千萬里。", "漢中由來說鷄肋，意謂棄之爲可惜。", "君今此去良似之，更欲遠遊尋故迹。", "漢都南鄭啟炎圖，秦置石牛山徑闢。", "淮陰拜將餘高臺，武侯葬處空松柏。", "大笑出門何慨慷，天涯離愁各盡觴。", "荷君走馬却送我，李侯參語夜未央。", "君方往蹈功名機，何止別駕歌王祥。", "先正九年遺愛在，更携故笏訪甘棠。"]'),
('2eda8019-768f-47c2-ac5c-f612a1c644f5','巾山','樓鑰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','兩鼇贔屭隨西行，勢欲吸盡西江清。',232,'全唐诗/poet.song.158000.json','["兩鼇贔屭隨西行，勢欲吸盡西江清。", "是誰繚以千丈城，欲去不去豈不靈。", "化爲青山鎮東溟，首冠窣堵雙崢嶸。", "安輿從東喜逢迎，笑指鼇背同來登。", "春殘雨足綠陰成，山鳥相和聲咿嚶。", "自從半山經小亭，仰望巨石扶軒楹。", "千山萬山擁翠屏，陰霾掃靜纖雲興。", "翠微下有長江橫，衮衮不盡千古情。", "廣軒俯瞰萬瓦平，佳處歷歷堪指名。", "雪蓬蹙雲連曲肱，蜂房蟻垤棲殘僧。", "扶欄更上三兩層，一覽物象無遺形。", "徙倚未厭茗椀傾，長嘯兩腋清風生。", "親顔甚怡輪爲停，我亦色笑喜不勝。", "願我雙親俱遐齡，方瞳鍊顔華髮星，如此兩峰相對青。"]'),
('4fbe7d0a-7afa-4a80-b7fd-732c3cb0bc7d','沿檄柯山歸別張特秀','樓鑰','宋','宋诗','song-poetry','','[]','我昔志學年，侍親宦西安。',288,'全唐诗/poet.song.158000.json','["我昔志學年，侍親宦西安。", "弟兄游庠校，見君平生歡。", "君才獨穎出，逸駕不可攀。", "夜窗共檠燈，春遊合盃盤。", "虛堂卧雪嶺，傑閣橫雲山。", "爛柯上危磴，烏巨沿溪灣。", "是時氣相高，辯論俱瀾翻。", "一別二十年，天街見峩冠。", "殿廬看決科，藍袍立清班。", "黄牒墨猶濕，大弨力能彎。", "爾來又五載，短書能幾番。", "茲焉捧檄來，吏牘方拏煩。", "室邇歎人遠，一朝脫籠樊。", "滿意縱劇談，痛飲到夜闌。", "十步九太行，此事亦孔艱。", "進哭老先生，畫圖慘青綸。", "特顯顧何爲，一昔成大還。", "回思我伯氏，人琴有餘嘆。", "感今念疇昔，相與涕淚潸。", "故人悵無幾，恍如春夢殘。", "有酒不得飲，有琴不成彈。", "復歸坐冷屋，使我凋朱顔。", "我歸不可遲，倚門夢連環。", "君言欲舂糧，伴我行路難。"]'),
('3baf4764-17dc-479f-9c73-c5588d3d252a','次韻沈史君懷浮岡梅花','樓鑰','宋','宋诗','song-poetry','','[]','玉人迥立山谷裏，不有使君誰與憐。',64,'全唐诗/poet.song.158000.json','["玉人迥立山谷裏，不有使君誰與憐。", "毋庸高牙煞風景，爲著佳句增孤妍。", "寒溪照影謾千樹，橫笛吹殘又一年。", "傳聞年後更多在，便思躍馬趨平川。"]'),
('62805c71-3a1c-43c0-9743-91e3318699c2','送王木叔推官分韻得錦字','樓鑰','宋','宋诗','song-poetry','','[]','王郎天下士，中和自生稟。',240,'全唐诗/poet.song.158000.json','["王郎天下士，中和自生稟。", "澹然初無營，見者輒歛衽。", "幕中資婉畫，處事極精審。", "與人如恐傷，律己淵冰懔。", "深恐馬駭輿，要使鴞食葚。", "一寸憂國心，幾年不甘寢。", "此意大未酬，退靜若已甚。", "使之行所學，庶幾人奠枕。", "向來孰間之，未免斯立噤。", "川泳而雲飛，頼有東陽沈。", "露章極推轂，分韻句裁錦。", "風流有如許，不復嘆踔踸。", "如君豈蓬蒿，人物妙流品。", "不應奉香火，爲養謀祿廩。", "與君幸瓜葛，心交今十稔。", "豈惟我惜別，行道情苒荏。", "紅蓮色何似，翠柏風逾凜。", "願君疎藥裹，一意護茵飪。", "棄鼎寶康瓠，浮名如拾瀋。", "行矣無多言，臨岐且劇飲。"]'),
('eb2f5302-045a-495c-ae47-459d01289ecf','彭子復臨海縣齋','樓鑰','宋','宋诗','song-poetry','','[]','乾道癸巳冬，此邦我經行。',288,'全唐诗/poet.song.158000.json','["乾道癸巳冬，此邦我經行。", "鬰攸氣未殄，千家真赤城。", "來訪臨海令，瓦礫紛縱橫。", "翹然三尺高，問是戒石銘。", "徘徊重太息，更聞愁歎聲。", "試詢來者誰，共言令姓彭。", "我時語傍人，此邑其將興。", "迨予來贅倅，客館方暫停。", "夜聞簫鼓沸，聽事先落成。", "起望輪奐美，壯觀聳連甍。", "百堵日以作，斧斤喜丁丁。", "層樓庋敕書，兩廡環中庭。", "久乃遊其間，宏大使我驚。", "位置既深穩，斲削仍攻精。", "田里不知役，纖粟無輸征。", "安得屋朗朗，突兀有寧馨。", "退食不苟處，扁榜皆佳名。", "中虛物自照，政平由心平。", "穉柏已可悅，況有賢弟兄。", "小亭真吏隠，縣擁高山青。", "琴堂雖增舊，此意宜細評。", "智調天下理，夸言笑後生。", "大弦可以急，小弦恐弗勝。", "舉意屬俄頃，立欲如所營。"]'),
('1639163c-4693-4719-972b-4e32842e7758','送虞仲房赴潼川漕','樓鑰','宋','宋诗','song-poetry','','[]','我來丹丘乘貳車，送客往往萬里餘。',256,'全唐诗/poet.song.158000.json','["我來丹丘乘貳車，送客往往萬里餘。", "盛山使君別寖久，漢中郡丞新寄書。", "公指四明喜鄰境，典午何知成畫餠。", "揚旌忽作梓潼行，去路六千抑何迥。", "餘杭名家多俊奇，君於輩行尤白眉。", "雍容晉韻足夷曠，百家到手無停披。", "向來郎曹天咫尺，引身閩山接商舶。", "賈胡嘆仰清節高，霧中親見越王石。", "此行叱馭不作難，手遮西日又長安。", "長安日近公應住，未放使星臨蜀山。", "不然一行亦不惡，潼川應如錦城樂。", "鄧侯功名凜如在，拾遺風采今猶昨。", "流馬木牛諸葛公，飛輓正欲修前功。", "蜀民險遠日凋瘵，摩撫要令畿甸同。", "況公五絕追鼻祖，隸古真有兩漢風。", "歸來富貴固未晚，爲傳此學川西東。"]'),
('037fef4d-de37-45a6-9343-09b291f86fac','奉口遇雨','樓鑰','宋','宋诗','song-poetry','','[]','七月欲盡八月初，天久不雨暑未徂。',176,'全唐诗/poet.song.158000.json','["七月欲盡八月初，天久不雨暑未徂。", "下田焦卷上田槁，愁歎不止田間夫。", "嘔啞水車日夜響，漕河揚塵成坦途。", "喜見此溪深且廣，玄雲忽起西北隅。", "林間槭槭水漚起，兩岸人物歡欲呼。", "未聞霶霈潤龜拆，且使萬物聊沾濡。", "船窗飄灑疎蓬漏，客意自適涼襟裾。", "引身東望雲氣薄，未知帝城有此無。", "傳聞今日方奏告，便有響應來斯須。", "人家百萬苦炎熇，君王齋禱幾月餘。", "君王齋禱幾月餘，雲師雨師其疾驅。"]'),
('e1b80eba-d662-4657-b787-8ccd3cf5a4df','游天台石橋','樓鑰','宋','宋诗','song-poetry','','[]','兩龍爭欲赴深壑，觸破山骨成脩梁。',64,'全唐诗/poet.song.158000.json','["兩龍爭欲赴深壑，觸破山骨成脩梁。", "滔滔共出一門去，凜凜直落千丈强。", "初疑鞭石跨滄海，絕勝乘鵲橫銀潢。", "要須高躡前峰過，往叩山中真寶坊。"]'),
('efe94365-ad63-48f1-b229-cc91410946fa','史少師賜第賞芍藥分韻得木字','樓鑰','宋','宋诗','song-poetry','','[]','帝城有僊山，雙徑森萬玉。',228,'全唐诗/poet.song.158000.json','["帝城有僊山，雙徑森萬玉。", "洞戶入深窈，突兀見華屋。", "相君領衆客，紅藥想芬馥。", "霜刀妙裁剪，烟脂點冰縠。", "枝弱不勝花，翠葉共斜矗。", "向來爭春風，桃李媿麤俗。", "百卉紛何在，庭樹擁新綠。", "此花丈人行，儼立見幽獨。", "相君戴花笑，和氣俱可掬。", "人言此花勝，相君意傾屬。", "誰知心廣大，何物不蒙福。", "豈以庭中花，而肯棄凡木。", "君看擇勝具，所在可追逐。", "自言居閑時，情話會親族。", "一花有可觀，爛賞費銀燭。", "此心何揀擇，寓意本無欲。", "以此宰天下，以此鎮藩服。", "兒童與走卒，人人歌相國。", "有能達此觀，春風四時足。"]'),
('ade89fc4-b4d5-41b7-8d0d-a313971177c6','送錢伯同寺丞守嚴陵','樓鑰','宋','宋诗','song-poetry','','[]','去年送君來，今年送君歸。',240,'全唐诗/poet.song.158000.json','["去年送君來，今年送君歸。", "君善全去就，我獨念別離。", "君是忠孝家，襲紫傳金龜。", "門戶二百年，所寄在一夔。", "少年便老蒼，況今更險夷。", "不獨妙言語，理窟深莫窺。", "健筆照手澤，典刑從可知。", "向來御祥琴，欲把江海麾。", "促召歸舊班，退食方委蛇。", "世事等飄瓦，人情嘆燃萁。", "向非渾金質，百煉豈不衰。", "浩然賦歸歟，潔身而去之。", "爲僚曾未幾，棄我忽若遺。", "君既棄我去，謫僊復追隨。", "陡去二良友，摻袪重分岐。", "前別易再會，今見當何時。", "才具素絕倫，涵養日以滋。", "且爲牧嚴陵，赤手摩瘡痍。", "歸來應不晚，青氈當屬誰。", "願君厚自愛，歲寒尚相期。"]'),
('2a8f7f01-6bd2-49a6-b874-30e22f7c4ad2','送楊嗣勳校書守眉山','樓鑰','宋','宋诗','song-poetry','','[]','我生東南陬，不識蜀道難。',156,'全唐诗/poet.song.158000.json','["我生東南陬，不識蜀道難。", "觀君眉宇秀，想見岷峨山。", "漢廷射策時，連璧照鴛班。", "伯氏書萬言，逸駕不可攀。", "茲焉從君游，頗得窺一斑。", "僊凡隔弱水，接辭良亦艱。", "矧茲萬里別，望望何當還。", "三蘇騎鯨去，詞章滿人間。", "豈無後來者，遺珠有餘嘆。", "願君效樂全，飛章達天關。", "報國此最急，餘事付等閑。", "宣室行見思，朝暮當予環。", "別語敢言詩，屬聯不容慳。"]'),
('ad9719e6-fcaa-4259-99d6-c5acf75a9a0c','送何道夫祕監守潼川','樓鑰','宋','宋诗','song-poetry','','[]','妙齡冠蜀士，名聲振王畿。',264,'全唐诗/poet.song.158000.json','["妙齡冠蜀士，名聲振王畿。", "晚隨召節來，天朝增羽儀。", "我昔倅丹丘，鹿侯掛冠歸。", "群公俱祖送，見公四三詩。", "頗恨著鞭先，自言乞身遲。", "拳拳慕下風，直欲夢見之。", "還朝挹高致，氣宇清且夷。", "稱者不容口，往往同一詞。", "始見荷傾倒，笑談欲忘疲。", "况當秋風高，濫吹參試闈。", "鼎臠得一嘗，豹斑容管窺。", "叔度真似道，莊生信忘機。", "親疎皆不可，况復容磷緇。", "諸生得公來，讙曰真吾師。", "叩簾或三請，響答了不疑。", "私謂如此人，定應備論思。", "胡爲歸興勇，抗章氣不衰。", "鼓盆萬里外，抱孫更成悲。", "擁麾東川去，無人留孔戣。", "別懷不自勝，別酒聽淋漓。", "他時念老成，追鋒且復西。", "公能重來否，此意非吾私。"]'),
('9750c1c2-279c-4518-ada6-1019cb59dee9','送趙子直貳卿帥三山','樓鑰','宋','宋诗','song-poetry','','[]','一蹴登從班，人胡謂公遲。',216,'全唐诗/poet.song.158000.json','["一蹴登從班，人胡謂公遲。", "建牙帥七閩，人胡爲公疑。", "公今第一流，志操古與期。", "兩州有遺愛，江西憺霜威。", "重來長道山，批敕兼瑣闈。", "一片憂國心，輾轉中夜思。", "正色抗危言，傳誦滿紳緌。", "造膝有啟沃，削藁知者誰。", "此心與天通，此意上所知。", "所以名愈尊，萬口同一詞。", "進用恐不速，小却成嘆咨。", "天語自昭然，更欲試望之。", "况彼三山重，謀帥皆衮衣。", "茲行豈細事，報政不待朞。", "登門恨最晚，臭味忘賤微。", "自慙空惜別，不解留孔戣。", "十連終歛惠，居中乃其宜。", "試問行道人，但知望公歸。"]'),
('20cb41d4-eb58-4f7b-996d-0868c710b050','玉版鮓次陸子元郎中韻','樓鑰','宋','宋诗','song-poetry','','[]','鱘黄不減鯨與鱣，逆風鼓鬣噴腥涎。',128,'全唐诗/poet.song.158000.json','["鱘黄不減鯨與鱣，逆風鼓鬣噴腥涎。", "漁人不顧浪如山，談笑坐致扁舟前。", "一鈎香餌不得去，何用大網相縈纏。", "揮刀紛紜臠肉骨，巨口噞喁誠可憐。", "珍鮓萬甕不論錢，頭顱萬里頳行肩。", "星郎日參玉版禪，頗厭蔬食供盤筵。", "尚書親作孟宗寄，坐覺匕箸生春妍。", "却笑多事張茂先，光怪異說空千年。"]'),
('9c0401be-6f90-4b4d-9515-1c81edab12a0','走筆送僧義沖','樓鑰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一氣行太虛，流形紛不齊。',264,'全唐诗/poet.song.158000.json','["一氣行太虛，流形紛不齊。", "要之本無物，洞然無足疑。", "梵志有至言，還我未生時。", "燒了似不曾，亦有毛僧詞。", "沖師名家子，少年習裘箕。", "談吐霏木屑，落筆皆珠璣。", "自稱十年來，不復念作詩。", "空門坐枯禪，綺語知昨非。", "聞之意已消，談笑到日西。", "習氣終未盡，舊編還自携。", "秀句堪供佛，古作力可追。", "愛玩不去手，未免成一癡。", "又欲上西湖，駐錫來語離。", "我生墮宿業，筆硯置藩籬。", "拔擢困胃腎，未老神已疲。", "幾欲焚故藁，要使心清夷。", "君詩既不作，何不等棄之。", "萬事都放下，一意探玄機。", "語罷復自笑，無使高人知。", "作詩固無用，參禪亦胡爲。", "勸人反自蹈，此紙何必揮。", "不如兩俱忘，他時赤體歸。"]'),
('02def3b8-76a6-4cbe-9585-d181167cd4df','催老融墨戲','樓鑰','宋','宋诗','song-poetry','','[]','古人惜墨如惜金，老融惜墨如惜命。',224,'全唐诗/poet.song.158000.json','["古人惜墨如惜金，老融惜墨如惜命。", "濡毫洗盡始輕拂，意匠經營極深夐。", "人非求似韻自足，物已忘形影猶映。", "地蒸宿霧日未高，雨带寒煙山欲暝。", "中含太古不盡意，筆墨超然絕畦逕。", "畫家安得論三尺，身世生緣俱墮甑。", "人言可望不可親，夜半叩門寧復聽。", "三生宿契誰得知，一見未言心已應。", "巖傾千丈雪散空，上有清池開錦鏡。", "意行忽發虎溪笑，許作新圖寫幽勝。", "歸尋一紙五十尺，傅以礬膠如練浄。", "自知能事難促迫，捲送松窗待清興。", "筆端膚寸今何如，西抹東塗應略定。", "何當一日快先覩，洗我昏眸十年病。"]'),
('18a90caa-820e-48af-9787-cf7979f0388b','獨旦蕈次九五從叔韻','樓鑰','宋','宋诗','song-poetry','','[]','朝菌晦朔雖不知，食之實冠東南味。',96,'全唐诗/poet.song.158000.json','["朝菌晦朔雖不知，食之實冠東南味。", "庾郎二十有七品，一見流涎驚絕異。", "擷蔬剪韮皆可却，味苦應無夏蟲避。", "大阮哦詩聲未了，又索蒸芝今再遺。", "邇來枯枿尚未茁，拳拳頗媿臺無餽。", "儻容小摘寄情親，會遣長鬚見芹意。"]'),
('c05b3e2b-bc8e-4fbd-945a-d4654cebee4e','雪','樓鑰','宋','宋诗','song-poetry','','[]','丙午九月才入冬，晦日忽驚雪墮空。',352,'全唐诗/poet.song.158000.json','["丙午九月才入冬，晦日忽驚雪墮空。", "傳聞都城更復早，萬官入賀明光宮。", "自從開霽更不雨，和氣直似青春濃。", "斗柄插子日丁卯，夜煽裂缺鞭雷公。", "從以震霆至三四，驚破蟄戶紛昆蟲。", "寧知玄冥全未究，翻手作雲千里同。", "暗窗初聽灑珠雹，巽二滕六方施工。", "一日喜見瓦溝積，忍寒待伴炯不融。", "二日三日遂盈尺，膏潤四海恩無窮。", "古來詩人詠不盡，巧思橫出昌黎翁。", "少時奮筆不肯已，老矣袖手便疎慵。", "兒曹作戲記昨夢，舞狻獰踞金雙瞳。", "誰人苦欲撩詩思，更作玉山高數峯。", "移將劉叉兩冰柱，輝映愈覺清心胸。", "見之躍躍忽技癢，起呵凍筆尋詩筒。", "開門一看天宇闊，素蜺百萬翻長風。", "瓊樓玉宇滿妙界，千林寶樹春玲瓏。", "恨無高臺三百尺，縱觀萬象凌空濛。", "固知幻景有變滅，一時如入崑閬中。", "僊家俄頃閲塵劫，安知此際非神功。", "賸喜年來米價賤，便欲扶犂隨老農。", "牆頭濁醪走來過，相與痛飲歌年豐。"]'),
('8a917ced-b180-4275-8b11-0bf11c322ff6','少及兄真率會','樓鑰','宋','宋诗','song-poetry','','[]','晝錦坊中作真率，群從相過無俗物。',96,'全唐诗/poet.song.158000.json','["晝錦坊中作真率，群從相過無俗物。", "主人就樹折楊梅，醉倒薰風涼拂拂。", "小舟傍城登雉堞，坐看白鳥蒼煙沒。", "須臾撐出洞天去，傑閣三層高突兀。", "樽前賦詩貴神速，十分鈍似遼天鶻。", "從他銀漏促殘更，要見林閒紅日出。"]'),
('fa190f3b-b72f-42a4-af81-853714ef769c','送元聲弟赴水陽監鎮','樓鑰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','吾翁積德厚，九子官其六。',228,'全唐诗/poet.song.158000.json','["吾翁積德厚，九子官其六。", "不幸失三人，孤嫠紛在目。", "三弟尚白丁，升沉猶未卜。", "吾人扶門戶，參立如鼎足。", "脫死憂患餘，偏親須水菽。", "阿連先著鞭，去去長江曲。", "弱冠承賞延，十載荷衣綠。", "閒關困家食，才就五斗粟。", "要知官無卑，豪髮當畏肅。", "督耕兩大圩，受輸十萬斛。", "處之誠未易，勉旃直自勗。", "執別動萬感，酌酒再三祝。", "吾子素解事，涉世要未熟。", "意行須揆理，言輕恐招辱。", "王事究一心，言玷復三復。", "細行累大德，陰財損陽祿。", "豈惟贈爾言，余亦每自恧。", "公餘稍有暇，更取故書讀。", "行矣更自愛，家聲要人續。"]'),
('00f7c37e-759f-4857-817d-d30d79f8874d','伯中弟生朝賦酴醿','樓鑰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春日足風雨，不知艷陽天。',120,'全唐诗/poet.song.158000.json','["春日足風雨，不知艷陽天。", "桃李俱成塵，懶上西湖船。", "春餘忽微和，酴醿發清妍。", "池塘芳草夢，况復向阿連。", "中庭月方午，密林澹清煙。", "蒙蒙青羅帔，粲粲白玉鈿。", "幽歡久不講，群從俱讙然。", "銀燭煩高燒，妃子浴溫泉。", "花以酒爲名，我以杯相傳。", "爛醉不復辭，此會期年年。"]'),
('e5581b23-4d9b-4b6d-897b-93460a55bea2','黄巖令鄭仁叔索委羽洞詩','樓鑰','宋','宋诗','song-poetry','','[]','君不見王君羽化脫秦厄，故山至今名落翮。',136,'全唐诗/poet.song.158000.json','["君不見王君羽化脫秦厄，故山至今名落翮。", "又不見烏程野鶴投氅毛，佞臣稱瑞民斯勞。", "何如奉林控鶴登青霄，傷然委羽登山椒。", "青衣出入洞方杳，紫氣氤氳風尚飄。", "令君頗似丁令威，鶴馭久去雙鳬歸。", "山川良是人民非，一新琳宮還舊規。", "黄山父老歌循良，誦君詩句游雲房。", "更將山石比堅操，百碎猶能徹骨方。"]'),
('8b3c0624-db54-45c1-96b6-837de7349d47','青林','樓鑰','宋','宋诗','song-poetry','','[]','郡齋偶休沐，驅車出西城。',240,'全唐诗/poet.song.158000.json','["郡齋偶休沐，驅車出西城。", "依依山水佳，蕭蕭松柏聲。", "雪餘春意動，新綠生坳泓。", "行行到青林，老眼增雙明。", "主人喜客來，倒屣欣逢迎。", "幽居迹甚遐，健筆詩方鳴。", "回首幾年別，千里摇心旌。", "相見又睽隔，此意猶未平。", "不如造齋閤，四座酒重傾。", "風流陶彭澤，骯髒阮步兵。", "看劍引三尺，論文驅六丁。", "綠野秀橫檻，山寺傍連甍。", "石罅幽泉溢，脚底輕雲生。", "詩盟忝予會，弈道從君爭。", "哦詩谷禽應，列炬林鴉驚。", "清歡未云足，累句忽已成。", "環坐粲十眉，舉酒酬三英。", "滿壁灑醉墨，歸夢含餘清。", "我方媿此集，君欲尋前盟。", "吏鞅方縛我，秋風爲君行。"]'),
('4b33013f-dfc2-49fa-92ec-996b561ad360','隠清','樓鑰','宋','宋诗','song-poetry','','[]','右軍訪文君，遁迹入深竹。',72,'全唐诗/poet.song.158000.json','["右軍訪文君，遁迹入深竹。", "我來尋歔歈，人亡但空谷。", "靈龜闖澄潭，華宇對飛瀑。", "若人今何之，尚想舊茅屋。", "吾聞古君子，千載守孤獨。", "楚些不可招，懷哉愴喬木。"]'),
('e4a27caa-03db-4da8-bc27-3f15461c5db3','送劉晉父監嶽','樓鑰','宋','宋诗','song-poetry','','[]','濟南劉夫子，生來逢百罹。',288,'全唐诗/poet.song.158000.json','["濟南劉夫子，生來逢百罹。", "乃翁負長才，宦游至京西。", "時當建炎間，寇盜紛不齊。", "轉徙入湖廣，一家屢阽危。", "五羊買海舟，萬里向鮚埼。", "舟破投永嘉，有如鳥擇棲。", "哀哀老治中，藁葬山之垂。", "母家在衡陽，孤嫠往相依。", "久卧漳濱疾，羈窮命如絲。", "事母以孝聞，執喪禮無虧。", "廬墓屏葷茹，至行徹丹墀。", "有詔寵數蕃，得官祇奉祠。", "行年六十二，霜髯照厖眉。", "慨然念防墓，千里來海涯。", "西山如蓮華，古今冢纍纍。", "况此久宿草，蕪穢不復治。", "孝思雖甚切，冥漠何從推。", "行道爲興嘆，智力無所施。", "有僧幾九齡，自言記當時。", "君聞亟叩請，東岡指荒基。", "吾師慕泓公，少也從吾師。", "墓中有版識，倉猝不暇碑。", "素棺無石槨，灰炭周四圍。", "君方感斯言，鑽穴從旁窺。"]'),
('2d45e73e-5c5f-4f7c-9de4-053426f564bb','王成之給事囿山堂','樓鑰','宋','宋诗','song-poetry','','[]','煙雨望麗陽，前山羅紫翠。',264,'全唐诗/poet.song.158000.json','["煙雨望麗陽，前山羅紫翠。", "照水挹南明，不與巾子對。", "朅來登囿山，一覽萬山會。", "蓮城山固多，此地要爲最。", "主人意軒豁，物境供曠快。", "山椒湧華屋，迥立風埃外。", "一物無遁形，所在見纖介。", "清霜肅天壤，佳樹隔闤闠。", "俯仰隨取捨，左右從盼睞。", "門牆尋故步，杖屨許從邁。", "恍然至絕頂，更覺宇宙大。", "樽酒屢勸酬，棋枰更勝敗。", "秋高月色皎，浮雲了無礙。", "不俟攀仙掌，徒手吸溪瀨。", "茲堂極崇敞，意若欠深邃。", "先植易生木，徐待松柏兌。", "望遠仍可喜，意滿聊自晦。", "無使山下人，或得窺外內。", "但恐趣賜環，樹藝或不逮。", "先生味斯言，一笑相領解。", "吾將飭園丁，隨處添翳薈。", "他時遶扶疎，吾廬益可愛。"]'),
('780264a8-a3f3-44a6-a6e7-89032f6d14ea','游初暘谷及白巖','樓鑰','宋','宋诗','song-poetry','','[]','重來游仙都，止欲訪獨峯。',288,'全唐诗/poet.song.158000.json','["重來游仙都，止欲訪獨峯。", "寧知一峯外，佳境無終窮。", "何處潁川子，鏡巖便相逢。", "約我游白巖，輕舟借溪翁。", "齋餘尋宿諾，秋霽波溶溶。", "清澈見石底，鑱刻驚神工。", "昨登初暘谷，但見石嵌空。", "茲浮懸崖下，萬石森巃嵸。", "上有勝絕地，古語留郭公。", "鬼神謹呵護，雷霆掃塵蹤。", "換船到白巖，脩篁摇清風。", "縈回進石屋，孤竹攢沙蜂。", "洞府僊所閟，無由辨西東。", "扣舷過巖下，數仞如崇墉。", "石趾平如甃，奇怪遮蒼穹。", "更尋小蓬萊，俯瞰馮夷宮。", "篙師進深窈，捫蘿捨枯筇。", "游子非不多，無人解從容。", "我因一日留，幽尋極山中。", "秋旻快排盪，日暖如春融。", "歸坐獨峯下，石影橫空濛。", "急呼醽醁清，澆此磊磈胸。", "幸有濟勝具，未能上金龍。", "爲君揮五弦，決眥送飛鴻。"]'),
('ef0bc4e7-2e75-4359-9f00-aa6556947d1f','夜游獨峰下','樓鑰','宋','宋诗','song-poetry','','[]','峯背正白月舒光，峯影橫野萬丈强。',64,'全唐诗/poet.song.158000.json','["峯背正白月舒光，峯影橫野萬丈强。", "仰之彌高立卓爾，蔽遮星斗摩穹蒼。", "半秋風露清徹骨，望望直欲隨風翔。", "歸尋玉虛步松逕，月輪正湧門中央。"]'),
('2ba2f7d1-82a5-42d0-85e0-83ca51165783','送顔希聖尚書守泉南','樓鑰','宋','宋诗','song-poetry','','[]','聖朝寶運開虞唐，太平天子垂衣裳。',344,'全唐诗/poet.song.158000.json','["聖朝寶運開虞唐，太平天子垂衣裳。", "恢張治具崇儒良，孰不願依日月光。", "用之則行舍則藏，孔門賢德遥相望。", "朝望方隆位文昌，跬步可到中書堂。", "問公擁麾何太忙，公獨三請志益剛。", "俞音一下冥鴻翔，行李徑出臨濤江。", "爭留孔戣動朝行，公更傴俯不敢當。", "老成全德真圭璋，溫如春風嚴如霜。", "柏臺峩豸肅朝綱，賢關嚮風士氣揚。", "大天小天稱公方，五年吏姦蓋而彰。", "金華勸講言加詳，明主傾聽談皇王。", "盍膺枋除任贊襄，名遂身退天所臧。", "明哲保身身更康，高風可仰不可量。", "泉山壤土接臨漳，建牙千里開封疆。", "老龍負圖寵煌煌，何殊衣錦還故鄉。", "賤子薄宦接王楊，曾陪御史臨文場。", "風簾官燭夜未央，劇談猶記聲琅琅。", "茲來誤忝尚書郎，始尋故步依門牆。", "西風津頭望歸艎，挽公不留遠予將。", "兩宮念公未詎忘，公雖遠去如在旁。", "庶幾重來上錢塘，夾輔大業恢中邦，儻有重事須平章。"]'),
('ad4d533a-8571-45cf-b3b2-5a625992025c','陳順之靈壁石硯山','樓鑰','宋','宋诗','song-poetry','','[]','名畫法書環四壁，中有米家真寶石。',256,'全唐诗/poet.song.158000.json','["名畫法書環四壁，中有米家真寶石。", "羣峯森聳外澗流，他物雖奇敢爭席。", "舊屬半山老僊人，佛印乞之如乞鄰。", "阿章有力負之走，一時攘取成紛綸。", "此石天然非琢磨，是時有水生巖阿。", "至今研池尚餘潤，歲月既久惜不多。", "幾年徒見士夫說，一旦喜看形偃月。", "傍連玉立兩於菟，主人照映冰壺澈。", "陳侯之富可敵國，會有寶光驚四塞。", "呼童吸盡研中水，更爲輕翻玩奇刻。", "不堪回首江南李，空唱多愁似春水。", "不如此石千載傳，玉砌雕欄等糠粃。", "寶晉得之真不易，身後寧知亦輕棄。", "只今傳玩知幾人，當日瑣窗空自祕。", "端歙爭名南北部，勿向雷門揚布鼓。", "相臺渴瓦更不須，祇合觚稜蔭風雨。"]'),
('15094328-5897-4f97-984a-d44606b5bc80','跋汪季路所藏脩禊序','樓鑰','宋','宋诗','song-poetry','','[]','永和歲癸丑，羣賢會蘭亭。',288,'全唐诗/poet.song.158000.json','["永和歲癸丑，羣賢會蘭亭。", "流觴各賦詩，風流見丹青。", "右軍草禊序，文采粲日星。", "選文乃見遺，至今恨昭明。", "字畫最能意，自言勝平生。", "七傳到永師，襲藏過金籝。", "辯才尤祕重，名已徹天庭。", "屢詔不肯獻，託言墮戎兵。", "妙選蕭御史，微服山陰行。", "譎詭殆萬狀，徑取歸神京。", "辯才恍如失，何異敕六丁。", "文皇好已甚，丁寧殉昭陵。", "當時馮趙輩，臨寫賜公卿。", "惟此定武本，謂出歐率更。", "採擇獨稱善，遂以鎸瑶瓊。", "流傳迨五季，皆在御寢扃。", "耶律殘石晉，睥睨不知名。", "意必希世寶，氈裹載輜軿。", "帝𤜱既北去，棄與朽壤并。", "久乃遇知者，龕置太守廳。", "或云政宣閒，此石歸紹彭。", "又言入內府，宣取恐違程。", "焚膏繼短晷，拓本手不停。", "疊紙至三四，肥瘠遂異形。"]'),
('87ec7a69-5dae-4e18-8855-0587fb646f23','送劉德脩少卿潼川漕','樓鑰','宋','宋诗','song-poetry','','[]','清朝重爭臣，選取妙一世。',264,'全唐诗/poet.song.158000.json','["清朝重爭臣，選取妙一世。", "矯矯劉御史，一鶚勝百鷙。", "顧瞻最有力，步武亦嚴毅。", "一生憂國心，千古敢言氣。", "氣足充所學，文能行其意。", "遇事輒奮發，觸邪無顧忌。", "乘驄行且止，歛手已知避。", "但思補衮闕，何暇爲身計。", "獨立當雷霆，三進氣彌厲。", "去魯固遲遲，出晝豈濡滯。", "上終行其言，群賢爭挽致。", "將輸向潼川，寓直尚中祕。", "風裁仰清峻，進退審難易。", "伊昔聯周行，睽違十餘歲。", "來爲同舍郎，愈篤金蘭契。", "洗眼看騰上，寧知攬征袂。", "抗章歎高絕，勇退尤知愧。", "去勿窮日力，予環日月冀。", "承君送道鄉，硬語吁可畏。", "毋以此自滿，當爲不止是。", "臨別提斯言，少盡交朋誼。", "萬里苟同心，吳蜀安有異。"]'),
('e4157714-c741-4c86-8936-24b513b01047','次韻李季章監簿泛湖','樓鑰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','僊舟共泛滄波去，且向蘇公堤下住。',208,'全唐诗/poet.song.158000.json','["僊舟共泛滄波去，且向蘇公堤下住。", "西風吹就芙蓉城，青鏡閑粧兩呈露。", "皇家家法崇儉素，宸心但欲乘商輅。", "離宮別殿無興作，天以西湖供一豫。", "吾儕公退得清賞，酒醆棋枰不知暮。", "深知夕照戀狎鷗，又恐昕朝追振鷺。", "自憐三入鳳凰城，歲月黄塵等閑度。", "湖光正欲捲簾看，風色更煩搴幕護。", "孤山不見處士廬，司馬空尋蘇小墓。", "酒乾人醉歡有餘，聯騎還趨湧金路。", "歸來健倒渾不知，睡覺燈前裊香霧。", "丈人公子真冰玉，曾爲出遨揮妙句。", "匆匆借韻僅成章，敢詫樽前鸚鵡賦。"]'),
('4ec0a74d-7272-446e-a7e7-71652c7f6497','送楊廷秀祕監赴江東漕','樓鑰','宋','宋诗','song-poetry','','[]','平生楊誠齋，可仰不可見。',216,'全唐诗/poet.song.158000.json','["平生楊誠齋，可仰不可見。", "去年尺一書，老韓忽同傳。", "道山故僊伯，再上右文殿。", "蓬萊幾清淺，筆力愈雄健。", "獨挾風雅輈，孰敢當白戰。", "一官定一集，流傳殆千卷。", "拙工見大匠，有技不敢獻。", "誰持斫鬃篇，徑徹巖下電。", "誦之百寮上，慙汗幾被面。", "公今欲何之，江左去乘傳。", "鼻閒長栩栩，仕已忘欣怨。", "英英日暮雲，薦紳極追戀。", "挽公不得留，觴豆紛祖餞。", "惟應三山高，須公和江練。", "君王念疇昔，臨遣尤繾綣。", "公乎遂來歸，密侍清閒燕。", "坐寢淮南謀，如彼雪見睍。", "從容處籌帷，侵疆歸古汴。"]'),
('9e098127-c930-47fa-96b5-313af1efcad5','送曾無玷寺丞守池陽','樓鑰','宋','宋诗','song-poetry','','[]','我朝衣冠盛，名家數三曾。',240,'全唐诗/poet.song.158000.json','["我朝衣冠盛，名家數三曾。", "南豐暨贛川，後起參溫陵。", "邇來螺川族，駸駸著簪纓。", "春風鴈塔中，參差見姓名。", "君才素穎出，健筆隨縱橫。", "江右兩壯縣，談笑政已成。", "河陽桃李花，武城絃歌聲。", "入朝八九載，去擁池陽旌。", "年家有舊好，一見意氣傾。", "更因劉御史，爲君寫先銘。", "去年叨省郎，君亦轉爲丞。", "中都但交謁，名紙空毛生。", "惟因候賓廡，接膝傾交情。", "分陰尤可惜，翻恐倒屣迎。", "阿連幸爲寮，庶幾多合并。", "寧知成勇退，拂袖尋歸程。", "秋浦素簡靜，不足煩公行。", "要當試盤錯，才刃新發硎。", "似聞有劇部，或已薦長卿。", "君其少停驂，有詔來皇扃。"]'),
('4969ec20-638f-41c8-92a0-00eab7292f5c','劉望之國錄惠示文卷次韻爲謝','樓鑰','宋','宋诗','song-poetry','','[]','吾聞三峽江，湍流下無底。',240,'全唐诗/poet.song.158000.json','["吾聞三峽江，湍流下無底。", "吾聞岷峨山，聳秀且千里。", "坤維氣淑靈，所産多名士。", "高文既鏗然，特立亦卓爾。", "久慕黄中劉，近有貢公喜。", "亟從蜀士問，人物定誰比。", "少年負奇節，論事如翻水。", "萬里見張胡，義激非氣使。", "賢關遂爲寮，八尺見英偉。", "諸君皆歛避，相與推德齒。", "惠我舂容篇，句法參子美。", "再誦平生言，作者真近似。", "戰國信徒勞，秦貪不知止。", "漢唐取與守，反覆皆造理。", "藩鎮論加詳，河朔紛鼎峙。", "詞源既淵深，浩博渺無涘。", "從今使諸生，教育均蒙被。", "論議歸正平，辭章掃浮靡。", "古人去已遠，時毋分彼此。", "君其挽之回，續絃須鳳髓。"]'),
('b53288de-578c-421e-bebb-74b165a0b425','餞李君亮著作守眉山分韻得翠字','樓鑰','宋','宋诗','song-poetry','','[]','天下大峨山，雄秀盤厚地。',216,'全唐诗/poet.song.158000.json','["天下大峨山，雄秀盤厚地。", "山雖不在眉，所在擁空翠。", "矯矯三蘇公，挹此淑靈氣。", "文章垂日星，照映蓋一世。", "李侯起廣漢，射策叩丹陛。", "褎然出群英，東南藹名字。", "來上著作庭，行入甘泉侍。", "胡爲把一麾，西歸尋藥市。", "吾聞此州俗，秉法更陳義。", "厚德坐鎮之，近古翻易治。", "君家義槩堂，活人百萬計。", "老親懷故山，色養謹承志。", "還家萬里餘，赴鎮夕可至。", "不作題柱驕，豈有晝繡意。", "班班老萊衣，人間真樂事。", "忠孝無兩心，出處固一致。", "他日上思君，命駕當不俟。", "此別諒非久，毋庸摻征袂。"]'),
('a62f15ae-2744-4c40-ad44-504740539c03','送張定叟尚書鎮襄陽','樓鑰','宋','宋诗','song-poetry','','[]','公家忠獻公，勳名照穹壤。',288,'全唐诗/poet.song.158000.json','["公家忠獻公，勳名照穹壤。", "南軒傳聖學，後進斗山仰。", "尚書天分高，百間真朗朗。", "日坐四益堂，濡染助涵養。", "小出輒驚世，發譽自英簜。", "兩朝倚才刃，三接承睿奬。", "堂堂尹京手，風采漢張敞。", "九街寢桴鼓，終朝清訟缿。", "汙流化清溝，閙市鋤巨駔。", "鈴齋晝無人，士友厚吾黨。", "政成化自行，談笑揮浩穰。", "皇家重閫寄，拊髀勞注想。", "頗牧起禁中，帝曰汝其往。", "人多惜公去，地位切台兩。", "惟公不擇地，引義猶慨慷。", "隃度更周詢，千里若尋丈。", "再拜受臨遣，因得進忠讜。", "邊臣固多事，備禦當素講。", "要須久其任，百弊隨剗磢。", "願假臣歲月，表裏如指掌。", "人材固不乏，第一戒欺罔。", "樸拙勝巧心，好佞寧木彊。", "願求忠信士，枉直謹誅賞。", "更須寬轡策，奏請應如響。"]'),
('2740443d-05bd-478e-8fcd-ecf006e6c1cf','送鄭惠叔尚書守建寧','樓鑰','宋','宋诗','song-poetry','','[]','十五年前送別詩，道山持節向江西。',256,'全唐诗/poet.song.158000.json','["十五年前送別詩，道山持節向江西。", "今年又見送公別，大天擁麾鎮閩越。", "向來惜別固已深，今日摻袪尤動心。", "尚書自是第一人，氣義相許披胸襟。", "南宮五表平明入，列辟傳聞俱聳立。", "壽皇聖孝冠百王，三復高文天爲泣。", "擢處螭坳寵數新，果然百日掌絲綸。", "拭圭修聘稱應變，握節不撓威殊鄰。", "直上銀臺尤振職，李藩氣槩時批敕。", "嗣皇銳意新百度，筆端真有回天力。", "星辰聽履冠文昌，急流勇退驚朝行。", "望之正欲試馮翊，長孺寧肯薄淮陽。", "孤拙自憐銷壯志，三入脩門空負媿。", "薦人不進終不已，獨頼當時言有味。", "公在猶嘆一居州，公去無人爲王留。", "公乎行歸佐天子，肯作管晏卑微休。"]'),
('5bd3ce04-6457-4946-8790-d65202cb235b','送蘇壽甫少卿赴潼川漕','樓鑰','宋','宋诗','song-poetry','','[]','老坡送江直入海，君今歸尋江之源。',160,'全唐诗/poet.song.158000.json','["老坡送江直入海，君今歸尋江之源。", "外臺去鄉苦不遠，爲持使節臨潼川。", "君家家世四海聞，單于一問驚胡塵。", "歸來便合上清禁，胡爲日念橫峨岷。", "賢哉群從傳家風，夕郎名節世所宗。", "諸卿亦復載清德，况君又似尚書公。", "壽皇念舊久更深，聖明親擢傳玉音。", "君歸寧能及黔突，定應召馹來追尋。", "清獻入蜀携一龜，君今數鶴同載歸。", "他時未免蕙帳怨，人在西清鶴自飛。"]'),
('faacac5e-330a-424b-bcd1-a4dd953f8ef4','分韻送孫從之司業使湖南得千字','樓鑰','宋','宋诗','song-poetry','','[]','夫君靜而敏，人十己則千。',240,'全唐诗/poet.song.158000.json','["夫君靜而敏，人十己則千。", "讀破萬卷書，操筆思湧泉。", "古事與今事，一一探本源。", "蚤蜚場屋聲，作吏志益堅。", "朅來上清班，漢庭誰在先。", "雍容行祕書，史館躬槧鉛。", "片言寤明主，立使登諫垣。", "拳拳憂國心，傾倒十三篇。", "司成天下選，歸志已浩然。", "赤日送妻子，襆被尋谿船。", "諸生慕陽城，欲挽不得專。", "竟持湖南節，征袂何翩翩。", "憶昨忝同登，于今三十年。", "朝行喜相會，終恨非官聯。", "請益殊未饜，匆匆啟離筵。", "始以長官來，今以繡衣還。", "書生素安分，豈問却與前。", "第惟公輩流，自應留日邊。", "德星聚南楚，予環當茹連。", "事體有關繫，臨岐欲無言。"]'),
('90bca06d-5596-4795-b081-009f9165493d','送王恭父倉部知洋州','樓鑰','宋','宋诗','song-poetry','','[]','天清無雲秋氣明，好風叢桂傳芳馨。',280,'全唐诗/poet.song.158000.json','["天清無雲秋氣明，好風叢桂傳芳馨。", "乃於此時送君行，江空目短難爲情。", "蚤從兩川馳大名，眉宇瑩徹春壺冰。", "語輒傾倒心地平，大篇小篇韶鈞鳴。", "壽皇一見喜不勝，璧水道山照群英。", "潼川題輿遠有聲，痛洗鹽筴疲民醒。", "天子呼來再登瀛，典領著作承明庭。", "絕域往陪蘇子卿，馬上談笑胡人驚。", "歸來期君侍西清，胡爲西去謀專城。", "士友重歎君不譍，視此進退秋毫輕。", "洋川風物天下稱，文翁流詠人載賡。", "當時猶待郡政成，君今未到意已傾。", "岢峩大艑秋江澄，圖史萬卷鷗與盟。", "殘編斷軸恐飄零，數輩裝潢手不停。", "我亦重來預彯纓，三日不見鄙吝生。", "况此摻袪將長征，欲挽不留鴻冥冥。", "賜環勿憚萬里程，江山多助筆縱橫，黼藻王度扶中興。"]'),
('d003f72d-ec71-4de6-b9b0-09c4777d34d9','題范寬秋山小景','樓鑰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','山高最難圖，意足不待大。',180,'全唐诗/poet.song.158000.json','["山高最難圖，意足不待大。", "尺楮眇千里，長江浸橫翠。", "畫家雜雲煙，戃怳徒意會。", "苟或森三尺，便若俗子對。", "此畫格律嚴，興寄獨超邁。", "洗眼映窗明，妙處乃不昧。", "流泉見原委，著屋分向背。", "推車度危橋，指路向關隘。", "輕舟最渺茫，浦嶼如有待。", "山稜瘦露骨，汀洲橫若带。", "木葉黄欲脫，秋容儼然在。", "霜餘無片雲，歷歷數沙界。", "搜尋目力疲，欲賦無可柰。", "近山才四寸，萬象紛納芥。", "欲識無窮意，聳翠更天外。"]'),
('95c9f491-cebd-4105-afae-cabe3592bd37','江西李君千能能和墨及畫梅艮齋許以三奇而詩非所長也','樓鑰','宋','宋诗','song-poetry','','[]','游藝無小大，要皆知本原。',120,'全唐诗/poet.song.158000.json','["游藝無小大，要皆知本原。", "後人率意作，終當媿前賢。", "老潘妙對膠，法從玉局傳。", "或假季心名，空掃千鐙煙。", "補之貌梅花，疎瘦仍清妍。", "折枝映月影，真態得之天。", "李君信雅尚，二者將求全。", "諸公競稱許，試之乃誠然。", "江西有詩派，皎皎俱成編。", "茲事未易窺，屬君尚加鞭。"]'),
('aa1dcc32-e61f-462b-9de3-0ff546b3a0f0','分韻送盧國華福建提刑得華字','樓鑰','宋','宋诗','song-poetry','','[]','盧侯場屋聲，天馬騰渥洼。',288,'全唐诗/poet.song.158000.json','["盧侯場屋聲，天馬騰渥洼。", "殘膏沾後人，奇芬吐天葩。", "來踏九陌塵，去種河陽花。", "向來再去國，盛山建高牙。", "平生長者譽，靜篤語不譁。", "古井絕微波，璞玉無纖瑕。", "使星照蜀道，惠愛流三巴。", "吏姦頼刮磨，民瘼煩搔爬。", "田里誦盧公，兒童知國華。", "白首尚郎潜，坐曹事如麻。", "翩翩擁軺車，去去向合沙。", "朝行惜君去，舉酒相邀遮。", "共登獅子峯，巨石臨唅呀。", "却來澄湖邊，野梅訪萌芽。", "老柳掃黄葉，枯荷矗寒茄。", "棋枰戰文楸，醉帽欹烏紗。", "伊昔送君行，相去萬里賒。", "荷君遠寄書，得得來東嘉。", "一見又成別，感念成咨嗟。", "羨君徑褰帷，往戍不待瓜。", "先尋上水船，何殊泛僊槎。", "作粥喜奉姊，上冢仍過家。", "此計正未疎，所恨成天涯。", "尚幾或留行，船鼓毋庸撾。"]'),
('2da0aab1-ac55-4a77-86bd-2f8c612eb22b','題老融畫牛溪煙雨','樓鑰','宋','宋诗','song-poetry','','[]','暝煙吹雨冥冥，兩牛半渡深清。',28,'全唐诗/poet.song.158000.json','["暝煙吹雨冥冥，兩牛半渡深清。", "京塵久污巾履，頗思歸濯吾纓。"]'),
('4d1a4bb3-72f4-4c71-9224-a641f7906f37','慧元畫寒林七賢','樓鑰','宋','宋诗','song-poetry','','[]','羣賢俱詩豪，世代不同處。',120,'全唐诗/poet.song.158000.json','["羣賢俱詩豪，世代不同處。", "安得寒林中，聯鑣睇相語。", "誰歟創妙意，臭味無今古。", "吾聞顧陸輩，寓意或如許。", "桃李並芙蓉，雪中蕉葉吐。", "元師師老融，淡墨掃風雨。", "作此寄攻媿，歸興渺煙渚。", "舊六今則七，未知果誰與。", "我欲從之遊，詎敢厠儔侶。", "畫我往執鞭，欣爲李君御。"]'),
('c768f60d-27be-4039-b1d2-d238b8d6a133','李文授和所贈老融詩復次韻爲謝','樓鑰','宋','宋诗','song-poetry','','[]','鄴侯插架書最多，筆力雄奇天所命。',224,'全唐诗/poet.song.158000.json','["鄴侯插架書最多，筆力雄奇天所命。", "萬人海中深閉門，理窟搜尋到幽夐。", "我詩無律如山謳，形穢豈堪珠玉映。", "時時歸夢入故山，曳杖松間記投暝。", "因君佳句撩秋思，便欲歸尋舊三徑。", "兼旬足痹不良行，况復炎蒸如釜甑。", "夜來一雨洗河漢，簷溜涓涓清入聽。", "晨興剝啄誰叩門，乃有同聲喜相應。", "讀之恍若濯清風，自覺昏眸怯明鏡。", "伊余何幸點班行，結交往往多名勝。", "夫君平處顧清新，解道澄江如練浄。", "從今我乃得四友，不特官梅動詩興。", "推枕裁詩謝高致，扶憊摇毫心靡定。", "舊聞讀檄愈頭風，今頼長篇起衰病。"]'),
('c1fab294-9ff6-41bb-875a-e8c2afb8af37','次韻六和塔秀江亭璧閒留題','樓鑰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','江外參差列萬山，我家深在萬山間。',64,'全唐诗/poet.song.158000.json','["江外參差列萬山，我家深在萬山間。", "好山正不用錢買，但要未老身先閑。", "長江比愁終似少，江水能回愁不了。", "扁舟何日過西陵，鄮山佳處吾歸老。"]'),
('4c51b960-9d7b-4455-9478-e58298cde911','跋袁起巖所藏脩禊序  其一','樓鑰','宋','宋诗','song-poetry','','[]','悵望當時真蹟，臨摹所在支分。',28,'全唐诗/poet.song.158000.json','["悵望當時真蹟，臨摹所在支分。", "千載但稱合作，誰能有感斯文。"]'),
('4631fc93-542a-42c2-930f-f8619289207d','跋袁起巖所藏脩禊序  其二','樓鑰','宋','宋诗','song-poetry','','[]','定本爲世第一，此又在定武前。',28,'全唐诗/poet.song.158000.json','["定本爲世第一，此又在定武前。", "今日錦標玉軸，向來不直一錢。"]'),
('aa3ae5d2-2277-4ea3-addc-992bca0b2061','送陳君舉舍人東歸','樓鑰','宋','宋诗','song-poetry','','[]','皇天生人物，千載非偶然。',288,'全唐诗/poet.song.158000.json','["皇天生人物，千載非偶然。", "沖和兼萬人，始得一英賢。", "夫君乃其人，人一己百千。", "飛黄欲追風，況復勤著鞭。", "文陣蚤奔放，氣欲摩青天。", "短褐東海瀕，名貫牛斗躔。", "聞道更獨早，自言若隊淵。", "出登龍虎榜，徑上鵷鷺聯。", "中閒幾流落，清湘窮泝沿。", "白首始爲郎，一見意已傳。", "登瀛上麟臺，授簡游兔園。", "擢爲柱下史，遂居紫微垣。", "去天真尺五，朝綱頼扶顛。", "龍樓缺問寢，萬口爭進言。", "惟君最勇決，螭頭屢直前。", "危言破人膽，三進加勤拳。", "天高聽亦高，歸袂何翩翩。", "高風激頹波，同列空慙顔。", "君雖未必去，一去勝九遷。", "我欲留孔戣，有懷不得專。", "況我自欲去，何心挽歸船。", "嗟我生何爲，與君幸齊年。", "先後才九日，相與同氣然。", "幾年苦契闊，班心忽差肩。"]'),
('f91bb88c-899f-4689-8fbc-8fb1e838566c','次韻趙子野石城釣月圖','樓鑰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','石城江頭可憐月，曾照六朝清夜獵。',156,'全唐诗/poet.song.158000.json','["石城江頭可憐月，曾照六朝清夜獵。", "古往今來知幾何，長江衮衮蕭蕭葉。", "謫僊去後詩盟寒，王孫詩瘦清欒欒。", "詩情浩蕩坐無奈，扁舟笑把磻溪竿。", "江平風輕波瑟瑟，宿靄卷空天一色。", "東風吹句入長安，一卷風流坐中得。", "初得神意清，再讀胸次平。", "回頭明月祇如故，世上興廢徒紛更。", "想君一葉方掀舞，夜靜水寒誰與語。", "船頭有酒且孤斟，莫向金陵重懷古。"]'),
('4ec4608e-7715-41f6-874d-88d20db95045','戌溪道中','樓鑰','宋','宋诗','song-poetry','','[]','寒潮高於埭，黄流濯西河。',108,'全唐诗/poet.song.158000.json','["寒潮高於埭，黄流濯西河。", "人牛力俱壯，相與衝流過。", "潮落勢叵禦，轉櫂依丘阿。", "暮靄起平楚，陰雲翳寒莎。", "夜分潮復上，櫓聲相軋摩。", "大江渺無津，不知身在何。", "餘生一虛舟，兀然聽風波。", "吾親白雲下，况爾方卧痾。", "遠游非吾事，歸矣毋蹉跎。"]'),
('e9b91f77-4c75-46c6-91f0-5d3a6606b781','哭表弟汪去僞墓','樓鑰','宋','宋诗','song-poetry','','[]','內弟幼而敏，抗志欲決科。',180,'全唐诗/poet.song.158000.json','["內弟幼而敏，抗志欲決科。", "一行試曹掾，吏才猶患多。", "謂當爲時用，舌在如命何。", "通籍已艱阻，入幕終蹉跎。", "我生依外家，侵尋閲羲娥。", "視君如同氣，竹馬聲相和。", "少長聯研席，詞場深琢磨。", "相期到晚歲，杖屨俱婆娑。", "寧知五年別，君隨東逝波。", "憶同戍溪行，我馬君乘驘。", "馬駑費十駕，驘後已倍過。", "重來意慘愴，樹擁山嵯峩。", "嗟君父與兄，相望空山阿。", "宿草埋白璧，寒風撼林柯。", "沉吟痛疇昔，有淚如懸河。"]'),
('1988a5d1-fe0a-4c0c-88cf-c176a17e50c0','次韻蔣德要三徑','樓鑰','宋','宋诗','song-poetry','','[]','居山或稱囚，得閑乃賦謫。',48,'全唐诗/poet.song.158000.json','["居山或稱囚，得閑乃賦謫。", "我方樂靜退，來作三徑客。", "西山致朝爽，膏肓在泉石。", "況當秋空浄，萬里看一碧。"]');
